INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603044A_CN8$$, $$0603044A$$, $$CN8$$, $$Soldier Enabled University Advanced$$, NULL, $$This Project leverages advanced technological innovations from academia to accelerate the optimization and demonstration of improved capabilities and systems that advance Soldier and Squad lethality-overmatch and Soldier performance and meet mission needs in the future operating environments. This Project funds collaborative, enduring advanced extramural university-based maturation and demonstration of technologies and brings together competitively selected universities with Army research teams into Technical Alliances. This Project will focus efforts on mid- to far-term Army modernization priorities while also maintaining delivery of near-term technologies critical to supporting the modernization priorities. The technical scope of this Project includes the optimization, maturation and demonstration of overarching Soldier-centric technologies including human systems integration, simplified synthetic training environments, advanced protective materials, power and energy, Warfighter endurance, robotics, as well as other innovative Soldier enabled advanced research technologies that will accelerate the Army modernization in Synthetic Training Environment, and Soldier Lethality. This Project conducts advanced research and development leading to potential emerging technologies in areas of strategic importance to the Army in Soldier capabilities related to increased protection, performance, agility, situational awareness, and lethality. This Project will also continuously strive to engage and collaborate with entities that might not otherwise collaborate with the Department of Defense (DoD) to demonstrate and provide novel Soldier-centric technologies for accelerating the adoption of emerging technologies for the Warfighter in the Army Soldier portfolio. The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Army Research Laboratory (ARL).$$, NULL, NULL, NULL, NULL, NULL, 566000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603342D8Z_488$$, $$0603342D8Z$$, $$488$$, $$Reusable hypersonic technology$$, 0, $$DIU increases the Department's access to commercial technologies and talent, with the ultimate goal of fielding technology at a pace that effectively deters our adversaries and helps ensure victory if we are forced to fight. Consistent with the Administration's 2026 interim National Defense Strategy and the National Defense Science and Technology Strategy, this new era of competition requires technological superiority to ensure the United States’ ability to project power, maintain international norms and rule of law, provide credible deterrence, and prevail in conflict.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603044A_CW1$$, $$0603044A$$, $$CW1$$, $$Technical-SAVVY Soldier Advanced$$, 1360000, $$This project conducts applied technology development to provide critical breakthroughs in developing a "technologically" fluent force. This research will refine, adapt, and validate methods and measures to assess and develop the technological fluency (TF) of Soldiers across a career (TF Personnel Assessments) and technologies to maximize technological fluency resilience and performance in Soldiers and units (Maximizing TF). TF is defined as the ability of Soldier and units to use and rapidly adapt new and intelligent technologies without formal training on these technologies, and it will be a decisive factor in a future operating environment in which Soldiers and squads are teamed with increasingly sophisticated and evolving technologies. Soldiers and leaders in specialty areas (e.g., Cyber, and Emerging Tech) and general purpose forces will require increased technological aptitudes and skills to adapt emerging technologies to evolving mission sets and avoid being overmatched by Artificial Intelligence (AI)-enabled "smart" technologies. This Project supports key Army needs and will coordinate and/or leverage findings of several PEs to include 0602184A (Soldier Applied Research), and 0603007A (Manpower, Personnel and Training Advanced Technology). This research will be performed by the U.S. Army Research Institute (ARI) for Behavioral and Social Sciences, and in coordination with collaborative research between ARI and the Army Research Laboratory (ARL) performed within 0602184A (Soldier Applied Research). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas, the Army modernization strategy, and the Army People Strategy.$$, 1360000, NULL, NULL, NULL, NULL, 604000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603044A_DN4$$, $$0603044A$$, $$DN4$$, $$Joint Service Small Arms Adv Tech$$, 4591000, $$This Project matures and demonstrates individual and crew-served armament systems; weapon, munitions, and fire control that enable increased capability, lethality, survivability and reduced negative health effects of the dismounted Warfighter across the Joint Services. This Project demonstrates blast overpressure characterization, monitoring and a wearable system that captures real-time physiological and blast exposure data to enable integrated Soldier monitoring in operational environments. Work in this Project complements Program Element (PE) 0602148A (Soldier Applied Research) / Project DN2 (Joint Service Small Arms Enabling Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Armaments Center (AC).$$, 4591000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603044A_DO2$$, $$0603044A$$, $$DO2$$, $$Modernized Composites &$$, 3000000, $$This Project matures and demonstrates advanced composite materials and manufacturing processes to deliver materials with properties to support broad applications across the DoD. Focus will be on properties required for understanding operation in future contested environments. This Project integrates manufacturing processes and advanced automation through additive, subtractive, and digital manufacturing sciences of novel composite materials, for use in both existing and future DoD-wide systems. The Project will use unique contract and collaborative approaches to accelerate transitions into and from university programs.? Work in this Project complements Project Element (PE) 0602184A (Soldier Applied Research) / Project DO1 (Modernized Composites & Manufacturing). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Advanced Materials Critical Technology Area and the Army modernization strategy. Work in this Project is performed by the Soldier Center (SC).$$, 3000000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603044A_EA7$$, $$0603044A$$, $$EA7$$, $$Enhanced Indirect Fire Adv Tech$$, 9192000, $$This project matures and demonstrates enhancements to current mortar systems. This effort will provide solutions that increase the range and lethality of currently fielded systems and mitigate blast overpressure. Work in this Project complements work done in Program Element (PE) 0602141A (Lethality Technology) / Project AH9 (Advanced Warheads Technology). The cited work is consistent with the Assistant Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Armaments Center (AC).$$, 9192000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603055D8Z_456$$, $$0603055D8Z$$, $$456$$, $$Operational Energy Surety$$, 40261000, $$This project secures U.S. warfighting advantages by driving innovations in operational energy surety, guaranteeing reliable and resilient access to energy and power for critical missions. Operational Energy Surety (OES) delivers critical enablers for operational flexibility, expanding freedom of maneuver through: • Autonomous delivery systems for assured energy resupply. • Silent watch-capable manned platforms for enhanced stealth and endurance. • Power and energy solutions enabling advanced maneuver and mobility concepts in contested environments. To achieve these goals, OES focuses on: • Agile Combat Employment (ACE): Developing energy surety options based on readily available, unique hybrid technologies; expanding energy options through innovative production methods; and generating power and heat from waste resources. • Interoperability and Standardization: Investing in tactical micro-gridding, electrical and communication standardization, and energy component commonality for multiplatform applications, ensuring seamless integration across the joint force. • Next-Generation Capabilities: Maturing high-power weapons enablers, advanced power and thermal management technologies, domestically manufactured advanced energy storage optimized for arctic and austere operations, and innovative, recoverable, offensive, effects-based energy disruption systems to deter adversaries.$$, 40261000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603055D8Z_457$$, $$0603055D8Z$$, $$457$$, $$Operational Energy and Power$$, 46457000, $$The Operational Energy and Power Projection (OE&PP) project powers the future of the DOD by delivering energy where it's needed most, enabling mission success anywhere on Earth and in space. The portfolio strategically invests in three critical areas: Aviation, Power Beaming, and Space. • Aviation: Extending the Reach of Uncrewed Aircraft: This area is revolutionizing uncrewed aircraft endurance by demonstrating innovative airframes, paving the way for more efficient on-board power generation with oil-less turbogenerators, and reducing weight through novel aircraft power electronics. • Power Beaming: Projecting Energy Across the Battlespace: This area is pushing energy forward with high-efficiency wireless power technology, including transmitters, relays, and receivers, and providing on-demand power to remote locations. • Space: Unleashing the Power of Space-Based Energy: This area is developing state-of-the-art solar cells and battery technology for maximizing energy generation and storage capabilities in space. It also leverages robotics for assembling large solar arrays and refueling satellites, dramatically increasing the availability of energy in the space domain.$$, 46457000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605531A_CQ7$$, $$0605531A$$, $$CQ7$$, $$C-sUAS Joint New Capabilities$$, 49880000, $$The Counter-small Unmanned Aircraft Systems (C-sUAS) Joint New Capabilities effort develops new technologies and materiel solutions to enable the military services and joint force to counter Groups 1-3 sUAS threats. These developments are aligned with Joint Requirements Oversight Council Memorandum (JROCM) 058-23 Operational Requirements. Joint solutions will address Fixed Site / Semi-Fixed Site, Mobile, and Dismounted systems. Efforts include development, test and evaluation, and integration sufficient for transition to fieldable capabilities.$$, 49880000, NULL, NULL, NULL, NULL, 29243000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603055D8Z_458$$, $$0603055D8Z$$, $$458$$, $$Nuclear Power$$, 30114000, $$This project is revolutionizing DOD operations by spearheading innovations in nuclear power (fission reactors and radioisotope power systems) for Joint operations across all domains. As a strategic priority for the Administration, nuclear power is poised to transform energy surety by: • Unleashing Unprecedented Energy Density: Increasing the energy density of existing power systems by approximately 1,000,000x, enabling longer mission durations and reduced logistical dependencies. • Extending Power Lifetimes in Extreme Environments: Dramatically extending power system lifetime in remote and austere locations, ensuring reliable power for critical operations in challenging environments. • Reducing the Burden on Personnel: Decreasing operational burden on personnel compared to traditional power systems (e.g., chemical batteries and fossil fuels), freeing up resources for other mission-critical tasks. The nuclear power portfolio's investments are focused on making nuclear technologies safer, lighter, more secure, more efficient, more economical, and more operational for the DOD. To achieve these goals, this project is driving technology improvements in the supply chain and power conversion efficiency of both small and large RPS and fission subsystems and components, as well as de-risking complete fission mobile nuclear reactor systems. These technology development efforts include investments in cutting-edge materials like smart carbon/carbon, shielding optimizations, betavoltaics, alphavoltaics, alpha photovoltaics, Stirling energy conversion technology, and supercritical CO2 energy conversion loops (sCO2). The nuclear power portfolio also funds studies ensuring the safety and security of these transformative technology investments.$$, 30114000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603055D8Z_459$$, $$0603055D8Z$$, $$459$$, $$Operational Energy Dominance$$, 51421000, $$The Operational Energy Dominance (OED) project enhances DOD operational effectiveness through targeted Science & Technology (S&T) investments, transforming energy data into a battlefield advantage. By embedding energy situational awareness into command and control (C2) architectures, OED enables warfighters to outpace adversaries with smarter, faster decisions in contested environments. The OED portfolio achieves this mission through three strategic thrusts: Collect, Camouflage, and Control. • Collect: OED digitizes legacy power systems (generators, batteries, and distribution nodes), integrating them into the operational data environment to eliminate blind spots and enhance situational awareness. Simultaneously, this thrust develops and deploys first-of-a-kind sensing capabilities to the front lines. • Camouflage: OED leverages power intelligence products from the Collect thrust to locate and mitigate threat surfaces within the power systems of critical military systems. • Control: OED exploits both power intelligence products and identified threat surfaces to create TTPs that expose the pacing threat's vulnerabilities, providing overmatch opportunities for US Forces in INDOPACOM. OED portfolio investments yield: 1. Enhanced mission-planning tools with integrated energy analytics. 2. Increased operational control of energy assets at every echelon. 3. Advanced metering and monitoring across modern and legacy platforms. 4. Modeling and simulation tools translating energy impacts into operational outcomes. 5. Actionable energy insights informing acquisition, sustainment, and budget decisions. 6. Foundational training embedding energy innovation across warfighters and the S&T community. All focus areas align with the DOD’s OE Strategy, ensuring energy data informs operations, logistics, and readiness. Program-wide efforts prioritize transparency tools, warfighter inclusion, and subject matter expertise to accelerate the adoption and impact of OECI investments. There is a classified addendum to this PE.$$, 51421000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603112F_632100$$, $$0603112F$$, $$632100$$, $$Electromagnetic Protection$$, 13571000, $$This project develops and demonstrates advanced materials and technologies to enable Department of the Air Force personnel, weapons, platforms, and mission- systems to operate with impunity in extreme electromagnetic spectrum environments. These extreme electromagnetic spectrum environments include those caused by deliberate electromagnetic radiation from Directed Energy Weapons (both laser and radio frequency) and nuclear detonation. In FY 2024 and beyond, work related to protection of space-based platforms is accomplished in PE 1206616SF: Space Advanced Technology Development/Demo; Project 633834: Project Integrated Space Technology Demonstrations; Effort: Advanced Materials for Spacecraft Resilience.$$, 13571000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603112F_633153$$, $$0603112F$$, $$633153$$, $$Non-Destructive Inspection$$, 4684000, $$This project develops and demonstrates advanced nondestructive inspection and evaluation technologies to monitor performance integrity and to detect failure causing conditions in weapon systems components and materials. Nondestructive inspection and evaluation capabilities greatly influence and/or limit many design, manufacturing, and maintenance practices. This project provides technology to satisfy Department of the Air Force requirements to extend the lifetime of current systems through increased reliability and cost-effectiveness at field and depot maintenance levels to include reduced manhours through automation. Equally important is assuring manufacturing quality, integrity, and safety requirements are built in.$$, 4684000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603112F_633946$$, $$0603112F$$, $$633946$$, $$Materials Transition$$, 12766000, $$This project develops and demonstrates advanced materials and processing technologies for fielded and planned Department of the Air Force weapon, airframe, aerospace structure, protection, and propulsion applications. Advanced materials and processes that have matured beyond applied research are characterized, critical data are collected, and critical evaluations in the proposed operating environment are performed. This design and scale-up data improves the overall affordability of promising materials and processing technologies, providing needed initial incentives for their industrial development.$$, 12766000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603116A_BO7$$, $$0603116A$$, $$BO7$$, $$Weapons & Munitions Adv Lethality$$, NULL, $$Congressional Interest Item funding provided for Weapons and Munitions Advanced Lethality Technology. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy.$$, NULL, NULL, NULL, NULL, NULL, 49000000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603116A_CG2$$, $$0603116A$$, $$CG2$$, $$Lethality Enabling University Adv$$, NULL, $$The Project leverages advanced developments and technological innovations from academia, lethal directed energy, laser diagnostics and accelerated design of future hypersonics, deep learning, novel materials, and emerging technologies of importance to the Army by maturing developments and performs demonstrations focused on getting technology to the warfighter more quickly. This Project exploits advanced research and development efforts to focus more on mid to far-term Army modernization priorities while also maintaining delivery of near-term technologies critical to the Long Range Precision Fires and Air and Missile Defense. This Project focuses on maturation and demonstration of various advanced technologies originating from extramural applied research in academia pertaining to lethal directed energy, laser diagnostics, future hypersonic glide body and scramjet propulsor design, deep learning, novel materials, and expansion of the Ballistic, Aero- Optics and Materials (B.A.M.) range applied to lethality. This effort validates advanced research and performs demonstrations leading to potential emerging technologies in areas of importance to the Army in directed energy, future hypersonic glide body design, deep learning and novel materials, etc., by bringing competitively selected Universities with research and development teams into Technical Alliances. Work in this Project complements Program Element (PE) 0602141A (Lethality Technology) / Project CJ1 (Lethality Enabling University), PE 0602147A (Long Range Precision Fires), PE 0603464A (Long Range Precision Fires Advanced Technology) / Project BY2 (Advanced Hypersonic Technology)., and (PE) 0602150A (Air and Missile Defense Technology) / Project DC1 (Next Generation DE Concept Development & Analysis). The cited work is consistent with Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Army Research Laboratory (ARL).$$, NULL, NULL, NULL, NULL, NULL, 8280000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603116A_CH5$$, $$0603116A$$, $$CH5$$, $$Terminal Effects Against Critical$$, 1026000, $$This Project matures and demonstrates engineering tools and high-fidelity modeling and simulation capabilities to predict and optimize weapon performance to ensure lethality against structures and critical assets. This project provides validated engineering tools and technologies to rapidly evaluate and predict weapon performance. Work in this Project complements Program Element (PE) 0602141A (Lethality Technology) / Project CF8 (Terminal Effects Against Critical Targets Tech). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Army Engineer Research and Development Center Geotechnical and Structures Laboratory.$$, 1026000, NULL, NULL, NULL, NULL, 3928000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603116A_CID$$, $$0603116A$$, $$CID$$, $$Sensor to Shooter (STS) Advanced$$, NULL, $$This Project matures and demonstrates an advanced network lethality architecture to enable Joint All Domain Command and Control decision aid algorithms for coordinated and synchronized response and incorporates a full spectrum of effects and scalability to reduce the sensor to shooter timeline for Large Scale Combat Operations. Work in this Project complements Program Element (PE) 0602141A (Lethality Technology) / Project CIB (Sensor to Shooter (STS) Applied Research). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project supports Next Generation Combat Vehicle, Tactical Network, Future Vertical Lift, and Long-Range Precision Fires Army Modernization Priorities. Work in this Project is performed by the Armaments Center and Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR).$$, NULL, NULL, NULL, NULL, NULL, 5449000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603116A_DB2$$, $$0603116A$$, $$DB2$$, $$Future Armaments Scalable$$, 6949000, $$Future Armaments Scalable Technologies addresses the need to enhance the capability of existing and future critical enabling technologies. This effort will mature critical armament component technologies in the areas of energetics & warheads, fuzing & sensing, guidance navigation and control (GNC), materials & structures in order to support critical technology insertions into program requirements. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Armaments Center (AC).$$, 6949000, NULL, NULL, NULL, NULL, 3872000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603116A_LR1$$, $$0603116A$$, $$LR1$$, $$Long Range Sensing Adv Tech$$, 5257000, $$This project develops the modeling and simulation tools, physics-based models, virtual and scaled radio frequency (RF) hardware and software prototypes to validate and mature adaptive multi-function resource management, tracking and discrimination algorithms, and radar sensor technologies in support of Long Range Precision Fires. Work in this Project complements Program Element (PE) 0602141A (Lethality Technology) / Project CG4 (Advanced Radar Concepts and Technologies). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Research in this Project is performed by the Command, Control, Communication, Computers, Cyber, Intelligence, Surveillance and Reconnaissance Center (C5ISR).$$, 5257000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603117A_BS2$$, $$0603117A$$, $$BS2$$, $$Army Advanced$$, NULL, $$The Army Advanced Technology Development budget line includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Efforts develop proof of technological feasibility and assessment of subsystem and component operability that may lead to full system development and prototyping.$$, NULL, NULL, NULL, NULL, NULL, 140980000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603118A_AY5$$, $$0603118A$$, $$AY5$$, $$Soldier Squad Small Arms$$, 4034000, $$This Project demonstrates individual and crew-served weapon designs and technologies that enhance the fighting capabilities and survivability of the dismounted Warfighter in support of the Army's Soldier Lethality Modernization priority and all of the Services. This Project matures blast overpressure characterization, monitoring and a wearable system that captures real-time physiological and blast exposure data to enable integrated Soldier monitoring in operational environments. All work is led by the Joint Service Small Arms Program (JSSAP) and is based upon the Joint Service Small Arms Master Plan (JSSAMP) and the Joint Capabilities Integration Development System's Small Arms Analyses. Work in this Project complements Program Element (PE) 0602143A (Soldier Lethality Technology) / AY6 (Soldier Squad Small Arms Armaments Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Armaments Center (AC).$$, 4034000, NULL, NULL, NULL, NULL, 6555000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603118A_AY7$$, $$0603118A$$, $$AY7$$, $$Small Arms Fire Control Advanced$$, NULL, $$This Project matures and demonstrates fire control and targeting sensor technologies and techniques to improve targeting and lethality in order to maintain overmatch at longer ranges in all operational environments and to meet the capability needs of Army Science and Technology Soldier Lethality, Next Generation Combat Vehicle, and Long-Range Precision Fires modernization priorities. Work in this Project complements Program Element (PE) 0602143A (Soldier Lethality Technology) / AY8 (Small Arms Fire Control Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Armaments Center (AC).$$, NULL, NULL, NULL, NULL, NULL, 2481000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603118A_AY9$$, $$0603118A$$, $$AY9$$, $$Body Armor & Integrated Headborne$$, 4577000, $$This Project matures and demonstrates body armor weight reductions and improves the performance of personal protection and survivability equipment. It also demonstrates combat helmet ballistic, blast, and small arms protection performance enhancements and the integration and optimization of power, energy, and digital sensor and display headborne technologies. This Project supports Force Protection capability demonstrations for Soldiers and Small Units and demonstrated technologies from this effort transition to various Program Executive Office (PEO) Soldier programs. This Project complements work done in Program Element (PE) 0602143A (Soldier Lethality Technology) / AZ2 (Body Armor & Integrated Headborne Technology). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Soldier Center (SC).$$, 4577000, NULL, NULL, NULL, NULL, 8065000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603342D8Z_490$$, $$0603342D8Z$$, $$490$$, $$Hypersonic unmanned wingman$$, 0, $$DIU increases the Department's access to commercial technologies and talent, with the ultimate goal of fielding technology at a pace that effectively deters our adversaries and helps ensure victory if we are forced to fight. Consistent with the Administration's 2026 interim National Defense Strategy and the National Defense Science and Technology Strategy, this new era of competition requires technological superiority to ensure the United States’ ability to project power, maintain international norms and rule of law, provide credible deterrence, and prevail in conflict.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603118A_AZ6$$, $$0603118A$$, $$AZ6$$, $$Soldier Signature Management$$, NULL, $$This Project optimizes, matures and demonstrates advances in novel materials, technologies, techniques, and applications increasing the capabilities of camouflage, concealment, and deception against known and emerging sensor threats. These technologies will produce proof of concept systems that decrease the probability of detection and targeting by peer and near-peer adversaries, enabling freedom of movement of semi-independent and dispersed formations, and increase protection of high-valued assets. This Project will demonstrate disruptive Camouflage, Concealment and Deception technologies, supporting expeditionary maneuver in the Multi- Domain Battle Environment to open and retain windows of advantage. Research in this Project supports key Army needs and leverages/complements the technical research of several Program Elements (PEs) and Projects to include PE 0602143A (Soldier Lethality Technology) / BB4 (Dismounted Soldier Survivability Materials), Project AZ5 (Soldier Protection Technology - Vulnerability), Project AZ9 (Soldier Protection Advanced Tech - Detectability); PE 0601102A (Defense Research Sciences; and PE 0602145A (Next Generation Combat Vehicle Technology) / Project BI2 (Sensor Protection Technology). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Soldier Center (SC).$$, NULL, NULL, NULL, NULL, NULL, 3051000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603118A_BB3$$, $$0603118A$$, $$BB3$$, $$Dismounted Soldier Survivability$$, 9361000, $$This Project matures and demonstrates Soldier survivability materials and technologies to increase the speed and efficiency of dismounted Soldier movement and maneuver. This Project matures and demonstrates body armor weight reductions and improves the performance of personal protection and survivability equipment. This project optimizes, matures and demonstrates advances in novel materials, technologies, techniques, and applications increasing the capabilities of camouflage, concealment, and deception against known and emerging sensor threats. This Project focuses on reducing Soldier-worn equipment weight, improving Soldier and system integration and reducing the dismounted Soldier's detectability, susceptibility, and vulnerability to operational threats. Operational threats are characterized as combat threats (e.g., flame and thermal, blast and ballistic, multispectral sensors, and laser threats), environmental threats (e.g., cold, heat, wet, vector, water contamination, concealment, etc.), and Soldier system components and system limitations (e.g., size, weight, and bulk). This Project includes the demonstration and validation of integrated technologies, novel subsystems/ systems, and test methods. This Project complements work done in Program Element (PE) 0602143A (Soldier Lethality Technology) / Project BB4 (Dismounted Soldier Survivability Materials). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Soldier Center (SC).$$, 9361000, NULL, NULL, NULL, NULL, 3416000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603118A_BB8$$, $$0603118A$$, $$BB8$$, $$Soldier Centric Advanced Technology$$, NULL, $$This Project matures and demonstrates an optimized training systems to enable effective training and provide increased levels of Soldier proficiency and readiness. This Project matures and demonstrates Soldier centric technologies for the Soldier/Squad virtual environment to support the Army's Synthetic Training Environment (STE). The STE is the next generation holistic collective training capability that will train units where they will fight, with whom they will fight with, and in complex operational environments to include dense urban and sub-terrain; within the entire range of combined arms maneuver tasks in support of Multi-Domain Operations. The Soldier/ Squad virtual environment combines and integrates several individual Soldier and Squad training capabilities, STE Squad Capability (SSC), Weapon Skill Development (WSD), Joint Fires Training (JFT), and Use of Force (UoF), into a single capability that can be conducted simultaneously or individually and enable physical movement/ exertion related to the execution of Soldier/Marine individual and Squad collective training tasks. The STE will provide the realistic repetitions necessary to fight 25 bloodless battles before the first battle. The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Soldier Center (SC).$$, NULL, NULL, NULL, NULL, NULL, 1833000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603118A_BC1$$, $$0603118A$$, $$BC1$$, $$Human Performance AdvTech for$$, 10848000, $$This Project matures technologies, methodologies, and human performance models to demonstrate increased mobility and lethality of the individual and small unit to achieve overmatch and offset vulnerabilities of maneuvering infantry. It validates and integrates human performance assessment methods and algorithms into training/ education, test and evaluation methodologies, and materiel solutions to optimize the Soldier as a weapons system and the small unit as an integration combat platform. These methods and algorithms have potential to enable the development of doctrine, organization, training, materiel, leadership and education, personnel and facilities (DOTMLPF) improvements and efficiencies. This Project also uses Soldier assessments to iteratively improve the performance and integration of technologies to augment Soldier function (e.g. shoot, move, perceive, decide, and communicate) during distributed operations utilizing cross-domain capabilities. This Project also complements and is fully coordinated with work performed across Army, Navy, and Air Force under the Human Systems Community of Interest: Systems Interfaces & Cognitive Processes and Protection, Sustainment, and Warfighter Performance. This Project supports key Army needs and complements the technical research of Program Element (PE) 0602143A (Soldier Lethality Technology)/Project BC2 (Next Gen Mobility & Lethality Tech for Warfighters). This research is in partnership with Forces Command (FORSCOM) operational units and the appropriate Training and Doctrine Command (TRADOC) organizations as well as established transition partners, including Program Executive Office-Soldier (PEO-S). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas, the Close Combat Lethality Task Force, and the Army modernization strategy. Work in this Project is performed by the Soldier Center (SC).$$, 10848000, NULL, NULL, NULL, NULL, 6866000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603118A_BC8$$, $$0603118A$$, $$BC8$$, $$Training Advanced Technology (Other$$, 22644000, $$This Project matures and demonstrates advanced training technologies in support of the Army's need for simulations that accurately replicate and realistically represent the effects of current and future weapons systems during live and synthetic training. Integration of the live and synthetic environments into a single synthetic training environment will modernize the current Live Training Environment and allow fair fight engagements across all training environments and training devices. This Project complements work done in Program Element (PE) 0602143A (Soldier Lethality Technology) / Project BC7 (Training Technology (Other than STE) and Program Element (PE) 0603118A (Soldier Lethality Advanced Technology) / Project BE9 STE Advanced Technology. The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Soldier Center (SC).$$, 22644000, NULL, NULL, NULL, NULL, 7411000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603807A_FF4$$, $$0603807A$$, $$FF4$$, $$Counterdrug, DDR, Sys Development$$, NULL, $$Supports the Secretary of Defense approved counterdrug advanced development efforts used in a major re-design of the Forensic Toxicology Drug Testing Laboratory (FTDTL) information management system used to test urine samples for the presence of illegal drugs. The Drug Testing Program - Client Collection System (DTP-CSS) is comprised of several variations of a desktop application used to select service members for random drug testing, prepare labels for urine specimen bottles, and print corresponding chain-of-custody documents. This Project will standardize DTP-CSS across all services and migrate it to a Web-based system.$$, NULL, NULL, NULL, NULL, NULL, 1981000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603118A_BC9$$, $$0603118A$$, $$BC9$$, $$Adv Soldier Sensors/Displays$$, 25684000, $$This Project matures, optimizes, and demonstrates fully digital sensor systems, architectures, and interfacing capabilities to fuse sensors, and network situational understanding information and targeting capabilities to enable maintained mounted and dismounted visual advantage, increased situational awareness, decreased fratricide, and decreased response times to all threats in all environments. Research in this Project supports the Army Science and Technology Soldier Lethality, Next Generation Combat Vehicle, and Future Vertical Lift Army Modernization priorities. This Project complements work done in Program Element (PE) 0602143A (Soldier Lethality Technology) / BD1 (Advanced Soldier Sensors/Displays Tech for Dismounts). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Command, Control, Communication, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center.$$, 25684000, NULL, NULL, NULL, NULL, 26470000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603118A_BD7$$, $$0603118A$$, $$BD7$$, $$Soldier Sys Interfaces/Integration-$$, 4662000, $$This Project will integrate and mature technologies for sensing, processing, displaying information, interfacing with users, and cognitive improvement to enhance Soldier & Small Unit situational awareness & understanding. This Project will integrate and demonstrate battlefield, body-worn sensors, and data fusion algorithms to provide the dismounted Small Unit leader with clear, actionable information for making well informed, rapid, tactical decisions over long duration in extreme conditions. This Project will also mature and integrate advanced dismounted Soldier robotic and autonomous systems technologies to demonstrate autonomous navigation, manned-unmanned teaming, and networked reconnaissance to improve Soldier lethality, situational awareness, and survivability during tactical operations in extreme conditions. Research in this Project complements several Program Elements (PEs) and Projects to include PE 0602143A (Soldier Lethality Technology) / BD6 (Soldier Sys Interfaces/Integration - Sensor Tech), PE 0603118A (Soldier Lethality Advanced Technology) / Project BC1 (Human Performance AdvTech for Mobility & Lethality) and Project BC9 (Adv Soldier Sensors/Displays AdvTech for Dismounts). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Research in this Project is performed by the Soldier Center (SC).$$, 4662000, NULL, NULL, NULL, NULL, 7011000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603118A_BD9$$, $$0603118A$$, $$BD9$$, $$Soldier & Sm Unit Tactical Energy$$, NULL, $$This Project will demonstrate advanced Power and Energy (P&E) technologies for the dismounted Soldier to lighten equipment load, reduce resupply need, and enhance mobility. This Project will conduct Soldier and Small Unit power and energy technology maturation, integration with clothing and individual equipment, technical analysis, and operational assessment. Work in this Project complements several Program Elements (PEs) to include PE 0603118A (Soldier Lethality Advanced Technology) / Project BD7 (Soldier Sys Interfaces/ Integration Adv Tech), Project BD8 (Soldier & Small Unit Tactical Energy Tech), and PE 0603118A (Soldier Lethality Advanced Technology) / Project BC9 (Adv Soldier Sensors/Displays Adv Tech for Dismounts). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Research in this Project is performed by the Soldier Center and the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center.$$, NULL, NULL, NULL, NULL, NULL, 9082000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603118A_BE2$$, $$0603118A$$, $$BE2$$, $$Joint Service Combat Feeding$$, 2749000, $$This Project matures and demonstrates combat ration and field feeding technologies to optimize Warfighter performance, decrease the risk of exposure to chemical and biological contaminants in foods, and reduce the logistics burden to enable semi-independent operations. The Army serves as the Executive Agent for this Department of Defense (DoD) program, with oversight and coordination provided by the DoD Combat Feeding Research and Engineering Board. This Project matures and demonstrates research done in Program Element (PE) 0602143A (Soldier Lethality Technology) / Project BE3 (Joint Service Combat Feeding Technology). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Research work in this Project is performed by the Soldier Center (SC).$$, 2749000, NULL, NULL, NULL, NULL, 2632000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603118A_BE5$$, $$0603118A$$, $$BE5$$, $$Personnel & Airdrop Safety Advanced$$, 9813000, $$This Project matures and demonstrates equipment and innovative techniques for precision aerial delivery of cargo and personnel. Technologies support Army Modernization Priority, Soldier Lethality. Aerial delivery is a key capability for rapid force projection and global precision delivery to support the mission readiness profile for Global Response Force (GRF). These efforts are designed to advance state of the art precision delivery technologies such as parachutes; guidance, navigation, and control (GNC) components and subsystems; tracking sensors; software algorithms; and safety rigging that integrates with currently equipped aircraft, unmanned aerial systems (UAS), and advanced rotary wing aircraft. These efforts provide the Warfighter with highly accurate, timely cargo/payload delivery and resupply in all terrain and weather conditions. Precision delivery/resupply reduces vulnerability of ground Soldiers, aircraft, and aircrew. Precision aerial delivery supports remote warfare with activities such as placement of battlefield sensors and reduction of Soldier load. Research in this Project supports key Army needs and complements the technical research in Program Element (PE) 0602143A (Soldier Lethality Technology) / Project BR9 (Personnel & Airdrop Safety Technology). This Project also complements research done in the Science & Technology Precision, Navigation and Timing Modernization priority. The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Research work in this Project is performed by the Soldier Center (SC).$$, 9813000, NULL, NULL, NULL, NULL, 6453000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603119A_BL8$$, $$0603119A$$, $$BL8$$, $$Power Projection in A2AD$$, 2658000, $$This Project matures and demonstrates remote assessment technologies to determine entry and maneuver corridors, provides site selection tools and decision support technologies for climatic regions in all season conditions including aviation site- selection tools, enhanced automated route reconnaissance technologies, mobility models for extreme temperatures, and road capacity assessment technologies. These technologies will reduce reliance on manned on-site reconnaissance for force projection assessments and provide all-season predictions to ensure air and ground battlespace entry and maneuver. This Project also matures and demonstrates material solutions to repair, rebuild, and construct infrastructure required for movement and maneuver in highly contested, complex operational environments such as Anti-Access/Area Denial. Work in this Project complements Program Element (PE) 0602144A (Ground Technology) / Project BL7 (Power Projection in A2AD Environments Technology). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work in this Project is performed by the United States Army Engineer Research and Development Center Geotechnical and Structures Laboratory.$$, 2658000, NULL, NULL, NULL, NULL, 3250000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603118A_BE9$$, $$0603118A$$, $$BE9$$, $$STE Advanced Technology$$, 814000, $$This Project matures and demonstrates technologies supporting the Army's Synthetic Training Environment (STE). The STE is the next generation holistic collective training capability that will train units where they will fight, with whom they will fight with, and in complex operational environments to include dense urban and sub- terrain; within the entire range of combined arms maneuver tasks in support of Multi- Domain Operations. STE Information Systems (STE-IS) delivers the Common Synthetic Environment consisting of Global Terrain/One World Terrain (OWT), Training Simulation Software (TSS), and Training Management Tools (TMT). The STE will be available where training occurs (home station, combat training centers, armories, institutions, shipboard, deployed) and will include Air and Ground Reconfigurable Virtual Collective Trainers (RVCTs), a Soldier/Squad Virtual Training (S/SVT), and a live training capability. The STE will be cloud-enabled, compatible with the Army Enterprise Network, and service-based through the Common Operating Environment, including Live and Constructive. The STE will provide the realistic repetitions necessary to fight 25 bloodless battles before the first battle. The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas, the Army modernization strategy, and supports the STE Cross Functional Team efforts. Work in this Project is performed by the Soldier Center (SC).$$, 814000, NULL, NULL, NULL, NULL, 8125000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603118A_BS8$$, $$0603118A$$, $$BS8$$, $$Soldier Lethality Advanced$$, NULL, $$Congressional Interest Item funding provided for Soldier Lethality Advanced Technology. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy.$$, NULL, NULL, NULL, NULL, NULL, 26500000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603119A_BK8$$, $$0603119A$$, $$BK8$$, $$Robotics for Engineer Operations Adv$$, 6001000, $$This Project matures and demonstrates robotic engineer equipment capabilities that can remotely characterize the environment and operate in the battlespace for autonomous Combat Engineer actions. This Project provides technologies for Combat Engineer mission planning, creating or reducing barriers and obstacles, as well as maintaining, repairing, and constructing expedient infrastructure. These efforts will enhance Combat Engineer missions of mobility, counter mobility, and survivability through semi-autonomous or autonomous operations. Work in this Project complements Program Element (PE) 0602144A (Ground Technology) / Project BK7 (Robotics for Engineer Operations Technology). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work in this Project is performed by the United States Army Engineer Research and Development Center Construction Engineering Research Laboratory, Information Technology Laboratory, and Geotechnical and Structures Laboratory$$, 6001000, NULL, NULL, NULL, NULL, 3789000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603119A_BK9$$, $$0603119A$$, $$BK9$$, $$Ground System Fluids and Fuels Adv$$, NULL, $$This Project matures and demonstrates liquid logistics technologies such as enhanced jet fuels, lubricants, oils, powertrain fluids, coolants, bulk fluid treatment, monitoring, metering, storage, and distribution in support of established Army regulations and requirements. This Project improves products and technologies to optimize fuel efficiency, meet new hardware fluid requirements, modernize fluids, ensure bulk fluid meets quality requirements, and provide bulk fluid asset visibility, to optimize logistics and reduce logistics requirements. This Project executes the demonstration of enhanced jet fuels for ground systems, enhanced performance coolants, fluids for vehicle electrification, and smart bulk fuel metering and monitoring technologies. This Project improves liquid logistics products and technologies that are critical enablers for multi-domain operations requiring semi-independent operations to enable dispersed operations to extend operational reach, prolong endurance and allow freedom of action for the Joint Force. The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work in this Project is performed by the Ground Vehicle System Center (GVSC)$$, NULL, NULL, NULL, NULL, NULL, 6840000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603119A_BL3$$, $$0603119A$$, $$BL3$$, $$Explosives Forensics Advanced$$, 2049000, $$This will mature and demonstrate instrumentation and algorithms required to provide improved point, proximity, and stand-off detection of low levels of explosives and solid chemical hazards. This will enable the warfighter to integrate portable chemical and explosive hazard detection equipment. This project will also integrate explosive detection into the family of Chemical, Biological, Radiological, and Nuclear point and stand-off sensors, alternative chemical detection modalities and algorithms, that will improve the probability of detection and attribution of an explosive hazard or home-made explosive manufacturing/assembly location. Work in this project compliments Program Element (PE) 0602144A (Ground Technology) / Project BL2 (Explosives Forensics Technology) The cited work is consistent with the Under Secretary of Defense Research and Engineering priority focus. Work in this Project is performed by the Chemical Biological Center (CBC)$$, 2049000, NULL, NULL, NULL, NULL, 2174000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603119A_BL6$$, $$0603119A$$, $$BL6$$, $$Expedient Passive Protection$$, 4152000, $$This Project matures and demonstrates rapidly deployable protection solutions to protect the Warfighter and critical assets; methodologies for intuitive decision support; and tactics, techniques, and procedures to increase the survivability of personnel, critical assets, and facilities from a range of threats. Force protection technologies will be matured and demonstrated for applications in complex and contested environments to protect against a range of threats, to include improvised, conventional, and emerging weapons such as ballistic missiles. Develop and demonstrate protective structure design guidance to reduce blast overpressure (BOP) exposure to Warfighters using rapid analysis and characterization of blast environments and novel materials and structural solutions. Work in this Project complements Program Element (PE) 0602144A (Ground Technology) / Project BL5 (Expedient Passive Protection Technology). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project supports the Army Science and Technology Ground Portfolio. Work in this Project is performed by the United States Army Engineer Research and Development Center Geotechnical and Structures Laboratory.$$, 4152000, NULL, NULL, NULL, NULL, 5908000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603119A_BM1$$, $$0603119A$$, $$BM1$$, $$Protection from Advanced Weapon$$, 5298000, $$This Project matures and demonstrates structural hardening solutions and force protection technologies to increase survivability of facilities and provide critical updates to protective design specifications and guidance. Additionally, this project matures and demonstrates passive protection technologies and provides protective design criteria advancements to mitigate attack from emerging advanced threats. Work in this Project complements Program Element (PE) 0602144A (Ground Technology) / Project BL9 (Protection from Advanced Weapon Effects Technology). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work in this Project is performed by the United States Army Engineer Research and Development Center Geotechnical and Structures Laboratory.$$, 5298000, NULL, NULL, NULL, NULL, 4866000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603119A_CJ9$$, $$0603119A$$, $$CJ9$$, $$Ground Enabling University Adv$$, NULL, $$The Project matures and demonstrates advanced developments and technological innovations from academia, in the focus areas of ground autonomy, Artificial Intelligence / Machine Learning (AI/ML) and robotics, occupant/vehicle survivability and other ground platform technologies of importance to the Army, by maturing and demonstrating technologies with the goal of delivering technology to the warfighter more quickly. This Project matures and demonstrates advanced technologies with a focus on mid to far-term Army modernization priorities while also maintaining delivery of near-term technologies critical to the next generation combat vehicles. This Project focuses on maturation and demonstration of various advanced technologies originating from extramural applied research in academia pertaining to navigation/ routing, autonomous robotic vehicles with the use of artificial intelligence and machine learning as applied to ground mobility and maneuver, and other innovative ground enabling applied research technologies. This Project also matures and demonstrates advanced technologies leading to potential emerging capabilities in areas of strategic importance to the Army in autonomy, robotics and AI/ML, protection of both platform and occupant, and other ground platform technologies in propulsion, survivability, powertrain, etc., by bringing competitively selected Universities with research and development teams into Technical Alliances. Work in this Project complements Program Element (PE) 0620144A (Ground Technology), PE 0602145A (Next Generation Combat Vehicle Technology) and PE 0603462A (Next Generation Combat Vehicle Advanced Technology). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work in this Project is performed by the Army Research Laboratory (ARL).$$, NULL, NULL, NULL, NULL, NULL, 4060000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603119A_CV5$$, $$0603119A$$, $$CV5$$, $$Engineer Enablers Maneuver, LOG, &$$, 2643000, $$This Project matures and demonstrates joint contested logistics operations technologies and provides capabilities to operate in dispersed battlefield operations and support sustainment operations through predicted dynamic scenario development that provides critical vulnerabilities assessment and methods/equipment to mitigate potential issues. Work in this Project complements Program Element (PE) 0602144A (Ground Technology) / Project CV3 (Engineer Enablers Maneuver, LOG, & Sustainment Apl). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project supports the Army Science and Technology Ground portfolio. Work is performed by the United States Army Engineer Research and Development Center Geotechnical and Structures Laboratory, Geospatial Research Laboratory, Coastal and Hydraulics Laboratory, Environmental Laboratory, Cold Regions Research and Engineering Laboratory, Construction Engineering Research Laboratory, and Information Technology Laboratory.$$, 2643000, NULL, NULL, NULL, NULL, 3192000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603119A_DA2$$, $$0603119A$$, $$DA2$$, $$SAFR Alternatives for Readiness$$, 3298000, $$This Project matures and demonstrates cross-cutting, safer alternative advanced technologies that enable warfighter readiness. These technologies also support product availability, Soldier and worker safety, and a reduced environmental footprint in the manufacturing, maintenance, and use of ground vehicles and other Army weapon systems. The Project matures and optimizes safer alternatives in technology areas including surface finishes, coatings, solvents, refrigerants, and fire suppressants. This research addresses the growing impacts to health and readiness associated with carcinogens such as hexavalent chromium, global warming chemicals including hydrofluorocarbons (HFCs), and forever chemicals such as like per- and polyfluoroalkyl substances (PFAS). This Project enables the Army to assess and resolve these types of emerging and continually evolving risks throughout the full life cycle of Army systems. This Project complements and transitions technologies developed under Program Element (PE) 0602144A (Ground Technology) /Project DA1 (SAFR Alternatives for Readiness Applied Research). Work in this Project is performed by the Army Research Laboratory (ARL); the Armaments Center; the Aviation and Missile Center (AVMC); the Soldier Center (SC), and the Ground Vehicle Systems Center (GVSC)$$, 3298000, NULL, NULL, NULL, NULL, 3509000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603119A_DG2$$, $$0603119A$$, $$DG2$$, $$Advanced Development of$$, 2655000, $$The Project matures and demonstrates obscurant technologies with potential to enhance personnel and platform survivability by degrading threat force surveillance sensors and defeating the enemy's target acquisition devices, missile guidance, and directed energy weapons. Dissemination systems for new and improved obscurants are developed with the goal of providing efficient and safe screening of deployed forces. Work in this Project compliments Program Element (PE) 0602144A (Ground Technology) / Project DG1 (Development of Obscurants) The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Chemical Biological Center (CBC).$$, 2655000, NULL, NULL, NULL, NULL, 3211000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603119A_DI8$$, $$0603119A$$, $$DI8$$, $$Environmental Security Resilience Adv$$, 1753000, $$This Project matures and demonstrates capabilities to support Army Environmental Security, providing decisions and support tools for critical mission environments to address natural resource impediments, man-made stressors, extreme weather, and environmental engineering challenges that impact mission, infrastructure, training activities, deployment staging or present security concerns to operations. Project capabilities span the functional domains of strategic support area management, emergency preparedness, surge capacity, environmental impact on operations, and analysis of future operational environment and environmental threats. This effort will provide new material solutions, models and decision support tools for operational planning and infrastructure management. Work in this Project complements Program Element (PE) 0602144A (DI7) / Project (Environmental Security Resilience Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Army Engineer Research and Development Center Environmental Laboratory, Construction Research Engineering Laboratory, and the Cold Regions Research and Engineering Laboratory.$$, 1753000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603119A_DI9$$, $$0603119A$$, $$DI9$$, $$Comprehensive Adapt Operational$$, NULL, $$This Project will provide power control and distribution hardware (i.e., inverters and metering and monitoring equipment) that supports interoperability between the energy source program of record, such as Advanced Medium Mobile Power Source (AMMPS) and energy storage solutions at the tactical level. This project matures, demonstrates, and integrates a seamless bridge between low and medium voltage tactical generators (defined as 500kW and below), and improves decision tools to assist the Commander in choosing the optimal operational energy power storage type for their mission or force structure. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas. Work in this Project is performed by the United States Army Engineer Research and Development Center, Construction Engineering Research Laboratory.$$, NULL, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603121D8Z_121$$, $$0603121D8Z$$, $$121$$, $$SO/LIC Advanced$$, 0, $$FY26 SO/LIC Advanced Development has been realigned into the CTTS 122. No funds in FY26 and out. This program supports the Department's initiatives to Deter Aggression, Defend the Homeland, and Build Sustainable and Long-Term Advantage. The Advanced Development (AD) subgroup within IWTSD built on lessons learned from more than a decade of developing, managing, and overseeing the Secure Unclassified Network (SUNet) and is now developing, testing, and delivering advanced tools and capabilities for the Department of Defense (DoD) to campaign in and through cyberspace, maximize cyber capabilities in support of integrated deterrence, and effectively use cyber operations to generate asymmetric advantages. The AD subgroup streamlines the implementation and validation of Artificial Intelligence and cybersecurity requirements across IWTSD’s project portfolio as well as develops novel tools and capabilities in collaboration with our partners across the cyber domain.$$, 0, NULL, NULL, NULL, NULL, 19181000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603122D8Z_484$$, $$0603122D8Z$$, $$484$$, $$Combating Terrorism Technology$$, 81513000, $$The Irregular Warfare Technical Support Directorate (IWTSD) conducts rapid research and development (R&D) in support of the Interim National Defense Strategic Guidance (INDSG) to provide leap-ahead technologies focused on surpassing current and expected levels of technology used and developed by our adversaries, with China as the pacing threat. IWTSD is mandated and structured to rapidly fill capability gaps, to include increasing lethal capability of U.S. forces at the squad and small unit level; developing lethal drones; countering small uncrewed aerial systems (drones); subterranean detection and operations; novel body and vehicle armor; detecting, protecting against, and mitigating novel and wartime CBRNE threats; telematics; covert communications; and of special interest, the use of machine learning and artificial intelligence to enhance the capability of systems used by the military and lessen the workload on the individual users. During FY 2025 and into FY 2026, IWTSD will continue to focus its R&D activities to rapidly fill the immediate, emerging, and critical capability gaps for those at the tactical edge to include our nation’s special operations forces, other military operators, intelligence analysts, and first responders. The number of capability gaps IWTSD can address are reduced due to the increased cost of incorporating artificial intelligence, machine learning, cyber hardening, and DoD safety testing of prototype systems prior to operational test and evaluation (OT&E). For instance, the focus on increased lethality has driven up costs to meet Defense safety and testing requirements. From a broader perspective, projects remain distributed among 11 mission subgroups: • Advanced Analytics • Advanced Development • Chemical, Biological, Radiological, Nuclear, and Explosives • Expeditionary Force Protection • Explosive Ordnance Disposal and Explosive Operations • Human Performance and Training • Indirect Influence and Competition • Innovation • Protection, Survivability, and Recovery • Surveillance, Collection, and Operations Support • Tactical Offensive Support$$, 81513000, NULL, NULL, NULL, NULL, 1479077000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603123N_2912$$, $$0603123N$$, $$2912$$, $$Force Protection Advanced$$, 43527000, $$This project addresses advanced technology development associated with providing the capability of Platform and Force Protection for the U.S. Navy. This project supports the development of technologies associated with mission capable, persistent and survivable Naval platforms (surface, subsurface, terrestrial, and air) in the areas of Manufacturing, Naval Engineering (formerly Platform Design & Engineering), Power and Energy (formerly Power, Energy & Propulsion), Undersea Systems and Naval Aerospace. This project develops technologies for enhanced capability of Naval aviation aircraft platforms in terms of mission effectiveness, platform range, responsiveness, survivability, observability, readiness, safety and life cycle cost. It also develops new Naval air vehicle concepts and high impact, scalable Naval air vehicle technologies. The FY 2026 request for Mission Capable and Survivable Force includes $0 thousand of discretionary and $2,000 thousand of mandatory (reconciliation) for a total of $2,000 thousand. The mandatory funds support the development of advanced technologies that provide resilient mission capabilities and improved survivability under asymmetric attack. Research includes full spectrum advancements to characterize complex threats; perform proactive cyber shaping with decision advantage in response; enable resilience and survivability through maneuver and protection of mission critical infrastructure and operational forces; and reconstitute and sustain mission critical capabilities throughout the timeline of events. Further information for this reconciliation request is provided in Section 20005 (Low-Cost Weapons) of the Reconciliation Exhibit.$$, 43527000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603123N_3049$$, $$0603123N$$, $$3049$$, $$Force Protection$$, 0, $$Develop advanced technologies, critical to protecting naval installations, to provide seamless full spectrum protection against asymmetric attack by improving the ability to: detect and identify developing and immediate threats; shape our responses through improved situational awareness and decision making; shield personnel, mission critical facilities, infrastructure, and operating fleet assets; maintain essential functions; and sustain and restore critical services in the aftermath of an incident. Technologies developed will also seek to reduce the required manpower and skill levels devoted to the force protection mission, improving performance and reducing costs for the Navy.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603123N_3270$$, $$0603123N$$, $$3270$$, $$Sec. 2912 Operational Energy$$, 0, $$This project addresses applied research associated with providing the capability of Platform and Force Protection for the U.S. Navy. It supports the development of technologies associated with surface naval platforms. Research is focused on providing technologically superior employment of naval assets and delivering warfighting capabilities at reduced operating and total ownership costs for surface and subsurface platforms through investments in applied research in Power and Energy.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603123N_9999$$, $$0603123N$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional Interest Items not included in other Projects.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603128N_3448$$, $$0603128N$$, $$3448$$, $$Marine Group 5 UAS Development$$, 28388000, $$The FY 2026 MALE program funding, PE 0603128N, addresses requirements identified in the October 2016 MUX ICD and April 2020 MUX Requirements Clarification document. Project 3448 - MALE RDTE is pursuing MQ-9A mission (payloads/sensors) and mission enabler capabilities design, development capabilities and integration and testing. These capabilities will support the MALE program's electronic warfare, Maritime Domain Awareness (MDA), tactical edge automation, and airborne network support missions. Consisting of Common Operating and Intelligence Picture (COP/CIP), Detect and Avoid System (DAAS), Airborne Network Extension, Electronic Support development, integration and testing. Additionally, this RDTE is pursuing automated sensor synchronization and onboard forward edge data fusion and transmission using AI/ML apparatus that will transmit fused signals and visual information back to Marine and Joint intelligence apparatus and proliferate the information at the forward edge to stand-in forces (SIF) through the use of Proliferated Low Earth Orbit (PLEO). The PLEO SatCom capacity provides high data throughput and resilient command and control architecture. The USMC MALE program will be supported by UX-24 and VMX-1 as the primary test activity/squadron for capability development as well as system modification validation efforts. UX-24 will provide direct support of testing associated with payloads/sensors in support of USMC requirements. The payloads/sensors which undergo testing may require or drive hardware and software modifications during testing to satisfy system, subsystem and component level test parameters. VMX-1 provides operational test and evaluation of capabilities for MAGTF SIF such as the Marine Littoral Regiment. In FY25 the program will close out the current MDA pod development and transition to conducting studies, analysis, and prototype development for alternative material solutions to meet MALE MDA capability requirements.$$, 28388000, NULL, NULL, NULL, NULL, 96813000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603128N_9999$$, $$0603128N$$, $$9999$$, $$Congressional Adds$$, 0, $$The Autonomous Maritime Patrol Aircraft (AMPA) project provides funding to address capability gaps identified in the 2026 Fleet and COCOM Integrated Priority Lists (IPLs), including a need for persistent Command, Control, and Communications (C3) and Intelligence, Surveillance, and Reconnaissance (ISR) capabilities. This ultra- long endurance (ULE) solar-powered unmanned aerial system (UAS) is scheduled to culminate a Joint Capability Technology Demonstration (JCTD) in Q4FY24 by executing a 7-day flight demonstration with operationally relevant payloads integrated. Performance tagets for the AMPA Low-Rate Initial Production variant of the aircraft are a 90+ day endurance, up to an 800-pound payload capacity, and enough electrical power available (target goal is 2kW) to simultaneously operate a suite of C3 and ISR payloads.$$, 0, NULL, NULL, NULL, NULL, 1931000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603133D8Z_313$$, $$0603133D8Z$$, $$313$$, $$Foreign Comparative Testing$$, 27958000, $$The Foreign Comparative Testing (FCT) Program Element funding supports projects that test and evaluate innovative technologies already developed by Partner Nations, and in doing so, directly aligns to the interim National Defense Strategy through increasing joint lethality in contested environments, strengthening partnerships, and fostering reform through delivery of capability at the speed of relevance. FCT individual projects typically average less than $1.000 million each and complete within 12-36 months. Projects are proposed by the Military Services and U.S. Special Operations Command (USSOCOM) and are selected using a merit-based process that identifies the most promising, innovative, and cost-effective solutions to validate warfighter requirements, with an emphasis on transitioning technologies into current or future programs of record. Project selection is based on potential to yield cost, schedule, or performance improvements over the existing capabilities.$$, 27958000, NULL, NULL, NULL, NULL, 209438000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603134A_CD3$$, $$0603134A$$, $$CD3$$, $$Counter Improvised-Threat Simulation$$, 15692000, $$This Project develops, matures, and demonstrates technologies for detecting and defeating improvised explosive devices (IEDs) and other threat explosive devices. The goal of this research is to increase the ability of deployed forces to positively identify IEDs with minimal false alarms and increase the rate of advance of deployed forces, as well as to identify vehicle and personnel borne IEDs at fixed sites. Additionally, the objective is to positively neutralize or mitigate the effects of IEDs with minimal collateral damage. Work in this Project complements Program Element (PE) 0602134A (Counter Improvised-Threat Advanced Studies) / Project CD2 (Counter Improvised-Threat Advanced). Work in this Project is executed by the U.S. Army Combat Capabilities Development Command (DEVCOM) in coordination with the Under Secretary of Defense for Research and Engineering (USD (R&E) with work being led by Joint Service laboratories in partnerships with industry and academia.$$, 15692000, NULL, NULL, NULL, NULL, 20965000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603135A_A32$$, $$0603135A$$, $$A32$$, $$Counter Small Unmanned Aircraft Sys$$, 7773000, $$This Project develops, matures, and demonstrates novel capabilities that aid in the detection, tracking, identification, mitigation, and/or defeat of small unmanned aerial systems (sUAS) groups 1-3. Matures, demonstrates, and transitions interceptor capabilities to deliver physical effects that enable faster intercept, greater standoff ranges, increased magazine depth, survivability, affordability, and/or decrease in size, weight, and power requirements. Develops capabilities to track and predict UAS flight paths, airspace situational awareness, and/or location of UAS operators to increase defeat and force protection capabilities. Matures and demonstrates algorithms to enable threat prioritization, airspace control, coordinated response, and resource management of CsUAS capabilities. Matures technical solutions to defeat sUAS capabilities, including target acquisition, navigation, and control, in addition to identifying and exploiting weaknesses in sUAS system design and operation. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC) and Armaments Center (AC).$$, 7773000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603142D8Z_123$$, $$0603142D8Z$$, $$123$$, $$Mission Engineering and Integration$$, 15835000, $$Mission Engineering and Integration Management is a strategically driven, mission-focused framework to synchronize concepts, requirements, research and engineering, budget, and programs across the DoD to integrate cross-Service capabilities to deliver timely and accurate end-to-end mission effects. • Carry out responsibilities described in the National Defense Authorization Act for FY 2017, Section 855, (Mission Integration Management) by conducting rigorous mission engineering activities to identify and prioritize investments in capabilities with the greatest potential to meet current and future warfighting needs, close warfighting gaps, and enable Joint Force interoperability and integration. • Execute a variety of Joint Force Integration Mission Engineering studies in support of the Interim National Defense Strategic Guidance, aligned with Defense Planning Scenarios and Key Operational Problems, that evaluate mission impacts of integrating new technologies and capabilities into critical warfighter missions. • Harness modeling and simulation (M&S) tools and advanced techniques to develop and analyze critical Joint Mission Engineering Threads (METs) / “Kill Webs” in operational scenarios, enabling DoD leaders to make informed technology investment decisions. • Develop digital, reusable, enterprise-level Joint METs that are used to assess and evaluate system-of-systems dependencies and risks in executing end-to-end missions. • Continue to maintain the Mission Engineering Guide and related guidance; and lead the Mission Engineering Practitioners Forum to share lessons learned, pain points, and advance the state of practice of Mission Engineering. • Increase collaboration with industry, utilizing technical information exchange agreements to share sensitive data. These efforts will identify material solutions that address operational gaps and mission requirements; building public-private partnerships that inform technology, modernization, research, and applied engineering investments.$$, 15835000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603142D8Z_124$$, $$0603142D8Z$$, $$124$$, $$Advanced Analysis and Capability$$, 83699000, $$Advanced Analysis and Capability Development (A2CD): Continues the execution of advanced analysis under the JLE initiative and development and use of an advanced hardware, software, and TS/SCI/SAP network architecture to conduct fully informed analysis, experimentation, and process improvement to accelerate the Department’s capability development and fielding efforts. Effort focuses on two areas. 1. JLE (formerly designated as Advanced Concept Development): Research and analysis efforts to solve specific critical military challenges and drive Department investment decisions that enhance the effectiveness of systems against adversarial threats. Activities span across all security levels, domains, and Service warfighting architectures. Additional classified information available upon request. 2. Joint Capability Development Environment (JCDE): Independent FY2025 activities - Advanced Modeling and Simulation (M&S) Technology and Tool Development and Modeling and Simulation Big Play – have been consolidated into an effort entitled Joint Capability Development Environment (JCDE) to provide a more unified and efficient development approach, afforded by previous accomplishments; advances in fully informed, all domain modeling and simulation (M&S) capabilities; and improved analysis and experimentation methods. JCDE provides a hardware, software, and TS/SCI/SAP network architecture designed to accelerate the Department’s ability to conduct rapid capability development and fielding. The JCDE provides industry, the DoD, FFRDC/UARCs, and international partners access to advanced modeling and simulation (M&S) tools and a multi- level security (MLS) enabled data/knowledge repository to enable rigorous, rapid analysis and experimentation in support of capability development and military utility analysis and experimentation. The JCDE also includes a development environment that enables the continuous creation and improvement of advanced M&S tools and corresponding analysis/experimentation processes.$$, 83699000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603160BR_RA$$, $$0603160BR$$, $$RA$$, $$CWMD CROSS-$$, 63598000, $$Counter Weapons of Mass Destruction (CWMD) Technologies and Capabilities Development project develops advanced technologies and weapon concepts and validates their applicability to CWMD. Research encompasses the following areas: Defeat Technologies supports Combatant Commands through research, development, and transition of offensive weapons and other capabilities to counter Weapons of Mass Destruction (WMD) while mitigating collateral contamination effects. Enable rapid capability delivery supports urgent warfighter operational requirements in countering WMD and emerging threats, often below the level of armed conflict. This research develops and delivers urgent CWMD capabilities to provide Combatant Commands a competitive advantage against WMD-capable adversaries with a focus on innovative, agile, achievable, and effective technology solutions for DoD sensitive and classified programs, Combatant Command hybrid warfare support, and competition below the level of armed conflict. Counter emergent threat technologies research develops and transitions a full spectrum of new technologies to counter emergent WMD threats providing combatant commanders improved offensive capabilities in support of near-peer emerging threats and counter-proliferation missions that combat weapons of mass destruction. This research supports the U.S. Special Operations Command (USSOCOM) in two areas: (1) counter proliferation research is a collaborative effort to develop advanced, warfighter-unique technologies to defeat WMD development and acquisition pathways, to include defeat of the devices themselves, while minimizing risks to U.S. forces; and (2) counter emerging threats concepts and technologies to integrate and synchronize activities that prevent violent extremist organizations and rogue nation states from developing, acquiring, proliferating, or using WMD. This effort supports Commander, USSOCOM responsibilities under the Chairman, Joint Chiefs of Staff Unified Command Plan. Counterforce technologies research develops, integrates, demonstrates, and transitions advanced sensors, surveillance, and target defeat planning technologies to enable the warfighter to hold WMD-related targets at risk. There are three core research efforts in this project: Technical Reconnaissance; CWMD Weapons Effects; and, Applied CWMD Computational, Physical and Life Science Research. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Threat Reduction Agency                                                            Date: June 2025 Appropriation/Budget Activity                                                           R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:                    PE 0603160BR / COUNTER WEAPONS OF MASS DESTRUCTION ADVANCED TECHN Advanced Technology Development (ATD)                                                   OLOGY DEVELOPMENT Target assessment technologies research develops, applies, and transitions processes and technologies providing advanced capabilities in the areas of WMD Targets Immersive Mission Planning (TIMP), and Full Dimensional Defeat Enterprise (FDDE). Nuclear - Advanced Automated Target Development automates intelligence input to provide more realistic target input parameters incorporating 3-D models. WMD-TIMP provides an interactive virtual reality platform for mission planning that mitigates impact of characterization uncertainty by allowing mission planners to execute multiple planning iterations with varied uncertainty parameters. FDDE aims to develop an enterprise capability for finding and identifying a facility, characterizing its function and physical layout, determining current or future vulnerabilities to available defeat mechanisms, planning and executing an attack, assessing damage, and denying reconstitution efforts. The dynamic capabilities encompassed in this effort provide Combatant Commands and the intelligence community tools and processes needed to hold at risk high value hard targets and WMD targets possessed by adversaries.$$, 63598000, NULL, NULL, NULL, NULL, 345718000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603160BR_RD$$, $$0603160BR$$, $$RD$$, $$NUCLEAR$$, 84153000, $$Counter Weapons of Mass Destruction (CWMD) Technologies and Capabilities Development project develops advanced technologies and weapon concepts and validates their applicability to CWMD. Research encompasses the following areas: Defeat Technologies supports Combatant Commands through research, development, and transition of offensive weapons and other capabilities to counter Weapons of Mass Destruction (WMD) while mitigating collateral contamination effects. Enable rapid capability delivery supports urgent warfighter operational requirements in countering WMD and emerging threats, often below the level of armed conflict. This research develops and delivers urgent CWMD capabilities to provide Combatant Commands a competitive advantage against WMD-capable adversaries with a focus on innovative, agile, achievable, and effective technology solutions for DoD sensitive and classified programs, Combatant Command hybrid warfare support, and competition below the level of armed conflict. Counter emergent threat technologies research develops and transitions a full spectrum of new technologies to counter emergent WMD threats providing combatant commanders improved offensive capabilities in support of near-peer emerging threats and counter-proliferation missions that combat weapons of mass destruction. This research supports the U.S. Special Operations Command (USSOCOM) in two areas: (1) counter proliferation research is a collaborative effort to develop advanced, warfighter-unique technologies to defeat WMD development and acquisition pathways, to include defeat of the devices themselves, while minimizing risks to U.S. forces; and (2) counter emerging threats concepts and technologies to integrate and synchronize activities that prevent violent extremist organizations and rogue nation states from developing, acquiring, proliferating, or using WMD. This effort supports Commander, USSOCOM responsibilities under the Chairman, Joint Chiefs of Staff Unified Command Plan. Counterforce technologies research develops, integrates, demonstrates, and transitions advanced sensors, surveillance, and target defeat planning technologies to enable the warfighter to hold WMD-related targets at risk. There are three core research efforts in this project: Technical Reconnaissance; CWMD Weapons Effects; and, Applied CWMD Computational, Physical and Life Science Research. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Threat Reduction Agency                                                            Date: June 2025 Appropriation/Budget Activity                                                           R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:                    PE 0603160BR / COUNTER WEAPONS OF MASS DESTRUCTION ADVANCED TECHN Advanced Technology Development (ATD)                                                   OLOGY DEVELOPMENT Target assessment technologies research develops, applies, and transitions processes and technologies providing advanced capabilities in the areas of WMD Targets Immersive Mission Planning (TIMP), and Full Dimensional Defeat Enterprise (FDDE). Nuclear - Advanced Automated Target Development automates intelligence input to provide more realistic target input parameters incorporating 3-D models. WMD-TIMP provides an interactive virtual reality platform for mission planning that mitigates impact of characterization uncertainty by allowing mission planners to execute multiple planning iterations with varied uncertainty parameters. FDDE aims to develop an enterprise capability for finding and identifying a facility, characterizing its function and physical layout, determining current or future vulnerabilities to available defeat mechanisms, planning and executing an attack, assessing damage, and denying reconstitution efforts. The dynamic capabilities encompassed in this effort provide Combatant Commands and the intelligence community tools and processes needed to hold at risk high value hard targets and WMD targets possessed by adversaries.$$, 84153000, NULL, NULL, NULL, NULL, 313366000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603160BR_RG$$, $$0603160BR$$, $$RG$$, $$CWMD TECHNOLOGIES$$, 233668000, $$Counter Weapons of Mass Destruction (CWMD) Technologies and Capabilities Development project develops advanced technologies and weapon concepts and validates their applicability to CWMD. Research encompasses the following areas: Defeat Technologies supports Combatant Commands through research, development, and transition of offensive weapons and other capabilities to counter Weapons of Mass Destruction (WMD) while mitigating collateral contamination effects. Enable rapid capability delivery supports urgent warfighter operational requirements in countering WMD and emerging threats, often below the level of armed conflict. This research develops and delivers urgent CWMD capabilities to provide Combatant Commands a competitive advantage against WMD-capable adversaries with a focus on innovative, agile, achievable, and effective technology solutions for DoD sensitive and classified programs, Combatant Command hybrid warfare support, and competition below the level of armed conflict. Counter emergent threat technologies research develops and transitions a full spectrum of new technologies to counter emergent WMD threats providing combatant commanders improved offensive capabilities in support of near-peer emerging threats and counter-proliferation missions that combat weapons of mass destruction. This research supports the U.S. Special Operations Command (USSOCOM) in two areas: (1) counter proliferation research is a collaborative effort to develop advanced, warfighter-unique technologies to defeat WMD development and acquisition pathways, to include defeat of the devices themselves, while minimizing risks to U.S. forces; and (2) counter emerging threats concepts and technologies to integrate and synchronize activities that prevent violent extremist organizations and rogue nation states from developing, acquiring, proliferating, or using WMD. This effort supports Commander, USSOCOM responsibilities under the Chairman, Joint Chiefs of Staff Unified Command Plan. Counterforce technologies research develops, integrates, demonstrates, and transitions advanced sensors, surveillance, and target defeat planning technologies to enable the warfighter to hold WMD-related targets at risk. There are three core research efforts in this project: Technical Reconnaissance; CWMD Weapons Effects; and, Applied CWMD Computational, Physical and Life Science Research. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Threat Reduction Agency                                                            Date: June 2025 Appropriation/Budget Activity                                                           R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:                    PE 0603160BR / COUNTER WEAPONS OF MASS DESTRUCTION ADVANCED TECHN Advanced Technology Development (ATD)                                                   OLOGY DEVELOPMENT Target assessment technologies research develops, applies, and transitions processes and technologies providing advanced capabilities in the areas of WMD Targets Immersive Mission Planning (TIMP), and Full Dimensional Defeat Enterprise (FDDE). Nuclear - Advanced Automated Target Development automates intelligence input to provide more realistic target input parameters incorporating 3-D models. WMD-TIMP provides an interactive virtual reality platform for mission planning that mitigates impact of characterization uncertainty by allowing mission planners to execute multiple planning iterations with varied uncertainty parameters. FDDE aims to develop an enterprise capability for finding and identifying a facility, characterizing its function and physical layout, determining current or future vulnerabilities to available defeat mechanisms, planning and executing an attack, assessing damage, and denying reconstitution efforts. The dynamic capabilities encompassed in this effort provide Combatant Commands and the intelligence community tools and processes needed to hold at risk high value hard targets and WMD targets possessed by adversaries.$$, 233668000, NULL, NULL, NULL, NULL, 1150190000, 2026) ON CONFLICT DO NOTHING;
