INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603462A_BK6$$, $$0603462A$$, $$BK6$$, $$Adv Direct InDirect Armament Sys$$, 10927000, $$This Project matures and demonstrates technologies for large caliber direct fire light-weight armament systems that will exceed the current capability of 120 millimeter (mm) direct fire cannons and be optimized for future operational environment with cross-domain engagement capability. Specifically, this Project integrates and demonstrates technologies for rapid fire on-the-move at all elevations (direct & indirect), compact ammunition design with advanced ignition, advanced recoil mitigation to reduce impulse and allow integration onto lighter platforms, and automated ammunition handling and reloading. This Project also supports open architecture to enable supervised autonomy and remote operation and integrates intelligent fire control to address multi-domain targets from manned and unmanned platforms. Work in this Project is related to and fully integrated with the efforts funded in Program Element (PE) 0602145A (Next Generation Combat Vehicle Technology) and PE 0604115A (Technology Maturation Initiatives). Work in this Project complements Program Element (PE) 0602145A (Next Generation Combat Vehicle Technology) / Project BK5 (Adv Direct In-Direct Armament Sys (ADIDAS) Tech) and Program Element (PE) 0603464A (Long Range Precision Fires Advanced Technology) / Project CE9 (Armaments Advanced Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project supports the Next Generation Combat Vehicle Army Modernization Priority. Work in this Project is performed by the Armaments Center (AC)$$, 10927000, NULL, NULL, NULL, NULL, 779000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603462A_BP6$$, $$0603462A$$, $$BP6$$, $$Ground Vehicle Advanced$$, NULL, $$Congressional Interest Item funding provided for Ground Vehicle Advanced Technology. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy.$$, NULL, NULL, NULL, NULL, NULL, 223134000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603462A_BZ9$$, $$0603462A$$, $$BZ9$$, $$Smart Targeting Environment for$$, NULL, $$This Project matures and demonstrates mission targeting support software and algorithms, to include Electronic Warfare capabilities, leveraged from the Defense Advanced Research Project Agency (DARPA) System-of-System Enhanced Small Unit (SESU), current force, and Science and Technology (S&T) in order to enable small units to continuously build and share targeting data and access strike assets in multi-domain operations. The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Research in this Project supports the Next Generation Combat Vehicle Army Modernization Priority. Work in this Project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, NULL, NULL, NULL, NULL, NULL, 4318000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603463A_AM7$$, $$0603463A$$, $$AM7$$, $$Modular RF Communications$$, 2417000, $$This Project matures developed techniques, methods, and standards for automation and intelligence to optimally broadcast data among available radio frequency (RF) and networking technologies. This Project will predict that a change in the network is needed and automatically make that change (transport, waveform mode, routing) prior to the network failing or being degraded. This Project provides a resilient transport agnostic network to the user. Work in this Project complements Program Element (PE) 0602146A (Network C3I Technology) / Project AM6 (Modular RF Communications Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, 2417000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603463A_AM9$$, $$0603463A$$, $$AM9$$, $$Protected SATCOM Advanced$$, 10612000, $$This Project matures and demonstrates technologies and components to increase resiliency of Wideband Satellite Communications (SATCOM) in contested and congested electromagnetic environments. This Project improves resiliency through science & technology investigation. This Project complements technologies that provide obfuscation of radio frequency (RF) spectrum signature in order to counter enemy electronic surveillance capabilities. Work in this Project complements Program Element (PE) 0602146A (Network C3I Technology) / Projects AM8 (Protected SATCOM Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, 10612000, NULL, NULL, NULL, NULL, 13663000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603463A_AN4$$, $$0603463A$$, $$AN4$$, $$Non Traditional Waveforms Advanced$$, 7797000, $$This Project demonstrates non-traditional waveforms and technologies for resilient communications in contested environments providing anti-jam, low probability of intercept, and low probability of detection for the dismounted and vehicular user. This Project also optimizes technologies not typically applied to the tactical environment, such as millimeter wave communications and directional networking with coherent combining of radio frequency signals, to maintain networked communications in and under contested and congested electromagnetic spectrum environments. Work in this Project complements Program Element (PE) 0602146A (Network C3I Technology) / Project AN3 (Non Traditional Waveforms Technology) and Project AO4 (Energy Efficient Devices Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, 7797000, NULL, NULL, NULL, NULL, 5130000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603463A_AN8$$, $$0603463A$$, $$AN8$$, $$COE - Every Receiver is a Sensor$$, NULL, $$This Project optimizes automated exploitation and fusion analysis tools, applications, and software services that harvest, correlate and fuse tactical receiver sources with new and emerging data sources to improve understanding of the threat picture and more efficiently support near-real time Situational Understanding of the battlefield. Work in this Project complements Program Element (PE) 0603463A (Network C3I Advanced Technology) / Project AO1 (UNT - Every Receiver is a Sensor Advanced Tech) and PE 0602146A (Network C3I Technology) / Project AN7 (COE - Every Receiver is a Sensor Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, NULL, NULL, NULL, NULL, NULL, 6374000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603525N_0428$$, $$0603525N$$, $$0428$$, $$Pilot Fish$$, 1218486000, $$The details of this budget justification are classified, per Executive Order 13526, Sec 1.4 (a) and are submitted annually to Congress in the classified budget justification book.$$, 1218486000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603527D8Z_527$$, $$0603527D8Z$$, $$527$$, $$Retract Larch$$, 0, $$This program is reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program Annual Report to Congress. For further information, please contact the Deputy Chief Technology Officer for Science and Technology (DCTO(S&T)) within the Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)).$$, 0, 0, 0, 0, 0, 76729000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603463A_AO1$$, $$0603463A$$, $$AO1$$, $$UNT - Every Receiver is a Sensor$$, 3494000, $$This Project demonstrates high fidelity Cyber-Electromagnetic Activity (CEMA) situational understanding by exploiting tactical receivers with sufficient capabilities as sensors; optimizes real-time radio frequency mapping of the tactical environment in support of network operation and decision making; and mature counter-AI algorithms to enhance Army's SIGNINT platforms survivability against peer adversaries' smart weapon systems. This project will help the Army pace global electromagnetic spectrum technology advancements by maturing and demonstrating critical near peer signals intelligence (SIGINT) capabilities designed for the Army's size, weight, and power (SWaP)-constrained tactical edge. Work in this Project complements Program Element (PE) 0602146A (Network C3I Technology) / Project AN9 (UNT - Every Receiver is a Sensor Technology) and Project AN7 (COE - Every Receiver is a Sensor Technology); and PE 0603463A (Network C3I Advanced Technology) / Project AN8 (COE Every Receiver is a Sensor Advanced Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, 3494000, NULL, NULL, NULL, NULL, 3054000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603463A_AO7$$, $$0603463A$$, $$AO7$$, $$EW for Maneuver Operations (EMO)$$, NULL, $$This Project matures and demonstrates distributed, coordinated Electromagnetic Warfare (EW) capabilities designed to extend effective range, reduce susceptibility to localization, and introduce errors into adversary Intelligence, Surveillance, Reconnaissance & Targeting (ISR&T) systems to facilitate multi-domain operations (MDO). This Project will mature Electromagnetic Warfare (EW) resources to mitigate Electromagnetic Protection (EP), against a finite set of threat capabilities, present in Anti- Access Area Denial (A2/AD) threats to achieve improved freedom of maneuver. Work in this Project complements Program Element (PE) 0602146A (Network C3I Technology) / Project AP5 (Electronic Warfare Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, NULL, NULL, NULL, NULL, NULL, 3106000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603463A_AQ5$$, $$0603463A$$, $$AQ5$$, $$Sensor CE-Integrated Sensor$$, NULL, $$This Project matures and demonstrates capabilities that enable and enhance sensor interoperability across disadvantaged and disparate networks.? It leverages and furthers the existing architectures consisting of standards, interfaces, and services. Enabling operationally relevant data to efficiently move across the network and ensures data is available for the Command & Control (C2) systems, integration into Tactical Operations Centers (TOC), ingestion into decision support aides and is actionable at the tactical edge. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, NULL, NULL, NULL, NULL, NULL, 1933000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603463A_AQ8$$, $$0603463A$$, $$AQ8$$, $$High Tempo Data Driven Decision$$, 18218000, $$This Project matures and demonstrates data driven decision tools that help develop Situational Understanding (SU) for Commanders. It enhances decision-making and accurately assesses and integrates cross-warfighting functional area impacts with all the domains in Multi-Domain Operations (MDO), and thereby enhances mission effectiveness by improving decision cycles. This Project matures and integrates methods to optimize the Army's Command and Control (C2) services and data architecture to strengthen data-driven decisions. Work in this Project complements Program Element (PE) 0602146A (Network C3I Technology) / Project AQ7 (High Tempo Data Driven Decision Tools Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, 18218000, NULL, NULL, NULL, NULL, 27083000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603463A_AT8$$, $$0603463A$$, $$AT8$$, $$Network-Enabled GeoSpatial-GEOINT$$, 6194000, $$This Project accelerates and exploits the tactical value of emerging field generated, mission relevant 3-dimensional (3D) geospatial data supporting mission planning, mission rehearsal and tactical situational awareness. Integrates and demonstrates the geo-registration, feature extraction, change detection, data visualization and transmission capabilities developed in the applied research portion of this Project. Tools developed for the exploitation of 3D datasets will be integrated into a streamlined workflow requiring low levels of expertise, putting advanced processing capabilities in the hands of the Soldier. This Project also includes demonstrations of tactical enhancements and the integrated ability to rapidly share mission critical 3D information in support of planning and execution. Work in this Project complements Program Element (PE) 0602146A (Network C3I Technology) / Project AT7 (Network-Enabled GeoSpatial and GEOINT Services Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Army Engineer Research and Development Center Geospatial Research Laboratory, Cold Regions Research and Engineering Laboratory, and Information Technology Laboratory. .$$, 6194000, NULL, NULL, NULL, NULL, 4586000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603463A_AU1$$, $$0603463A$$, $$AU1$$, $$Tactical GeoSpatial Information$$, 3422000, $$This Project matures and demonstrates next generation geospatial analytical tools for three-dimensional (3D) complex environments applicable to low echelon and tactical edge exploitation. These new capabilities will allow deployed units to enhance/update provisioned (baseline) standard, sharable, geospatial foundation (SSGF) data through automated analytics on multi-sourced spatial data resulting in streamlined, high fidelity terrain analysis products. Reducing data gaps and processing timelines will greatly increase Soldier situational awareness and support faster decision making in complex terrain. Work in this Project complements Program Element (PE) 0602146A Network C3I Technology / Project AT9 (Tactical GeoSpatial Information Capabilities Techn). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Army Engineer Research and Development Center Geospatial Research Laboratory.$$, 3422000, NULL, NULL, NULL, NULL, 2035000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603527N_2690$$, $$0603527N$$, $$2690$$, $$Retract Larch$$, 0, $$The details of this budget justification are classified, per Executive Order 13526, Sec 1.4 (a) and are submitted annually to Congress in the classified budget justification book.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603536N_4016$$, $$0603536N$$, $$4016$$, $$Retract Sycamore$$, 206429000, $$The details of this budget justification are classified, per Executive Order 13526, Sec 1.4 (a) and are submitted annually to Congress in the classified budget justification book.$$, 206429000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603463A_AU4$$, $$0603463A$$, $$AU4$$, $$Geospatially Enabled Operational$$, 3491000, $$This Project demonstrates, integrates and transitions to Mission Command Systems, a geospatially enabled collaborative planning environment, accessible across echelons, with capabilities that support Army Design Methodology (ADM) by providing the ability to perform conceptual planning and problem framing, supporting a greater understanding and visualization of the dynamic operational environment, a shared understanding of the operations purpose across echelons, and enhanced products to drive detailed budget planning and operational assessment processes, enhancing the collaborative interaction between commanders, staffs, and unified action partners. Work in this Project complements Program Element (PE) 0602146A (Network C3I Technology) / Project AU3 (Geospatially Enabled Operational Design Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Army Engineer Research and Development Center Geospatial Research Laboratory and Information Technology Laboratory.$$, 3491000, NULL, NULL, NULL, NULL, 10888000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603463A_AV8$$, $$0603463A$$, $$AV8$$, $$Navigation Warfare (NAVWAR)$$, NULL, $$This Project matures and demonstrates capabilities allowing the Army to monitor, understand, and control the Navigation Warfare (NAVWAR) environment. This requires an integrated approach to Electronic Protection (EP), Electronic Support (ES), and Electronic Attack (EA) to rapidly characterize the NAVWAR environment, deny Positioning, Navigation, and Timing (PNT) based capabilities to our adversaries, and maintain Army capabilities. Work in this Project complements Program Element (PE) 0602146A (Network C3I Technology) / Project AW1 (Autonomous Navigation Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center.$$, NULL, NULL, NULL, NULL, NULL, 5900000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603463A_AW6$$, $$0603463A$$, $$AW6$$, $$Modular GPS Independent Sensors$$, 4923000, $$This Project matures and demonstrates a resilient, soldier-integrated precision navigation and timing solution, providing precision geolocation, geospatial survey information, global positioning system (GPS) spoofing awareness and countermeasures to dismounted warfighters in GPS-denied/degraded environments. It develops capabilities to enable open and flexible Position Navigation and Timing (PNT) systems architecture with unlimited data rights for the Army's dismounted systems. Work in this Project complements Program Element (PE) 0602146A (Network C3I Technology) / Project AW1 (Autonomous Navigation Technology) and Program Element (PE) 0602141A (Lethality Technology) / Project CG4 (Advanced Radar Concepts and Technologies). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center and the Army Applications Laboratory.$$, 4923000, NULL, NULL, NULL, NULL, 8298000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603463A_BP4$$, $$0603463A$$, $$BP4$$, $$ELECTRONIC WARFARE$$, NULL, $$Congressional Interest Item funding provided for Electronic Warfare Advanced Technologies. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy.$$, NULL, NULL, NULL, NULL, NULL, 94000000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603463A_CI7$$, $$0603463A$$, $$CI7$$, $$Mobile & Survivable Command Post$$, 11491000, $$The Project matures and demonstrates technologies to support scalable, survivable, mobile Command Posts (CP). Technologies addressed will use the Brigade CP as a baseline while providing the opportunity for solutions to scale up or down to Army tactical echelons. Research in this Project includes integrating anti-jam (AJ) and low probability of intercept (LPI)/low probability of detection (LPD) communications focused on enabling the CP to disperse, form & reform, and employ technologies for signal remoting; optimizing power generation and storage for distributed CP operations; reducing computing infrastructure footprint, size, weight, and power (SWAP), manpower, and complexity; maturing technologies to reduce CP emissions and have situational awareness of those signatures to improve CP node employment; maturing electro-magnetic spectrum (EMS) emulation technologies to improve survivability options; and optimizing emerging electronic-textiles and composite materials for CP structures. Work in this Project complements Program Element (PE) 0602146A (Network C3I Technology) / Project CI3 (Mobile and Survivable Command Post (MASCP) Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Work in this Project is performed by the Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, and Reconnaissance (C5ISR) Center and Soldier Center (SC).$$, 11491000, NULL, NULL, NULL, NULL, 15731000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603463A_CJ8$$, $$0603463A$$, $$CJ8$$, $$Assured PNT Communications$$, 5145000, $$This Project provides prototyping and development of Space-enabled and quantum technologies to support wide-area, responsive deep area sensing required for beyond line of sight (BLOS) targeting, significantly reducing Sensor to Shooter (S2S) timelines and increasing lethality and force protection. This Project provides Army forces access to commercial and National space assets and develops algorithms that process space and near space sensor data in real and near real time for integration into battlefield operating systems. The payoff of this work will be demonstrated advanced technologies for space-enabled capabilities for more secure, rapid communications, and deep target sensing for deep strike lethality, and freedom of maneuver. Work in this project complements Program Element (PE) 0602146A (Network C3I Technology) / Project CG3 (Assured PNT Communications Applied Research)/and Program Element (PE) 0602182A (C3I Applied Research) / Project CZ6 (Assured PNT Enabling Technologies). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Army Space and Missile Defense Technical Center.$$, 5145000, NULL, NULL, NULL, NULL, 11563000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603463A_DB6$$, $$0603463A$$, $$DB6$$, $$Pathfinder 3D Advanced Technology$$, 1335000, $$This Project matures and demonstrates a geospatial rapid position and navigation solution in Global Positioning System (GPS) degraded and denied environments. Research focuses on using onboard sensors and high-resolution digital terrain geospatial alternative solution based upon Visual Three-Dimensional (3-D) Terrain Referencing and Navigation (VTRAN). This Project will result in the linkage of air and ground assets integrating sensory and (One World Terrain and Reference) geospatial data within the modular GPS Independent Sensors architecture. This Project provides critical alternatives to maneuver forces for position and navigation in a multi-domain operational environment. Work in this Project complements Program Element (PE) 0602146A (Network C3I Technology) / Project CV4 (Pathfinder 3D Applied Technology). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the United States Army Engineer Research and Development Center Geospatial Research Laboratory.$$, 1335000, NULL, NULL, NULL, NULL, 1007000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603464A_AF2$$, $$0603464A$$, $$AF2$$, $$Long Range Maneuverable Fires$$, 70417000, $$This Project directly supports Long Range Precision Fires Modernization Priority capabilities by developing, maturing and demonstrating next generation Multi-Domain Operations extended range weapon system technology for Precision Strike Missile to increase survivability, penetration, and range in complex Anti Access/Area Denial (A2/AD) and denied environments. This Project also includes both the maturation and demonstration of advanced extended range missile technology and autonomous, unmanned launcher technology. The combination of these technologies offers the potential to dramatically increase force projection through increases in range, firepower, and magazine depth. Work in this Project complements Program Element (PE) 0602147A (Long Range Precision Fires Technology), Project AF1 (Long Range Maneuverable Fires (LRMF) Technology); and PE 0602147A/Project AF8 (Affordable Extended Range Precision); and Project AF3 (Extended Range Propulsion Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC).$$, 70417000, NULL, NULL, NULL, NULL, 60465000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603464A_AG5$$, $$0603464A$$, $$AG5$$, $$Extended Range Artillery Munition$$, NULL, $$This Project directly supports Long Range Precision Fires Modernization Priority capabilities. This Project matures and demonstrates extended range artillery technologies including advanced projectile propulsion and guidance technologies to increase range and accuracy. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Armaments Center.$$, NULL, NULL, NULL, NULL, NULL, 22403000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603464A_BO8$$, $$0603464A$$, $$BO8$$, $$Long Range Precision Fires$$, NULL, $$Congressional Interest Item funding provided for Long Range Precision Advanced Technology. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy.$$, NULL, NULL, NULL, NULL, NULL, 56500000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603464A_BY2$$, $$0603464A$$, $$BY2$$, $$Advanced Hypersonic Technology$$, 9906000, $$This Project directly supports Long Range Hypersonic Precision Fires Modernization Priority capabilities by developing and maturing critical technologies for strategic missiles. Technology development includes critical technologies to improve strategic missile components such as advanced structures and materials, thermal protection systems, navigation systems, data links, and seekers/terminal sensors. Work in this Project complements Program Element (PE) 0603464A (Long Range Precision Fires Advanced Technology) / Project AF2 (Long Range Maneuverable Fires (LRMF) Advanced Tech); and PE 0602147A (Long Range Precision Fires Technology)/ Project AF8 (Affordable Extended Range Precision Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC).$$, 9906000, NULL, NULL, NULL, NULL, 61795000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603464A_CE9$$, $$0603464A$$, $$CE9$$, $$Armaments Advanced Technology$$, 5680000, $$Improve defeat of imprecisely located and relocated/moving targets by leveraging and advancing component technologies in armament technologies (multi-mode g- hardened seekers for cross spectrum targeting, advanced guidance, navigation, and control (GNC) and in-flight update technologies). Work in this Project complements PE 0602141A (Lethality Technology) / Project AH9 (Advanced Warheads Technology) and PE 0602147A (Long Range Precision Fires Technology) / Project AG4 (Extended Range Artillery Munition Suite Technology) and Project BN5 (Fuze and Power for Munitions). The cited research is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Armaments Center (AC).$$, 5680000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603464A_CZ8$$, $$0603464A$$, $$CZ8$$, $$PrSM Modular Payload Advanced$$, 75732000, $$This Project directly supports Long Range Precision Fires Modernization Priority capabilities by maturing and demonstrating critical technologies for autonomous, Cluster Munition policy compliant, enhanced lethality payloads deployed from Precision Strike Missile to autonomously and cooperatively find and engage the full spectrum of deep moved, moving, dispersed, and poorly located targets in areas with contested access at extended ranges. Work in this Project complements Program Element (PE) 0602147A (Long Range Precision Fires Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC).$$, 75732000, NULL, NULL, NULL, NULL, 32643000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603464A_DM5$$, $$0603464A$$, $$DM5$$, $$Affordable High Speed Strike$$, 501000, $$This Project directly supports Long Range Precision Fires Modernization Priority capabilities by developing, maturing, and demonstrating affordable high speed strike missile technologies for responsive, mobile, deployable, survivable, and sustainable Army conventional theater strike weapons unconstrained by previous treaties. Provide hardware and software technologies demonstrated, including affordable advanced propulsion, complementary warhead, guidance, navigation and control technologies, and integration onto Army mobile launch platforms. The Army needs affordable, responsive high speed strike capability to attack theater level targets, provide offensive counter-air capability, and be launched from Army mobile, deployable, and survivable platforms. Work in this Project complements Program Element (PE) 0603464A (Long Range Precision Fires Advanced Technology) / Project BY2 (Advanced Hypersonics Technology), PE 0602147A (Long Range Precision Fires Technology) / Project AF8 (Affordable Extended Range Precision Tech and Program) and Project AF3 (Extended Range Propulsion Tech) The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC).$$, 501000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603465A_AJ9$$, $$0603465A$$, $$AJ9$$, $$Integ Mission Equip for Vert Lift$$, NULL, $$This Project matures and demonstrates a mission systems architecture to support Future Vertical Lift (FVL) through utilization of a reconfigurable and flexible tiered architectural approach. Work in this Project is fully coordinated with Program Element (PE) 0602148A (Future Vertical Lift Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army Modernization Strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC).$$, NULL, NULL, NULL, NULL, NULL, 16604000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603673N_1162$$, $$0603673N$$, $$1162$$, $$Air Warfare (AW)$$, 59240000, $$The Air Warfare Project focuses on the advanced technology development of new capabilities that leverage the underlying applied research investments in Program Element (PE) 0602750N, Future Naval Capabilities (FNC) Applied Research. These advanced technology investments align to acquisition programs of record. Efforts include human machine interfaces for unmanned platforms and payloads that will assist with delegation of resources from one operator to another, airframe corrosion protection, and a Carrier Air Wing performance assessment tool that uses live, virtual, and constructive data to improve pilot and aircrew performance in near real-time. Different software efforts address unique and specific requirements.$$, 59240000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603465A_AK5$$, $$0603465A$$, $$AK5$$, $$Multi-Role Small Guided Missile$$, NULL, $$This Project matures and demonstrates a holistic lethality solution for current Army Aviation and Future Vertical Lift (FVL) Modernization Priority. This Project matures and demonstrates critical technology and designs components for future affordable rockets and missiles to provide overwhelming defeat of conventional and asymmetrical threats in all environments. Matures and demonstrates component technologies to enable an expeditionary short-to-medium range loitering maneuvering missile with man-in-the-loop capability for situational awareness, targeting, and lethal effects against hard and soft targets; and matures and demonstrates critical component technology and designs for future missiles that provide simultaneous multiple launch, control, and supervised autonomous terminal engagement of multiple missiles. Work in this Project is fully coordinated with Program Element (PE) 0602148A (Future Vertical Lift Technology) / Project AK4 (Multi-Role Small Guided Missile Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army Modernization Strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC).$$, NULL, NULL, NULL, NULL, NULL, 11554000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603465A_AK8$$, $$0603465A$$, $$AK8$$, $$Air Launched Effects Advanced$$, NULL, $$This Project develops and demonstrates the ability to launch an Unmanned Aircraft System (UAS) from a manned or unmanned Future Vertical Lift (FVL) aircraft at tactical altitudes and to control the UAS from the cockpit or a crew station; and assesses the enabled capabilities and determine their relevance to current Army Aviation engagement and survivability portfolios. Work in this Project is fully coordinated with Program Element (PE) PE 0602148A (Future Vertical Lift Technology) / Project CH2 (Air Launched Effects Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army Modernization Strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC).$$, NULL, NULL, NULL, NULL, NULL, 27143000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603465A_AL1$$, $$0603465A$$, $$AL1$$, $$Adv Teaming for Tactical Aviation$$, 25135000, $$This Project matures, demonstrates and drafts frameworks for autonomous teaming behaviors, autonomous decision making, targeting and visualization concepts in complex environments for Future Vertical Lift (FVL) and Future Unmanned Aircraft System (FUAS) platform formations in combined arms operations. Work in this Project is fully coordinated with Program Element (PE) 0602148A (Future Vertical Lift Technology) / Project AK9 (Adv Teaming for Tactical Aviation Operations Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC) and Command, Control, Communication, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center.$$, 25135000, NULL, NULL, NULL, NULL, 38920000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603465A_AL7$$, $$0603465A$$, $$AL7$$, $$Full Spectrum Targeting Advanced$$, 6222000, $$This Project demonstrates next generation targeting concepts for Future Vertical Lift (FVL) and Future Unmanned Aircraft System (FUAS) platforms. Matures automated threat detection algorithm and payload technologies that enable manned and unmanned Army aviation platforms to meet Electro-Optic / Infrared (EO/IR) Detect, Identify, Locate and Report (DILR) requirements in the forward line of sensors for Army Aviation. Work in this Project is fully coordinated with Program Element (PE) 0602148A (Future Vertical Lift Technology) / Project AK9 (Advanced Teaming for Tactical Aviation Operations Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Work in this Project is performed by the Command, Control, Communication, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center.$$, 6222000, NULL, NULL, NULL, NULL, 8768000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603465A_AL9$$, $$0603465A$$, $$AL9$$, $$Holistic Sit Awareness and Dec$$, 10858000, $$This Project matures and demonstrates a pilotage and decision aiding system that allows for carefree operations in complex and hostile environments through demonstration of a comprehensive human machine interface for all situational awareness (SA) domains (terrain & obstacles, threat, weather, & environment); and demonstration of decision aiding technologies to reduce cognitive loading of air crews during operations in complex and hostile environments. Work in this Project is fully coordinated with Program Element (PE) PE 0602148A (Future Vertical Lift Technology) / AL8 (Holistic Situational Awareness and Dec Making Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Work in this Project is performed by the U.S. Army Combat Capabilities Development Command (DEVCOM) Analysis Center (DAC) and Aviation & Missile Center (AvMC).$$, 10858000, NULL, NULL, NULL, NULL, 20476000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603465A_BP8$$, $$0603465A$$, $$BP8$$, $$Future Vertical Lift Air Platform Adv$$, NULL, $$Congressional Interest Item funding provided for Future Vertical Lift Air Platform Advanced Technology. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy.$$, NULL, NULL, NULL, NULL, NULL, 64750000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603465A_CA8$$, $$0603465A$$, $$CA8$$, $$Adv Rotocraft Armaments Protection$$, 201000, $$This Project investigates and demonstrates a holistic lethality solution for Future Vertical Lift (FVL) offensive and defensive applications, focused on but not limited to Future Long Range Assault Aircraft (FLRAA). Develop components for use in multi-role armament solutions for fire control, armament systems, munitions and integration of threat agnostic countermeasures. Work in this Project complements Program Element (PE) 0602183A (Air Platform Applied Research) / Project DE2 (Airborne Threat Defeat). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Work in this Project is performed by the Armaments Center (AC).$$, 201000, NULL, NULL, NULL, NULL, 6225000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603465A_CC4$$, $$0603465A$$, $$CC4$$, $$FVL Radar Advanced Technologies$$, 2253000, $$This Project matures and demonstrates next generation radar capabilities including next generation airborne radars apertures used for detection, tracking and precision targeting, navigation and fire control for multiple modalities. This project will demonstrate fully automated target recognition for radar, advanced processing techniques, distributed radar sensing and sensor coordination methods needed for targeting-quality detect, identify, locate and report (DILR) capabilities from airborne platforms. This project will further improve radar survivability and lethality across the Aviation ecosystem, speed target prosecution timelines for actionable information on the battlefield and will provide the Warfighter with persistent DILR enabling day/night/all-weather sensing in congested/contested Multi-Domain Operations (MDO) environments. Work in this Project is fully coordinated with Program Element (PE) 0602148A (Future Vertical Lift Technology) / Project CC3 (FVL Radar Technologies). The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is performed by the Command, Control, Communication, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center.$$, 2253000, NULL, NULL, NULL, NULL, 4242000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603465A_CG1$$, $$0603465A$$, $$CG1$$, $$Holistic Team Survivability Adv Tech$$, 10447000, $$This Project matures and demonstrates increased Future Vertical Lift (FVL) Family of Systems Survivability (FoS) in an advanced integrated air defense systems environment through a multi-layered approach. The approach focuses on maturing and demonstrating technologies for reducing aircraft susceptibility and vulnerability during pre-mission planning, mission execution (combat survivability and safety), and post-mission repair and return to service. Work in this Project is fully coordinated with Program Element (PE) 0602148A (Future Vertical Lift Technology) / Project CH3 (Holistic Team Survivability Technology). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC) and Command, Control, Communication, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center.$$, 10447000, NULL, NULL, NULL, NULL, 14919000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603465A_CH7$$, $$0603465A$$, $$CH7$$, $$Power & Thermal Management for$$, NULL, $$This Project matures and demonstrates at the system level, integrated electrical power technologies (including power generation, distribution, and control along with advanced energy storage) and thermal management technologies to provide significantly higher electrical power capability to Future Vertical Lift (FVL) aircraft while addressing consequential size, weight, pulsed power, and thermal issues. Provides power capability for advanced electric aeromechanical effectors, advanced mission systems that for example, execute algorithms for route planning and teaming, and for advanced survivability and electronic warfare capability. Will demonstrate software- in-the-loop performance of power & thermal management technologies to provide significantly higher electrical power capability to FVL aircraft while addressing consequential SWAP-C & thermal issues. Work in this Project is fully coordinated with Program Element (PE) 0602148A (Future Vertical Lift Technology) / Project CH4 (Power & Thermal Management for FVL Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC) and Command, Control, Communication, Computers, Cyber, Intelligence, Surveillance and Reconnaissance (C5ISR) Center.$$, NULL, NULL, NULL, NULL, NULL, 4222000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603465A_CI8$$, $$0603465A$$, $$CI8$$, $$Adaptive Avionics Advanced$$, 7591000, $$This project will develop the ability for rapidly adaptable mission systems hardware and software that utilizes tactical situational awareness to optimize performance and will develop robust, secure and ruggedized computing elements, advanced architectures for efficient data storage and processing, algorithms for optimized computing resources and hardware qualification approaches. These resource technologies will be used in the development of solider tailorable software applications, adaptable security controls and dynamic use of system of systems capabilities across the Combat Aviation Brigade (CAB). Work in this Project is fully coordinated with Program Element (PE) 0602148A (Future Vertical Lift Technology) / Project CI4 (Adaptive Avionics Technologies). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC).$$, 7591000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603465A_CJ5$$, $$0603465A$$, $$CJ5$$, $$Future Vertical Lift Medical Advanced$$, 1354000, $$This Project evaluates, validates, matures and delivers medical guidelines and strategies to assure optimal Soldier performance and protection on the future technologically-intensive battlefield. Key elements of the program include: 1) tailored medical selection and retention standards for Future Vertical Lift (FVL); 2) medical strategies to maintain and enhance human performance in Multi-domain operations (MDO); 3) human-centered technology design guidance to accommodate the range of aircrew; 4) improved protection standards to reduce FVL occupant injury; and 5) operator state monitoring tools to enable scalable autonomy in FVL aircraft. Efforts in this Project further develop work done in Program Element 0602148A (Future Vertical Lift Technology) / Project BZ7 (Future Vertical Lift Medical Technologies). Work in this Project is performed by the United States Army Aeromedical Research Laboratory (USAARL).$$, 1354000, NULL, NULL, NULL, NULL, 1314000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603465A_CK2$$, $$0603465A$$, $$CK2$$, $$High Speed Maneuverable Missile$$, 2625000, $$The Project matures and demonstrates missile component technologies compatible with Future Vertical Lift (FVL) aviation platforms in a Multi-Domain Battle/Cross- domain Maneuver operational environment. Efforts mature technologies to support a smaller, faster, maneuverable missile capable of long-range non-line-of-sight attack in contested/degraded environments. Technology development increases aviation lethality and platform survivability by increasing missile standoff range, speed, and maneuverability, a faster rate of fire, shorter times of flight, and multi-threat lethal effects. Enables cross domain applications for aviation and ground vehicle platforms, including handoff capability, to engage threats in dead zones, and to operate in contested environments. Work in this Project is fully coordinated with PE 0602148 (Future Vertical Lift Technology) / Project CI5 (High Speed Maneuverable Missile Tech). The cited work is consistent with the Under Secretary of Defense for Research and Engineering Science and Technology focus areas and the Army modernization strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC).$$, 2625000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603466A_AE3$$, $$0603466A$$, $$AE3$$, $$Unconventional Countermeasures-$$, 11818000, $$This Project matures and demonstrates technologies to increase survivability of personnel and critical assets using integrated unconventional countermeasures. These countermeasures include tone down concepts for signature management using novel materials, rapidly deployable, low-cost, multisprectral survivability enhancement technologies as well as intuitive decision support technologies to select and assess non-kinetic protective measures. Work in this Project complements Program Element (PE) 0602150A (Air and Missile Defense Technology) / Project AE2 (Unconventional Countermeasures-Survivability Tech). The work cited is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army Modernization Strategy. Work in this Project is conducted by the United States Army Engineer Research and Development Center Geotechnical and Structures Laboratory.$$, 11818000, NULL, NULL, NULL, NULL, 10835000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603466A_BN7$$, $$0603466A$$, $$BN7$$, $$Weapons Components Adv$$, NULL, $$Congressional Interest Item funding provided for Weapons Components Advanced Technology. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy.$$, NULL, NULL, NULL, NULL, NULL, 78500000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603673N_1163$$, $$0603673N$$, $$1163$$, $$Information Warfare (IW)$$, 68211000, $$The Information Warfare Project focuses on the advanced technology development of new capabilities that leverage the underlying applied research investments in Program Element (PE) 0602750N, Future Naval Capabilities (FNC) Applied Research. These advanced technology investments align to acquisition programs of record. Efforts provide Information Warfare capabilities across several disparate uses and environments.$$, 68211000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603466A_CV6$$, $$0603466A$$, $$CV6$$, $$Optimized High Energy Laser Source$$, 5025000, $$This Project matures and demonstrates Optimized High Energy Laser Source advanced technology establishing a more affordable laser source for application in High Energy Laser weapon systems. This Project will deliver a lower cost laser weapon source to next generation HEL systems. Research in this Project complements other Army Directed Energy efforts conducted under (PE) 0602150A (Air and Missile Defense Technology)/Projects DC1 (Next Generation Directed Energy Concept Development and Analysis) and CV7 (High Energy Laser Direct Diode Applied Technology). The cited research is consistent with the Army's modernization programs, the Under Secretary of Defense for Research and Engineering priority focus areas, the Army Modernization Strategy, and supports the Army's future capability opportunities for leap-ahead technology for Directed Energy. Research is performed by the United States Army Space and Missile Defense Command - Technical Center (USASMDC-TC) in coordination with RCCTO and PEO Missiles and Space/PM Shield.$$, 5025000, NULL, NULL, NULL, NULL, 6497000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603466A_DB3$$, $$0603466A$$, $$DB3$$, $$Radar Survivability through Dis$$, 1977000, $$This Project matures and demonstrates distributed and collaborative engagement decision making for Multi-Domain Operations. The Augmented Intelligence for Mission Planning and Control effort will develop and mature Artificial Intelligence (AI) Decision Aids enabling operators to continuously manage IAMD component deployments and to select best engagement options in support of Multi-Domain Operations (MDO). Work in this Project complements Program Element (PE) 0602141A (Lethality Technology) / Project CG4 (Advanced Radar Concepts and Technologies) and Project CJ7 (Future Air Defense Missile Enabling Tech; PE 0602148A (Future Vertical Lift Technology) / Project CC3 (FVL Radar Technologies); PE 0601102A (Defense Research Sciences) / Project AA8 (Sensing and Electromagnetics) and PE 0602150A (Air and Missile Defense Technology) / Project DA9 (Radar Survivability through Dis Sensing Tech); and PE 0602275A (Electronic Warfare Applied Research)/ Project A70 (Sensor Electronic Support Tech); and PE 0603275A (Electronic Warfare Advanced Technology) / Project A78 (Sensor Electronic Support Adv Tech) The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Army modernization strategy. Work in this Project is performed by the Aviation & Missile Center (AvMC).$$, 1977000, NULL, NULL, NULL, NULL, 2952000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603466A_IB1$$, $$0603466A$$, $$IB1$$, $$Integrated Beam Control Systems$$, 4510000, $$This program will mature and demonstrate advanced beam control technologies to extend the effective range of a High Energy Laser weapon system. Integrate a large- aperture, off-axis telescope into a government testbed with advanced adaptive optics and tracking. Validate and optimize adaptive optics and laser-quality tracking algorithms to demonstrate increased range capabilities for multi-domain missions, including counter-cruise missile operations.. Research in this Project complements other Army Directed Energy efforts conducted under (PE) 0602150A (Air and Missile Defense Technology)/Projects DC1 (Next Generation Directed Energy Concept Development and Analysis) and DE3 (Advanced Beam Control Component Development for Counter-Cruise Missile). The cited research is consistent with the Army's modernization programs, the Under Secretary of Defense for Research and Engineering priority focus areas, the Army Modernization Strategy, and supports the Army's future capability opportunities for leap-ahead technology for Directed Energy. Research is performed by the United States Army Space and Missile Defense Command - Technical Center (USASMDC-TC) in coordination with RCCTO.$$, 4510000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603467E_DAT-01$$, $$0603467E$$, $$DAT-01$$, $$ADVANCED SYSTEMS$$, 445310000, $$The efforts described in this Program Element (PE) address the Advanced Technology Development associated with Systems, Intelligence, Surveillance and Reconnaissance (ISR) and Sensors that addresses high payoff opportunities to develop and rapidly mature advanced technologies required for today's warfare concepts. It is imperative that future U.S. forces operate seamlessly in all domains with improved battlefield awareness, strike capability and battle damage assessment. This PE also supports innovation and robust transition and experimentation planning in the technology cycle to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. The Advanced Systems project will create enabling technologies for seamless all domain operations, from strategic planning to tactical and urban operations. All Domain Warfare Systems leverage current and emerging network, robotic, and information technology and provide next generation U.S. forces with greatly increased capability, lethality, and rapid responsiveness. Critical issues facing this project are: (1) U.S. opponents using systems that are flexible, robust, and difficult to neutralize; and (2) U.S. doctrine that limits the use of firepower to lessen the impact of operations on noncombatants. Meeting these challenges places a heavy burden on joint war planning. Understanding opponent networks is essential so that creative options can be developed to counter their strategies. Synchronization of air, sea, space, and ground operations to apply force only where needed and with specific effects is required. This project supports all levels of the force structure including: (1) the strategic/ operational level by generating targeting options against opponents' centers of gravity that have complex networked relationships; (2) the tactical/operational level by managing highly automated forces with tight coupling between air, seas, space, and ground platforms; and (3) the focused tactical level by developing platforms and tools, which acquire targets of opportunity and cue network-based analysis of likely enemy operations. The ISR and Sensors project develops technologies to improve surveillance and targeting systems for improved battlefield awareness, strike capability and battle damage assessment, and demonstrates these technologies and system concepts against emerging threat scenarios to support rapid technology adoption by the warfighter. Leveraging technology advancements in size, weight, power and cost and enabling with the practical application of mature machine learning and artificial intelligence, these efforts are also packaged in novel ways for rapid deployment and adoption for operational use. Capabilities are intended to overcome an adversary s intent to deny and deceive sensing and ISR systems in order to provide all-weather continuous coverage over areas of interest. This project will exploit recent advances Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                         Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:           PE 0603467E / DARPA ADVANCED TECHNOLOGY DEVELOPMENT Advanced Technology Development (ATD) in multispectral target phenomenology, signal processing, low-power high-performance computing, and low-cost microelectronics to develop advanced surveillance and targeting systems. The DARPA Advanced Technology Development Support project contains non-headquarters management costs in support of DARPA functions and activities across the entire DARPA Advanced Technology Development PE. These costs include: DARPA classified and unclassified network support and equipment; contractor support; classified program security; building security; commercial transition services that increase the likelihood that DARPA-funded technologies remain in the U.S. and provide new capabilities for national defense; DARPA outreach to universities and industry; external contracting, financial and support fees; Program Manager Intragovernmental Personnel Act (IPA) Funding; Program Managers from other Government Agencies; and similar operating expenses. Agency support is allocated on a pro-rata basis across the Agency's BA1, BA2 and BA3 PEs and, therefore, fluctuates per PE by fiscal year based on the total Agency budget in that fiscal year. Prior to FY 2026, efforts in this PE were funded in PE 0603760E, Command, Control and Communications Systems, PE 0603766E, Network-Centric Warfare Technology and PE 0603767E, Sensor Technology.$$, 445310000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
