INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603468E_ACX-01$$, $$0603468E$$, $$ACX-01$$, $$ADVANCED$$, 331116000, $$The efforts described in this Program Element (PE) address the Advanced Technology Development associated with the Advanced Complex Systems Program that is focused on exploiting high pay-off opportunities to provide revolutionary new system capabilities, as opposed to incremental or evolutionary advancements, in order to achieve undeterrable air and space presence at dramatically reduced costs. Rapid prototyping and experimentation of integrated system concepts, as well as enabling vehicle subsystems will be conducted. Programs will explore new architectural concepts that employ a mix of weapon technologies that achieve lethality through a combination of overwhelming performance and overwhelming numbers rather than through the use of singular and costly high value assets. Efforts conducted under this PE include examination and evaluation of emerging aerospace threats, technologies, concepts, use of autonomy to minimize risk, and applications for missiles, munitions, and vehicle systems. This PE also supports innovation and robust transition and experimentation planning in the technology cycle to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. The Advanced Complex Systems project is focused on exploiting high pay-off opportunities to provide revolutionary new system capabilities, as opposed to incremental or evolutionary advancements, in order to achieve undeterrable air and space presence at dramatically reduced costs. Rapid prototyping and experimentation of integrated system concepts, as well as enabling vehicle subsystems will be conducted. Programs will explore new architectural concepts that employ a mix of weapon technologies that achieve lethality through a combination of overwhelming performance and overwhelming numbers rather than through the use of singular and costly high value assets. Efforts conducted under this program element include examination and evaluation of emerging aerospace threats, technologies, concepts, use of autonomy to minimize risk, and applications for missiles, munitions, and vehicle systems. The Advanced Complex Systems Support project contains non-headquarters management costs in support of DARPA functions and activities across the entire Advanced Complex Systems PE. These costs include: DARPA classified and unclassified network support and equipment; contractor support; classified program security; building security; commercial transition services that increase the likelihood that DARPA-funded technologies remain in the U.S. and provide new capabilities for national defense; DARPA outreach to universities and industry; external contracting, financial and support fees; Program Manager Intragovernmental Personnel Act (IPA) Funding; Program Managers from other Government Agencies; and similar operating expenses. Agency support is allocated on a pro-rata basis across the Agency's BA1, BA2 and BA3 PEs and, therefore, fluctuates per PE by fiscal year based on the total Agency budget in that fiscal year. Prior to FY 2026, efforts in this PE were funded in PE 0603286E, Advanced Aerospace Systems, and PE 0603287E, Space Programs and Technology. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:       PE 0603468E / ADVANCED COMPLEX SYSTEMS Advanced Technology Development (ATD)$$, 331116000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603468E_ACX-07$$, $$0603468E$$, $$ACX-07$$, $$ADVANCED$$, 19579000, $$The efforts described in this Program Element (PE) address the Advanced Technology Development associated with the Advanced Complex Systems Program that is focused on exploiting high pay-off opportunities to provide revolutionary new system capabilities, as opposed to incremental or evolutionary advancements, in order to achieve undeterrable air and space presence at dramatically reduced costs. Rapid prototyping and experimentation of integrated system concepts, as well as enabling vehicle subsystems will be conducted. Programs will explore new architectural concepts that employ a mix of weapon technologies that achieve lethality through a combination of overwhelming performance and overwhelming numbers rather than through the use of singular and costly high value assets. Efforts conducted under this PE include examination and evaluation of emerging aerospace threats, technologies, concepts, use of autonomy to minimize risk, and applications for missiles, munitions, and vehicle systems. This PE also supports innovation and robust transition and experimentation planning in the technology cycle to increase the likelihood that DARPA funded technologies take root in the U.S. and provide new capabilities for national defense. The Advanced Complex Systems project is focused on exploiting high pay-off opportunities to provide revolutionary new system capabilities, as opposed to incremental or evolutionary advancements, in order to achieve undeterrable air and space presence at dramatically reduced costs. Rapid prototyping and experimentation of integrated system concepts, as well as enabling vehicle subsystems will be conducted. Programs will explore new architectural concepts that employ a mix of weapon technologies that achieve lethality through a combination of overwhelming performance and overwhelming numbers rather than through the use of singular and costly high value assets. Efforts conducted under this program element include examination and evaluation of emerging aerospace threats, technologies, concepts, use of autonomy to minimize risk, and applications for missiles, munitions, and vehicle systems. The Advanced Complex Systems Support project contains non-headquarters management costs in support of DARPA functions and activities across the entire Advanced Complex Systems PE. These costs include: DARPA classified and unclassified network support and equipment; contractor support; classified program security; building security; commercial transition services that increase the likelihood that DARPA-funded technologies remain in the U.S. and provide new capabilities for national defense; DARPA outreach to universities and industry; external contracting, financial and support fees; Program Manager Intragovernmental Personnel Act (IPA) Funding; Program Managers from other Government Agencies; and similar operating expenses. Agency support is allocated on a pro-rata basis across the Agency's BA1, BA2 and BA3 PEs and, therefore, fluctuates per PE by fiscal year based on the total Agency budget in that fiscal year. Prior to FY 2026, efforts in this PE were funded in PE 0603286E, Advanced Aerospace Systems, and PE 0603287E, Space Programs and Technology. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:       PE 0603468E / ADVANCED COMPLEX SYSTEMS Advanced Technology Development (ATD)$$, 19579000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603502N_1234$$, $$0603502N$$, $$1234$$, $$Unmanned Surface Vehicle (USV)$$, 17713000, $$The MCM USV program consists of Unmanned Surface Vehicles (USVs) with Mine Countermeasures (MCM) payloads. The program began as the Unmanned Influence Sweep System (UISS) program which consisted of a USV paired with a magnetic and acoustic sweep capability. As the USV progressed, the Navy modified the program so the craft would integrated and operate other payloads. The UISS program was subsumed by the MCM USV Program upon successful Full Rate Production Decision Review in September, 2023. The program consists of four products: 1) The MCM USV is a semi-autonomous dual drive, 38 foot long, 10 foot wide aluminum hulled craft powered by two diesel engines. The craft contains a situational awareness and contact avoidance suite consisting of optical, radar, and GPS and is directed and monitored by the Multi Vehicle Communication System (MVCS) with a host station, such as LCS, Vessel of Opportunity (VOO), or shore site. The reconfigurable payload bay adds a modular mission capability enabling multiple payloads (mine sweep and mine hunt). 2) The Mine Sweep Payload Delivery System (PDS) brings magnetic and acoustic mine influence sweep capability to the MCM USV. The PDS includes a winch, a magnetic sweep cable, and a Towed Acoustic Generator (TAG) along with capability to deploy and retrieve the towed equipment. 3) The Mine Hunt PDS brings a mine hunting capability by integrating the existing AN/AQS-20 on to the craft. The PDS includes a winch, cable and tow body handling equipment. 4) The Mine Neutralization PDS will neutralize mines previously identified throughout the water column using the Barracuda Mine Neutralizer. The PDS will consist of a launcher and communications gear to communicate with the neutralizer in the water. The program completed ship-based TECHEVAL and IOT&E in FY22. The program declared Initial Operational Capability in Q2FY23. In FY 2023 the MCM USV program began contract planning for the integration of a next generation Influence Sweep Payload (Magnetic & Acoustic Generation Next Unmanned Superconducting Sweep - MAGNUSS). Mine Neutralization payload design activities and Engineering Development Model (EDM) will start in FY26. The MCM USV program will have a continuous reliability, autonomy, and engineering changes process. The program developed improvements to address IOT&E findings. Leveraging ongoing developments for autonomous systems, the program will continue to develop performance improvements. Upgrades will consist of processing and sensing hardware, autonomy, situational awareness/collision avoidance algorithms, integration of new payloads, increased range, and upgrades to electronics configuration. MCM USV will continue to support Navy experimentation of Beyond Line of Sight (BLOS) and alternative payloads.$$, 17713000, NULL, NULL, NULL, NULL, 223613000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603502N_2989$$, $$0603502N$$, $$2989$$, $$Barracuda$$, 14646000, $$FY 2025 to FY 2026 increase corresponds with the Barracuda Program initiating Government Developmental Testing and Government Live Fire Testing with contractor support in FY 2026. The Barracuda system is an expendable, modular, mine neutralizer launched from the Mine Countermeasures (MCM) Unmanned Surface Vessel (USV) as part of the Littoral Combat Ship (LCS) MCM Mission Package (MP) to autonomously reacquire and neutralize previously detected near-surface mines. Upon entering the water, the vehicle will conduct a search, capture an image, and use a communications buoy to send the image to the operator in the MCM MP to evaluate the image and order the weapon to fire, abort, or continue searching. Future capabilities may include launch from manned or unmanned aircraft or vessels of opportunity as well as the ability to neutralize mines in volume and on the bottom. The Barracuda detailed design and development contract includes system design, program management, systems engineering, software development, integrated product support and contractor testing.$$, 14646000, NULL, NULL, NULL, NULL, 196137000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603506N_0225$$, $$0603506N$$, $$0225$$, $$Surface Ship Torpedo Defense$$, 11832000, $$ATTDS is a system of systems, comprised of the Torpedo Warning System (TWS) and the Countermeasure Anti-Torpedo Torpedo planned to develop NIXIE HK new AN/SLQ-25 capabilities in order to pace the torpedo threat. This includes integrating and testing a kinematics-based target discrimination and fire control into the AN/ SLQ-25E, improving existing soft kill capabilities within AN/SLQ-25E, and adding a hard kill capability with a launcher for the Mk 58 CRAW and the (ADC) MK5 and MK 2 Mod 6/8. The FY 2026 funds support the development of a torpedo alertment and fire control capability integrated into the AN/SLQ-25E tow system in support of a torpedo defense requirements along with software improvements to specific NIXIE counter measures.$$, 11832000, NULL, NULL, NULL, NULL, 757733000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603512N_3216$$, $$0603512N$$, $$3216$$, $$Tactical Support Center-Integration$$, 4394000, $$The AN/SQQ-34 CV-TSC project delivers ASW and SUW combat capability to the Aircraft Carrier. This project delivers capability updates to the Fleet, developing, testing, certifying, and fielding system upgrades and cyber-security patches. The project maintains interoperability with current and future interfaces; supports mission data exchange; improves track/sensor processing and analysis techniques; improves mission planning; improves data recording, reconstruction, and distribution; improves embedded simulation and training capabilities and implements cyber-security measures to effectively employ overall CVN self-defense capabilities. CV-TSC integrates sensor data from off-board aircraft, organic platform sensors, Minotaur multi-sensor fused track data, Link-16 track data, SSDS track data (PLA and non-PLA), GCCS OTH track data, and environmental and threat databases to assess the threat and assist the TAO and Composite Warfare Commander (CWC) to effectively employ overall CVN self-defense capabilities. CV-TSC generates real-time ASW/SUW information and recommendations, tactical planning and employment of ASW/ SUW assets, ASW/SUW sensor data processing and analysis, and distribution of tactically significant data. Aircraft supported include MH-60R/S Seahawk, and P-8 Poseidon and MQ-4C Triton as future ASW/SUW systems. System development is accomplished through the following initiatives: 1) Maintaining interoperability with the local CVN warfare systems through current and future interfaces; 2) Continuing to support mission data exchange and tactical control with current and future ASW/SUW assets and their mission systems; 3) Improving track and sensor processing and analysis techniques as new track and sensor data becomes available; 4) Improving mission planning support for the ASW/SUW missions conducted from the CVN; 5) Improving data recording, reconstruct, and distribution to meet the decreasing timelines associated with getting tactically significant data to other end users both on and off platform; 6) Improving embedded simulation and training capabilities to enable operator proficiencies; and 7) Implementing cyber security measures.$$, 4394000, NULL, NULL, NULL, NULL, 80280000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603512N_4005$$, $$0603512N$$, $$4005$$, $$In-Service Carrier Systems$$, 3967000, $$The In-Service Carrier Systems Demonstration and Validation Program develops new technology and enhancements for 11 nuclear powered Aircraft Carriers with nearly 300 systems onboard each vessel. These systems are a combination of historical and new initiatives that deliver an affordable, robust, operator-friendly automated control environment. In order to deter threats and properly integrate all of the systems, the Demonstration and Validation Program segments the testing and upgrades into four areas: system architecture, requirements/specification development, technology selection, cyber-security engineering and integration, and software development. The Demonstration and Validation Program also focuses on the Total Ownership Costs of each system and any equipment obsolescence issues. Initial technologies include the Uninterruptible Power Supply (UPS) Replacements, the Integrated Condition Assessment System (ICAS), the On-Machine I/ O development for Low Pressure Air Plants (LPAP) and LPAP Air End Re-design. Demonstration technologies include Advanced Damage Control System (ADCS) software improvements, Input / Output Controller (IOC) Replacement, Fleet wireless Personal Digital Assistant (PDA), Weapons Elevator Laser Positioning System (WELPS), Legacy Steering Interface (LSI) upgrades, Passive Countermeasures System (PCMS) alternate measurement capability, additive manufacturing efforts, and Weapons Elevators Programmable Logic Controller (PLC) redesign.$$, 3967000, NULL, NULL, NULL, NULL, 34253000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603512N_9999$$, $$0603512N$$, $$9999$$, $$Congressional Adds$$, 0, $$Establishing a Digital Component Certification Laboratory on Joint Base McGuire-Dix-Lakehurst, where overseas and domestic manufactured digital components can be scanned and certified before their installation in weapon systems, would significantly enhance our ability to test components and certify digital integrity. The mission of the laboratory will include developing the processes, metrics, and tools to evaluate internal component designs and the embedded software (i.e., Firmware) with the ability to evolve a trustworthiness factor for each component. This mission intends to identify infected chip lots before installation in weapon systems, identify and track those manufacturers that deliver infected components, eliminate identified manufacturers as component suppliers, document the cyber tactics being employed in components, and assure that U.S. military systems are reliable, secure, and operable in the event of a conflict.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603542N_1830$$, $$0603542N$$, $$1830$$, $$RADIAC Development$$, 730000, $$Mission: The Radiation Detection, Indication and Computation (RADIAC) Program is responsible for providing radiation monitoring instruments that detect and measure radiation in accordance with the provisions of Title 10 of the Code of Federal Regulations (10 CFR 20). These instruments are used on all vessels afloat and at every shore installation in order to ensure the safety of personnel and the environment. RADIACs are also required after an act of terrorism or war that involves nuclear material in order to enable continuation of warfighting ability. Justification: Many RADIAC instruments and dosimetry systems are decades old and approaching the end of their useful lives. In some cases the equipment and replacement parts are no longer manufactured, making the equipment logistically unsupportable. In other cases increasing failure rates due to age make replacements an economic efficiency improvement. In all cases a technology refresh will make both economic sense in terms of lowering the total ownership costs, and will also provide increased operational capabilities. Naval Nuclear Propulsion Program (NNPP): Instruments are developed to support the safe operation and maintenance of nuclear powered vessels and at nuclear maintenance facilities. Non-NNPP: Instruments are developed to support other than NNPP end users, such as Explosive Ordnance Disposal, Nuclear Weapons, Medical, Industrial Radiography, Radiological Defense and Training. Visit, Board, Search & Seizure (VBSS): The Navy has been tasked to intercept and board vessels at sea to search for nuclear or radiological materials that could be used for terrorist attacks. These instruments would have different characteristics than those used for NNPP and non-NNPP purposes and prototypes must be developed and/or tested and evaluated.$$, 730000, NULL, NULL, NULL, NULL, 8781000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603553N_1704$$, $$0603553N$$, $$1704$$, $$Undersea Warfare$$, 0, $$The objective of this Project is to pursue the development of technologies with the goal of improving ASW effectiveness to the point of rendering the enemy submarine irrelevant against U.S. and coalition forces. U.S. adversaries continue to develop asymmetric capabilities and capacities to deter, disrupt, or delay the entry of U.S. and allied naval forces, and pose a constant challenge as we implement the Maritime Strategy. These trends increase the threats to U.S. surface combatants, thus requiring a focused effort to identify the most promising ASW technologies through a process of discovery, assessment, experimentation, and analysis. Studies, experiments, and/ or technology developments under this PE will seek to improve the ability of surface combatants to detect, classify, localize, and track submerged contacts and detect and defend against modern torpedoes. To achieve these objectives, it is essential to develop new ASW technologies. The products from these efforts will be provided to the ACB program supporting the continuing improvement of the AN/SQQ-89A(V)15 Surface Ship ASW Combat System.$$, 0, NULL, NULL, NULL, NULL, 193514000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603561N_0223$$, $$0603561N$$, $$0223$$, $$Sub Combat System Improvement$$, 58157000, $$The Submarine Combat System Improvement (Advanced) (Non-ACAT) project addresses technology challenges to improve tactical control in littoral and open ocean environments for a variety of operational missions including peacetime engagement, surveillance, battle space preparation, deterrence, regional sea denial, precision strike, task group support, and ground warfare support. These technologies, developed by Navy technology bases, the private sector, Office of Naval Research (ONR), Future Naval Capabilities (FNC), and the Defense Advanced Research Projects Agency (DARPA) are then transitioned. Prototype hardware/software systems are developed to demonstrate technologically promising system concepts in laboratory and at-sea submarine environments. The Advanced Sensor development program develops and tests new sensors and demonstrates large array configurations. Current efforts are directed at towed array sensor technologies, telemetry, and architecture, to improve reliability and performance while decreasing program life-cycle costs. For large array configurations, Conformal Acoustic Velocity Sonar (CAVES), Wide Aperture Array (WAA), Large Vertical Aperture (LVA), and Bow Conformal Array (BCA) technologies are also being pursued. The focus of sensor processing technology efforts through the Advanced Processing Build (APB) program will address improvements in imaging, tactical control, Electronic Warfare (EW) and acoustics, including detection, localization, classification, ranging, tracking, situational awareness, tactical decision aids, command decision support tools and displays and other functions essential to mission success. APB will also develop capabilities related to off-hull cueing and coordination with other platforms. Technologies and/or capabilities developed under this Project will be shared, as applicable to reduce costs and optimize reuse, with development programs for surface ship sonar, Advanced Capability Build (ACB) and surveillance platforms, Advanced Surveillance Build (ASB). ACB and APB are managed under a common development process titled AxB. While each platform retains its uniqueness and focus in functional domains essential to mission success, a premium is placed on development of common capabilities and modular architecture technologies to maximize commonality and cost effectiveness.$$, 58157000, NULL, NULL, NULL, NULL, 823884000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603561N_0770$$, $$0603561N$$, $$0770$$, $$Adv Sub Supp Equip Prog$$, 6526000, $$A continuing need exists to improve Imaging and Electronic Warfare (EW) support capabilities in view of the advancements in potential imaging counter-detection and the increasingly dense electromagnetic environment caused by the proliferation of complex radar, communications, and navigation equipment of potential adversaries. Improvements are necessary for submarine Imaging and EW to be operationally effective in the following mission areas: Joint Littoral Warfare, Joint Surveillance, Space and Electronic Warfare, Intelligence Collection, Maritime Protection, and Joint Strike. This project will concurrently consider both Imaging and EW domains as improved mast systems are designed. The evaluation of state-of-the-art technology to implement periscope/mast improvements via EW electromagnetic and electro-optic sensors results in improved capability. Engineering Development Models (EDMs) are developed, evaluated, and validated in the lab and through at-sea testing. This project is a non-Acquisition Category (ACAT) program. The test articles identified consist of critical components that will be fully developed during Engineering Manufacturing and Development phase into EDMs. Software-based capabilities in Imaging and/or EW domains that will process inputs from improved masts may be integrated and tested within this project.$$, 6526000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603561N_1704$$, $$0603561N$$, $$1704$$, $$Undersea Warfare$$, 1186000, $$The objective of this Project is to pursue the development of technologies with the goal of improving ASW effectiveness to the point of rendering the enemy submarine irrelevant against U.S. and coalition forces. U.S. adversaries continue to develop asymmetric capabilities and capacities to deter, disrupt, or delay the entry of U.S. and allied naval forces, and pose a constant challenge as we implement the Maritime Strategy. These trends increase the threats to U.S. surface combatants, thus requiring a focused effort to identify the most promising ASW technologies through a process of discovery, assessment, experimentation, and analysis. Studies, experiments, and/ or technology developments under this PE will seek to improve the ability of surface combatants to detect, classify, localize, and track submerged contacts and detect and defend against modern torpedoes. To achieve these objectives, it is essential to develop new ASW technologies. The products from these efforts will be provided to the ACB program supporting the continuing improvement of the AN/SQQ-89A(V)15 Surface Ship ASW Combat System.$$, 1186000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603673N_1164$$, $$0603673N$$, $$1164$$, $$Surface Warfare (SW)$$, 82716000, $$The Surface Warfare Project focuses on the advanced technology development of new capabilities that leverage the underlying applied research investments in Program Element (PE) 0602750N, Future Naval Capabilities (FNC) Applied Research. These advanced technology investments align to acquisition programs of record. Efforts include technologies that will provide mission visualization, network analysis, and training for operators in denied and degraded environments.$$, 82716000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603561N_1739$$, $$0603561N$$, $$1739$$, $$Submarine Arctic W/F Development$$, 9379000, $$The Submarine Arctic Warfare Development Project provides the U.S. Navy Submarine Force (SUBFOR) a cadre of trained Arctic Operation Specialists (AOS) and an inventory of unique Arctic sensors that are installed to optimize submarine safety during under-ice operations. AOS personnel assigned from ASL embark on submarines that deploy to the Arctic, cold water and iceberg regions, and marginal ice zones (MIZ) in northern latitudes of the Atlantic and Pacific Oceans and are advisers to the Commanding Officer. ASL is a shore facility at Naval Base Point Loma with the infrastructure capable of supporting personnel and equipment to conduct the submarine Arctic Warfare Development mission. Improvements and life-cycle expenditures to the facility and warehousing are made as necessary to support the mission. The Submarine Arctic Warfare Development Project, via ASL, responds to the increased threat of naval activity in the Arctic regions while continuously supporting the Navy's strategic objective of Assured Access and Combat Credibility. ASL provides a unique capability that enables the SUBFOR to satisfy the requirements laid out in the Arctic Maritime Homeland Defense Initial Capabilities Document (ICD). ASL and SUBFOR demonstrate existing Arctic Warfare capabilities and operational and tactical proficiency while developing advanced submarine technology in unique cold-water environments, in under-ice conditions, and in ice-covered shallow water regions through the Ice Exercise (ICEX) program that includes Operation Ice Camp. ICEX places an emphasis on submarine operability and mission capability in the world's harshest maritime environment. Efforts include assessment of combat system effectiveness, weapons testing, use of High Frequency (HF) sonars in Arctic regions, testing of ice-capable submarine structures, and development of class-specific Arctic operational guidelines. Tactical Development (TACDEV) is conducted biennially and requires up front comprehensive planning and work-up training, as well as post exercise analysis and reporting. ICEX provides the framework for various submarine test and evaluation efforts in Arctic regions and at periodic Ice Camps. The ICEX program represents DoD's only drifting ice station capability through Operation Ice Camp. Emphasis during Operation Ice Camp is placed on the areas of sonar operability, tactical surveillance, weapon utility, and other submarine support missions. A Torpedo Exercise (TORPEX) occurs every four (4) years in order to meet minimum Fleet requirements of exercise torpedo (EXTORP) firings in the Arctic. A TORPEX requires a significantly higher level of logistics, personnel, and infrastructure to account for the recovery and transportation efforts of the EXTORPs. The ICEX Program also includes Arctic Exercise (ARCEX), a biennial exercise that rotates with the biennial Operation Ice Camp drifting ice camps, that includes Arctic operations to support ice camp equipment evaluation, systems development, extreme cold weather training, drifting sea ice and scientific research.$$, 9379000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603561N_1916$$, $$0603561N$$, $$1916$$, $$Surface ASW System Improvement$$, 29766000, $$ASW remains a Navy core competency in a dynamic and uncertain maritime environment. U.S. adversaries continue to develop asymmetric capabilities and capacities to deter, disrupt, or delay the entry of U.S. and allied naval forces, and pose a constant challenge as we implement the Maritime Strategy. Evolving submarine technologies offer enhanced stealth, speed, endurance, weapons, and operational proficiency, foretelling that the adversary submarine of the future will have a significantly larger sphere of influence, while presenting less vulnerability to U.S. forces. The effective offensive engagement range of the adversary submarine of the future will continue to match or outrange individual U.S. and multinational platform sensors and weapons in many tactical environments. Submarines are an increasing threat to all Naval and Allied ships, particularly modern diesel subs and faster torpedoes. Not only can the presence of potential hostile submarines delay naval combatant action until they are located and neutralized, submarines can also disrupt all seaborne logistics supply for any ground campaign as well as maritime commerce. U.S. forces must be effective in all operating environments, ranging from the deep open ocean to the littorals, and are key to countering adversarial anti- access and area denial strategies. The Surface ASW Systems Improvements project will support essential performance enhancements to the AN/SQQ-89A(V)15 Surface Ship ASW Combat System. This project will improve Measures of Performance (MOP) by enhancing operator interface methods and tools; active and passive detection; tracking, classification, and localization; Torpedo Detection, Classification, and Localization (TDCL); sonobuoy data processing and display capabilities; and increasing acoustic sensor frequency bandwidth (Operational Requirements Document (ORD) #667-76-05 titled 'AN/SQQ-89 Improvement Program' and Test & Evaluation Master Plan (TEMP) 802-2). This project will take advantage of the AN/SQQ-89A(V)15 Surface Ship ASW Combat System Open System Architecture (OSA) and Acoustic Rapid Commercial-Off- The-Shelf (COTS) Insertion (ARCI) initiatives to integrate TDCL and ASW sonar and combat system capability improvements. The AN/SQQ-89A(V)15 Surface Ship ASW Combat System is planned as a backfit program for CG47 (select CG59-73 Baseline 3 and 4 ships) and all DDG51 class ships. The OSA and high-performance COTS processing hardware on ships fielded with the AN/SQQ-89A(V)15 Surface Ship ASW Combat System provides an opportunity to integrate emergent, transformational ASW and Undersea Warfare (USW) technological improvements that were previously unachievable. The ASW/USW suites on these ships will require periodic upgrades to remain effective well into the 21st century and to pace the threat. Software upgrades developed under this project will target capability increases in high interest areas as prescribed by the Fleet and captured in campaign analysis. To achieve this, the project will package and deliver incremental upgrades every two (2) years to the AN/SQQ-89A(V)15 Surface Ship ASW Combat System production program via an Advanced Capability Build (ACB) spiral development process. The project has undergone a transition in software development methodology from a legacy waterfall approach to an Agile development, security, and operations (DevSecOps) approach. This new Agile approach involves modern Continuous Integration/Continuous Delivery (CI/CD) modular software architectures, coding,$$, 29766000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603561N_2033$$, $$0603561N$$, $$2033$$, $$Adv Submarine Systems$$, 46762000, $$Advanced Submarine Systems Development (ASSD) is a non-acquisition program that develops, matures and tests advanced technologies for successful integration into current and future submarine classes, lowers the technical/cost risks of integrating new technologies prior to acquisition, and speeds the delivery of capability and lethality to the Fleet. ASSD transitions Hull, Mechanical, and Electrical (HM&E) technologies, and future naval concepts from the Science & Technology (S&T) and Research and Development (R&D) communities through the development, maturation, and integration of technology projects to operational submarine platforms for assessment, testing, and evaluation. Once projects have proven their maturity and promise through at-sea demonstration, they are formally transitioned into acquisition Programs Of Record (PORs). Additionally, ASSD operates and maintains strategic R&D infrastructure and measurement assets that are critical to the long-term design, assessment and construction of modern, stealthy submarine platforms. Project 2033 is comprised of three programmatic budget categories: Strategic Capability R&D Infrastructure, Long Range R&D Investment, and Rapid Technology Development. Strategic infrastructure investments maintain and operate critical, one-of-a-kind undersea warfare R&D assets that enable the design and manufacture of the stealthiest submarines in the world, without the requirement to develop and test at full scale, which is inordinately expensive and risky. Long-range R&D investment is the maturation and prototyping at full scale of long-range (5-10 years) technologies, to enable their readiness for incorporation into existing and future submarines. The objective is to achieve high technology readiness levels (TRL-7) of the targeted technology so that it can be incorporated into the baseline submarine design during the detailed design and construction contract award and evaluated for back-fit into existing platforms. This is class agnostic technology development that supports the VIRGINIA program, COLUMBIA program, and the Next Generation Attack Submarine (SSN(X)) programs. Rapid Technology Development projects are efforts designed to rapidly mature higher TRL capabilities and field the particular technology project capability within an 18-30 month window, from program start to submarine at- sea demonstration. Also included in this category are innovative technology transition projects, seedling efforts (<$800K/year) which assess new technology candidates and keep the submarine and Undersea Warfare (USW) technology pipeline primed. All SUB073/ASSD projects are determined by senior USW leadership and N97 sponsor direction. The Program works with Small Business Innovation Research (SBIR), Small Business Technology Transfer (STTR), Office of Secretary of Defense (OSD), Office of Naval Research (ONR), and Defense Advanced Research Projects Agency (DARPA) organizations to identify and mature technology candidates for integration into current/future submarine classes to provide new/transformational capabilities, while achieving total-ownership cost reductions. Experimentation and demonstration are also conducted in a joint warfighting context with other services (i.e. Marine Corps, Army, Air Force to enable early assessment of a new technology's warfighting capabilities, and to inform the Fleet and acquisition community on smarter technology-selection decisions. This Program also supports cooperative R&D through$$, 46762000, NULL, NULL, NULL, NULL, 566784000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603561N_3094$$, $$0603561N$$, $$3094$$, $$USW Decision Support$$, 10125000, $$Undersea Warfare Decision Support System (USW-DSS) is the Navy Program of Record Anti-Submarine Warfare (ASW) Command and Control (C2) Net-Centric system supporting the warfighter. USW-DSS provides an integrated, near-real time, net-centric ASW Common Tactical Picture (CTP) and Common Operational Picture (COP) for the Carrier Strike Groups (CSGs). USW-DSS is a C2 capability identified in the ASW Initial Capabilities Document (ICD) for the Sea Combat Commander (SCC) and Theater USW Commander (TUSWC). USW-DSS enables effective planning and execution of USW operations, optimizes placement of sensors for exploitation of the environment, manages available resources, balances operations versus risk, and provides a clear vulnerability assessment of the operational environment. USW-DSS ensures safe operational and tactical C2 of submerged U.S. and allied submarines via Prevention of Mutual Interference (PMI) capability, and protects from blue-on-blue engagement with a Waterspace Management planning and execution tool. USW-DSS shortens C2 decision processes for detection-to- engagement across multiple platforms, including those with low-bandwidth communications or intermittent connectivity. Tactical data such as tracks, environmental, and sensor processing data is ingested into USW-DSS through platform specific interfaces such as the AN/SQQ-89A(V)15 Surface Ship ASW Combat System, the Global Command and Control System - Maritime (GCCS-M), and the AN/SQQ-34 Aircraft Carrier Tactical Support Center (CV-TSC). USW-DSS processes this and other tactical data and supports intelligent dissemination of the data to unit and theater level platforms in support of an enhanced USW tactical picture. USW-DSS provides USW Commanders with an expanded, net-centric USW collaborative capability across CSG platforms (CVNs, CGs, DDGs, FFGs) as well as supporting shore nodes to include Commander Task Force (CTF), the Naval Oceanographic Processing Facility (NOPF), and Tactical Operations Center (TOC) and Maritime Operations Center (MOC). On afloat platforms, USW-DSS processing software is virtualized for portability and is hosted on the Consolidated Afloat Networks and Enterprise Services (CANES) system and implements a Service-Oriented Architecture (SOA) with display generation and operator interfaces provided via USW-DSS hardware. For support and ashore nodes, USW-DSS processing software is hosted on Commercial-Off-The-Shelf (COTS) hardware. Starting in 2024, USW-DSS fielding will be entirely hosted on CANES with no additional USW-DSS hardware. This software-only fielding plan will allow for more frequent system patching and upgrades. To accommodate this transition, USW-DSS is developing a secure container-based architecture. Future USW-DSS capability is phased to deliver timely and cost-effective software improvements to the warfighter via the Fleet Capability Release (FCR) process. USW- DSS Build 3 FCR incremental developments implement cost-effective cyber security and Theater ASW (TASW) functionality by integrating inputs from data sources and platforms such as the P8-A Poseidon aircraft and associated Air ASW sensors, provide improved and additional functionality, and improve stability and reliability. USW-DSS Build 3 provides common and improved visualization, integrated USW platform sensor data sharing, reduced data entry, improved sensor performance predictions, data fusion, and reduced redundancy across USW Tactical Decision Aids (TDAs). The project provides a greater understanding of the undersea battle space by allowing the entire force (carrier and expeditionary strike group, theater, or other) to have a common and thorough understanding of the battle space with characterized uncertainties. The Navy continues to modernize and add sensor capabilities to existing programs of record that are significant data sources of information for USW-DSS. These include, but are not limited to the AN/SQQ-89A(V)15 Surface Ship ASW Combat System, AN/SQQ-34 CV-TSC, GCCS-M, and Link Monitoring and Management Tool (LMMT). As the sensor capabilities and systems mature, the tactical data valuable to USW-DSS is incorporated as part of a future FCR. Through targeted architectural improvements, follow-on FCRs will facilitate the migration of select components of USW-DSS to a DoD commercial cloud computing environment,$$, 10125000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603561N_3439$$, $$0603561N$$, $$3439$$, $$Project NAUTICA: Integrated Theater$$, 750000, $$The Networked Architecture for Undersea Theater Integrated C2 Advantage (NAUTICA) project provides Theater Anti-Submarine Warfare (TASW) architecture development, systems engineering, and design. NAUTICA will identify requirements to integrate intelligence (operational and tactical) and sensor (national and organic) systems to provide a fully informed Naval Integrated Fires - Counter Undersea (N2CX) Common Operational Picture (COP) of enemy undersea forces, maximizing decision superiority and theater level planning, and address TASW C2. Using Model-Based Systems Engineering (MBSE), NAUTICA decomposes warfighting requirements into system requirements allocated to existing Programs of Record or identified as new program requirements. Theater Undersea Warfare Operations Center's (TUSWOC) systems today are not integrated to support performance requirements during all threat levels. This results in failure to most effectively employ Theater USW assets. Near term, the Project will continue to accelerate development by rapidly prototyping the framework for existing legacy systems to be federated, to exchange key information and significantly improve existing TASW capability. NAUTICA will also establish a transition path for new USW technologies such as the Operational Planning Tool (OPT), Water Space Planner (WASP), Battlespace Management Tactical Decision Aid (BAM TDA), and other Future Naval Capabilities (FNCs) that will start to transition Technology Readiness Level (TRL) 5/6 enabling technologies into the USW-DSS Program of Record. NAUTICA investments are prioritized in accordance with the Commander U.S. Fleet Forces endorsement of "Theater ASW Capability Requirements" letter (dated 24 February 2017) and Center for Security Forces (CSF) letter "Criticality of Sustaining Prevention of Mutual Interference (PMI) and Water Space Management (WSM) Capability and Meeting Emerging Requirements for Great Competition" submitted to OPNAV N2N6. The design of the integrated TASW battle management suite will include a system of systems TASW architecture to enable the existing programs of record under development from the Program Executive Office (PEO) for Integrated Warfare Systems (IWS), PEO Command, Controls, Communications, Computers and intelligence (C4I), PEO AIR, PEO Undersea Warfare Systems (UWS), and N9SP to exploit a common framework. The common architecture will define the key data exchanges, common displays and processing, data models, cross domain interfaces, and multi-level security software that will enable systems such as USW-DSS to exchange, display, and exploit information at the appropriate classifications. NAUTICA focuses development of Theater USW C2 multi-system integration challenges that require coordination across multiple programs, multiple platforms, and multiple resource sponsors.$$, 750000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603561N_9999$$, $$0603561N$$, $$9999$$, $$Congressional Adds$$, 0, $$This project represents a onetime $10M congressional add in FY25 to enhance the development of advanced submarine hull coatings for improved acoustic performance, maintainability and cost, with the objective of near-term implementation on VIRGINIA and COLUMBIA Class platforms, as well as future submarine classes.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603562N_0770$$, $$0603562N$$, $$0770$$, $$Adv Sub Supp Equip Prog$$, 0, $$A continuing need exists to improve Imaging and Electronic Warfare (EW) support capabilities in view of the advancements in potential imaging counter-detection and the increasingly dense electromagnetic environment caused by the proliferation of complex radar, communications, and navigation equipment of potential adversaries. Improvements are necessary for submarine Imaging and EW to be operationally effective in the following mission areas: Joint Littoral Warfare, Joint Surveillance, Space and Electronic Warfare, Intelligence Collection, Maritime Protection, and Joint Strike. This project will concurrently consider both Imaging and EW domains as improved mast systems are designed. The evaluation of state-of-the-art technology to implement periscope/mast improvements via EW electromagnetic and electro-optic sensors results in improved capability. Engineering Development Models (EDMs) are developed, evaluated, and validated in the lab and through at-sea testing. This project is a non-Acquisition Category (ACAT) program. The test articles identified consist of critical components that will be fully developed during Engineering Manufacturing and Development phase into EDMs. Software-based capabilities in Imaging and/or EW domains that will process inputs from improved masts may be integrated and tested within this project.$$, 0, NULL, NULL, NULL, NULL, 46912000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603563N_3376$$, $$0603563N$$, $$3376$$, $$Strategic Sealift$$, 14572000, $$Project 3376 - Strategic Sealift Research and Development - Develops new concepts and technologies which can be applied to or will enable future strategic sealift, and Seabasing systems. The technologies include ship configuration concepts, equipment to increase cargo handling and cargo loading/unloading rates (including commercial and merchant ship systems), improved man/machine interfaces, improved structural configurations and materials, and Logistics-Over-the-Shore (LOTS) equipment and system improvements. Prior Years include: FY2016 and prior years (FY2014 and earlier) efforts financed under the National Defense Sealift Fund (NDSF) BA 04 Project 3116 Strategic Sealift Research and Development; FY2015, FY2017, FY2019 thru FY2023 efforts financed under this program element, RDT&E,N BA04, Project 3376 (Strategic Sealift); and FY2018 efforts financed under RDT&E,N BA 04 Project 9999/C403 (Congressional Adds). The FY 2026 request for Strategic Sealift includes $14,572 thousands of discretionary and $21,200 thousands of mandatory (reconciliation) for a total of $35,722 thousands. The mandatory funds will be allocated to T-AKE Expeditionary Reload Equipment. Further details regarding this reconciliation request can be found in Section 20002 (Shipbuilding) of the Reconciliation Exhibit.$$, 14572000, NULL, NULL, NULL, NULL, 45082000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603562N_1739$$, $$0603562N$$, $$1739$$, $$Submarine Arctic W/F Development$$, 0, $$The Submarine Arctic Warfare Development Project provides the U.S. Navy Submarine Force (SUBFOR) a cadre of trained Arctic Operation Specialists (AOS) and an inventory of unique Arctic sensors that are installed to optimize submarine safety during under-ice operations. AOS personnel assigned from ASL embark on submarines that deploy to the Arctic, cold water and iceberg regions, and marginal ice zones (MIZ) in northern latitudes of the Atlantic and Pacific Oceans and are advisers to the Commanding Officer. ASL is a shore facility at Naval Base Point Loma with the infrastructure capable of supporting personnel and equipment to conduct the submarine Arctic Warfare Development mission. Improvements and life-cycle expenditures to the facility and warehousing are made as necessary to support the mission. The Submarine Arctic Warfare Development Project, via ASL, responds to the increased threat of naval activity in the Arctic regions while continuously supporting the Navy's strategic objective of Assured Access and Combat Credibility. ASL provides a unique capability that enables the SUBFOR to satisfy the requirements laid out in the Arctic Maritime Homeland Defense Initial Capabilities Document (ICD). ASL and SUBFOR demonstrate existing Arctic Warfare capabilities and operational and tactical proficiency while developing advanced submarine technology in unique cold-water environments, in under-ice conditions, and in ice-covered shallow water regions through the Ice Exercise (ICEX) program that includes Operation Ice Camp. ICEX places an emphasis on submarine operability and mission capability in the world's harshest maritime environment. Efforts include assessment of combat system effectiveness, weapons testing, use of High Frequency (HF) sonars in Arctic regions, testing of ice-capable submarine structures, and development of class-specific Arctic operational guidelines. Tactical Development (TACDEV) is conducted biennially and requires up front comprehensive planning and work-up training, as well as post exercise analysis and reporting. ICEX provides the framework for various submarine test and evaluation efforts in Arctic regions and at periodic Ice Camps. The ICEX program represents DoD's only drifting ice station capability through Operation Ice Camp. Emphasis during Operation Ice Camp is placed on the areas of sonar operability, tactical surveillance, weapon utility, and other submarine support missions. A Torpedo Exercise (TORPEX) occurs every four (4) years in order to meet minimum Fleet requirements of exercise torpedo (EXTORP) firings in the Arctic. A TORPEX requires a significantly higher level of logistics, personnel, and infrastructure to account for the recovery and transportation efforts of the EXTORPs. The ICEX Program also includes Arctic Exercise (ARCEX), a biennial exercise that rotates with the biennial Operation Ice Camp drifting ice camps, that includes Arctic operations to support ice camp equipment evaluation, systems development, extreme cold weather training, drifting sea ice and scientific research.$$, 0, NULL, NULL, NULL, NULL, 103566000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603563N_2196$$, $$0603563N$$, $$2196$$, $$Design, Tools, Plans and Concepts$$, 22297000, $$Project 2196 - This project provides the analytical foundation for making informed force structure, capability and affordability decisions in the development of all future surface ship platforms, weapons, sensors and combat systems. It achieves this through total ship system engineering, technology integration, cost estimation, mission effectiveness analysis, force architecture synthesis, and force-level effectiveness analysis, as well as continuous development of the people, tools and processes required to efficiently accomplish these efforts efficiently. This includes early-stage concept development studies for all potential future surface ships. It includes quantitative mission and force-level analysis to identify future capability gaps and requirements related to advances in threat capabilities, and evaluation of the effectiveness and affordability of potential future technology and concept of operations (CONOP) solutions. Results from this project are used to inform senior Navy leadership in support of budgetary decisions, Capability Evolution Plans (CEP), and requirements related to surface ship force structure, platforms and major combat system elements.$$, 22297000, NULL, NULL, NULL, NULL, 56807000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603563N_3161$$, $$0603563N$$, $$3161$$, $$NAVSEA Tech Authority$$, 7122000, $$This project supports the NAVSEA Technical Authority with the coordination of design and development efforts for cross-platform applicability to result in more affordable, mission-capable, and interoperable surface ship forces including ships that are less expensive to build and operate with reduced manning, reduced support costs, and greater utilization of emerging technology. NAVSEA Tech Authority efforts under Project Unit (PU) 3161, known as the Cross Platform Systems Development (CPSD) Program, develops cross-program technology solutions and associated Technical Authority products. This project provides a coordinated, collaborative approach to the development of cross-platform naval ship and weapon system technical requirements, design, as well as engineering capabilities in the areas of design tools, criteria, and methods. The CPSD project provides innovative solutions for current fleet issues involving Technical Authority, such as interoperability issues with new systems or platforms and/or cross-cutting technology insertion topics. CPSD maintains the use of established functional areas for scope prioritization and portfolio diversification but now aligned to the "Support of Technical Authority." Project Unit 3161 includes the following sub-projects: - Additive Manufacturing (AM): The AM program focuses on development and use of AM equipment for Naval applications in land-based and afloat applications, including system performance requirements, shipboard integration requirements and considerations, material selection, design optimization, equipment and component certification, and digital engineering integration. Efforts include consideration of AM across a wide variety of potential applications ensuring AM manufactured components can meet mission requirements and that system/component technical requirements are updated to leverage AM. In FY 2026, the AM program moves to program element 0604286N, Navy Advanced Manufacturing, for better transparency. - Learning to Action Board (L2AB) Firefighting: Following the USS Bonhomme Richard fire, the L2AB Firefighting Program was established to research and develop solutions for damage control and firefighting issues identified in a subsequent Major Fires Review. This program funds critical efforts in shipboard fire detection/ suppression systems, fire prevention features, and advanced firefighting equipment. In FY 2026, the L2AB sub-project moves to program element 0604516N, Ship Survivability, for better transparency. - Underway VLS At-Sea Reload (VASR) program: The VASR is a high-level, high visibility demonstration and testing of connected replenishment for the VLS Reload process, also known as the Transportable Rearming Mechanism Process (TrAM). - Condition Based Maintenance Plus (CBM+): CBM+ is a maintenance optimization program that generates significant benefits through maintenance program resets, maintenance effectiveness reviews, and active reliability centered maintenance (RCM) strategies at the program level. Employed as an enduring cross-life-cycle$$, 7122000, NULL, NULL, NULL, NULL, 311773000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603563N_3244$$, $$0603563N$$, $$3244$$, $$Cybersecurity Engineering$$, 6806000, $$This effort funds two continuing cybersecurity programs; Situational Awareness Boundary Enforcement and Response (SABER) and a maturing Cybersecurity project, High Availability Virtual Environment (HAVEN), and USS SECURE. SABER is the research, design, development, testing, and installation of Cybersecurity solutions for installed integrated computer networks to include shipboard Hull Mechanical and Electrical (HM&E), Navigation Systems, Combat Systems, Fire Control, Sonar, Radar, Communications, and other shipboard computerized control systems for all afloat U.S. Navy platforms. SABER provides network boundary defense and situational awareness to protect and detect against external and internal cybersecurity-threats. HAVEN is a secure operating environment that provides a resilient and redundant infrastructure platform for rapid software deployment and system restoration. HAVEN provides the secure operating environment for SABER and a secure hosting environment. HAVEN has been considered a part of SABER and continued HAVEN development has led the Navy to understand that this capability may have use beyond hosting SABER. USS SECURE is a cybersecurity Test & Evaluation capability for operationally representative distributed system of-systems testing with scalable events from individual systems to enclave, platform, and strike group levels. USS SECURE is applicable to systems across Navy SYSCOMS and DoD Services.$$, 6806000, NULL, NULL, NULL, NULL, 47496000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603563N_3505$$, $$0603563N$$, $$3505$$, $$Maritime Prepositioning Force Next$$, 2301000, $$The MPF(X) ships will recapitalize the aging BOBO Class maritime prepositioning ships in consideration of evolved force concepts such as Distributed Maritime Operations. The 'Sealift the Nation Needs' report to Congress defines a three-phase Sealift Recapitalization approach: Service Life Extensions, Acquiring Used ships, and new construction. The MPF(X) portion represents the prepositioning new construction aspect of the three-phase sealift recapitalization approach in full consideration of force concepts. FY 2026 will leverage the previous Analyses of Alternatives (AoA) on Crane Ships and conduct an AoA on Marine prepositioning to continue defining military requirements associated with the nation's sealift and ready reserve force. This requirements definition will then feed into creation of the Capability Development Document (CDD).$$, 2301000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603563N_4045$$, $$0603563N$$, $$4045$$, $$Next Generation Medium Logistics$$, 1124000, $$The Next Generation Logistics Ship (NGLS), also known as T-AOL, is planned to be a new class of ships to augment the traditional Combat Logistics Force (CLF) to enable refueling, rearming, and resupply of Naval assets - afloat and ashore - near contested environments via ship-to-ship operations and ship-to port operations in support of Distributed Maritime Operations (DMO), Littoral Operations in a Contested Environment (LOCE), and Expeditionary Advanced Base Operations (EABO). Augmenting the traditional CLF, NGLS will provide a flexible, responsive platform to move fuel, personnel, equipment, and supplies between ships, advanced bases, ports, and dispersed nodes of the seabase; sustaining afloat (Surface Action Group) and ashore (Expeditionary Advanced Base) requirements. RDT&E funding will continue to support development of the NGLS ship design(s), specification development, affordability analyses, and definition of ship mission systems.$$, 1124000, NULL, NULL, NULL, NULL, 43206000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603563N_5010$$, $$0603563N$$, $$5010$$, $$AS(X) Submarine Tender$$, 4996000, $$AS(X) will conduct steady state and wartime sustained, forward-based tending, resupply, depot and intermediate level repair operations on submarines and ships while anchored or pier side. In steady state, AS(X) will provide pier side support in a forward deployed submarine homeport, providing sustained repair, supply, weapons handling, and tending operations for submarines. AS(X) is being specifically designed to support deployed VIRGINIA class (VCS), COLUMBIA class (CLB) and future generation submarines in the 21st century. AS(X) is required to support all aspects of Intermediate level maintenance and support to deliver expeditionary tending operations to VCS block V (and later) submarines.$$, 4996000, NULL, NULL, NULL, NULL, 30700000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603563N_9999$$, $$0603563N$$, $$9999$$, $$Congressional Adds$$, 0, $$Represents 4 separate Congressional Adds aligned under Ship Concept Advanced Design. Funding provided in the Department of Defense Appropriations Act 2024 for wave energy converters and marine energy systems for sensors and microgrids for digital cybersecurity engineering, Navy Expeditionary Sustainment and Repair (NESAR), Forward Advanced Manufacturing for Expeditionary Deployment (FAMED), Maintenance Technologies Supporting Operational Readiness (MTOR). Budgets have been updated to reflect Small Business Innovative Research (SBIR) taxes applied.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603564N_0409$$, $$0603564N$$, $$0409$$, $$DDG-51 Flt III Concept Development$$, 25152000, $$This project provides Test and Evaluation (T&E) requirements for DDG-51 Flight III ships and efforts for the Navigation, Aviation and Hull, Mechanical & Electrical (HM&E) Cyber Enclaves Design for implementation on future new construction ships. T&E will concentrate on verifying integration and interoperability of employed technologies and systems in the DDG-51 FLT III design to achieve the mission capabilities and performance requirements as defined in the DDG-51 Flight III Capability Development Document (CDD) to reach Initial Operational Capability (IOC). T&E functions will include the evaluation of Critical Technical Parameters (CTP), Measures of Effectiveness (MOE), Measures of Suitability (MOS), and Key Performance Parameters (KPP). Funding is also planned for the execution of Developmental Testing (DT), Operational Testing (OT), Live Fire Test and Evaluation (LFT&E), and Full Ship Shock Trials (FSST). The Navigation, Aviation and Hull, Mechanical & Electrical (HM&E) Cyber Enclaves Design effort will provide a new design to physically separate Hull, Mechanical, and Electrical (HM&E) communications from Navigation communications to meet multiple DoD Directives/Instructions on Cybersecurity and Navy Joint-SYSCOM Cybersecurity Standards on Enclave management. This design will be utilized to support implementation on future new construction DDG-51 class ships.$$, 25152000, NULL, NULL, NULL, NULL, 17106000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603564N_0411$$, $$0603564N$$, $$0411$$, $$DDG(X) Concept Development$$, 51594000, $$To compete and win in an era of great power competition, the United States needs a balanced Naval force, capable of striking targets from all domains. The force design must emphasize distributed awareness, lethality and survivability in high-intensity conflict. The force must be adaptable, demonstrate presence, and be capable of projecting power by delivering precision effects at long ranges. The Future Naval Force Study (FNFS) and the Future Surface Combatant Force Analysis of Alternatives (FSCF AoA) identified the requirement for future large surface combatants (LSCs) to be capable of hosting directed energy (DE) weapons, larger missiles for increased range and speed, increased magazine depth, growth in organic sensors, and an efficient integrated power system to manage the dynamic loads. DDG 51 is highly capable, but after over 40 years in production and 30 years of upgrades the hull form does not provide sufficient space and center of gravity margin to host future capabilities. To reset these design allowances for the future, requirements tradeoff and design studies were performed from FY 2018 to FY 2020 that considered modification of existing surface combatant and amphibious ships in addition to new concepts. These studies concluded that DDG(X) is required to deliver the necessary margins and flexibility to succeed the DDG 51 Class as the next enduring LSC combining the DDG 51 FLT III combat system elements with new hull form, an efficient Integrated Power System (IPS) and greater endurance, reducing the Fleet logistics burden. By including the DDG 51 FLT III combat system in a new hull, mechanical and electrical (HM&E) baseline, Navy is taking an "evolutionary" (vice "revolutionary") approach to the class. This is a critical lesson learned proven by the successful evolution of the original DD 963 Spruance design of the early 1970s that focused on lead ship HM&E capabilities and upgraded warfare capability over the next 50 years, including evolving DD 963 into the CG 52 class and incorporating the Aegis Combat System. In the early 1980's, the DDG 51 class applied a similar approach by incorporating the proven Aegis Combat System into a new hull form and subsequently executed upgrades over a period greater than 40 years before reaching hull limitations on incorporation of new, larger systems. When DDG(X) enters production, over 30 DDG 51 FLT III Ships will have been in production and early DDG(X) production transition will overlap DDG 51 FLT III production ensuring stability in the Large Surface Combatant industrial base. The CNO approved DDG(X) Top Level Requirements (TLR) in December 2020 that set the basis for a draft Capabilities Development Document (CDD) released in October 2021. Based on evolving threats and recent Battlegroup deployment feedback, the operational community revalidated the requirements and in August 2024 delivered revised TLRs. The updated draft CDD focuses on concept formulation, collaboration with DDG 51 shipyards in program planning, and targeted trade studies to achieve the CNO's cost, schedule, and performance targets.$$, 51594000, NULL, NULL, NULL, NULL, 69372000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603564N_3262$$, $$0603564N$$, $$3262$$, $$T-AGS Design & Total Ship$$, 0, $$T-AGS(X), Oceanographic Survey Ship, is the planned recapitalization of the Pathfinder Class (T-AGS 60) six vessels which are approaching the end of their life starting in 2024. The T-AGS ship is a multi-mission, world-wide deployable oceanographic survey ship providing oceanographic capabilities in coastal and deep ocean areas. Data collected from charting the world's coastlines is vital in support of undersea warfare, enemy ship detection, and humanitarian assistance and disaster relief efforts. The recapitalization ensures the CNO requirement for eight T-AGS survey ships.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603564N_3389$$, $$0603564N$$, $$3389$$, $$OPLOG IPT Development$$, 7163000, $$Project 3389 - Develops enabling technologies for future and in-service afloat operational logistics and integrated supply systems; defines integrated combat logistics force and combatant logistics requirements; and conducts cooperative initiatives with acquisition programs, program sponsors, engineering managers, the Navy science and technology community, and Fleet customers. Operational Logistics Integration R&D (OPLOG) develops new logistics platforms, integrated cross-platform (i.e., applicable to more than one ship class/type) operational logistics and operational energy technologies and capabilities, as well as draft acquisition and operations policy ensuring future Naval systems leverage emerging logistic capabilities and technologies to provide operationally effective and efficient logistics delivery for both peacetime and wartime contested environments. Though the operational logistics family of systems touches all aspects of Naval presence and power projection, operational logistics capability and system interfaces typically have been left to individual acquisition programs to develop and resolve. Technology development is necessary to mitigate technological and operational risk before ship acquisition programs accept new technologies. This project provides a foundation for the transition and systems development of science & technology initiatives evolving from the Office of Naval Research (ONR) Power & Energy Future Naval Capabilities (FNC), Enterprise and Platform Enablers FNC, Seabasing FNC, and from other enabling Government, industry and academia concepts to the acquisition community. Thus, this project resources continued research and development of appropriate technologies with applicability to multiple acquisition programs and defines and matures performance and interface requirements for those technologies. This project continues to identify, develop, integrate, demonstrate, and transition logistics technologies to improve both the cost effectiveness of Fleet at sea logistics delivery in peacetime, as well as delivery capability effectiveness in wartime, through outreach, coordination and collaboration with industry, academia, Fleet, and Enterprise representatives. This project will continue to develop new logistics platforms, improved shipboard replenishment, transfer, and handling systems and components, as well as asset visibility and standardized packaging technologies. This project includes development of approaches to reduce operation and maintenance costs of, and energy consumption by the logistics Fleet. This integrated suite of developed capabilities will enable multiple ship types to leverage technologies common across DoD (Joint) and commercial transportation networks to provide a more affordable, energy efficient, and contested environment mission capable force. These capabilities and system-of-systems approach will be applied to concept development of future auxiliary force architectures.$$, 7163000, NULL, NULL, NULL, NULL, 113979000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603564N_4044$$, $$0603564N$$, $$4044$$, $$Medium Landing Ship$$, 12113000, $$Medium Landing Ship (LSM) is a medium-sized landing ship that enables distributed maneuver and logistics such as Distributed Maritime Operations (DMO), Littoral Operations in a Contested Environment (LOCE), and Expeditionary Advanced Base Operations (EABO), in support of the Marine Littoral Regiment (MLR). It is designed to fill the gap in capability between the Navy's large, multipurpose amphibious warfare class ships and smaller landing vessels. This ship will deploy tailored logistics, select power projection and support strike capabilities via the embarked MLR. With the authorities granted in Section 128 of the FY 2025 National Defense Authorization Act, the LSM program will procure an existing design to construct Non-Developmental Vessels (NDV). This procurement is known as LSM Block 1.$$, 12113000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603564N_9999$$, $$0603564N$$, $$9999$$, $$Congressional Adds$$, 0, $$To compete and win in an era of great power competition, the United States needs a balanced Naval force, capable of striking targets from all domains. The force design must emphasize distributed awareness, lethality and survivability in high-intensity conflict. The force must be adaptable, demonstrate presence, and be capable of projecting power by delivering precision effects at long ranges. The Future Naval Force Study (FNFS) and the Future Surface Combatant Force Analysis of Alternatives (FSCF AoA) identified the requirement for future large surface combatants (LSCs) to be capable of hosting directed energy (DE) weapons, larger missiles for increased range and speed, increased magazine depth, growth in organic sensors, and an efficient integrated power system to manage the dynamic loads. DDG 51 Flight (FLT) III is highly capable, but after over 40 years in production and 30 years of upgrades the hull form does not provide sufficient space and center of gravity margin to host these future capabilities. To reset these design allowances for the future of naval warfare, requirements tradeoff and design studies were performed from FY 2018 to FY 2020 that considered modification of existing surface combatant and amphibious ships in addition to new concepts. These studies concluded that DDG(X) is required to deliver the necessary margins and flexibility to succeed the DDG 51 Class as the next enduring LSC combining the DDG 51 FLT III combat system elements with new hull form, an efficient Integrated Power System (IPS) and greater endurance reducing the Fleet logistics burden. By including the DDG 51 FLT III combat system in a new DDG(X) hull, mechanical and electrical (HM&E) baseline, Navy is taking an "evolutionary" (vice "revolutionary") approach to the class. This is a critical lesson learned proven by the successful evolution of the original DD 963 Spruance design of the early 1970s that focused on lead ship HM&E capabilities and upgraded warfare capability over the next 50 years, including evolving DD 963 into the CG 52 class and incorporating the Aegis Combat System. In the early 1980's, the DDG 51 class applied a similar approach by incorporating the proven Aegis Combat System into a new hull form and subsequently executed upgrades over a period greater than 40 years before reaching hull limitations on incorporation of new, larger systems. When DDG(X) enters production, over 30 DDG 51 FLT III Ships will have been in production and early DDG(X) production transition will overlap DDG 51 FLT III production ensuring stability in the Large Surface Combatant industrial base. Furthermore, the first DDG 51 FLT III ship entered production in FY 2017 and will not be able to accommodate any significant capability upgrades dues to SWAP-c constraints. The DDG(X) design tool is intended to be a common CAD (Computer Aided Design) and PLM (Product Lifecycle Management) hardware and software suite utilized by both Shipbuilders involved in the design and construction of DDG(X) ships. The DDG(X) design tool implementation will optimize the design work between the Shipbuilders and the Navy in a common data environment for 3D models, drawings, technical information, logistics, parts data, change management and configuration control. It is part of the overall DDG(X) Digital Environment and aligns with the DoN digital engineering strategy. The objective is to significantly reduce the design hours throughout the entire lifecycle of the ship from design, production and modernization by eliminating majority of duplicative work between the Shipbuilders.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603570N_1258$$, $$0603570N$$, $$1258$$, $$Nuclear Technology Development$$, 87857000, $$The details of this program element are classified CONFIDENTIAL and are submitted annually to Congress in the classified budget justification books.$$, 87857000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603573N_9999$$, $$0603573N$$, $$9999$$, $$Congressional Adds$$, 0, $$C332 Silicon Carbide Power Electronics & System Integration: As part of the Silicon Carbide based power converter and bus node that provides the correct power for distributed mission systems loads, the power electronics and system integration will be initiated. C872 Silicon Carbide (SiC) Flexible Bus Node (FBN): In support of future Integrated Power System (IPS) architectures, the R&D goal is to develop a Silicon Carbide based power converter and bus node that provides the correct power for distributed mission system loads. The technology offers a more efficient alternative to traditional transformers and a smaller footprint. C873 Large Format Lithium Ion Batteries: Objective will be to demonstrate alternative format lithium ion batteries that can provide energy storage for potential Naval applications. C994 Tactical Energy Management Controller: The R&D goal is to develop an intelligent, cyber-hardened TEMC that coordinates shipboard power sources and loads to optimize fuel efficiency and enhance operational capabilities related to advanced sensors, radars, and directed energy weapons. C995: High Temperature Superconducting Main Propulsion Electric Motor Technology: The R&D goal is to develop a concept for a High Temperature Super Conducting (HTSC) propulsion motor, conducting risk reduction activities including a land based test and study integration methods for Navy applications. The technology could demonstrate a high-efficiency and high-power propulsion in comparison to current state of the art propulsion motors.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603576N_1578$$, $$0603576N$$, $$1578$$, $$Chalk Eagle$$, 156686000, $$The details of this budget justification are classified, per Executive Order 13526, Sec 1.4 (a) and are submitted annually to Congress in the classified budget justification book.$$, 156686000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603581N_3096$$, $$0603581N$$, $$3096$$, $$Littoral Combat Ship$$, 10203000, $$The RDT&E portion of the LCS Program comprises design and development efforts required to field the LCS Class Ships, including integration with the Mission Packages (MCM and SUW) activities both pre- and post-delivery. It includes the design and development effort required to support the introduction and deployment of a Flight 0+ baseline (LCS 3/4 and Follow) with incorporation of lessons learned from the design and construction of USS FREEDOM (LCS 1) and USS INDEPENDENCE (LCS 2). Additionally, it includes design, development, issue resolution, certification and testing efforts required to support the design baseline for the six year block buy in FY10-15. This baseline includes lessons learned from the LCS 1 through LCS 4. The LCS design and development phases include platform design and development, experimentation, ship system design and integration, hull platform testing, development of Technical Data Packages (TDPs), total ship system engineering and integration, combat systems and warfare systems certification, and planning and conduct of system testing. These efforts include procurement of combat and warfare system elements and/or simulators to support production representative testing in support of design, development, and certification efforts and ordnance in support of testing. The RDT&E portion of LCS funding also comprises formal Developmental and Operational Assessment testing of the LCS Ships and Mission Packages. Test and Evaluation (T&E) will concentrate on verifying integration and interoperability of employed technologies and systems in the LCS seaframe designs and modular mission packages to achieve the mission capabilities and performance requirements as defined in the LCS program's Flight 0 and Flight 0+ Capabilities Development Documents (CDD). T&E functions will include the evaluation of Critical Technical Parameters (CTP), Measures of Effectiveness (MOE), Measures of Suitability (MOS), and Key Performance Parameters (KPP) for the core seaframe and the focused missions. This budget provides funds for the design, development, engineering, implementation, and testing of the combat system modifications for Lethality and Survivability (L&S) for both LCS variants (Independence and Freedom). The L&S upgrades include the development of a common Combat Management System (CMS) and integration and testing of government furnished systems including the Gun Weapon System (GWS), Electronic Warfare (EW) system, and Decoy Launching System (DLS) for both LCS Class Variants (Independence and Freedom) ships. Without funding for L&S trainer upgrades, sailors on ships with L&S configuration will not be trained on the L&S configuration in our trainers.$$, 10203000, NULL, NULL, NULL, NULL, 1521234000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603581N_4506$$, $$0603581N$$, $$4506$$, $$LCS Training$$, 0, $$As a minimally-manned ship, the LCS uses a Train-to-Qualify (T2Q)/TYCOM Certification Training process in an off-ship/shore-based virtual ship trainer environment. These simulators and blended training solutions focus on tactical, equipment operations, and maintenance training. When completely developed and procured, the LCS shore-based training capability will satisfy individual, team, unit, and force training, with an objective of meeting Capability Development Document (CDD) T2Q/TYCOM Certification Training Key Performance Parameter (KPP) requirements. Funding will develop upgrades of the Surface Training Advanced Virtual Environment (STAVE) courseware and associated simulators to achieve the training objectives. Additionally, after fielding more of the systems and courseware, out-year funding will be utilized to upgrade training to maintain conformity with LCS configurations and approved operational technical manuals and procedures, as well as test and evaluate training devices to verify compliance with requirements.$$, 0, NULL, NULL, NULL, NULL, 69621000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603582N_0164$$, $$0603582N$$, $$0164$$, $$Combat System Integration$$, 19643000, $$Project 0164: Combat System Integration: This project consists of four key Pillars executed within the Strike Force Interoperability (SFI) Program: (1) Command, Control, Communications, Computer, Combat Systems, Intelligence, Surveillance and Reconnaissance (C5ISR) Modernization Process (C5IMP). The C5IMP validates the introduction of new systems and upgrades to existing systems into the fleet and ensures systems' maturity prior to shipboard installation thereby reducing risk and enhancing readiness and effectiveness of deploying ships and strike groups. (2) Warfare Systems Certification (WSCERT), which is essential to validating the maturity and operational performance of warfare systems prior to Fleet delivery and deployment. (3) The integrated Navigation System Certification (NAVCERT) program certifies the shipboard integrated navigation suite for safe navigation using the Electronic Charting and Display Information System Navy (ECDIS-N) as the primary plot. To support Strike Force Interoperability and ship's mission requirements, it ensures that the installed integration navigation suite provides accurate and timely navigation information (position, velocity, speed, heading, roll, and pitch) to all navigation data consumers (Warfare/Weapons Systems, Control Systems, and precision approach and landing systems) to enable the safe maneuver of naval forces to execute missions throughout the full spectrum of conflict. (4) Interoperability Certification and Assessment (IOP C&A) is the critical independent assessment of strike group warfare systems operational performance. Interoperability assessment examines force level engagement threads, aircraft control, air battle management, and operational displays to ensure the warfighter is being provided the most interoperable systems available. Assessments of deploying ships in strike force configurations are accomplished through the use of the Navy's Distributed Integration and Interoperability Assessment Capability (DIIAC) which supports the Deputy Assistant Secretary of the Navy (DASN) "shift to the left" policy by providing early interoperability testing in the acquisition lifecycle. Interoperability characterization results are used to develop fleet tactical tools (Strike Group Interoperability Capabilities & Limitations (SGI C&L) documentation and Tactical Information Coordinator Technical Aids (TIC TECHAIDS)) that ensure that systems' operators understand the interoperability capabilities and limitations of their combat systems, as well as all units within the networked architecture, and have the watch station tools necessary for the execution of their tactical responsibilities. The Fleet operators require these products to ensure warfighter awareness of Strike Force Interoperability.$$, 19643000, NULL, NULL, NULL, NULL, 507187000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603595N_3220$$, $$0603595N$$, $$3220$$, $$COLUMBIA Class Submarine$$, 208419000, $$The COLUMBIA Submarine Class Program (previously the OHIO Replacement Class) is developing the next generation sea-based strategic deterrent. The funding applies to the design, systems engineering, prototyping, and vendor qualification activities needed to execute the schedule for Common Missile Compartment (CMC) design, whole ship design, and component technologies development for the next generation U.S. ballistic missile submarine (SSBN). This RDT&E program supports cooperation with the United Kingdom (UK) to maintain strategic deterrence, based on a single effort to develop a CMC as agreed by the UK Secretary of State for Defense and the U.S. Secretary of Defense in 2009. At the COLUMBIA Program Semi-Annual Interim Progress Review (IPR) held on August 30, 2021, the USD(A&S) Milestone Decision Authority (MDA) directed COLUMBIA to be funded to the program baseline, including Integrated Enterprise Plan (IEP) funding as reflected in this budget submission. The COLUMBIA program strategy is to leverage the re-use of existing Submarine system designs (as applicable), focus on lifecycle Total Ownership Cost (TOC) affordability, and meet the military requirements established for this SSBN to achieve mission success in a challenging environment. The requested funding levels provide for the Technology Development, Design, Engineering, and Integration efforts necessary to support the COLUMBIA Class SSBN lead ship construction along with continued development and design support for construction of the class. A Contract Modification for ongoing design/advance construction efforts was awarded on 22 Jun 2020, which also included the Build I Option for the First Two Ships. This was a Pre-Priced Option for the two ships, SSBN 826 and SSBN 827, and associated design/support efforts. This was a modification of the current Integrated Product & Process Development (IPPD) contract (N00024-17-C-2117) and is in line with the program's approved Acquisition Strategy. The program requested authorization of SSBN 826 in FY21, funded with three years of incremental funding in FY21-23, and is requesting authorization of SSBN 827 in FY24, funded with two years of incremental funding in FY24-25. The RDT&E efforts support this plan. The following key activities support the COLUMBIA Class SSBN Program: 1. Design and development of a missile compartment, launch system, and Strategic Weapons Support Systems (SWSS) to meet U.S. strategic requirements while cooperating with the UK on modernizing its strategic deterrent in accordance with Presidential direction (December 2006). 2. Concept Definition, System Definition, and Detailed Design for remaining portions of the ship accomplished through a Design/Build/Sustain approach modeled after the approach used by the VIRGINIA Class program. 3. Engineering and integration of existing technologies and development of new technologies required to provide the capabilities necessary to ensure platform operational effectiveness and minimize life cycle cost. 4. Ongoing design support for construction of the submarine class. COLUMBIA Class SSBN concept study, system definition prototyping, and technology development efforts support design, systems engineering, component development and vendor qualification activities needed to develop the CMC design and the COLUMBIA whole ship design. The COLUMBIA design timelines are$$, 208419000, NULL, NULL, NULL, NULL, 4312598000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603595N_3440$$, $$0603595N$$, $$3440$$, $$SBSD Obsolescence$$, 19094000, $$This project provides the engineering development and program management effort required to sustain Non-Propulsion Electronic Systems (NPES) outfitting of each ship of the COLUMBIA Class throughout the duration of the 12-ship construction program. Non-recurring engineering activity is required to ensure specification compliant components are available for procurement as fleet common sub-systems, which evolve over the life of the program due to either competitive selection of new suppliers, component obsolescence replacement, increased technical performance, or improvements in reliability. Non-recurring engineering activity is needed to perform platform integration of the components, and software modification to accommodate electronic data exchange, COLUMBIA unique submarine environment qualification, and update of all logistics products.$$, 19094000, NULL, NULL, NULL, NULL, 19738000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603595N_3441$$, $$0603595N$$, $$3441$$, $$SBSD Technology Refresh$$, 45752000, $$This project encompasses ship system development, coordination, and management efforts for the COLUMBIA Class Submarine Technology Insertion Program and Technology Refresh Program over the life cycle. The purpose of the Technology Insertion Program is to efficiently upgrade performance of all hulls by virtue of improvements in HM&E ship systems. The purpose of the Technology Refresh Program is to develop, coordinate, and manage technical refresh plans for ship systems reliant on Commercial off the Shelf (COTS) technology that have short product life cycles to ensure materiel solutions for obsolescence issues. Additionally, this project will support mitigation of obsolescence issues for HM&E components that are not included in systems that have not historically had a formal Tech Refresh plan. Technology development implementation and logistics for developmental items, and COLUMBIA Class test & evaluation for these items are also included. Testing of components and systems will be used to inform performance predictions for later ships in the class and determine if design changes are needed. Technologies developed in this program will be considered for applicability to the VIRGINIA Program for commonality opportunities. The thrust of these efforts will be to maintain required technical performance and materiel readiness of COLUMBIA SSBNs in order to support the Sea Based Strategic Deterrence (SBSD) mission.$$, 45752000, NULL, NULL, NULL, NULL, 45338000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603595N_9999$$, $$0603595N$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional Add supports the COLUMBIA Class Submarines advanced composite shaft design and shipyard and ship repair workforce training.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603596N_2550$$, $$0603596N$$, $$2550$$, $$Mine Countermeasure (MCM)$$, 23676000, $$The MCM Mission Package (MP) employs an incremental development approach to deliver capability which allows the continued insertion of mature capabilities throughout the life of the program without the need for modifications to the seaframes. The focus is to minimize service life extensions to both MCM-1 ships and the MH-53E helicopters. Future MCM MP capabilities will be considered when joint warfighting objectives or changing threats create new operational capability requirements that cannot be met by current mission package designs, or when new technological opportunities allow significant progress toward delivering cost effective enhanced capabilities. Future mission module increments can be tested, constructed, and incorporated into existing mission packages, one of the most important benefits of LCS modular design. MCM MP successfully completed IOT&E in Q4FY22 and achieved Initial Operational Capability (IOC) on 31MAR 2023. MCM MPs have begun to be fielded Q3FY24 and deployed in Q2FY25. The program has begun investigation into the feasibility of integrating the MCM MP on Vessels of Opportunity (VOO). In FY19 and FY20, the program demonstrated the flexibility of the modular MCM MP components by conducting a MCM Vessel of Opportunity (VOO) at-sea demonstration onboard the USS Hershel "Woody" Williams (T- ESB 4). The MCM MP will counter deep, shallow, and tethered mines in the littorals without putting sailors in the minefield. When the MCM MP is embarked, LCS is capable of conducting detect-to-engage operations (hunting, sweeping, and neutralization) against very shallow to deep-water sea mine threats and detect mines in the Beach Zone. The MCM MP provides these capabilities through the use of sensors and weapons deployed from an MH-60S multi-mission helicopter, unmanned offboard vehicles, and support equipment/containers. The MCM MP consists of the following modules: - Unmanned Minesweeping (UMS) Module: Unmanned Influence Sweeping System (UISS) (USV + Minesweeping Payload Delivery System (PDS)) - Airborne Mine Neutralization (AMN) Module: Airborne Mine Neutralization System (AMNS) + MH-60S helicopter - Near Surface Detection (NSD) Module: Airborne Laser Mine Detection System (ALMDS) + MH-60S helicopter - Coastal Mine Reconnaissance (CMR) Module: Coastal Battlefield Reconnaissance & Analysis (COBRA) + MQ-8 Fire Scout Vertical Take-off and Landing Tactical Unmanned Aerial Vehicle (VTUAV) - Remote Minehunting (RMH) Module: Unmanned Surface Vehicle (USV) + Minehunting PDS + AN/AQS-20 Minehunting Sonar - Near-surface Mine Neutralization (NSN) Module: Barracuda (Barracuda Neutralizer + USV + Mine Neutralization PDS)$$, 23676000, NULL, NULL, NULL, NULL, 175153000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603596N_2552$$, $$0603596N$$, $$2552$$, $$Surface Warfare (SUW) Mission$$, 0, $$The SUW MP increases firepower and offensive/defensive capabilities against large numbers of highly maneuverable, fast, small craft threats, giving LCS the ability to protect the sea lanes and move a force quickly through a choke point or other strategic waterway. The SUW MP is composed of several mission modules including the Gun Mission Module (GMM), the Aviation Module, the Maritime Security Module (MSM), and the Surface-to-Surface Missile Module (SSMM). The GMM is composed of two high velocity 30mm cannons which is augmented by the ship's resident 57mm gun to counter close in to mid-range threats. The Aviation Module uses the embarked MH-60R helicopter with Hellfire missile and the MQ-8B Fire Scout VTUAV for the detection, identification, and classification of surface contacts and to engage long range threats. The MSM supports the embarkation of a Visit, Board, Search, and Seizure (VBSS) team. The SSMM is a self-contained module consisting of 2 Missile Exhaust Containment Structures (MECS), integrated articulating hatch covers, a fire control system, and 12 two-rail MK 210 launchers to support load out and firing of 24 Longbow Hellfire missiles. SSMM provides missile coverage for mid-range threats and small boats.$$, 0, NULL, NULL, NULL, NULL, 38748000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603596N_3129$$, $$0603596N$$, $$3129$$, $$LCS Mission Package Development$$, 15582000, $$The LCS Mission Modules Common Equipment consists of the development and integration of vital C5I products required by all Mission Packages to provide common hardware interfaces, computer operating environment, communications systems, aviation interface systems, UxV interfaces and portable development & integration test- sets. Common hardware interfaces include definition, installation, and control of mechanical, electrical, and cooling requirements common to all mission packages. The Mission Package Computing Environment (MPCE) provides common services and Operating Environment to support all Mission Package Application Software (MPAS) and Open Architecture Products. The Multi-Vehicle Communications System (MVCS) enables the control and data exchange of simultaneous unmanned mission vehicles and the ship. Aviation interface systems include integration and management of data communications, data processing, and physical hardware interfaces such as common equipment and containers used by all mission packages. Development and integration test-sets provide a mobile operating environment installed in the Mission Package Portable Control Stations (MPPCSs) to serve as a surrogate ship during mission package development and integration test events at test ranges.$$, 15582000, NULL, NULL, NULL, NULL, 669727000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603597N_9999$$, $$0603597N$$, $$9999$$, $$Congressional Adds$$, 0, $$ATRT technologies provide essential development and operational analysis capabilities to streamline testing and certification for software for both single systems/units and systems of systems capabilities to reduce development time for new capabilities from years to weeks. Leveraging cloud and virtualization technologies within a force-level system of systems interoperability test bed, ATRT enables agile software updates to afloat and airborne edge infrastructures with automated near real-time analysis of interoperability improvements and performance virtually.$$, 0, NULL, NULL, NULL, NULL, 122820000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603673N_1165$$, $$0603673N$$, $$1165$$, $$Undersea Warfare (UW)$$, 53902000, $$The Undersea Warfare Project focuses on the advanced technology development of new capabilities that leverage the underlying applied research investments in Program Element (PE) 0602750N, Future Naval Capabilities (FNC) Applied Research. These advanced technology investments align to acquisition programs of record. Efforts include improvements to a broad range of undersea warfare capabilities, including undersea weapons, submarine acoustic sensing and signal processing systems, communications, electro-optics systems, signature management, training, and decision aids.$$, 53902000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603597N_9B88$$, $$0603597N$$, $$9B88$$, $$Automated Test and Analysis$$, 9862000, $$Automated Test and Re-Test (ATRT) capabilities enable faster and more consistent testing across the Naval enterprise. Specifically in the near term this project seeks to implement ATRT into digital capabilities, laboratory testing, and the Overmatch Software Armory (OSA) DevSecOps environment to conduct secure system development scalable distributed simulation. A seamless push to afloat, airborne, and edge infrastructure allowing the Navy's designated user community to make software updates (new and modernization of old code) while maintaining, or eliminating, the need for an Authority to Operate (ATO). The Continuous Delivery/Continuous Integration (CD/ CI) of capability enabled by the ATRT technology for real time software code analysis and performance testing in the Cloud Development Environment (CDE) as well as rapid feedback in the Operational Environment (OE). Enabling this effort, this program is developing and scaling the Integrated Modeling Environment (IME), which supports shared and linked Model Based Systems Engineering (MBSE) from the mission level to the function/system level. This will in turn power the ATRT models that analytically link together software code production output with intended planned capability developed against gaps filled at the mission level, enabling rapid and continuous iteration and deployment of software into the digital environment.$$, 9862000, NULL, NULL, NULL, NULL, 78574000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603598N_9999$$, $$0603598N$$, $$9999$$, $$Congressional Adds$$, 0, $$Automated Test and ReTest (ATRT) Enterprise Rapid Capability develops, integrates, and deploys novel capabilities aggregated from mature technologies in support of Distributed Maritime Operations. These capabilities are enabled through the use of virtualized systems of systems, automated test and analysis, automated certification, rapid interface development, and field with and data collection and edge analytics.. These technologies are at the heart of the Navy's rapid capability approach, which combines digital engineering tools with evolutionary approaches to requirements generation, operational testing, and deployment. This process will meet Fleet demands for near-term capability in a predictable and repeatable fashion.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603598N_9B88$$, $$0603598N$$, $$9B88$$, $$Automated Test and Analysis$$, 20000000, $$Automated Test and ReTest (ATRT) Enterprise Rapid Capability develops, integrates, and deploys novel capabilities aggregated from mature technologies in support of Distributed Maritime Operations. These capabilities are enabled through the use of virtualized systems of systems, automated test and analysis, automated certification, rapid interface development, and field with and data collection and edge analytics.. These technologies are at the heart of the Navy's rapid capability approach, which combines digital engineering tools with evolutionary approaches to requirements generation, operational testing, and deployment. This process will meet Fleet demands for near-term capability in a predictable and repeatable fashion.$$, 20000000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603599N_3086$$, $$0603599N$$, $$3086$$, $$Frigate$$, 84199000, $$Frigate (FFG 62 Class) efforts are composed of the design and development for a more lethal and survivable multi-mission warship focused on Anti-Surface Warfare (SUW) and Anti-Submarine Warfare capabilities (ASW), local air defense and enhanced survivability features. FFG 62 Class design modifications for added capability over the Littoral Combat Ship (LCS) include an Over-the-Horizon (OTH) surface-to-surface missile system, upgraded air defense weapons and sensors, advanced electronic warfare system and improved decoys, local air defense, and enhanced survivability features. This effort will encompass design, development, and technical issue resolution to support design maturity for DD&C FY 2020 contract award. Certification and testing efforts are also required to support the FFG 62 Class delivery, operations, and introduction to the fleet. The FFG 62 Class design and development phases include platform design, development and risk reduction; combat system element integration; total ship system engineering and integration; combat systems and warfare systems certification; and planning and conduct of system testing. These efforts include procurement of combat and warfare system equipment and/or simulators to support production representative testing in support of design, development, and certification efforts and ordnance in support of testing. This funding will also include efforts and activities required for formal Developmental and Operational testing of the FFG 62 program. Test and Evaluation (T&E) will concentrate on verifying integration and interoperability of employed technologies and systems in the FFG 62 design to achieve the mission capabilities and performance requirements as defined in the FFG 62 Class Capability Development Document (CDD). Funding will also be for the execution of LFT&E DT, C4I integration & test, cyber test and certification, warfare system integration & test and certification, aviation (manned and unmanned) integration & test and certification. T&E functions will include the evaluation of Critical Technical Parameters (CTP), Measures of Effectiveness (MOE), Measures of Suitability (MOS), and Key Performance Parameters (KPP).$$, 84199000, NULL, NULL, NULL, NULL, 700620000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603600D8Z_600$$, $$0603600D8Z$$, $$600$$, $$WALKOFF$$, 152449000, $$Classified.$$, 152449000, NULL, NULL, NULL, NULL, 144818000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603605F_633151$$, $$0603605F$$, $$633151$$, $$High Power Solid State Laser$$, 0, $$This project develops and demonstrates integrated, state of the art, high energy laser (HEL) weapon demonstrator systems to satisfy Department of the Air Force requirements in areas including, counter adversary unmanned aerial systems (c-UAS), counter adversary intelligence/surveillance/reconnaissance (c-ISR), and counter adversary missiles (c-Missile) for High Value Airborne Asset (HVAA) protection and point defense. Technologies developed under PE 0602605F (Directed Energy Technology), 625173 (Laser Technology), feed directly into this project.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603605F_633152$$, $$0603605F$$, $$633152$$, $$High Power Microwave$$, 4434000, $$This project develops and demonstrates high power microwave and other unconventional electromagnetic field generation and transmission technologies that can be integrated into future weapon systems to support a wide range of the Department of the Air Force missions such as air base defense or the damage/destruction of an adversary's electronic infrastructure. It also provides inputs to the susceptibility, vulnerability, and lethality databases used across the Department of Defense to understand thresholds for scalable effects of directed energy weapons.$$, 4434000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603609N_0363$$, $$0603609N$$, $$0363$$, $$Insensitive Munitions Adv.$$, 7035000, $$Energetic materials producibility is demonstrated to assure national capability to produce and load munitions systems. The program leverages are being closely coordinated with other military departments, North Atlantic Treaty Organization (NATO) and allied countries to eliminate redundant efforts and maximize efficiency. A joint service IM requirement has been developed and through the IM strategic planning process, all Program Executive Offices (PEO) are implementing IM in their priority munitions. IM are identified as a Department of Defense (DoD) critical technology requirement and considered as part of a weapon design. The IMAD program matures the technology developed by a variety of Science and Technology (S&T) sources for program management integration into weapons systems to meet the IM technical deficiencies documented in the PEO IM Strategic Plans. IMAD provides the link between S&T programs and the program managers (PM) by optimizing IM technologies to meet Navy requirements. IMAD offers risk mitigation for the PMs in terms of IM technical knowledge, expertise and manpower with the state of the art expertise across IM products. Each technology area is divided into subtasks addressing specific munition and munition class IM deficiencies.$$, 7035000, NULL, NULL, NULL, NULL, 287079000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603609N_0364$$, $$0603609N$$, $$0364$$, $$Explosives Safety and Weapons$$, 3842000, $$Reduce risk introduced by new weapons systems and technologies that have potential to interfere with ordnance safety and Fleet operations. Emerging radars for all classes of ships introduce a heightened electromagnetic environment (EME) with the likelihood of exceeding the maximum allowable environment (MAE) currently in place. The MAE provides the safety barrier in identifying the electrostatic safety threshold for ordnance items. Exceeding MAE introduces increased risk of inadvertent detonation of electrically primed explosives.$$, 3842000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603618D8Z_245$$, $$0603618D8Z$$, $$245$$, $$EW Enterprise Exploration and$$, 20575000, $$Electronic Warfare (EW) Exploration and Innovation (E&I) research efforts focus on the Electromagnetic Spectrum Operations (EMSO) capabilities of electronic warfare (EW), sensing, communications; cyber capabilities, and the delivery platforms that are associated with them. The scope of the EW E&I research efforts is from a joint, multi-domain perspective over the broad range of potential non-kinetic effects. The non-kinetic effects can overlap into the Electro-Optical and Infrared (EO/IR) phenomenologies and potentially, integration with directed energy subsystems. New EW-related and EW/Cyber-related technologies are identified relative to current and projected EMSO challenges informed by the most current threat intelligence and from a joint and multi-domain perspective. Service operational perspectives are obtained through participation or facilitation of joint Communities of Interest (COIs). Potential solutions and technological synergies are explored through interaction with the research and practitioner communities. Considerable efforts are expended to avoid the potential for redundant efforts. The Joint Electronic Advanced Technology program element (JEAT) supports large-scale, operationally-relevant scenario driven multi-domain experimentation events focused on early development EMSO capabilities that are employed on small unmanned systems (UxS) across multiple operational domains. The events are structured for technology developers to experiment within an operationally relevant environment and includes wide participation by DoD operational and technical subject matter experts. Focus Areas include Distributed Electronic Attack, Deception, Digital Payload Delivery, Distributed Electronic Support and Electronic Protect with an emphasis on Swarming Algorithms, Artificial Intelligence, Machine Learning and Resilient Communications. These events started including AUKUS integration in FY-23. The purpose of the events is to observe and highlight the most current and promising capabilities available – or under development by- the commercial, academic, federal, and defense sectors of the U.S. and select international partners. The experiments provide the Defense Industrial Base (DIB), non-traditional and emerging Industry, Government and Academic based Labs opportunities to meet with Department of Defense (DoD) experts to refine their technologies on a test-fix-test basis. The experiments allow the system developers to prepare for technology transition. Typically, the Technology Readiness level (TRL) is advanced which improves commercial viability and the potential for transition. The experiment also offers a venue to demonstrate capabilities to potential transition partners.$$, 20575000, NULL, NULL, NULL, NULL, 55772000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603619A_CE5$$, $$0603619A$$, $$CE5$$, $$Breaching Capability Development -$$, 12633000, $$The current mounted breaching system, the M58 Mine Clearing Line Charge (MICLIC), is a rocket-projected explosive line charge that was initially fielded over 50 years ago and is becoming increasingly less effective against modernized threat obstacles which does not support Multi-Domain Operations (MDO). This effort will focus on the development of the XM123 Ground Obstacle Breaching Lane Neutralizer (GOBLN) system, an MDO-capable modular mission payload which will provide greater effectiveness against current and emerging threat obstacles and enhanced operational reliability, supportability, mobility and survivability beyond the current state. The Program will collaborate with Transformation In Contact (TIC) units to further mature breaching technologies. The target platform for GOBLN is the ground robotic vehicle to support the Combat Engineer mission and any future emerging requirements. GOBLN has been endorsed by the Next Generation Combat Vehicle (NGCV) Cross Functional Team (CFT) and will have the ability to integrate with current and future platforms. The modularity also allows for integration with other current and future platforms. The FY 2026 request supports continued Technology Maturation and Risk Reduction (TMRR) and a soldier touchpoint that will include a Technology Readiness Level (TRL) 6 prototype demonstration.$$, 12633000, NULL, NULL, NULL, NULL, 6871000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603619A_EK7$$, $$0603619A$$, $$EK7$$, $$Area Denial Capability Development$$, 28883000, $$Project EK7 Area Denial Capability Development provides for the advanced capability development of Terrain Shaping systems and develops modernized, non- persistent U.S. Anti-personnel landmine policy compliant munition fields. During joint, multi-domain, high intensity conflicts, Terrain Shaping systems disrupt, fix, turn and block enemy freedom of maneuver while enhancing friendly freedom of maneuver within the same battle space. Terrain Shaping systems enable maneuver commanders to directly influence where battlefield engagements occur. Terrain Shaping systems will replace a portion of the Family of Scatterable Mines (FASCAM) systems which are beyond their designed life. The project will develop Terrain Shaping prototype systems to evaluate and integrate emerging technologies in collaboration with Transformation in Contact (TIC) units to further mature terrain shaping technologies in real time to drive innovation, enhance learning, refine requirements and accelerate solution development. Terrain Shaping systems will use an open system and modular architecture to facilitate future development, maintenance, repair, and product improvements to include emerging requirements such as the ground robotic vehicle to support the Combat Engineer mission. XM204 Interim Top Attack program, the first Terrain Shaping capability insertion, has entered into production with Initial Operational Capability (IOC) projected for 1QFY26 to meet United States Army Europe (USAREUR) Operational Needs (ONS) #18-22702. The Army is developing an enduring solution to fill the directed obstacle capability gap. FY 2026 budget supports the research and development of the Terrain Shaping systems to include development of a complex obstacle employing a modernized, semiautonomous/autonomous bottom attack capability. Terrain Shaping systems will include complementary lethal capability and advanced network integration to provide a complex Terrain Shaping capability that complies with U.S. Anti-Personnel Landmine Policy and provides the commander greater speed and flexibility to transition between offensive and defensive operations. The enduring Terrain Shaping capability development supports the approved Terrain Shaping Abbreviated-Capability Development Document (A-CDD) and Army Futures Command (AFC) Terrain Shaping Strategy for Land Domain and Multi-Domain Operations (MDO).$$, 28883000, NULL, NULL, NULL, NULL, 53331000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603635M_1558$$, $$0603635M$$, $$1558$$, $$Advanced Reconnaissance Vehicle$$, 240222000, $$The Advanced Reconnaissance Vehicle (ARV) program is designed to fill a pressing operational need with the Marine Corps portfolio of reconnaissance, surveillance, and target acquisition systems. The ARV will be a purpose-built combat vehicle system, highly mobile on land and water, that can sense, communicate, and fight in the performance of reconnaissance and battlespace shaping activities. Equipped with modern command, control, communications, and surveillance systems the ARV will transform the ability of Fleet Marine Forces to sense and communicate within the littoral operating environment by providing a persistent and mobile systems of systems to augment and sustain effective sensor webs and kill chains. The base program will consist of the following mission role variants (MRV): ARV-30mm (ARV-30), ARV- Command, Control, Communications and Computers/Unmanned Aircraft Systems (C4UAS) and ARV-Logistics (LOG). The complete family of vehicle capability is planned to consist of 3 additional mission role variants: ARV-Recovery (R), ARV-Precision Fires (PF) and ARV-Counter Unmanned Arial System (CUAS).$$, 240222000, NULL, NULL, NULL, NULL, 130642000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603635M_2614$$, $$0603635M$$, $$2614$$, $$SMAW Follow-On$$, 546000, $$The Family of Anti-Armor Weapon Systems (FOAAWS) portfolio supports the Shoulder-launched Multipurpose Assault Weapon (SMAW) Follow-On solution. The solution is the Multi-purpose Anti-Armor Weapon System (MAAWS) M3A1, which is a portable, shoulder-fired, line-of-sight, reloadable, 84mm recoilless rifle. The MAAWS provides anti-armor, anti-personnel, anti-material, and assault capabilities to Marine Rifle Squads, Combat Engineers, and Reconnaissance Teams to effectively execute both offensive and defensive operations. Also contained in FOAAWS is the research, development, test, and evaluation for a suite of ammunition which supports a wide range of mission sets including obscuration, illumination, anti-personnel, armored penetration, bunker penetration, and soft target engagement. This line also supports the development of training aids and materiels to include reduced impacts of blast over pressure and impulse noise on the Fleet Marine Force (FMF).$$, 546000, NULL, NULL, NULL, NULL, 24582000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603635M_3835$$, $$0603635M$$, $$3835$$, $$Family of Expeditionary Fuel$$, 0, $$Family of Expeditionary Fuel Systems (FEFS) is a line that contains highly versatile fuel systems in support of Fleet Marine Force (FMF) operations. The family contains individual Table of Allowance Material Control Numbers which support FMF and Marine Air-Ground Task Force (MAGTF) operations and future operating concepts by providing all aspects of land and littoral-based fuel support to include receiving, test, additization, storage, sensors and metering, transfer and dispensing of fuel.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603635M_6639$$, $$0603635M$$, $$6639$$, $$Multiple-Launch Rocket System$$, 28980000, $$This line develops a Multiple Launch Rocket System (MLRS) Family of Munitions (MFOM) Launcher Unit (MLU) to interface with the Remotely Operated Ground Unit for Expeditionary Fires (ROGUE-Fires) carrier. This development provides Medium-range Missile (MMSL) batteries the capability to utilize the ROGUE-Fires carrier for either Navy Marine Expeditionary Ship Interdiction System (NMESIS) launchers with Naval Strike Missiles (NSM) or MLUs capable of firing the entire selection of MFOM similarly employed by High Mobility Artillery Rocket System (HIMARS). This modular capability is an essential element of the Marine Corps artillery modernization strategy as it affords operational flexibility for the artillery regiments and Marine Littoral Regiments (MLR), as well as component commonality with other Department of Defense systems. The MLU will consist of a MLU sled (composed of the launch unit with a Fire Control System (FCS)) and a weapon control system termed Remote Gunner Station (RGS). The RGS, formerly termed as Weapon Control System (WCS), is a modular, scalable tablet that can be operated from a Mobile Command Vehicle as well as from a command post and is being adapted to control up to three MLUs per section. The MLU sled will be mounted upon a ground-based, tele-operated carrier (ROGUE-Fires) and will be capable of firing the Guided Multiple Launch Rocket System (GMLRS), the Reduced Range Practice Rocket (RRPR), the pending Precision Strike Missile (PrSM) series, and other MFOM-related munitions that the HIMARS platform can accommodate. A ROGUE-Fires leader-follower kit will be capable of steering up to three systems. This effort includes design, development, integration, and test of the MLU and RGS for interface with the ROGUE-Fires carrier. The MLU makes extensive use of existing systems to increase operational flexibility and reduce procurement and product support. FY 2025 continued initial software development and testing for the one- to-one radio-controlled operations of the MLU and conducted an integrated flight test. FY 2026 completes the development of one-to-one radio-controlled operations, continues development for the one-to-three radio-controlled operations of the MLU, purchases test assets, and conducts developmental testing.$$, 28980000, NULL, NULL, NULL, NULL, 17443000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603635M_7400$$, $$0603635M$$, $$7400$$, $$Combat Capability Development$$, 8513000, $$Long Range Unmanned Surface Vessel (LRUSV) is a Marine Corps Force Design priority that has demonstrated, through extensive wargaming and simulations, significant operational impact in the Naval Expeditionary Force's surface warfare campaign against peer competitors in the maritime battlespace, particularly when operating within planned sensor and communication networks. LRUSV is a semi-autonomous platform capable of multi-domain sensor collections that enables the Marine Division / Marine Expeditionary Force to enhance Maritime Domain Awareness (MDA) for the Naval Expeditionary Force and Coalition maritime operations centers. LRUSV will employ a suite of organic sensors (RADAR, EO/IR, and Electromagnetic Support) to accomplish its primary mission of gaining and maintaining custody of surface contacts of interest in the littoral operating environment. LRUSV sensor capabilities will assist the Marine Division's Marine Reconnaissance Company in its mission to conduct seaward reconnaissance, surveillance, and target acquisition in a peer-threat contested, littoral operating environment across the spectrum of competition, crisis, and conflict to enhance Joint and coalition maritime domain awareness and facilitate the application of Joint fires. In FY 2025, LRUSV continued autonomy software development and sensor integration activities and conducted testing of the manned/unmanned teaming concepts and sea-based command and control (C2). In FY 2026, LRUSV will implement sensor enhancements, complete small form factor testing, and begin facilities studies.$$, 8513000, NULL, NULL, NULL, NULL, 91990000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603639A_CD8$$, $$0603639A$$, $$CD8$$, $$Long Range Precision Munition$$, NULL, $$Long Range Precision Munition (LRPM) is the lethal variant of the Launched Effects (LE) Family of Systems which provide a range of capabilities through variations of platforms, payloads, and mission systems. LE provides tactical and operational flexibility through collaboration of heterogeneous groups of LE launched from multiple domains (land and air) in conjunction with other manned platforms, C2, unmanned systems, and sensors throughout the operational environment. The ability to interoperate and coordinate with other LE systems at long ranges and adapt to changing threats is a core concept of the Launched Effects Abbreviated Capability Development Document validated in June 2024. Primary target set for LRPM is Integrated Air Defense Systems. LRPM will provide Army Aviation and Ground Forces with a precise long range munition system to rapidly respond in a combat environment to improve the lethality and stand-off of Warfighters and aviation platforms in an Anti-Access Area Denial (A2AD) and positioning, navigation, and timing (PNT) denied environment. FY 2026 funding for LRPM transferred to PE 0609345A/Project A46.$$, NULL, NULL, NULL, NULL, NULL, 20171000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603639A_DK5$$, $$0603639A$$, $$DK5$$, $$Conventional Artillery Modernization$$, 1155000, $$The 155 millimeter (mm) High Explosive Conventional Artillery Modernization Project is focused on the design and development of common artillery projectiles capable of accurate delivery of multiple payloads to deliver the Army's Field Artillery operational efficiencies. These efforts will provide the Army's Field Artillery lethal and nonlethal area effects at ranges relevant and decisive to the Division fight. The Modular Artillery for Combat Effectiveness (MACE) line of effort will develop lethal area effects. The Extended Range (ER) Cargo line of effort will develop lethal and non-lethal areas effects at the longer ranges necessary to enable transformation in contact. The Army requires versatile, affordable, sustainable, and enduring projectiles capable of rendering a variety of lethal and non-lethal effects necessary to disable and destroy a broad set of targets within multiple threat formations. This Project is executing an evolutionary approach to ensure a common projectile can support multiple cargo capabilities, including lethal, Radio Frequency (RF) obscuration, visible obscuration, Intelligence, Surveillance, and Reconnaissance (ISR), Infra-red (IR) illumination, visible illumination, electronic attack, Terrain Shaping Obstacles, and future cargo capabilities. Fiscal Year (FY) 2026 funding will support the technical assessments, system development, prototypes and integration, concept studies, component testing, technology maturation, and engineering evaluations in support of the Army's Field Artillery Cannon Transformation Strategy.$$, 1155000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603639A_DK7$$, $$0603639A$$, $$DK7$$, $$155mm Artillery Propulsion Mod - Adv$$, 10341000, $$155mm Artillery Propulsion Modernization (Advanced Component Development) supports the United States Army's Cannon Transformation Strategy and develops and improves three propulsion systems components: (1) modular charge that achieves minimum to intermediate ranges, (2) super charge that achieves maximum range and (3) percussion primer that initiates both the modular and super charges. Development efforts also include the design of packaging solutions (for protection during transportation and long-term storage), digital engineering, test measurement devices and modeling and simulation tools. Design emphasis will be placed upon Joint Ballistic Memorandum of Understanding (JBMOU) compatibility to maximize interoperability with foreign allies and ensuring that the components support manufacturability within the National Technology and Industrial Base (NTIB) that includes Australia, Canada, UK and US. The Fiscal Year (FY) 2026 funding will support prototyping and testing of propelling charge and ignition components to advance technology for improvement of the propellant effectiveness, cannon life, primer and charge ignition performance, system-level handling and rates-of-fire, and overall propulsion suitability and survivability.$$, 10341000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603746N_1906$$, $$0603746N$$, $$1906$$, $$Retract Maple$$, 647914000, $$The details of this budget justification are classified, per Executive Order 13526, Sec 1.4 (a) and are submitted annually to Congress in the classified budget justification book.$$, 647914000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603639A_DL5$$, $$0603639A$$, $$DL5$$, $$155mm Extended Range Artillery$$, 44866000, $$The Extended Range Artillery Munitions (ERAM) Project supports the development of a 155mm system of systems that includes projectile, propellant, primer, fuze, and fuze setter which will deliver lethality and range overmatch in 155mm artillery weapon systems at more than double the current range from legacy artillery cannons and will be compatible with future 155mm artillery systems in Global Positioning System (GPS) degraded and denied environments. The ERAM development effort is part of an organic Long Range Precision Fires capability, which will provide overmatching cannon artillery range capability at both Tactical and Operational Fires range by shaping the nature of the close fight through seeking moving and imprecisely located targets at extended ranges, increase range capability of the current 39 caliber cannon fleet and will also be compatible with future 52 caliber and above artillery weapon systems. Fiscal Year (FY) 2026 funding will support technology maturation and risk reduction of key system and subsystems, improvements in performance in difficult use cases, and integration of the tactical warhead and seeker supporting a series of Design Verification Testing (DVT) to achieve Technology Readiness Level (TRL) six (6) maturity.$$, 44866000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603639A_DN7$$, $$0603639A$$, $$DN7$$, $$Mobile Long Range Precision Strike$$, 5956000, $$DN7: The Mobile-Long Range Precision Strike Missile (M-LRPSM) is an approved Directed Requirement (DR). It must defeat Tier 1 thru Tier 3 Armor (stationary & defilade) Troops, Field Fortifications & Urban structures, and achieve a range of greater than 25 KM. It will be transportable by existing Infantry Brigade Combat Teams (IBCT) Light Tactical Vehicle platforms. It has the ability to adjust the missile flight, retarget, and abort, and have multiple missile launch capability. It must be survivable and resilient in denied and degraded environments. The FY 2026 request for M-LRPSM includes $5,956 thousand of discretionary and $10,000 thousand of mandatory (reconciliation) for a total of $15,956 thousand. The mandatory funds will provide developmental engineering, product improvements, integration support for the M-LRPSM system in FY 2026. Further information for this reconciliation request is provided in Section 20004 Munitions & Supply Chain of the Reconciliation Exhibit.$$, 5956000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603639A_EC3$$, $$0603639A$$, $$EC3$$, $$Ammunition Logistics Prototyping$$, 1931000, $$This project supports the future force by improving the distribution, management, reliability, and survivability of ammunition through the advanced development, integration, and demonstration of logistics system enablers supporting the Design of Army 2040. These enablers will improve the efficiency and effectiveness of ammunition operations, to include retrograde, while reducing the logistics footprint on the battlefield. Technology areas addressed include handling, distribution, management (strategic and tactical), prognostics, diagnostics, asset visibility, explosives safety, autonomous friendly packaging, and palletization. The efficient deployment and sustainment of reliable ammunition is vital to success on the battlefield. This project enhances the operational effectiveness of the ammunition logistics system to ensure the distribution of reliable ammunition to the Warfighter.$$, 1931000, NULL, NULL, NULL, NULL, 1823000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603639A_FA5$$, $$0603639A$$, $$FA5$$, $$Assured Precision Weapons and$$, 21223000, $$The Assured Precision Weapons and Munitions (APWM) - FA5 Project is focused on advanced risk mitigation, technology integration, prototyping, and product support to identify, evaluate, mature, test, and demonstrate various assured precision and countermeasure prototype technologies in Weapon and Munitions (W&M) components and subsystems within a complex System-of-Systems (SoS) environment. The APWM Project reinforces the National Defense Strategy's (NDS) major lines of effort through technology development and prototyping, which increases lethality and ensures future combat overmatch success of the Joint Force against peer/near-peer adversaries. This project also aims to improve program performance and affordability for multiple W&M Programs of Record (PoRs) via Joint Lethality Positioning, Navigation and Timing (PNT), layered Navigation Warfare (NavWar) and Electronic Warfare (EW) converged munition delivered effects, and Army M-Code Global Positioning System (GPS) coordinated efforts. The APWM Project directly supports the top Army Modernization Priorities via the All-Domain Sensing (ADS) and Long Range Precision Fires (LRPF) imperatives in support of the NDS and multiple Public Law related Congressional imperatives. Funding will support engagement by W&M PNT experts in the development, evaluation, and technology maturation/delivery activities of the US Space Force's (USSF) M-Code GPS, Army's PNT related programs, and ADS Cross-Functional Team (CFT) programs in support of LRPF and Counter Anti- Access/Area Denial (A2/AD) missions. Funding will also enable component and subsystem architecture input essential for Precision W&M operating in a contested NavWar and EW SoS environment, Army M-Code GPS technology integration and evaluation, planning and evaluating next generation M-Code GPS to validate capability for future Joint precision munitions, and maturation of alternative PNT and NavWar related technologies and solutions to enable informed PoR milestone and Army cross-functional modernization decisions.$$, 21223000, NULL, NULL, NULL, NULL, 51069000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603639A_FG1$$, $$0603639A$$, $$FG1$$, $$Cannon-Delivered Area Effects$$, NULL, $$The Cannon Delivered Area Effects Munitions (C-DAEM) Budget Activity Four (BA4) Project supports the development efforts of the Extended Range Artillery Projectile (ERAP), which transitioned in Fiscal Year (FY) 2025 from Budget Activity Three (BA3) PE 0603464A / Long Range Precision Fires Advanced Technology Project BO8 Long Range Precision Fires Advanced Tech), will deliver lethality and range overmatch in 155mm artillery weapon systems at more than double the current range from legacy artillery cannons and will be compatible in future 155MM artillery systems in a Global Positioning System (GPS) degraded and denied environments. ERAP, developed as part of an organic Long Range Precision Fires capability, will provide overmatching cannon artillery range capability at both Tactical and Operational Fires range by shaping the nature of the close fight through seeking moving and imprecisely located targets at extended ranges, will increase range capability of the current 39 caliber cannon fleet and will also be compatible with future 52 caliber and above artillery weapon systems. This Project does not have a FY 2026 budget request.$$, NULL, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603639A_XT5$$, $$0603639A$$, $$XT5$$, $$30mm Anti-Personnel and Counter$$, NULL, $$Airburst capability is identified as a threshold Key System Attribute (KSA) in Apache Block 3 Capability Production Document (CPD) - Approved 14 June 2017 and other cannon caliber Operational Needs Statements (ONS) and Capability Development Documents (CDD). The Anti-Personnel and Counter Unmanned Aerial Systems (UAS) munition provides increased lethality through airburst effects against personnel, small boats, and small Unmanned Aerial Systems (UAS) without requiring modification to the platform.$$, NULL, NULL, NULL, NULL, NULL, 17076000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603640M_2223$$, $$0603640M$$, $$2223$$, $$Marine Corps ATD$$, 86304000, $$This project funds technology demonstration, experimentation, and prototyping; and more technologically mature projects within the Future Naval Capability (FNC) process as means to inform, enhance, enable, and invent future concepts and capabilities with new Science and Technology (S&T). This project is organized into ten activities, the core of which is represented by the eight Expeditionary Warfighting Capability Areas. Emphasized within this project are increased efforts to actively demonstrate advanced technologies and system concepts. These demonstrations and experiments focus on the specific technologies, not necessarily their operational application, and vary based on the technical maturity of the project. This early technology exposure gives Marines a view into the future and enables them to use their imagination and innovation to envision novel employment of the technology and inform the acquisition process.$$, 86304000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603640M_2297$$, $$0603640M$$, $$2297$$, $$Futures Directorate$$, 218206000, $$The mission of the Marine Corps Warfighting Laboratory / Futures Directorate (MCWL/FD) is to generate and examine threat-informed operating concepts and capabilities and provide analytically-supported recommendations to inform subsequent force design and development activities. The Deputy Commandant, Combat Development and Integration (DC, CD&I) is the United States Marine Corps (USMC) advocate for Science and Technology (S&T). MCWL's Commanding General (CG) is the proponent of USMC S&T and serves as the USMC Executive Agent for Marine Corps S&T. The MCWL/FD also serves as the Marine Corps' liaison to the Joint Staff for Joint Concept Development and Experimentation; thereby, facilitating service-specific experiments as well as participation in joint service experimentation. As reflected in strategic guidance, expeditionary forces will provide an ever-ready quick strike force to protect United States (US) interests. MCWL/FD pursues concepts, capabilities, and solutions to ensure that Marines of the future force will be effectively organized, trained, and equipped to win across the range of military operations in an uncertain and complex environment. Prioritized investments in S&T are necessary to enable the future Marine Corps and maintain a technological advantage over our adversaries. This project is organized into 6 activities, the core of which are represented by the Warfighting Capability Areas of the Marine Air-Ground Task Force (MAGTF). The project emphasizes development and demonstration of advanced technology capability concepts, and the examination of their operational application and military utility in the context of formal wargames, Modeling, Simulation, and Analysis (MS&A), and live-force field experimentation with Marines. This operational experimentation directly supports Marine Corps combat development to inform future capability requirements and optimize the acquisition process.$$, 218206000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603640M_2958$$, $$0603640M$$, $$2958$$, $$Cyberspace Activities$$, 5201000, $$This Project activity provides freedom of maneuver and influence in the cyber-electronic warfare domain while simultaneously denying the same to the adversary and protecting critical command systems. Technologies are being developed using a multi-disciplinary approach that combines Radio Frequency electronics, digital signal processing, computer engineering, software engineering, machine learning and data science to support Naval Expeditionary warfighters operating with size, weight and power constrained equipment in Disrupted, Intermittent, Limited environments. Areas of applied research include distributed precision time, predictive software defined radio architectures, coordinated Cyber and Spectrum maneuver to mitigate detection and exploitation, tactical Cyber visualization, discovering and mapping networks in dense urban environments, contextual awareness and blind channel characterization.$$, 5201000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603640M_9999$$, $$0603640M$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional add projects not included in other efforts.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603645A_EV7$$, $$0603645A$$, $$EV7$$, $$Combat Vehicle Prototyping$$, 22645000, $$Armored System Modernization Advanced Development will continue the maturation of emerging ground combat vehicle capabilities to provide a bridge from S&T investment to application on a vehicle platform, informing requirements through User Evaluations, identification of capability gaps and reduction of integration risks. Maturing emerging technologies like those in Project Convergence Capstone (PCC) will enable ground combat platforms to meet the Army's strategy of fielding key Modernization efforts. The funding will support virtual and physical concept development, trade studies, technical and operational analyses to assess future concepts and designs. This would also include the support for survivability, lethality and other soldier defined system requirements. In addition, this funding will provide program management, expertise and a business process for the maturation and transition of emerging Science and Technology systems, system integration labs, technology demonstration efforts risk reduction, maturation, testing and assessment, and develop and integrate systems for Ground Combat Systems (GCS) platforms. The Robotic Combat Vehicle (RCV) Middle Tier Acquisition-Rapid Prototype (MTA-RP) program was funded through RDT&E appropriation via lines 643645EV7, 644107CF4 and 654641CF5. The total investment of the program prior to Army Transformation Initiative (ATI) Executive Order (EXORD) directing to cease development of RCV Hardware was $225M Base-Year 2025 (BY25) dollars. Future development efforts focused on Software Pathway (SWP), as well as autonomous and unmanned system initiatives, will be funded under RDT&E lines 644017FD9 and 655053FB3.$$, 22645000, NULL, NULL, NULL, NULL, 54456000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603651M_3022$$, $$0603651M$$, $$3022$$, $$Joint Non Lethal Weapons$$, 6561000, $$This project funds the research and development of next-generation Non-Lethal Weapons and includes performing analysis, technical development efforts, and modeling and simulation necessary to ensure optimum weaponization and use of these NLW. Investment areas include research and development of next-generation Non-Lethal Weapons (NLW) such as: non-lethal directed energy weapons (lasers, millimeter wave and high-power microwave) for counter-personnel and counter- materiel missions; non-lethal counter-personnel technologies (acoustic, optical, and human electro-muscular disruption technologies), and advanced non-lethal materials (including materials for vehicle/vessel stopping and counter-facility applications). Next-generation Non-Lethal Weapons systems focus on long-range localized Non- Lethal effects to identified threat individuals (or groups of individuals) and/or their threat weapons systems operating in complicated environments such as urban areas, crowds, buildings, vehicles, vessels, and also in close proximity to high-value civilian facilities.$$, 6561000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603654N_0377$$, $$0603654N$$, $$0377$$, $$JT Service Expl Ord Disp System$$, 10555000, $$This Program Element (PE) Project (0377) provides funding for the detailed design, development, risk mitigation, issue resolution, integrations, test, test equipment, simulations and technology insertion of specialized equipment, tools and assessment of accessories that expand range of military operations required to support DoD's only Joint Explosive Ordnance Disposal (EOD) programs. EOD exclusively executes world-wide missions for detection/location, identification, render-safe, recovery, field and laboratory evaluation, and disposal of hazards and unexploded ordnance (UXO) that is a threat to military operations, installations, personnel, or material. UXO includes foreign and domestic, both conventional and non- conventional, including Improvised Explosive Devices (IEDs) and devices using radiological and biological means with or without explosives. As defined in DOD Directive 5160.62E, assigns the Secretary of the Navy (SECNAV) the responsibility of Executive Agent for Explosive Ordnance Disposal (EOD) Technology and Training (T&T) to include the Joint Service Explosive Ordnance Disposal Research and Development Program. EOD programs are designed to reduce the EOD operator's exposure to explosive hazards or limit the risk to an acceptable level. EOD operations range from hand entry of explosive devices by EOD technicians to robotic actions and sensing capabilities that provide a safe distance to the explosive hazard at a greatly reduced cost to trained and experienced EOD operators.$$, 10555000, NULL, NULL, NULL, NULL, 391338000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603654N_1317$$, $$0603654N$$, $$1317$$, $$Expeditionary Diving Systems$$, 2090000, $$These resources support the development of equipment for the Navy's only comprehensive expeditionary detect to engage and exploitation Mine Countermeasures (MCM) capability. Specifically, it provides for development of Diver Safety/Life Support Equipment, Advanced Diver Integrated Sensors and Command Detonation Systems to support Navy Explosive Ordnance Disposal (EOD) underwater operations, expeditionary salvage, and Expeditionary MCM Company operations. The equipment must have inherently low acoustic and magnetic signatures in order to allow the EOD divers to safely detect, reacquire, approach, render-safe, recover, exploit, and dispose of underwater explosive threats to include sea mines, limpet mines, underwater improvised explosive devices, and unexploded ordnance.$$, 2090000, NULL, NULL, NULL, NULL, 134431000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603654N_3177$$, $$0603654N$$, $$3177$$, $$Joint Counter Radio-Controlled IED$$, 8685000, $$This project supports the defense objective of preventing terrorist, near peer, and peer operations against the US, allies, and partners within the Radio Frequency (RF) spectrum. It provides for the research and development of Electronic Warfare (EW) systems, equipment, procedures, and tactical aids for all military services to counter the threat posed by Radio-Controlled Improvised Explosive Devices (RCIEDs), small Unmanned Aricraft Systems (sUAS), and other RF spectrum operations to pervent disruption aross the spectrum of Joint military operations. It utilizes Joint requirements to provide a system of systems approach for a suite of equipment for mounted, dismounted, and fixed site operations, and develops equipment, procedures, and tactical aids to make rapid improvements to performance, supportability and affordability, while maintaining pace with the evolving RF global threats. Joint Counter RCIED Electronic Warfare (JCREW), Increment 1 Block 1 (I1B1) is the next generation of counter RCIED system of systems. JCREW includes fixed site, mounted and dismounted units, which provide countermeasures against the global RCIED threat and sUAS. The JCREW 2.0 technology insertion expands the capabilities to include Multi-Function RF capabilities as part of the Office of Naval Research (ONR) Ubiquitous Edge (UbE) FNC. Key system design features include significant performance increases over current legacy systems, a modular open architecture system design to facilitate improvements to address current and future advanced threats, robust information assurance and security, and is net-capable for improved Communications and Control (C2). JCREW I1B1 supports global deployment and sustainment for all combatant commands providing increased protection to Warfighter against the evolving worldwide RCIED threats. This project also provides for the research, development, and systems engineering of related CREW systems, providing capability improvements to fielded systems based on ever- changing RCIED threats against EOD technicians. And it provides for research, development, and systems engineering of electronic forensic capabilities related to the technical exploitation of asymmetric threats, including RCIEDs, unmanned systems, and underwater mines. The information generated is used to increase the performance of CREW and other counter-IED systems, as well as enable development of new countermeasure capabilities.$$, 8685000, NULL, NULL, NULL, NULL, 147211000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603654N_3447$$, $$0603654N$$, $$3447$$, $$Mine Expeditionary Response$$, 22327000, $$Funding supports the development of unmanned systems for the Navy's expeditionary unmanned underwater Explosive Ordnance Disposal (EOD) and Mine Countermeasures (MCM) capability. Specifically, it provides for development of affordable expeditionary remote stand-off underwater systems to support Navy Expeditionary forces including EOD, Mobile Diving and Salvage, Underwater Construction Teams (UCT), and Expeditionary Mine Countermeasures (ExMCM) mission operations. The equipment must be highly portable in order to support the Navy EOD technician to safely detect, approach, render safe, recover, exploit, and dispose of underwater explosive threats to include sea mines, limpet mines, maritime IEDs, and unexploded ordnance. Provides support for the Navy's high priority missions of Maritime Homeland Defense and MCM. This project directly supports Department of the Navy Strategic Roadmap for Unmanned Systems promulgated in March 2018 and addresses capability gaps defined by the Joint Service EOD (JSEOD) Initial Capabilities Document (ICD), Serial Number 671-75-05 of 3 June 2005, Joint Improvised Explosive Device (IED) Defeat Initial Capabilities Document (ICD) of 23 February 2006/JROCM 070-06, and the Expeditionary MCM ICD of June 2017. This project is being executed in accordance with approved CNO N9I Requirement #056-95-19, "Capability Development Document (CDD) for Maritime Expeditionary Standoff Response Family of Systems (MESR)," July 23, 2019. Additional efforts continue to execute the open competition process necessary to acquire and verify an EOD Response ROV capability focusing on user effectiveness and operational suitability to provide a ROV based target interdiction capability to address the capability gaps assessed in the previously conducted Expeditionary UUV Neutralization System (EUNS) AoA. This next generation capability is developed to decrease risk when reacquiring/investigating a potential threat (i.e. sea mine or maritime IED). In response to emergent maritime threat assessments ISO of INDOPAC Global Power Competition (GPC) scenarios, the MESR Program of Record (PoR) will initiate and conduct a Proof-of-Concept effort to demonstrate the potential ability to counter deep-water explosive threats as an ExMCM enabling capability ISO Joint Force Maneuver.$$, 22327000, NULL, NULL, NULL, NULL, 19676000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603662D8Z_663$$, $$0603662D8Z$$, $$663$$, $$Networked Communications Analysis$$, 19937000, $$Threats to communication systems emanate from a variety of sources, encompassing electromagnetic, cyber, and kinetic elements, among others. The central objective of research and development in network communications is to guide the Services, partners, and industry towards the creation of fully networked and integrated capabilities that exhibit interoperability, resilience, and security. This involves the strategic identification and acceleration of critical technologies, leading to their transition to both strategic and tactical forces. The ultimate goal is to ensure that C3 systems are trusted, accessible, and reliable anywhere, anytime, and under any conditions for tactical to strategic missions, thereby enhancing the lethality of the warfighting force. In the face of peer aggressors armed with advanced kinetic and non-kinetic threats, the imperative for trusted and reliable C3 becomes even more pronounced. This capability is viewed not only as a critical deterrence measure but also as essential for providing a decisive and lethal response when required, spanning tactical to strategic missions.$$, 19937000, NULL, NULL, NULL, NULL, 11622000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603669D8Z_829$$, $$0603669D8Z$$, $$829$$, $$Microelectronics Research Maturation$$, 0, $$This project focuses on the advanced technology development activities of the Commons including prototyping of devices or components using new microelectronics materials, processes, device designs, and architectural designs. It will also enable the establishment and operation of a Commons Consortium Manager (CM), which will provide efficient coordination and administration of regional innovation hubs. The CM is tasked with operating the Commons network, in alignment with the OUSD(R&E) Commons vision to ensure DoD access to and benefit from resulting technologies. The project also supports the establishment of the Commons Hubs, which will be networks of regional capabilities organized in collaboration with the CM to address DoD and commercial needs and requirements. The Hubs may include existing facilities augmented to enhance intrinsic specializations in emerging areas of microelectronics. Each Hub will concentrate on one of six technical areas including: Secure Edge Computing, 5G/6G Technology, Artificial Intelligence Hardware, Quantum Technology, Electromagnetic Warfare, and Commercial Leap Ahead Technologies. Core Facilities (i.e., fabs) are integral parts of the Hubs network that will provide key fabrication capabilities that are required to demonstrate prototypes with the volume and characteristics required to ensure reduced risk for full manufacturing production. Additionally, the project will directly support early workforce development activities through the Commons network. Activities may span K-12, undergraduate, graduate and continuing education and may include, for example, establishment of PhD internships and post-doc training at Hub facilities and internships with Hub members.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603673N_1160$$, $$0603673N$$, $$1160$$, $$Capable Manpower (CMP)$$, 5329000, $$The Capable Manpower Project focuses on the advanced technology development of new capabilities that leverage the underlying applied research investments in Program Element (PE) 0602750N, Future Naval Capabilities (FNC) Applied Research. These advanced technology investments align to acquisition programs of record. Efforts focus on all aspects of training, including accelerated learning, training environments, ready relevant training, and Live-Virtual-Constructive (LVC) training.$$, 5329000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603673N_1161$$, $$0603673N$$, $$1161$$, $$Expeditionary Maneuver Warfare$$, 18600000, $$The Expeditionary Maneuver Warfare (EMW) Project focuses on the advanced technology development of new capabilities that leverage the underlying applied research investments in PE 0602750N, Future Naval Capabilities (FNC) Applied Research. These advanced technology investments align to acquisition programs of record. The advanced technologies being developed under this Project include innovative naval mine, mine counter measures (MCM), mine delivery methods, low observable mine neutralization technologies, and other technologies supporting expeditionary maneuver warfare overall.$$, 18600000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603673N_2966$$, $$0603673N$$, $$2966$$, $$S&T Campaigns$$, 167853000, $$The S&T Campaigns Project contains the Budget Activity 3 portion of the Innovative Naval Prototype (INP Program). INP efforts attempt to solve problems and respond to mission requirements, by exploratory research for new ideas and breakthrough capabilities. INPs are Larger in scope, scale and risk and are selected for their high- payoff and potential to revolutionize operational concepts. Due to high technical risk, INPs often have long trial-and-error timeframes to work through challenges, but typically no more than three years between decision points. INP BA3 efforts require advanced technology development funding to bridge from Applied Research to working prototypes. INPs prove technological and capability potential, validate production feasibility, and acquisition potential. ONR demonstrates INPs with field experiments and or tests in a simulated environment as aligned to BA 03. Successful experimentation and demonstrations present the Department of the Navy with disruptive capabilities that may lead to a new acquisition programs. INPs are selected by senior leadership in the Department of the Navy.$$, 167853000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603673N_3346$$, $$0603673N$$, $$3346$$, $$Future Naval Capabilities Adv Tech$$, 0, $$The Future Naval Capabilities (FNC) Program exploits technology advances and responds quickly to Naval needs. As a result, future Budget Activity (BA) 3 investments supporting the FNC Program are made less than one year before commencing execution. Because FNCs start at higher Technology Readiness Levels (TRL), the typical duration of an FNC is 3-years. The FNC Program favors a high level of collaboration. Program Element R-2 Activities align to warfare areas where the FNC technologies will be integrated into acquisition programs of record. A complete accounting of FNC technologies and a full disposition of each technology development effort is provided annually to the Congressional oversight committees.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603673N_9999$$, $$0603673N$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional add projects not included in other efforts.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603680D8Z_350$$, $$0603680D8Z$$, $$350$$, $$Manufacturing Innovation Institutes$$, 138079000, $$This project supports nine Department of Defense (DoD) led Manufacturing Innovation Institutes (MIIs) within the national Manufacturing USA network. The MIIs are an essential component of the DoD ManTech mission and unique resource to address DoD challenges through public/private partnerships with members from industry, academia, and federal and state governments - including small and medium as well as large manufacturers - that address both commercial and defense manufacturing needs within specific, defense-relevant technology areas to mature manufacturing processes, build out a supporting ecosystem, and provide for manufacturing education and workforce development. The MIIs’ flexible business models and strong focus on enabling highly collaborative research and development (R&D) are catalyzing important new organizational relationships across government, industry, and academia. MIIs bring together both traditional defense and non-traditional sectors to accelerate key innovation cycles, expand U.S. industrial capability, and assist in creating resilient supply chains that will support innovative defense products. Each MII consortium attracts partner funding to match DoD investments at a one-to-one ratio (or greater) and some offer state-of-the-art pilot facilities. MIIs receive active participation and support from the military departments and defense agencies and their members. The nine MII technology domain focus areas are: (1) Additive Manufacturing Innovation; (2) Manufacturing Digital Innovation; (3) Materials Innovation; (4) Photonic Foundry and Packaging Innovation (6) Revolutionary Fabric and Textiles Innovation); (7) Medical Cell, Tissue, and Organ Manufacturing Innovation; (8) Robotic Automation Innovation; and (9) Bioindustrial Manufacturing Innovation. MII funding is focused on: • Developing and implementing education, training, and workforce recruitment courses, materials, and programs. • Developing innovative methodologies and practices for supply chain integration and introduction of new technologies into supply chains. • Engaging with small and mid-sized manufacturers, including women and minority-owned manufacturing enterprises, and larger-sized manufacturing firms. • Providing DoD programs of records with access to advanced manufacturing technologies for demonstration, prototyping, and transition to production through MII ecosystems. Each MII has a different model, with the following core tenets: • Each MII is a public/private partnership with representatives from industry, academia, state and local governments, and the DoD that co-invest in world-leading technologies and capabilities. • Each MII provides facilities to allow collaborative, precompetitive development of promising technologies and to promote the creation of stable and sustainable innovation ecosystems for advanced manufacturing. • The partnership forming the MII must commit non-federal resources that equal or exceed the federal commitment. • Each institute participates in the national Manufacturing USA network.$$, 138079000, NULL, NULL, NULL, NULL, 669627000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603680D8Z_351$$, $$0603680D8Z$$, $$351$$, $$Manufacturing Education and$$, 4911000, $$Manufacturing Education and Workforce Development (M-EWD) provides strategic leadership of advanced manufacturing talent development within the Defense Industrial Base (DIB) with three mission objectives: (1) invest in strategic education and workforce development capabilities, (2) expand the talent acquisition pool, (3) modernize manufacturing EWD by driving action within DIB-critical regional economies with a focus on Career & Technical Education (CTE). The M-EWD project drives regional action to modernize manufacturing CTE for the U.S. and organic DIB, invests in strategic education and workforce development capabilities, and expands strategic leadership of advanced manufacturing human capital development.$$, 4911000, NULL, NULL, NULL, NULL, 13806000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603680D8Z_549$$, $$0603680D8Z$$, $$549$$, $$Advanced Manufacturing$$, 225441000, $$Advanced manufacturing demonstrations of biomanufactured products for critical defense applications. This project addresses the necessary activities to rapidly mature biomanufactured products and establish the necessary production capacity.$$, 225441000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603680D8Z_680$$, $$0603680D8Z$$, $$680$$, $$Manufacturing Science and$$, 33199000, $$The Office of the Secretary Defense (OSD) Manufacturing Science and Technology Program (MSTP) concentrates on cross-cutting defense manufacturing needs that are beyond the ability of a single service to address. MSTP projects focus on cross-cutting defense manufacturing advancements and stimulate early development of manufacturing processes and enterprise business practices. The MSTP invests in broad technology initiatives within Advanced Electronics and Optics, Advanced Materials and Composites, Advanced and Emerging Manufacturing Processes, and Advanced Energetics Manufacturing.$$, 33199000, NULL, NULL, NULL, NULL, 288303000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603680D8Z_681$$, $$0603680D8Z$$, $$681$$, $$Technology Industrial Innovation Base$$, 6095000, $$Technology Industrial Base (TIB) provides support to technology leaders in identifying industrial innovation base needs; characterizing and assessing priority technology investments, identifying and mitigating issues and risks impacting the industrial innovation base, and exploiting opportunities to advance technology development, testing, and manufacturing. TIB efforts develop near- and long-term strategies and employ mechanisms to retain the U.S. advantage in current and emerging modernization technology priorities by addressing the capabilities of the industrial innovation base to develop, test, manufacture, and sustain them. One of TIB’s main objectives is to create balance between promotion of the industrial innovation base while protecting the technology from interference or exploitation by competitors. This balance will aid the Department’s advancing critical and emergent technologies ahead of competitor nations and actors while sustaining a healthy, resilient, and globally competitive industrial innovation base. This portfolio of activity extends efforts initiated in response to FY 2019 National Defense Authorization Act (NDAA) Section 1793.$$, 6095000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603680D8Z_961$$, $$0603680D8Z$$, $$961$$, $$Tech Trans & Comm Partnership$$, 1768000, $$Technology Transfer and Commercial Partnership’s (T2CP) mission is to provide policy, guidance and coordination of the DoD T2 Components’ programs which encompass more than 9,000 active public private partnerships with DoD laboratories. The T2 budget is used to implement the 15 USC 3702 and 3710, multiple 10 USC partnership authorities, and DoD Instructions 5535.08 and .11.$$, 1768000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603680F_635280$$, $$0603680F$$, $$635280$$, $$Manufacturing$$, 38891000, $$The Air Force Research Laboratory (AFRL) is focused on high-impact, multi-domain science & technology (S&T) solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. AFRL effectively synchronizes the Department of the Air Force (DAF) S&T enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing S&T. This program executes technical efforts to develop and maintain an affordable and reliable industrial base and manufacturing capability responsive to Department of the Air Force warfighter needs. The program develops and improves manufacturing technologies and processes to reduce transition risk, enable cost reduction, improve component and system quality, increase readiness and affordable mission availability, enhance industrial capability, and promote transformation through the industrial base. Value stream modifications and manufacturing throughput improvements are implemented to shorten weapon system cycle times during design, development, production, and sustainment. Cost savings are realized through early engagement with stakeholders to promote producible designs, ensuring the industrial base will be ready to manufacture at the needed quantities. Manufacturing technologies objectives are conducted through industrial partnerships that enable targeted investment of manufacturing technologies and reduce risk in the industrial supply chain for existing weapon system upgrades and new warfighter systems. Efforts in the program have been coordinated through the Department of Defense Science and Technology Executive Committee process to harmonize efforts and eliminate duplication. Funds in this PE may be used to investigate specified technology advancements in air, space and/or cyber domains. This program includes funding for the requisite DAF Science & Engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to develop, manage, and deliver science & technology capabilities. The use of program funds in this program element is in conjunction with the civilian pay expenses budgeted in the following program elements: 1206601SF, 0601102F, 0602020F, 0602102F, 0602202F, 0602203F, 0602204F, 0602298F, 0602336F, 0602602F, 0602605F, and 0602788F. In FY 2026, $8.996 million is budgeted in this program for 45 direct Full-Time Equivalent (FTE) civilians. The Air Force Research Laboratory (AFRL) utilizes 10 USC 4091, "Authorities for certain positions at science and technology reinvention laboratories” to manage the workforce strength, structure, positions, and compensation. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology capabilities. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603680F / Manufacturing Technology Program Technology Development (ATD) This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment.$$, 38891000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603680N_1050$$, $$0603680N$$, $$1050$$, $$Manufacturing Tech$$, 63903000, $$The Office of Naval Research's (ONR) mission is to foster scientific research for the advancement of naval power. This work does not stop at the laboratory. Delivery of breakthrough capability often requires new technologies in manufacturing and supply chains of national security. The Manufacturing Technology (ManTech) Program is intended to improve the productivity and responsiveness of the U.S. defense industrial base by funding the development, optimization, and transition of enabling manufacturing technologies to key naval suppliers. In general, investments transition emerging Science and Technology (S&T) results to acquisition programs; improve industrial capabilities in production, maintenance, repair and industrial base responsiveness; and advance manufacturing technology to reduce cost, improve performance, and responsiveness. Currently, the ManTech Program is focused on affordability improvements for specific key acquisition platforms as defined in the Navy ManTech Investment Strategy. Key platforms currently targeted include: VIRGINIA Class submarine (VCS)/COLUMBIA Class submarine (CLB), DDG 51 Class destroyer, CVN 78 Class carrier, FFG 62 Class frigate, PEO IWS (in support of NAVSEA acquisition platforms), and F-35 Lightning II aircraft. Through its affordability efforts, ManTech helps these Navy programs achieve their respective affordability goals by transitioning developed manufacturing technology which, when implemented, results in needed cost reduction or cost avoidance. In addition to addressing affordability for key naval platforms, ManTech also addresses manufacturing technology to aid in capability acceleration to the fleet.$$, 63903000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603680N_9999$$, $$0603680N$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional add projects not included in other efforts.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603680S_IBA$$, $$0603680S$$, $$IBA$$, $$Industrial Base & Aging Weapon$$, 41533000, $$Industrial Base and Aging Weapon System Support (IBA) Line of Effort seeks to implement innovative and proactive technology solutions to ensure a robust, reliable industrial base that provides affordable and previously hard-to-procure critical parts for DOD weapon systems through the following objectives: 1. Viable and Responsive Industrial Base: maximize Defense Industrial Base capability and capacity and improve availability, quality, and affordability to support the Warfighter. 2. Obsolescence Solutions: establish a trusted manufacturing capability for qualified microcircuits to support DOD weapon system lifecycles. 3. Advanced Manufacturing: leverage advanced manufacturing capabilities to introduce and integrate additive and advanced manufacturing concepts into the DOD supply chain. The portfolios within the IBA LOE include food-service supply chain solutions (Subsistence Network), Castings (Procurement Readiness Optimization—Advanced Casting Technology), Forgings (Procurement Readiness Optimization—Forging Advanced System Technology), Batteries (Battery Network), Additive Manufacturing (AM), Advanced Microcircuit Emulation (AME) and Strategic Materials (SM). The Subsistence Network (SUBNET) program focuses on developing and promoting manufacturing solutions in the subsistence supply chain for the Department of Defense and the Defense Logistics Agency. The program's expanded areas of interest include combat rations, food equipment, field and garrison feeding solutions, supply chain infrastructure and footprint, food innovations, food safety and food defense, nutrition and health, storage and packing solutions, surge and sustainment support, and water security. SUBNET forms a community of practice with the Military Services, U.S. Department of Agriculture, U.S. Army Combat Capabilities Development Command Soldier Center, Industry, Academia, and other federal partners to conduct RDT&E in the Subsistence Supply Chain. The SUBNET goals are to advance and innovate logistics processes and capitalize on industrial base’s latest technological capabilities and capacity through RDT&E. The desired outcomes include reduced costs, increased efficiency and transparency, modernized processes, enhanced quality and safety, and greater ability to meet customer and operational surge demands. The Casting (CAST) program works to ensure a stable, reliable, and competitive domestic casting industrial base supporting the weapon system needs of the Department of Defense (DOD) and the DLA. The casting program works with industry, universities, and the Casting Industry Associations to identify projects that improve the materials, processes and business practices of the nation’s foundry industry. The program aligns projects with strategic issues and identified focus areas within the DLA and DOD. Guidance for these projects comes from the DLA Strategic Plan and input from the casting industry. Weapon system spare parts managed by DLA that contain castings are responsible for a disproportionate share of DLA’s backorders or unfilled orders (UFOs). Cast parts are about two percent of National Stock Numbered Class IX parts but represent about five percent of all backorders, and when only the oldest backorders are considered, up to 10 percent$$, 41533000, NULL, NULL, NULL, NULL, 233327000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603680S_TDM$$, $$0603680S$$, $$TDM$$, $$3D Tech Data Modernization / Model$$, 9077000, $$The three-dimensional (3D) Technical Data Modernization (TDM) / Model-Based Enterprise (MBE) includes efforts to improve and facilitate the exchange of engineering and logistics information among DLA, the Military Services, industry partners, and customers. This LOE includes the Military Unique Sustainment Technology (MUST), the Defense Logistics Information Research (DLIR), and the Emerging Requirements (EMR) portfolios. A primary focus of this LOE is to capitalize on the emerging “Model Based Enterprise” paradigm and the semantic web as an enabler to a logistics system that is smart and connected up and down the supply chain and across all DLA Customers and suppliers. A major focus is to transform DoD engineering data from two-dimensional paper-based products to three-dimensional computer-based models, and to develop processes to move from “electronic paper” (i.e. PDF files) to technical data files that can interface directly with industries’ engineering systems. The benefits include shorter product introduction cycles, lower set up-costs for parts production and more economical small batch production. Objectives for this LOE includes: 1. Transform technical data into modern, machine-usable, neutral formats: support DoD’s digital modernization efforts and provide significant readiness improvements. 2. Create a model-enabled knowledge base shared among DLA, the Military Services and industry: streamline the delivery of accurate requirements and high-quality material and end-items throughout the supply chain. 3. Quickly develop emergent and breakthrough technologies into military significant capabilities. The Military Unique Sustainment Technology (MUST) program addresses GAO Report 12-707 recommendations for DoD to establish a “knowledge-based approach” to define, communicate, and collaborate on military unique Combat Uniforms and Individual Equipment (CUIE) requirements. DLA has the responsibility to manage and maintain the technical requirements among the Services and the Defense Industrial Base. Currently there is no common environment for collaborating on new requirements among the stakeholders. The strategic objective of the DLA MUST program is to identify, develop, and adopt technologies that can significantly improve the joint process from transitioning new item development to DLA sustainment and operations. The Program focuses on technologies that will transform the military CUIE supply chain from an “electronic paper” (i.e. PDF/MS Word) based manual environment, into a knowledge-based model driven environment. This approach will result in seamlessly communicating military unique technical requirements throughout the end-to-end supply chain, leading toward a Model Based Enterprise. The Defense Logistics Information Research (DLIR) program utilizes digital technologies to enhance the quality, security, and interoperability of logistics data, transforming DLA's business processes and supporting the Defense Industrial Base (DIB). A key focus of DLIR is assisting Micro, Small, and Midsize Manufacturers (MSMMs) in adopting Industry 4.0 practices and developing the workforce within the DIB.$$, 9077000, NULL, NULL, NULL, NULL, 174984000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603712S_LOI$$, $$0603712S$$, $$LOI$$, $$Logistics Operations Innovation$$, 7876000, $$The Logistics Operations Innovation Line of Effort (LOE) seeks to improve DLA supply chain performance and security through the integration of advanced technology and innovative processes into daily business operations. Research in these areas drive improvements to internal costs, reduce award delays, and improve material availability, supply chain security, and logistical planning. This will be accomplished using artificial intelligence/machine learning, block-chain technology, and research of emerging commercial best practices and technologies. In addition, out of cycle emergent technologies across all DLA supply chains and logistics processes are resourced in a timely manner without disrupting ongoing projects by funds reallocation. The objectives for this LOE include: 1. Secure supply chains: Improvements to the DoD Class III Bulk Fuel Petroleum, Oil and Lubricants supply system. - New or improved analytical methods to determine product quality or identify anomalies - Renewable energy technologies for military and government use - Enhanced military adoption and use of fuel products derived from petroleum alternatives 2. Technical Solutions for anti-counterfeiting detection: innovative solutions to prevent counterfeit parts in the logistical supply chain. - Reduced supply chain vulnerabilities through low-cost anti-counterfeiting solutions 3. Integrated logistics and acquisition information that yields cost savings and shortens lead times: - An enterprise market intelligence capability to optimize spending strategies and business outcomes - An enterprise market intelligence capability to optimize spending strategies and business outcomes - An automated contract quality capability that will result in a higher percentage of contracts executable upon award and subsequently a reduction of production lead time - A smart contracting capability using blockchain technology to automatically execute digital contracts when predetermined terms and conditions are met The Logistics Operations Innovation LOE includes R&D efforts to develop new products and services for DLA customers in three programs: ‒ The Energy Readiness Program (ERP) roadmap helps to achieve the operational energy strategy goals of increasing sources of supply, developing and implementing alternative fuels under the ERP. ‒ The Acquisition Modernization Technology Research (AMTR) program assesses acquisition and procurement processes, uncovers and prioritizes areas that would benefit from IT modernization or advanced technologies, evaluates technical requirements, and pursues future research efforts for DLA.$$, 7876000, NULL, NULL, NULL, NULL, 54300000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603712S_PAM$$, $$0603712S$$, $$PAM$$, $$Predictive Analytics / Modeling &$$, 4013000, $$The Predictive Analytics, Modeling & Simulation Line of Effort (PAM) includes R&D efforts within the Logistics Technology Research (LTR) program. The focus of LTR is to develop predictive analytic solutions by applying AI/ML algorithms to data obtained from DLA and external sources which can help solve high-impact problems, improve business operations, and provide actionable strategies for optimized business decisions. Through the development of decision support tools, such as modeling, simulation, and other analytics to improve operational strategy decision-making, forecasting, and procurement, DLA will achieve more effective and efficient responses to emerging market and customer requirements. The objectives for this LOE include: 1. Leverage technological solutions for data analytics and integration for demand projections and supply chain risk management. 2. Data analytics integration for DLA, the military services and industry: allows businesses and vendors to aggregate data, analyze it, and transform it into useful information. 3. Explore emergent technologies in quantum computing and edge computing to enable advanced analytics.$$, 4013000, NULL, NULL, NULL, NULL, 34696000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603712S_SWM$$, $$0603712S$$, $$SWM$$, $$Smart-Warehouse Modernization$$, 7751000, $$The Smart Warehouse Modernization Line of Effort will assess and test cyber-secure smart-warehouse technologies to transform and modernize distribution and disposition operations. The objectives for this LOE include: 1. Increase productivity and efficiency through interconnected technologies and automation such as enhanced inventory management, materiel distribution, and asset visibility 2. Provide enhanced and cyber-secure operations The Strategic Distribution & Disposition (SDD) Program collaborates with DLA Distribution and Disposition Services to identify legacy capabilities that are inadequate for emerging worldwide distribution and disposition requirements. A key objective of the SDD Program is to anticipate, assess, and meet the current and future Warfighter requirements by leveraging R&D to infuse innovation into solutions. Long-term objectives include mitigating the DOD Supply Chain Management high risk issues identified by the Government Accountability Office (GAO), 2018 (Inventory Management, Material Distribution and Asset Visibility).$$, 7751000, NULL, NULL, NULL, NULL, 32493000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603713N_0099$$, $$0603713N$$, $$0099$$, $$Deep Submergence Bio Med Dev$$, 3426000, $$This project: 1) Develops advanced biomedical and bioengineering technology for medical and life support enhancement to decrease submariner deaths and permanent injury in a disabled submarine (DISSUB) and during submarine escape and rescue; 2) Conducts research for diver health, safety, and effectiveness to increase understanding of human performance and enhanced diver stress management and survivability in high stress environments such as in cold/warm water and at altitude. This project also validates and improves the accuracy of assumptions associated with equipment testing and certification, diving procedures, and diver biomedical physiology. Deliverables for DISSUB include: medical guidance/procedures increasing submariner survivability for submarine escape and rescue (including new Submarine Rescue Diving and Recompression System (SRDRS)), life support parameters, medical procedures for life support; exposure and mitigation guidance for atmospheric contaminants, high levels of oxygen and/or carbon dioxide; prevention and treatment of decompression sickness and pulmonary oxygen toxicity; and senior survivor expert decision system. Deliverables for diver health and safety include: decompression guidance in extreme environment diving with various breathing mixtures, temperatures, durations, and altitudes; exposure guidance for oxygen breathing; diver performance guidance based on physiological effects of diving; enhanced underwater swimming efficiency; enhanced diver thermal protection; collection of operational diving depth/time profiles to predict decompression risk, and exposure and mitigation guidance for divers experiencing underwater continuous noise, impulse noise, or underwater blast. Requirements: OPNAVINST 3150.27D, Navy Diving Policy and Joint Military Diving Technology and Training Program, 01 Mar 2021 Navy Salvage and Navy Diving Capabilities-Based Assessment (CBA) Report, 19 Dec 2013 NAPDD #587-873, Deep Submergence Biomedical Development, 23 Nov 1999 NAVSEA Instruction 3900.10A, Management of the Deep Submergence Biomedical Research and Development Program, 6 Nov 2018 Navy Diving Initial Capabilities Document (ICD)$$, 3426000, NULL, NULL, NULL, NULL, 55052000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603713N_0394$$, $$0603713N$$, $$0394$$, $$Shallow Depth Diving EQ$$, 6221000, $$(Diving - N97) This project develops systems to support submarine escape and rescue missions, and conventional diver operations. Diver operations include ship husbandry, salvage/recovery, and submarine rescue operations to support national, as well as Navy, needs around the world. Modern certifiable diving systems that ensure diver safety and allow maximum work efficiency will replace currently antiquated systems. R&D will be performed in the areas of diver tools to improve work efficiency, tracking and navigation, visual enhancement, contaminated water diving, diver environmental protection, and recompression chamber technology. (Submarine Escape and Rescue - N97) The modernization of Submarine Rescue System (SRS) is required to address known reliability and obsolescence issues and support the planned minimum 15 year system service life extension prior to SRS's end of life and inoperability. (Diving - N95) This project develops systems to support Naval Expeditionary Combat Command Diving. Operations include salvage/recovery and underwater construction to support national, as well as Navy, needs around the world. Modern certifiable diving systems that ensure diver safety and allow maximum work efficiency will replace currently antiquated systems. R&D will be performed in the areas of diver tools to improve work efficiency, tracking and navigation, visual enhancement, contaminated water diving, diver environmental protection and recompression chamber technology. Requirements: Operational Requirements Document, Revision 2 for Submarine Rescue Diving and Recompression System (SRDRS) Serial 694-87-06 dtd 6 June 2006 COMSUBLANT/COMSUBPAC OPORD 2137 (Submarine Rescue) dtd 5 Aug 2014 Mission Needs Statement, M016402-92 Survivability, OPNAV N87 ltr Serial N87/5U659719 dtd 30 Jan 1995$$, 6221000, NULL, NULL, NULL, NULL, 35579000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603716D8Z_470$$, $$0603716D8Z$$, $$470$$, $$Strategic Environmental Research and$$, 58092000, $$The Strategic Environmental Research and Development Program (SERDP) invests in basic and applied research to secure Department of Defense installations, while its sister program, the Environmental Security Technology Certification Program (ESTCP), demonstrates and validates these technologies in operational settings. SERDP addresses cross-Service requirements and pursues solutions to installation challenges, strengthening America's defense posture and military readiness. By tackling critical issues affecting military bases and training grounds, SERDP develops innovative approaches that enhance resilience, sustainability, and operational capability. Through partnerships with researchers across DoD, federal agencies, academia, and industry, SERDP identifies promising technologies that transition to ESTCP for field demonstration. These innovations reduce costs, risks, and time required to resolve installation challenges while advancing combat readiness. SERDP's investments ensure military installations can withstand operational threats and environmental hazards. By focusing on practical solutions that enhance warfighting capabilities, SERDP helps maintain installations that are resilient, mission-focused, and prepared to support forces as they train to deter adversaries and defend the nation.$$, 58092000, NULL, NULL, NULL, NULL, 819386000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603720S_004$$, $$0603720S$$, $$004$$, $$Defense MicroElectronics Activity$$, 135016000, $$DMEA maintains an in-house ability to quickly develop and deliver timely, cost-effective, technically appropriate solutions to sustain weapon systems, to modernize their capabilities, increase their lethality, address new threats, and meet operational demands. These funds also support DMEA’s ability to partner with industry, other Government agencies, and academia to enable streamlined access to a variety of microelectronics technologies and engineering services. These funds enable DMEA to provide increasingly rare government microelectronics design, fabrication, and test expertise to DoD programs. DMEA’s knowledge of varying military requirements across a broad and diverse range of combatant environments and missions—along with its unique technical perspective—allows it to develop, manage and deliver novel, decisive, quick-turn microelectronics solutions for defense, intelligence, special operations, cyber and combat missions. These funds allow DMEA to maintain and enhance critical, microelectronics design, aggregation, fabrication, post-processing, assembly, hardware assurance and analysis capabilities to ensure that the Department is provided with solutions that enable or maintain the warfighter’s technological superiority over potential adversaries. These solutions use high mix, low volume, unique microelectronics that are endemic to military requirements but are not commercially available. In addition, funding provides for the development and sustainment support necessary to ensure availability of microelectronics technologies in accordance the Department's needs and facilitates the Trusted Supplier Accreditation program required by DoDI 5200.44. DMEA will continue to manage and operate the Trusted Access Program Office (TAPO) to facilitate DoD and US Government access to state-of-the-art microelectronics manufacturers, including Trusted Foundries, for secure production runs and manufacturing and production planning for wafers, dies, and modules. DMEA will also continue to accredit trusted suppliers and leverage its designation by Secretary Austin as a Center for Industrial Technical Excellence (CITE) and continue to support small runs of DoD-critical microelectronics and semiconductors both inside and outside DoD. The CITE designation also delegates the authority to DMEA to establish Public Private Partnerships (PPP).The Department, other US Agencies, and the Intelligence Community require uninterrupted access to semiconductor processes to produce custom integrated circuits designed specifically for military purposes. DMEA, via the TAPO, partners with industry to provide the required solutions, and the necessary access to commercial SOTA microelectronics semiconductor capabilities to meet confidentiality, integrity, availability, performance and delivery needs. A critical element required to enable continued success is DMEA’s protection of the industry partners’ valuable Intellectual Property (IP). DMEA is an agile, Government- owned-and-operated organization, providing the structure and confidence necessary to assure them that commercial IP is protected from potential competitors. This strategic and cooperative industry partnership approach allows DMEA to use industry-developed IP by acquiring, installing, and applying them toward meeting the immediate and long-term needs of the Department. This unique capability is essential to all major weapon systems, combat operations, and support needs. As such, DMEA serves the Department, other US Agencies, industry and Allied nations.$$, 135016000, NULL, NULL, NULL, NULL, 1652240000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603721N_0401$$, $$0603721N$$, $$0401$$, $$Shipboard Waste Mgmt$$, 10334000, $$Navy ships and submarines operate and visit U.S. and international waters and ports where shipboard waste management restrictions impact the movements and operations of Navy vessels. The Navy must be able to conduct its national security mission in compliance with applicable waste management requirements in U.S. and international waters without compromising performance, safety, or health, while simultaneously minimizing the cost of compliance. PE 0603721N Project 0401, Shipboard Waste Management, supports efforts that enable Navy ships and submarines to comply with laws, regulations, and policies in six major areas: (1) Technical Authority, (2) Liquid Wastes, (3) Hazardous Material Control and Management, (4) Ballast Water Management, (5) Solid Waste Management, and (6) Copper-Free and Low Copper Antifouling. The Shipboard Waste Management Program supports two designated Technical Warrant Holders for Waste Systems & Materials Engineering, with responsibility and accountability for ensuring that ships and submarines are designed and upgraded, and can be operated, in compliance with existing and anticipated environmental requirements while minimizing total ownership cost and manning. This responsibility encompasses legacy platforms and new vessel designs, as well as fleet operations exercises, and training. Major performers are Naval Surface Warfare Centers at Carderock, MD, and Philadelphia, PA, where engineering agents execute research and development responsibilities for Navy surface ship and submarine environmental engineering, which includes reviewing/updating various military specifications, ship specifications, DoD and Chief of Naval Operations documentations, and maintaining the technology identification and assessment process.$$, 10334000, NULL, NULL, NULL, NULL, 384673000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603721N_0817$$, $$0603721N$$, $$0817$$, $$Environmental Sustainability$$, 5882000, $$The vision outlined in "A Design for Maintaining Maritime Superiority, Version 2.0" (December 2017) and "2018 National Defense Strategy of the United States of America" is for our Navy to become more lethal, resilient and a rapidly innovating joint force. We must maintain a fleet that is trained ready to operate and fight decisively. Today's reality requires training and operating within environmental constraints (national and international laws and agreements) and searching for alternatives to comply with and alleviate those constraints. Moreover, as we develop new systems and technologies in support of the National Defense Strategy, the Navy must anticipate and address potential environmental constraints which could in the future adversely impact our ability to protect and sustain our forces at home and abroad. This program identifies pervasive Navy shore side environmental requirements and develops and validates information, new processes, and technologies that address requirements that pose significant impact on Naval shore activities in complying with environmental laws, regulations, orders, and policies. The goal of the program is to maximize opportunities for significant cost savings while minimizing personnel liabilities, operational costs, and regulatory oversight and preserving or enhancing the ability of Naval shore activities to accomplish their required missions and functions in support of the Navy's transformational strategy. Environmental Enabling Capabilities -2 (EEC-2) MAXIMIZE TRAINING AND TESTING RANGE REQUIREMENTS WITHIN ENVIRONMENTAL CONSTRAINTS: This capability addresses environmental impacts and restrictions at Navy land and sea ranges, including munitions testing and manufacturing, to ensure Navy ranges are available to conduct required training and testing operations for the Fleet. Investments in EEC-2 provide validated knowledge, models, and processes to mitigate environmental impacts, restrictions, and costs at Navy training and test ranges to maximize the availability and utilization of the ranges. The results support operational readiness by providing the tools and technologies necessary for sustaining and managing Navy land and sea ranges related to unexploded ordnance (UXO) and munitions, encroachment, air quality, airborne noise, water quality, and wetlands. Capabilities gained include the ability to assess and determine the risks from underwater UXO, the evaluation and prioritization of ordnance contaminated sites for evaluation in environmental programs and the implementation of range specific best management practices by evaluating and modeling available process, procedures, and technologies. Environmental Enabling Capabilities-3 (EEC-3) PLATFORM MAINTENANCE AND REPAIR WITH MINIMAL ENVIRONMENTAL FOOTPRINT: This capability focuses on minimizing or eliminating environmental impact related to Navy and Marine Corps weapon system repair and maintenance operations. Investments in EEC-3 provide valid knowledge, models, processes, and technologies to minimize regulated emissions, discharges and hazardous material usage during the repair and maintenance of ships, submarines, and surface/sub-surface vehicles and aircraft and air vehicles. The program supports Fleet operational readiness and Navy acquisition communities by investing in information to understand emerging environmental requirements and to develop innovative processes and technologies that result in savings while reducing the fleet environmental constraints related to platform maintenance. Capabilities and benefits gained include, but are not limited to, the reduction in the usage$$, 5882000, NULL, NULL, NULL, NULL, 79401000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603721N_9204$$, $$0603721N$$, $$9204$$, $$Marine Mammal Research$$, 6613000, $$The Navy has been and will continue to be subject to litigation with regard to the potential injuring, killing or biologically significant disturbance of marine animals by the use of intense underwater sound. Since Fleet operation and training areas coincide with known or probable habitats, migration routes, or breeding areas of marine mammals and other protected marine species, the possibility exists that such incidents are likely to continue in the future. The increasing public interest and pressure has resulted in escalating Fleet costs. For example, Fleet and SYSCOM development activities have been interrupted; modified, or altogether cancelled and environmental regulations have, among other things, required new ship construction shock trials to obtain Federal permits and conduct extensive environmental planning that can take several years to complete. The incorporation of mitigation measures in Fleet training operations to minimize the potential adverse effects on protected marine animals can significantly reduce the realism of these operations. In addition, the testing, evaluation, and deployment of new sonar detection and monitoring systems that use active acoustics are under intense public scrutiny for their potential adverse effects on whales and other marine mammals. Navy needs scientific evidence to substantiate its claims of limited or inconsequential adverse effects to marine life from operations. This project primarily focuses on the development of planning, monitoring, and mitigating tools to aid the Fleet in minimizing contact with and the potential harassment of protected marine animals during operations, exercises, training, and undersea surveillance and weapons testing. These new capabilities will encompass historical and newly acquired data and analytical models that together can predict marine animal habitats (where they are likely to be), and their natural and expected behavior (diving patterns, prey localization, calling activity, etc.). This project consists of three major areas that will help ensure Navy compliance with the Marine Mammal Protection Act (MMPA) and Endangered Species Act (ESA). These areas are (1) Marine Ecology and Population Dynamics - determine the likelihood of the presence of marine mammals or other protected species by developing habitat and ecological models. Refine marine animal survey techniques to optimize the accuracy of abundance estimates in small ocean regions of Navy interest. (2) Criteria, Thresholds, and Mitigation - Establish criteria and thresholds from which to measure potential impact on marine mammals and other marine species from Navy training operations. Determine the effectiveness and usefulness of various mitigation measures in relation to the potential impact of Navy operations on marine mammals; and (3) Mitigation Methodologies - Determine the observation, detection and classification measures required to develop effective monitoring and mitigation procedures for Fleet and SYSCOM use. Focus on improving marine animal monitoring capabilities over current methods by developing new technologies or improving existing technologies that improve monitoring and mitigation effectiveness, reduce cost and minimize impacts on readiness activities.$$, 6613000, NULL, NULL, NULL, NULL, 53685000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603724N_0829$$, $$0603724N$$, $$0829$$, $$Afloat Energy Technology$$, 11447000, $$This project is designed to enhance lethality, resilience, reach, and sustainment of warfare systems through more effective generation, use and distribution of energy on existing and future surface fleet assets, including Unmanned Surface Vessels (USVs), by developing and transitioning energy and maintenance improvements. This project, managed through NAVSEA 05T, identifies, promising energy related technologies through involvement with Fleet representatives, Life-Cycle Managers (LCMs), NAVSEA Technical Warrant Holders, In-Service Engineering Agents (ISEAs), the Navy Shipbuilding Research Program (NSRP), PEOs, Industry, and Academia. The project directly supports Department of Navy goals for agility, resilient force posture, and innovation by maximizing energy to increase operational capability (e.g., extend range, increase time on station, reduce energy demand on fuel logistics forces, enable high power combat systems). Potential technology areas include Power Generation and Storage (PG&S), Hull Hydrodynamics (HH), Underwater Hull Husbandry (UHH), Heating, Ventilation & Air Conditioning (HVAC) Systems, Thermal Management (TM), Main Propulsion Systems (MP), Electrical Systems (EL), Auxiliary Systems (AUX) and Energy Monitoring, Planning, and Assessment (EMP&A). Promising energy related projects that improve the effective use, conversion, storage, distribution, and control of energy to enable the integration with future weapons and sensors onto platforms are proposed each FY for evaluation. Projects are selected based on technical review and business case analysis. Not all proposals are pursued, and funding changes between functional categories or fiscal years may occur based on fleet needs, technology maturity level, ship schedule changes, or other factors.$$, 11447000, NULL, NULL, NULL, NULL, 67860000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603724N_0838$$, $$0603724N$$, $$0838$$, $$Mobility Fuels (ADV)$$, 8043000, $$This program represents the Navy's only RDTE investment designed to maintain and enhance its capability to operate as a "smart" customer for aviation and ship tactical fuels that are an operationally critical, single point of failure, $4.0+ billion per year consumable requiring worldwide availability and interoperability. Recent field problems have demonstrated the adverse effects that fuel-related problems can have on ship and aircraft performance, durability, and readiness. The potential risk and adverse operational impacts from fuel-related problems over the next decade, given the evolving production technologies, changing feedstocks, more stringent environmental regulations and the introduction of new operational requirements and platforms will continue to increase. This program provides data and enables technology through laboratory, component, fuel system, engine, and platform tests. These evaluations relate the effects of changes in the Navy fuel properties and chemistry to the performance and durability of Naval ship, aircraft, ground and fuel distribution systems. The information is required by technical authorities and decision makers to: (a) assure interoperability with fuel procured from commercial/ international specifications, (b) determine the extent to which unnecessarily restrictive military specification requirements can be relaxed to reduce cost and increase availability worldwide, (c) provide guidance to fleet operators for the safe use of off-specification fuels or emerging CONOPS requiring the use of non-traditional fuels, (d) assure operational interoperability with evolving changes in fuel production technology, feedstocks, environmental regulations and tactical system demands, (e) improve the capability and reduce the cost of field fuel quality surveillance, and (f) facilitate rapid identification and resolution of field identified fuel deficiencies.$$, 8043000, NULL, NULL, NULL, NULL, 139087000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603724N_0928$$, $$0603724N$$, $$0928$$, $$Shore Energy Technology$$, 2104000, $$This Energy RDT&E Project will model, research, develop, test, evaluate, demonstrate and validate the technical and lifecycle cost viability of installation energy technologies with the goal of energy security, efficiency, surety, and reliability. Efforts will be coordinated across DOD and with other agencies as appropriate. Research areas include new and distributed energy resources, grid and microgrid management technologies including cyber security of controls, installation energy efficiency technologies (lighting, HVAC, building envelope, etc.), energy water nexus, all for use at Naval installations with potential for widespread applicability. Reducing installation energy demand, increasing efficiency and improved installation energy surety improves readiness and enables fleet lethality.$$, 2104000, NULL, NULL, NULL, NULL, 62898000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603724N_0996$$, $$0603724N$$, $$0996$$, $$Aircraft Energy Technology$$, 16909000, $$Naval aviation must operate independently worldwide often with limited logistics support. Additionally, legacy and emerging aircraft continually add capabilities to enhance their lethality and survivability. Improving an aircraft's utilization and management of energy has a direct relationship to enhanced combat capability to meet the challenges of emerging threats. This program engages technical experts from across Naval aviation, industry, and academia to identify best practices and technologies for development, testing and validation to determine technical viability and assess benefit to mission capability.$$, 16909000, NULL, NULL, NULL, NULL, 206254000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603724N_2566$$, $$0603724N$$, $$2566$$, $$Battery Development and Safety$$, 8074000, $$1) Provide an advanced battery database with standard battery families for program offices to use to allow for selection of batteries early in the design process increasing the likelihood of design and fielding success, 2) leverage the battery database to begin common battery design efforts to save cost, 3) establish common battery standards and design requirements (e.g., propagation resistant designs, standard battery monitoring and casualty detection systems, etc.) to make advanced batteries safer and therefore deployable, 4) develop and test standard battery storage/container systems that can safely house batteries and withstand catastrophic failure (thermal runaway) of the batteries within the container while minimizing damage to surrounding equipment and platforms, 5) streamline the battery safety certification process especially for high energy storage magazines and other large battery designs (lasers) to allow battery based weapon systems to be fielded in time to support strategic needs, 6) develop hazard mitigation technologies to support rapid safe deployment of advanced batteries to support weapon systems, 7) generate analytics that characterize the Department's current and projected energy/advanced battery needs, 8) establish the Navy's contribution to DoD and cross-service advanced battery supply chain efforts.$$, 8074000, NULL, NULL, NULL, NULL, 16509000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603724N_3270$$, $$0603724N$$, $$3270$$, $$Sec. 2912 Operational Energy$$, 0, $$The Navy needs to extend operational reach of intelligence, surveillance, reconnaissance and target platforms to meet current and emerging threats. This program expands and demonstrates the capabilities of the path optimization software to enhance UAS operators' ability to find the energy optimal path through weather, terrain and airspace constraints to extend range and time on station.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603724N_3720$$, $$0603724N$$, $$3720$$, $$Applied Biomedical Technology$$, 0, $$The Navy needs to extend operational reach of intelligence, surveillance, reconnaissance and target platforms to meet current and emerging threats. This program expands and demonstrates the capabilities of the path optimization software to enhance UAS operators ability to find the energy optimal path through weather, terrain and airspace constraints to extend range and time on station.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603724N_9999$$, $$0603724N$$, $$9999$$, $$Congressional Adds$$, 0, $$Project C545: Marine energy systems for sensors and microgrids. Project C998: Wave energy converters for the Navy energy program. Project C391: Cargo drone advanced batteries. The Marine Energy Development (MED) program supports research, development, test and evaluation (RDT&E) of marine energy technologies for sustained investment and advancement of a variety of marine energy systems. This program, managed through the Naval Facilities Engineering Command, supports research, prototyping, and testing for future naval capabilities related to powering maritime security systems, at-sea persistent surveillance, communications systems, at-sea vehicle charging, and shore installations. The marine energy projects, within this program, are designed to accelerate the development and transition of novel energy technologies, such a marine energy converters, for autonomous systems, tactical ashore and at-sea energy solutions. The RDT&E marine energy projects are conducted through partnerships with research universities, industry, federal agencies and laboratories, and within the Department of Defense to advance the technical maturity of tactical marine energy components and associated systems and subsystems. The program directly supports the Department of the Navy by accelerating fleet unmanned systems forward presence at sea. The Naval Facilities Engineering Command directs and coordinates all aspects of the Wave Energy Test Site (WETS) via its contractor to provide maintenance and operations support of the WETS facility and at-sea testing. WETS has three mooring sites offshore MCB Hawaii to enable testing of Wave Energy Conversion (WEC) devices up to 1MW-rated, in 60m and 80m water depths; and < 40kW-rated WEC devices in 30m water depth. WETS provides support to WEC developers allowing for testing, improvement, and ultimate deployment of cost-effective wave energy production. WETS supports efforts to advance wave energy technology via in-situ testing/ demonstration and to evaluate wave energy technology readiness. The Naval Air Warfare Center Aircraft Division is responsible for the research, development and Test and Evaluation (RDTE) of Unmanned Air Systems and all the subsystems that are needed for them to operate successfully. Group 3 Logistics UAS's are a critical focus area and heavily dependent on lithium-Ion Battery packs currently manufactured outside the US. These battery solutions do not meet the quality, reliability and safety needed to meet emerging mission requirements safely in a maritime environment. Design, develop, fabricate, test and integrate ultra-high-capacity batteries into emerging logistics UAS platforms is a critical enabler to meeting emerging operational requirements in a contested environment. This program coordinates battery developers and fabricators, technical SMEs across the DON and UAS designers/builders to produce a cost and time effective common solution applicable to multiple systems to meet operational and safety requirements.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603725N_0995$$, $$0603725N$$, $$0995$$, $$Naval Facilities System$$, 2422000, $$Project 0995 addresses research, development, testing and evaluation of technologies related to 1) waterfront facilities (such as dry docks, piers, etc.) 2)Facilities sustainment, restoration and modernization (such as runways, magazines, etc.) to include the performance of alternative materials, and surfacing concepts and methods, and corrosion technologies to improve performance and reduce lifecycle cost. Waterfront facilities, repair, upgrade and service life extension: Improved availability and adaptability of our installations enables readiness and fleet lethality. Research focus areas include: 1) Design and analysis to adapt to extreme weather risks at Naval Facilities, especially nuclear capable waterfront facilities. 2) New design, retrofit and material methods to extend service life and/or improve capability. Approximately 75% of the Navy's waterfront facilities are over 45 years old, designed for a service life of 25 years, and need to support different, larger platforms. Critical Facilities Sustainment, Restoration and Modernization (SRM): Technologies that improve capability and/or reduce the cost of SRM for critical facilities (such as runways, magazines, etc.) including material reduction, strength increase, corrosion reduction, etc. The Navy's portion of corrosion deficiencies at DoD shore facilities is estimated to be $433M (DOD Annual Cost of Corrosion for the Department of Defense Facilities and Infrastructure July 2010).$$, 2422000, NULL, NULL, NULL, NULL, 23371000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603725N_3018$$, $$0603725N$$, $$3018$$, $$Facilities Related Controls Systems$$, 6487000, $$The Cyber Vulnerability Assessments and Evaluations program funds cyber vulnerability assessments of critical shore infrastructure. Funding will be used for assessments of prioritized critical shore infrastructure and will build upon existing mission assurance, blue team, and red team capabilities. As instructed by the Congressional language, the assessments will utilize DoE and DoD national laboratory partnerships. Assessments will end with the submission of a final report to Congress. Strategies and procedures for mitigating the risk of cyber vulnerabilities should be identified during the course of evaluation vulnerability.$$, 6487000, NULL, NULL, NULL, NULL, 7277000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603725N_3155$$, $$0603725N$$, $$3155$$, $$Force Protection Ashore$$, 2016000, $$In accordance with Navy Shore Strategic Guidance 2024-2029 Protection of Navy installations against evolving threats in a peer competition environment requires deployment of advanced technology for force protection capabilities. This Force Protection ashore project will develop, demonstrate and validate technologies for the following: access control and integrated perimeter security surveillance sensors and intelligent electronic security systems for automated counter intrusion detection (Installation Protection); perimeter security; waterside protection against craft and swimmer intrusion; secure and efficient operations centers and emergency management centers including human and information support systems (Command and Control).Programs currently being evaluated are, standard-based enterprise physical security system integration and automation; Command, Control, and Communications (C3) capabilities for emergency operations; integrated and networked mass notification systems (MNS); Waterside intelligent video security systems; integrated over-the-water sensors and analytics for automated course of action planning; identifying and interdicting malevolent threats - watercraft, swimmers, divers, and unmanned underwater vessels (UUVs) to reduce injury and death to the warfighter and damage to high value units (HVUs)(Waterside Protection). Through demonstration and validation of risk modeling and simulation models, the potential of emerging technologies will be evaluated and installation security strategies that reduce manpower and other costs will be formulated. Multiple systems with sensors and cameras are being deployed on Navy installations to be used for threat assessment. These systems are not integrated and there is not a centralized location or system that all the data can be analyzed. The Installation Defense Operations Center aggregates all these sensor feeds into one location and the Sensor Management System (SMS) software provides an integrated picture so that an intelligent assessment can be made. Current Force Protection systems to be integrated include Airfield Enclave Electronic Security Systems (AE-ESS), Blue Robotic and Autonomous Systems (RAS), Counter Unmanned Systems (C-UxS) (Air, land, sea) and the Electronic Harbor Security System and leverages personnel specifically trained to operate in in the RAS environment. These demonstrations and validations derive advanced technology from science and technology programs of government academia and industry. The technology evaluation and validation produces data for performance specifications used for competitive procurement. Utilizing agile management methods, each FY intentionally develops in sequence to iteratively advance the IDOC, C-UxS and Blue Robotics into operational environments. Testing in operational environments enables the Navy shore to gather valuable feedback and make necessary adjustments. All work will be coordinated with other programs and through industry forums as appropriate.$$, 2016000, NULL, NULL, NULL, NULL, 10405000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603725N_9999$$, $$0603725N$$, $$9999$$, $$Congressional Adds$$, 0, $$C999: Groundwater storage analysis$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603727D8Z_727$$, $$0603727D8Z$$, $$727$$, $$Joint Warfighting$$, 945000, $$The Joint Warfighting Program (JWP) supports the Assistant Secretary of Defense for Acquisition (ASD(A))'s responsibilities for acquisition and portfolio management. The JWP underwrites analyses, studies, performs limited scope experiments, wargaming, and partnerships that define joint capability gaps and develops credible requirements for follow-on acquisition efforts. These analyses and assessments deliver independent perspectives on potential remedies to align acquisition investments and solutions for joint capability gaps created by future warfighting environments and emerging threats. The JWP supports mission engineering integration management, as well as other high priority emerging issues requiring independent analysis to inform acquisition decisions that impact National Security. Anticipated Impact: Provides analytical support for acquisition efforts for ASD(A) staff elements and joint customers. It promotes analyses and assessments for acquisition insights and decisions focused on capability development serving the needs of joint forces and the warfighter.$$, 945000, NULL, NULL, NULL, NULL, 61052000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603729N_2914$$, $$0603729N$$, $$2914$$, $$Warfighter Protection Adv Tech$$, 7653000, $$This Program Element supports the advanced development and demonstration of technologies to improve warfighter performance, safety and survivability. Naval investment in these areas is essential in order to improve the ability to enhance, maintain, and sustain Warfighter effectiveness.$$, 7653000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603729N_9999$$, $$0603729N$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional add projects not included in other efforts.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603734N_1804$$, $$0603734N$$, $$1804$$, $$Chalk Coral$$, 414282000, $$The details of this budget justification are classified, per Executive Order 13526, Sec 1.4 (a) and are submitted annually to Congress in the classified budget justification book.$$, 414282000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603747A_610$$, $$0603747A$$, $$610$$, $$Food Adv Development$$, 4033000, $$This Project provides for the advanced component development and prototyping of Joint Service combat ration components/platforms and field feeding equipment designed to improve warfighter performance and reduce the logistics burden of subsistence support. Efforts funded in this Project support all four Services, the Special Operations Command, and the Defense Logistics Agency. The Army serves as the Executive Agent for this Department of Defense (DoD) program, with oversight and coordination provided by the DoD Combat Feeding Research and Engineering Board as required by DoD Directive (DoDD) 3235.02E. Centralized execution of the DoD Combat Feeding Research and Engineering Program (CFREP) with Joint Service review and approval eliminates unnecessary duplication of efforts across the Services and maximizes use of common materiel solutions. Prototypes validated within this effort transition to Army Program Element 0604713A (Combat Feeding, Clothing and Equipment) / Project 548 (Mil Subsistence Sys) for System Development and Demonstration. Work in this Project is performed by the United States Army Futures Command (AFC), U.S. Army Combat Capabilities Development Command (DEVCOM) Soldier Center (SC), Natick, MA.$$, 4033000, NULL, NULL, NULL, NULL, 3420000, 2026) ON CONFLICT DO NOTHING;
