INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603739E_MT-15$$, $$0603739E$$, $$MT-15$$, $$MIXED TECHNOLOGY$$, 0, $$The efforts described in this Program Element (PE) address the Advanced Technology Development associated with the Advanced Electronics Technologies Program that seeks to design and demonstrate state-of-the-art manufacturing and processing technologies for the production of various electronics and microelectronic devices, sensor systems, integrated photonic-electronic components that have military applications and potential commercial utility. Introduction of advanced product design capability and flexible, scalable manufacturing techniques will enable the commercial sector to rapidly and cost-effectively satisfy military requirements. The Mixed Technology Integration project funds the advanced development and demonstration of selected basic and applied electronics research programs. Examples of technologies with funded development and demonstration activities include, but are not limited to: reducing the size, weight, and power (SWaP) of components for laser weapon systems that will protect airborne platforms from emerging surface-to-air missiles; integrated photonic-electronic components for positioning, navigation and timing in GPS-denied environments; flexible, software-defined cameras that enable real-time image analysis of complex scenes to provide more actionable information; and optical communications systems that rely on no moving parts enabling their use on SWaP-restricted platforms. Funding under this project is intended to advance transitioning novel technologies to use, providing advanced components compatible with mid-term and other future warfighting requirements. The Beyond Scaling Advanced Technologies Project supports activities to enable and accelerate the transition of disruptive microelectronics advancement, including those developed under the Beyond Scaling Sciences (ES-02) and Beyond Scaling Technology (ELT-02) projects. Funding under this project will include developing new technologies and capabilities in commercial settings, establishing access to these new processes and to commercial state-of-the-art foundries, enabling prototyping, developing manufacturable processes for three-dimensional heterogeneous integration (including integrated photonics), advancing new architectures and integration technologies for advanced field programmable gate arrays (FPGAs), and innovating back end of line technologies for wide bandgap semiconductors. Beginning in FY 2026, efforts in this PE will be funded in PE 0603469E, Advanced Enabling Technologies. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                   Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:         PE 0603739E / ADVANCED ELECTRONICS TECHNOLOGIES Advanced Technology Development (ATD)$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603739E_MT-16$$, $$0603739E$$, $$MT-16$$, $$BEYOND SCALING$$, 0, $$The efforts described in this Program Element (PE) address the Advanced Technology Development associated with the Advanced Electronics Technologies Program that seeks to design and demonstrate state-of-the-art manufacturing and processing technologies for the production of various electronics and microelectronic devices, sensor systems, integrated photonic-electronic components that have military applications and potential commercial utility. Introduction of advanced product design capability and flexible, scalable manufacturing techniques will enable the commercial sector to rapidly and cost-effectively satisfy military requirements. The Mixed Technology Integration project funds the advanced development and demonstration of selected basic and applied electronics research programs. Examples of technologies with funded development and demonstration activities include, but are not limited to: reducing the size, weight, and power (SWaP) of components for laser weapon systems that will protect airborne platforms from emerging surface-to-air missiles; integrated photonic-electronic components for positioning, navigation and timing in GPS-denied environments; flexible, software-defined cameras that enable real-time image analysis of complex scenes to provide more actionable information; and optical communications systems that rely on no moving parts enabling their use on SWaP-restricted platforms. Funding under this project is intended to advance transitioning novel technologies to use, providing advanced components compatible with mid-term and other future warfighting requirements. The Beyond Scaling Advanced Technologies Project supports activities to enable and accelerate the transition of disruptive microelectronics advancement, including those developed under the Beyond Scaling Sciences (ES-02) and Beyond Scaling Technology (ELT-02) projects. Funding under this project will include developing new technologies and capabilities in commercial settings, establishing access to these new processes and to commercial state-of-the-art foundries, enabling prototyping, developing manufacturable processes for three-dimensional heterogeneous integration (including integrated photonics), advancing new architectures and integration technologies for advanced field programmable gate arrays (FPGAs), and innovating back end of line technologies for wide bandgap semiconductors. Beginning in FY 2026, efforts in this PE will be funded in PE 0603469E, Advanced Enabling Technologies. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                   Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:         PE 0603739E / ADVANCED ELECTRONICS TECHNOLOGIES Advanced Technology Development (ATD)$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603739N_0356$$, $$0603739N$$, $$0356$$, $$NADACS inventory$$, 0, $$Stable annual funding is required to facilitate implementation and execution of a robust, flexible Logistics R&D program that will provide the means for Naval Supply Systems Command (NAVSUP) to effectively pursue solutions to mission-related capability and technology gaps. The NAVSUP Logistics R&D program has an established infrastructure and business process for ensuring that R&D funds are applied to projects that address high priority enterprise needs established in accordance with OPNAV goals and the NAVSUP Commander's Guidance. From a process perspective, Logistics R&D investments are governed by a NAVSUP enterprise-wide Executive Steering Group (ESG) chaired by the NAVSUP Vice Commander and comprised of SES and Command leadership representatives. The ESG ratifies capability and technology gaps identified by all activities within the enterprise and then assesses and prioritizes all proposed Logistics R&D initiatives in accordance with their potential for filling the established gap and generating return on investment. The established Logistics R&D business management process has currently identified capability/technology gaps in the following general areas: 1) the need to develop formalized food service management techniques that focus on increased efficiency of new and existing systems and facilities, 2) the need to modernize quality of life (QOL) services to improve overall services, offer additional desired features and reduce total ownership costs, 3) the need to assess clothing protection for the warfighter in areas of thermal/flame threats, protective footwear, and physical (hearing, vibration, etc.) clothing/accessories, 4) the need to develop logistics data access and information sharing through enhanced Graphical User Interfaces (GUI) and web-based data services, 5) the need to develop a capability that allows Integrated Logistics Support (ILS) repair and modernization tools, 6) the need to leverage breakthrough technologies to improve supply chain processing. This modest R&D investment will establish a NAVSUP Logistics R&D Program to explore additional technologies and significantly increase potential cost savings. The Naval Autonomous Data Collection System (NADACS) is an Enterprise level, multi-source, digital tracking tool that supports asset visibility, accountability & auditability. The system directly supports both Congressional and Departmental dictates that require Navy to improve its ability to maintain and track material, assets and equipment with a high degree of accuracy and accountability. NADACS uses a variety of handheld readers, fixed readers, Mesh networking, and sensors to collect asset and combine data from barcoding, Radio Frequency identification (RFID) and Internet of Things (IOT) sensors to provide locational and health information of assets which can then be compared with on-hand inventory records. NAVSUP will be employing cellular 5G capabilities with Satellite Communication (SATCOM) along with other communication transport methods to move data from point of collection to the NADACS database and then providing end users with a 'Web Browser' picture to assess and manage the asset picture. NADACS is based on government owned software coupled with specialty and commercially available hardware to create a complete system. For commercial hardware, the system is hardware agnostic, encouraging use of available hardware while maintaining a high degree of competition.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603739N_3223$$, $$0603739N$$, $$3223$$, $$Logistics R&D$$, 1016000, $$Stable annual funding is required to facilitate implementation and execution of a robust, flexible Logistics R&D program that will provide the means for Naval Supply Systems Command (NAVSUP) to effectively pursue solutions to mission-related capability and technology gaps. The NAVSUP Logistics R&D program has an established infrastructure and business process for ensuring that R&D funds are applied to projects that address high priority enterprise needs established in accordance with OPNAV goals and the NAVSUP Commander's Guidance. From a process perspective, Logistics R&D investments are governed by a NAVSUP enterprise-wide Executive Steering Group (ESG) chaired by the NAVSUP Vice Commander and comprised of SES and Command leadership representatives. The ESG ratifies capability and technology gaps identified by all activities within the enterprise and then assesses and prioritizes all proposed Logistics R&D initiatives in accordance with their potential for filling the established gap and generating return on investment. The established Logistics R&D business management process has currently identified capability/technology gaps in the following general areas: 1) the need to develop formalized food service management techniques that focus on increased efficiency of new and existing systems and facilities, 2) the need to modernize quality of life (QOL) services to improve overall services, offer additional desired features and reduce total ownership costs, 3) the need to assess clothing protection for the warfighter in areas of thermal/flame threats, protective footwear, and physical (hearing, vibration, etc.) clothing/accessories, 4) the need to develop logistics data access and information sharing through enhanced Graphical User Interfaces (GUI) and web-based data services, 5) the need to develop a capability that allows Integrated Logistics Support (ILS) repair and modernization tools, 6) the need to leverage breakthrough technologies to improve supply chain processing. This modest R&D investment will establish a NAVSUP Logistics R&D Program to explore additional technologies and significantly increase potential cost savings.$$, 1016000, NULL, NULL, NULL, NULL, 3921000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603742F_642597$$, $$0603742F$$, $$642597$$, $$Noncooperative Identification$$, 22307000, $$Non-cooperative combat identification (CID) employs multiple sensing technologies and signal processing techniques designed to extract discriminating features from a battlespace entity (target). Specifically designed algorithms compare those extracted features to a tailored database to identify those targets. This is the primary method for advanced CID development and the key enabler for aiding Air Force kill-chains in denied access environments. These technologies include: (A) non-cooperative Air Target Identification (ATID) technologies, (B) non-cooperative Ground Target Identification (GTID) technologies, and (C) Studies evaluating potential new technologies. ATID development focuses on platform-centric CID technologies that enhance capability to determine enemy air threats. A primary area of focus is the development/ implementation of the government-owned joint standard for CID, Joint Multi-platform Advanced Combat identification (JMAC) architecture shared/implemented by Army, Air Force, Navy, and MDA; it fuses multiple sensors to provide a robust, advanced CID solution aimed at the discovery/generation of CID features from fielded sensors. JMAC is one of three key technologies in the Missile Defense Agency's Joint Tactical Integrated Fire Control (JTIFC) Architecture, as such it is being adopted by Golden Dome. Other areas of focus include combat identification technologies that broaden the application of CID across air platforms utilizing larger air-to-air kill-webs planned for employment by the Air Force and utilize assets in unmanned aerial systems and space to improve and enable CID in future threat air engagements. GTID development focuses on platform-centric CID technologies that enhance capability to determine priority enemy ground threat systems (both offensive and defensive systems). Primary areas of focus include transitioning CID capability for denied access environments using passive radio frequency and electronic warfare information, integrating radio-based technologies into the cockpit to increase confidence of target identification and situational awareness as well as reduce fratricides, and to demonstrate weapon-based combat identification back to the launch platform using a communication link from that launched weapon. GTID also advances technology to address efficiency and sustainability issues associated with the development, operation and maintenance of non-cooperative monostatic and bi-static synthetic aperture radar aided target recognition algorithms and databases. Other areas of focus include combat identification technologies that broaden the application of CID across air platforms utilizing larger air-to-ground kill-webs planned for employment by the Air Force and utilize assets in unmanned aerial systems and space to improve and enable CID in future threat ground engagements. The Studies area discovers novel technologies that are ready to become transition-able projects and includes activities to develop a robust ability to quantitatively evaluate promising combat identification technologies using enhanced modeling and simulation capabilities, database generation, and database enhancement/ employment (machine learning, deep learning, and artificial intelligence) to employ CID technologies in an operationally useful manner. The Studies effort also performs early assessments of promising technologies through Concept Calls to determine if the program should incorporate them as a formal project within the CID portfolio. Activities also include studies and analysis to support both current program planning and execution, as well as future program planning.$$, 22307000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603742F_642599$$, $$0603742F$$, $$642599$$, $$Cooperative Identification$$, 84000, $$Cooperative Combat Identification (CID) investigates technologies required to rapidly identify friendly platforms. The program develops, integrates and evaluates technologies that provide Air Force platforms with a means of positively identifying an air or ground platform as a friendly, via active or passive cooperative identification capabilities. This thrust area includes non-traditional cooperative approaches, as well as initial work on a follow-on cooperative system advancing beyond Identification Friend or Foe (IFF - Mode 5) previously developed and transitioned by this PE. Funding for initial studies related on the next generation IFF (potentially labeled Mode 6) began in FY 2023. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Combat Identification capability. The use of program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F.$$, 84000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603742F_643420$$, $$0603742F$$, $$643420$$, $$Combat ID Database Development$$, 2781000, $$The Database thrust area is designed to remove the "hard-coded”, static, identification (ID) parameters (typically updated every 4-5 years) from the host platform's sensor(s) and replace them with parameterized values that are more easily and rapidly updated when new intelligence inputs come available. This allows maximum flexibility to tailor each aircraft's Combat Identification (CID) database(s) based on assigned theater of operation, threat country of interest, and assigned mission tasks. This project primarily consists of four objectives: A) determining a sensor's capability to capture target features for CID, B) designing and developing a database to contain the CID features identified in Objective A, C) developing techniques to generate the requisite features, and D) providing CID features developed from measured or modeled data. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Combat Identification capability. The use of program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F.$$, 2781000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603758N_1097$$, $$0603758N$$, $$1097$$, $$NavalX (Naval Accelerator)$$, 17932000, $$NavalX powers the rapid development and deployment of relevant technologies that solve User-defined and User-owned problems through a collaborative Naval Enterprise approach. Through intentional innovation operations in the pursuit of novel and decisive capabilities for our Sailors and Marines, NavalX is focused on delivering disruptive capabilities that address operational problems within 5 years. Investments in Project 1097 were previously funded in this same PE under pieces of several projects spread across Project 2918 and in PE 0602123N/0000. This new Project was created to promote greater transparency for NavalX execution and investments across innovation lines of effort. This Project consolidates several prior year projects to be managed and executed by NavalX. NavalX executes several lines of effort in support of its vision to materialize new Fleet capabilities through innovative product and solution development: (1) Naval Warfare Prototype and Demonstration (investments previously funded in 0603758N/2918/Naval Warfare Experimentation) develops rapid prototypes through innovation operations, and transitions them to the warfighter for further iteration and technology incubation, aligned with Fleet demonstrations and exercises; (2) Technology Analysis, Development, and Investments (investments previously funded in 0603758N/2918/Operations Analysis) provides the Navy and Marine Corps the means to address capability gaps with technology solutions from the defense and commercial marketplaces, along with kickstart initial capital investment to mature the technology and integrate into the Naval mission architecture; (3) Innovation Agility (investments previously funded in 0603758N/2918/Swampworks) develops, demonstrates, and transitions newly invented or recently discovered technologies that address emergent and enduring operational problems in an accelerated timeframe, including digital environments that support innovation operations and Innovation Protection Policy (IPP); (4) Tech Bridges (investment previously funded in 0603758N/2918/Swampworks) cultivate local business ecosystems in order to facilitate tech scanning across non-traditional and small business startups to enable incubation, prototyping, and transition of technology solutions that rapidly address Fleet/Force needs; and (5) Innovation Operations (NRE) (investment previously funded in 0602123N/0000/Naval Research Enterprise) supports mission-driven problem solving within the Naval Research and Development Establishment (NR&DE) and academia in support of culture, organizational, and business changes to enable agile and rapid prototyping, development, and transition processes across the DON.$$, 17932000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603758N_2918$$, $$0603758N$$, $$2918$$, $$Navy Warfighting Experiments and$$, 63991000, $$This project focuses on the application of recent technology breakthroughs to meet current operational needs from a subscale proof-of-principle into a full-scale prototypes for warfighter experimentation during laboratory and operational demonstrations, Fleet Battle Problems (FBPs), Limited Objective Experiments (LOEs) and Fleet/Force exercises.$$, 63991000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603758N_9999$$, $$0603758N$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional Interest Items not included in other Projects.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603760E_0400$$, $$0603760E$$, $$0400$$, $$Research, Development, Test & Evaluation, Defense-Wide / BA 3:$$, NULL, $$The efforts described in this Program Element (PE) address the Advanced Technology Development associated with the Command, Control and Communications Systems Program focused on demonstrating and evaluating advanced information systems research and development concepts. The Information Integration Systems project develops and demonstrates technologies that will provide effective communications to U.S. forces. The success of military operations depends on timely, reliable, secure, and synchronized dissemination of command and control and relevant situational awareness information to every military echelon. While wired communications and networks are fairly well developed, providing assured high-bandwidth mobile wireless capabilities that match or exceed commercial wired infrastructure is needed to meet the demands of military users. Approaches to this goal include developing technologies in these areas: - High-Capacity Links technologies - enables greater back-haul capability. - Advanced Networking technologies - supports resilience, adaptability, scalability, and composable systems to enable adaptive effects webs. - Low Probability of Detection and Anti-Jam (LPD/AJ) technologies - provides assured communications in very high-threat environments. - Novel Radio Frequency and Spectral Sensing (RF/SS) - supports efficient spectrum management in congested environments and detection of electromagnetic threats. The Cyber Systems project develops, implements, and demonstrates techniques, tools, and frameworks for the full range of cyber operations. Cyber is now ubiquitous to warfighting. For non-kinetic operations in advance of lethal conflict, cyber can be a powerful enabler of information operations that limit adversary options and deter adversary actions. For kinetic operations during lethal conflict, cyber can be a force multiplier and provide an asymmetric advantage. The Cyber Systems project aims to create operational prototypes based on the cyber technology developed in applied research programs (budgeted in PE 0602303E, Project IT-03), in the private sector, and in academia. The utility of the operational prototypes that are developed in this project will be assessed, and improvements made, based on demonstrations and evaluations conducted in collaboration with warfighters, acquisition programs, and combatant commands. Beginning in FY 2026, efforts in this PE will be funded in PE 0603467E, DARPA Advanced Technology Development, and PE 0603469E, Advanced Enabling Technologies. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                              Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:       PE 0603760E / COMMAND, CONTROL AND COMMUNICATIONS SYSTEMS Advanced Technology Development (ATD)$$, NULL, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
