INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603801A_CK7$$, $$0603801A$$, $$CK7$$, $$FARA Ecosystem$$, NULL, $$Prior to the Army's decision to discontinue FARA program funding beyond FY 2024, funding supported persistent experimentation of FARA Ecosystem relevant technologies in a Joint All Domain Operations (JADO) environment. The Army's persistent experimentation events garnered early user feedback to inform and refine requirements and accelerate technology development. Demonstration of critical technologies in relevant operational environments informed refinement and validation of requirements for the FARA Ecosystem and its enablers; enabled timely decisions to transition relevant S&T technologies into the Ecosystem; provided an opportunity for operational assessment of capability gaps in the Ecosystem; and accelerated development and delivery of Army Aviation capabilities.$$, NULL, NULL, NULL, NULL, NULL, 28087000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603767E_SEN-01$$, $$0603767E$$, $$SEN-01$$, $$SURVEILLANCE$$, 0, $$The efforts described in this Program Element (PE) address the Advanced Technology Development associated with the Sensor Technology Program focused on sensor efforts that will improve the accuracy and timeliness of our surveillance and targeting systems for improved battlefield awareness, strike capability and battle damage assessment. The Surveillance and Countermeasures Technology project funds sensor efforts that will improve the accuracy and timeliness of our surveillance and targeting systems for improved battlefield awareness, strike capability, and battle damage assessment. Timely surveillance of enemy territory under all weather conditions is critical to providing our forces with the tactical information needed to succeed in future wars. This operational surveillance capability must continue to perform during enemy efforts to deny and deceive the sensor systems, and operate, at times, in a clandestine manner. This project will exploit recent advances in multispectral target phenomenology, signal processing, low-power high-performance computing, and low-cost microelectronics to develop advanced surveillance and targeting systems. In addition, this project encompasses several advanced technologies related to the development of techniques to counter advanced battlefield threats. The Sensors and Processing Systems project develops and demonstrates the advanced sensor and processing technologies and systems necessary for Intelligence, Surveillance, and Reconnaissance (ISR) missions. Future battlefields will continue to be populated with targets that use mobility and concealment as key survival tactics, and high-value targets will range from specific individual insurgents and vehicles to groups of individuals and large platforms such as mobile missile launchers and artillery. The Sensors and Processing Systems project is primarily driven by four needs: (a) providing day-night ISR capabilities against the entire range of potential targets; (b) countering camouflage, concealment, and deception of mobile ground targets; (c) detecting and identifying objects of interest/targets across wide geographic areas in near-real-time; and (d) enabling reliable identification, precision fire control tracking, timely engagement, and accurate battle damage assessment of ground targets. The Sensors and Processing Systems project develops and demonstrates technologies and system concepts that combine novel approaches to sensing with emerging sensor technologies and advanced sensor and image processing algorithms, software, and hardware to enable comprehensive knowledge of the battlespace and detection, identification, tracking, engagement, and battle damage assessment for high-value targets in all weather conditions and combat environments. Beginning in FY 2026, efforts in this PE will be funded in PE 0603467E, DARPA Advanced Technology Development. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:       PE 0603767E / SENSOR TECHNOLOGY Advanced Technology Development (ATD)$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603767E_SEN-02$$, $$0603767E$$, $$SEN-02$$, $$SENSORS AND$$, 0, $$The efforts described in this Program Element (PE) address the Advanced Technology Development associated with the Sensor Technology Program focused on sensor efforts that will improve the accuracy and timeliness of our surveillance and targeting systems for improved battlefield awareness, strike capability and battle damage assessment. The Surveillance and Countermeasures Technology project funds sensor efforts that will improve the accuracy and timeliness of our surveillance and targeting systems for improved battlefield awareness, strike capability, and battle damage assessment. Timely surveillance of enemy territory under all weather conditions is critical to providing our forces with the tactical information needed to succeed in future wars. This operational surveillance capability must continue to perform during enemy efforts to deny and deceive the sensor systems, and operate, at times, in a clandestine manner. This project will exploit recent advances in multispectral target phenomenology, signal processing, low-power high-performance computing, and low-cost microelectronics to develop advanced surveillance and targeting systems. In addition, this project encompasses several advanced technologies related to the development of techniques to counter advanced battlefield threats. The Sensors and Processing Systems project develops and demonstrates the advanced sensor and processing technologies and systems necessary for Intelligence, Surveillance, and Reconnaissance (ISR) missions. Future battlefields will continue to be populated with targets that use mobility and concealment as key survival tactics, and high-value targets will range from specific individual insurgents and vehicles to groups of