INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603767E_SEN-06$$, $$0603767E$$, $$SEN-06$$, $$SENSOR$$, 0, $$The efforts described in this Program Element (PE) address the Advanced Technology Development associated with the Sensor Technology Program focused on sensor efforts that will improve the accuracy and timeliness of our surveillance and targeting systems for improved battlefield awareness, strike capability and battle damage assessment. The Surveillance and Countermeasures Technology project funds sensor efforts that will improve the accuracy and timeliness of our surveillance and targeting systems for improved battlefield awareness, strike capability, and battle damage assessment. Timely surveillance of enemy territory under all weather conditions is critical to providing our forces with the tactical information needed to succeed in future wars. This operational surveillance capability must continue to perform during enemy efforts to deny and deceive the sensor systems, and operate, at times, in a clandestine manner. This project will exploit recent advances in multispectral target phenomenology, signal processing, low-power high-performance computing, and low-cost microelectronics to develop advanced surveillance and targeting systems. In addition, this project encompasses several advanced technologies related to the development of techniques to counter advanced battlefield threats. The Sensors and Processing Systems project develops and demonstrates the advanced sensor and processing technologies and systems necessary for Intelligence, Surveillance, and Reconnaissance (ISR) missions. Future battlefields will continue to be populated with targets that use mobility and concealment as key survival tactics, and high-value targets will range from specific individual insurgents and vehicles to groups of individuals and large platforms such as mobile missile launchers and artillery. The Sensors and Processing Systems project is primarily driven by four needs: (a) providing day-night ISR capabilities against the entire range of potential targets; (b) countering camouflage, concealment, and deception of mobile ground targets; (c) detecting and identifying objects of interest/targets across wide geographic areas in near-real-time; and (d) enabling reliable identification, precision fire control tracking, timely engagement, and accurate battle damage assessment of ground targets. The Sensors and Processing Systems project develops and demonstrates technologies and system concepts that combine novel approaches to sensing with emerging sensor technologies and advanced sensor and image processing algorithms, software, and hardware to enable comprehensive knowledge of the battlespace and detection, identification, tracking, engagement, and battle damage assessment for high-value targets in all weather conditions and combat environments. Beginning in FY 2026, efforts in this PE will be funded in PE 0603467E, DARPA Advanced Technology Development. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Advanced Research Projects Agency                                Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 3:       PE 0603767E / SENSOR TECHNOLOGY Advanced Technology Development (ATD)$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603774A_BQ5$$, $$0603774A$$, $$BQ5$$, $$Visual Augmentation System$$, NULL, $$This project evaluates and integrates technologies and representative prototype systems transitioning from the Science and Technology (S&T) stage. It develops the next generation augmented vision and situational awareness system providing Soldiers and Squads a single platform for increased lethality, mobility, and situational awareness to achieve overmatch against our current and future adversaries. Funded efforts accelerate the development of components, Heads Up Display (HUD) improvements, terrain shared coordinate data and processing, algorithms including machine learning/artificial intelligence, human machine integration, and demonstrations in support of the next generation augmented vision and situational awareness system. Efforts will provide rapid decision making and passive targeting capabilities with the integration of external video and data sources such as weapon sights, air and ground platforms, unmanned air and ground assets, and other data sources enabled by edge computing devices and advanced network services. This project will provide data driven analytics to optimize unit performance and enhance lethality and to enable Synthetic Training Environment (STE) squad capability to perform live mixed reality training and rehearsing. This project includes costs for efforts associated with edge computing platforms, movement of information and high- level processing, integration, and interface of products with the Soldiers' head, body, weapon, and platforms. Funding in this project aligns with the Army's priorities in support of the National Defense Strategy. This project supports the Soldier Lethality Cross Functional Team. The FY 2026 cost of the Integrated Visual Augmentation System (IVAS) Middle Tier of Acquisition effort is $85.5 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission.$$, NULL, NULL, NULL, NULL, NULL, 24410000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603774A_VT7$$, $$0603774A$$, $$VT7$$, $$Soldier Maneuver Sensors - Adv Dev$$, 3142000, $$This project enables development of emerging capabilities for the maneuver force, that are envisioned by the Soldier Lethality Cross Functional Team, the Maneuver Center of Excellence (MCoE), the Maneuver Capabilities Development Integration Directorate (MCDID), the Science and Technology (S&T) community, industry partners or the acquisition workforce that may provide the Soldier or Squad increased capability to "fight, win and survive, day and night, in a multi- domain environment now and tomorrow". This project also allows pursuit of technology breakthroughs that challenge current technical solutions and have the potential for providing increased Soldier performance. This effort focuses on capabilities that enable modernization of Soldier sensor and laser devices, including digital features and enhanced solutions including maneuver capabilities to detect, recognize and identify targets, and to provide target acquisition and handoff but not limited to capabilities to mitigate threats. The integration of higher performing multi-spectral sensors with smart processing will provide adjusted weapon sight reticles and leverage network connectivity for improved situational awareness/understanding. Additional project capabilities include advanced optical components and assemblies and techniques for signature management, resiliency across the electromagnetic spectrum, and integration of a modular design structure for target acquisition applications including support for wireless data transfer, passive range determination, technologies for working in a global positioning system (GPS) contested environment, advanced GPS replacement technologies and mitigation of manned and unmanned threat sensor systems. This project supports efforts to evaluate and integrate technologies and representative prototype systems including Micro Electronics Modules (MEMS) technology with improved size, weight and power for development of modernized Soldier sensor capabilities transitioning from the S&T stage to operational use. This project includes costs for efforts associated with development, certification, verification and validation of interface products into the Adaptive Squad Architecture (ASA). This project also includes development of tools and emulators of ASA components. Funding in this project aligns with Army's priorities in support of the National Defense Strategy.$$, 3142000, NULL, NULL, NULL, NULL, 15593000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603774A_VT8$$, $$0603774A$$, $$VT8$$, $$SOLDIER PRECISION TARGETING$$, 2011000, $$This project enables development of emerging technologies that are envisioned by the Fires Center of Excellence (FCoE), the Fires Capabilities Development and Integration Directorate (FCDID), the Science and Technology (S&T) community, industry partners and the acquisition workforce that provide the Fire Support Soldier increased capability and reduced weight to improve operational effectiveness. This project focuses on developing component technologies and representative prototype systems for Soldier portable precision targeting devices to continue improvements to system performance while reducing size, weight, and power required by those systems. The effort will consider emerging Micro-Electronic Modules (MEMs) technologies for improved efficiency and performance. Efforts will improve the Soldier's ability to precisely locate and laser designate targets across a broader range of operating environments, including all weather conditions and in Global Positioning System (GPS)-contested environments using active and passive methods and technologies. Component technology development will precede integration into specific systems and will include improved Precision Azimuth and Vertical Angle Measurement (PAVAM) devices; solid-state, improved lasers for range finding/designation/ marking; novel passive target acquisition methods; electro-optical sensors such as infrared, near-infrared, ultra-violet, and visible spectrum imagers; sensor and data fusion; laser designator spot detection and imaging; integration of advanced power management technologies, and GPS military-code (M-Code) receivers. The effort will also develop, mature and integrate next generation sensors to enable Human Machine Integration (HMI) improving situational awareness and combat overmatch in complex environments. Funding in this project aligns with Army's priorities in support of the National Defense Strategy.$$, 2011000, NULL, NULL, NULL, NULL, 1938000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603778A_093$$, $$0603778A$$, $$093$$, $$Multi-Launch Rocket System (MLRS)$$, 7751000, $$Project 093. The M270A2 Multiple Launch Rocket System (MLRS) launcher is a full-spectrum, combat-proven, all-weather, 24/7 lethal and responsive, precision strike weapon system. MLRS launchers support the Army's Long Range Precision Fires modernization effort. MLRS provides critical missile precision strike, operational shaping fires, counterfire, and close support destructive and suppressive fires. MLRS is a tracked, indirect fire, rocket/missile launcher capable of firing two pods of precision rockets/missiles from the current Multiple Launch Rocket System (MLRS) Family of Munitions (MFOM) including the Guided Multiple Launch Rocket System (GMLRS), the Army Tactical Missile System (ATACMS), and the Precision Strike Missile (PrSM), and future MFOM to include the Extended Range GMLRS (ER- GMLRS). MLRS launchers support Integrated Fires and Multi-Domain Operations. Funds software development, training updates, Assured Positioning, Navigation and Timing (APNT) technology implementation, integration of satellite communications, integration of evolving cybersecurity requirements, and nonrecurring engineering for the MLRS launcher. Funds development related to maintaining capability associated with the current and evolving threat. Funds non-recurring engineering for system hardware and software modernization to the MLRS chassis, launcher loader module, and fire control system. MLRS is part of the Army Transformation Initiative. Funding for Project 093 contributes to common efforts such as Assured Positioning, Navigation and Timing (APNT) integration and rocket launcher software development. The Next Generation APNT Receiver effort will replace the Increment 1 M-code receiver. Next Generation APNT Receiver development will replace the obsolete Increment 1 receiver with an Increment 2 receiver as well as address the evolving threat environment. Potential advancements such as: Alternative Navigation (ALTNAV), timing holdover, Network Assisted Assured (NA2), Other Signals of Opportunity, Advanced Anti-Jam, or Beamforming. Supports the Army's goal to develop common solutions applicable to both M270A2 MLRS and M142 HIMARS launchers. Justification: FY2026 Base funding in the amount of $7.751 million for Project 093 completes the integration of M-Code into the rocket launcher allowing MLRS to effectively operate in near-peer and peer-threat environments, integration of Anti-Jam (AJ) capabilities, and integration of satellite communications. Continues tactical launcher software development, qualification, and materiel release. These efforts support the fire control system (FCS) electronic obsolescence mitigation hardware upgrade required to operate the launcher and field additional launchers. Initiates Next Generation APNT Receiver development which will replace the M-code receiver with an upgraded receiver that addresses the evolving threat environment.$$, 7751000, NULL, NULL, NULL, NULL, 9859000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603778A_DX8$$, $$0603778A$$, $$DX8$$, $$HIMARS Product Improvement$$, 6888000, $$Project DX8. The M142 High Mobility Artillery Rocket System (M142 HIMARS) launcher is a full spectrum, combat proven, all weather, 24/7 lethal and responsive, precision strike weapon system. M142 HIMARS launchers support the Army's Long Range Precision Fires modernization effort. M142 HIMARS provides critical missile precision strike, operational shaping fires, counterfire, and close support destructive and suppressive fires. M142 HIMARS is a C-130 or C-17 transportable, wheeled, indirect fire, rocket/missile launcher capable of firing one pod of precision rockets/missiles from the current Multiple Launch Rocket System (MLRS) Family of Munitions (MFOM) including the Guided MLRS (GMLRS), the Army Tactical Missile System (ATACMS), and the Precision Strike Missile (PrSM), and future MFOM to include the Extended Range GMLRS (ER-GMLRS). M142 HIMARS launchers support Integrated Fires and Multi-Domain Operations. Funds software development, training updates, Assured Positioning, Navigation and Timing (APNT) technology implementation, integration of satellite communications, integration of evolving cybersecurity requirements, and nonrecurring engineering for the M142 HIMARS launcher. Funds development related to maintaining capability associated with the current and evolving threat. HIMARS is part of the Army Transformation Initiative. Funding for Project DX8 contributes to common efforts such as Assured Positioning, Navigation and Timing (APNT) integration and rocket launcher software development. The Next Generation APNT Receiver effort will replace the Increment 1 M-code receiver. Next Generation APNT Receiver development will replace the obsolete Increment 1 receiver with an Increment 2 receiver as well as address the evolving threat environment. Potential advancements include efforts such as: Alternative Navigation (ALTNAV), timing holdover, Network Assisted Assured (NA2), Other Signals of Opportunity, Advanced Anti-Jam, and Beamforming. Supports the Army's goal to develop common solutions applicable to both M270A2 MLRS and M142 HIMARS launchers. Justification: FY2026 Base funding in the amount of $6.888 million for Project DX8 completes the integration of Increment 1 M-Code and Anti-Jam (AJ) capabilities into the rocket launcher, Assured Positioning, Navigation and Timing (APNT) capabilities, and integration of satellite communications; allowing HIMARS to effectively operate in near- peer and peer-threat environments. It continues CFCS software development, qualification, and materiel release. These efforts support the fire control system (FCS) electronic obsolescence mitigation hardware upgrade required to operate an HIMARS launcher. The tactical software is required to field additional launchers, maintain backward compatibility for current fleet sustainment, and is the first release of government developed software common to both the M270A2 MLRS and M142 HIMARS launcher. Initiates Next Generation APNT Receiver development which will replace the obsolete Increment 1 M-code receiver, advancing the APNT posture to address the evolving threat environment.$$, 6888000, NULL, NULL, NULL, NULL, 4078000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605024N_2801$$, $$0605024N$$, $$2801$$, $$Anti-Tamper$$, 1637000, $$Anti-Tamper Program - Perform as the Navy Technical Process Owner for the Anti-Tamper (AT) systems engineering activity that is intended to prevent and/or delay the exploitation of critical technologies in U.S. Systems. Manage the research, design, development, implementation, and testing of AT measures. Coordinate with Department of Defense AT Executive Agent and implement Department of Navy AT policy in conjunction with the Deputy Assistant Secretary Navy. Manage Security and Information Security requirements commensurate with the requirements of ALL Navy Programs throughout their lifecycles.$$, 1637000, NULL, NULL, NULL, NULL, 7148000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603779A_035$$, $$0603779A$$, $$035$$, $$National Defense Cntr For Enviro$$, 7795000, $$The National Defense Center for Environmental Excellence (NDCEE) was established by Congress in 1990 with a directive to "serve as a national leadership organization to address high priority environmental problems for the Department of Defense (DoD), other government organizations, and the industrial community." In May 2008, the Program was re-designated from the National Defense Center for Environmental Excellence to the National Defense Center for Energy and Environment to ensure that the Center's mission recognizes and addresses the strategic interdependence of energy and environmental technology requirements within an overall sustainability framework in support of our installations, weapons systems and war fighters. This name change also directly supports the DoD's proactive implementation of Executive Order 13423, "Strengthening Federal Environmental, Energy and Transportation Management." The NDCEE Program has evolved into a national resource for demonstrating, validating and transitioning innovative Environmental, Safety & Occupational Health and Energy (ESOHE) technologies. This Program is managed by the Army on behalf of the Assistant Secretary of Defense (Energy, Installations and Environment). The United States (U.S.) Army's broadly encompassing and growing mobile, personal and stationary technological requirements include: infrastructure, alternative and synthetic energy, training lands, emerging contaminates, transportation, systems integration, personnel well-being, and others. Further, to train as we fight, validated ESOHE technologies need to be available and implemented at Army installations. The NDCEE will continue to demonstrate, validate, and transfer these technologies supporting our integrated environment, energy, safety, occupational health and energy objectives to enable mission, readiness, innovation, lethality and modernization to ensure our Soldiers maintain a technological advantage over our adversaries.$$, 7795000, NULL, NULL, NULL, NULL, 5337000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603779A_E21$$, $$0603779A$$, $$E21$$, $$Environmental Quality Technology$$, 3548000, $$This Project supports Advanced Component Development and Prototypes of innovative environmental quality technologies that modernize materials and processes required for current and future operational sustainment and warfighter training capabilities. The Project showcases technologies that increase life safety, reduce Soldier and worker human health risks, enhance readiness and enable mission capabilities of the current and future force with a focus on eliminating the high priority issues associated with hexavalent chromium, cadmium and airborne lead through material substitution. The Project expedites technology transition from the laboratory to operational use by demonstrating modern materials and processes to fulfill or surpass the performance requirements outlined in Material Specifications, Depot Maintenance Work Requirements, Technical Manuals, Drawings and other technical data. Forward-looking materials and processes demonstrated under this project support the Cross Functional Teams and the Army's top modernization priorities by addressing potential obsolescence of legacy materials and current and emerging impacts on human health and the environment. Modernized materials and processes have the additional benefit of addressing future regulatory compliance and cleanup requirements while simultaneously increasing performance and standardization across the Army, resulting in significantly reduced life cycle costs incurred by acquisition, industrial base and installation end users. Work in this Project is performed by the United States Army Futures Command (AFC), U.S. Army Combat Capabilities Development Command (DEVCOM) and U.S. Army Corps of Engineers (USACE).$$, 3548000, NULL, NULL, NULL, NULL, 14032000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603781D8Z_781$$, $$0603781D8Z$$, $$781$$, $$Software Engineering Institute (SEI)$$, 12972000, $$This project focuses on two main research thrusts with known military applications: (1) Software Engineering, Systems Verification and Validation, and Mission Assurance (formerly Mission Assurance); and (2) Information Assurance. SEI research focuses on the most significant and pervasive software challenges within the DoD, such as the scalability and reliability of software assurance, supply chain risk management, validation of and trust in autonomous systems, human-computer and human-technology teaming and interaction, computing and communication at the tactical edge, and efficiency and performance of acquisition strategies and software development appropriate for a contested cyber environment.$$, 12972000, NULL, NULL, NULL, NULL, 11874000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603782N_2917$$, $$0603782N$$, $$2917$$, $$Shallow Water MCM Demos$$, 2075000, $$This Project develops and demonstrates prototype technology for Mine Countermeasures (MCM), US Naval sea mining, and Expeditionary Warfare and Joint EOD system components that support capabilities enabling Naval and Joint EOD Forces to influence operations ashore. Adversarial nations have the capability to procure, stockpile and rapidly deploy all types of naval mines, throughout the littorals including new generation mines having sophisticated performance characteristics. They also have the capability to develop or modify explosive devices such as mines and unexploded ordnance to construct Improvised Explosive Devices (IEDs) for the purpose of targeting Joint Forces. Real world operations have demonstrated the requirement to quickly counter the mine threat. Current operations have also demonstrated the requirement to quickly counter the threat from explosive hazards and IEDs during DoD operations. Advanced technologies must rapidly detect and neutralize all mine types, from deep water to the inland objective. Advanced technologies must enable Joint EOD forces to detect/locate, gain access, diagnose, render safe, neutralize, recover, exploit and dispose of a broad spectrum of explosive hazards including unexploded ordnance and IEDs. This program supports the advanced development and integration of sensors, processing, warheads, and delivery vehicles to demonstrate improved Naval Warfare capabilities. This Project supports the advanced development and integration of sensors and tools for standoff capabilities such as detection and location of IEDs (particularly in dismounted operations), dismounted diagnosis of buried munitions and other explosive hazards, precision render safe and neutralization of surface munitions and other explosive hazards, and enhanced access to IEDs. It supports advanced development for battlespace shaping weapons including advanced undersea weapons. It supports the MCM related FNC Enabling Capabilities (ECs).$$, 2075000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603788F_635321$$, $$0603788F$$, $$635321$$, $$C4I Battlespace Dev and Demo$$, 18155000, $$This project supports the Department of the Air Force's (DAF) strategic objectives by advancing cutting-edge research technologies critical for achieving multi-domain superiority and operational agility across the full spectrum of military operations. Specifically, it enables the DAF and DoD to: (1) develop and implement Combined Joint All-Domain Command and Control (CJADC2) capabilities, ensuring seamless integration across land, air, space, and cyber domains for effective joint decision making, command, and operational execution; (2) field and sustain assured, resilient, and high-capacity communications and networks, providing enduring support for global, persistent, and survivable military operations—both kinetic and non-kinetic—critical to maintaining a strategic advantage and operational continuity in contested environments; and 3) design and deploy advanced systems to process, fuse, and exploit real-time data from diverse sources, empowering decision-makers with enhanced situational awareness and enabling rapid, data-driven decisions to outpace adversaries.$$, 18155000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603801A_CS7$$, $$0603801A$$, $$CS7$$, $$FLRAA MTA$$, NULL, $$The Army's use of Middle Tier of Acquisition (MTA) authorities for Future Long Range Assault Aircraft (FLRAA) transitions work completed during the Competitive Demonstration and Risk Reduction effort to support three priority efforts: (1) completion of the rapid prototyping for the delta Preliminary Design Review; (2) deliver two virtual prototypes including a vehicle dynamic model and portable crew station; and (3) support the requirements for Milestone B certification under 10 U.S.C. 2366b. Funds provided for the completion of the FLRAA weapon system preliminary design to include development of a digital backbone architecture to meet modular open system approach (MOSA) objectives. The development and delivery of two virtual prototypes directly support early user involvement at the Air Maneuver Battle Lab (AMBL), the Combat Aviation Brigade Architecture Integration Lab (CABAIL), and also support system and subsystem analysis and testing. The FLRAA MTA effort completes in FY 2025 with the delivery of the FLRAA Virtual Prototypes, which will continue to inform the FLRAA program through the Engineering and Manufacturing Development phase of the program.$$, NULL, NULL, NULL, NULL, NULL, 15932000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603788F_635329$$, $$0603788F$$, $$635329$$, $$Cyber Battlespace Dev & Demo$$, 12657000, $$This project supports the Department of the Air Force's (DAF) strategic objectives by advancing cutting-edge research technologies critical for achieving The Department of the Air Force (DAF) requires the development and deployment of advanced cyber capabilities to ensure superiority in both offensive and defensive operations, as well as to maintain resilience in contested cyber environments. This includes: 1) Cyber offense capabilities - enabling access, stealth, and persistence within adversary networks, while leveraging advanced intelligence collection and non-kinetic weapons to disrupt, degrade, or destroy enemy capabilities, ensuring strategic advantage in both peacetime and conflict scenarios. 2) Cyber defense capabilities - establishing robust defenses to detect, attribute, and respond to cyberattacks, ensuring the integrity of critical systems, networks, and data, while actively mitigating threats and neutralizing adversary attempts to compromise U.S. cyber infrastructure. 3) Cyber resilience - developing systems and protocols for rapid adaptation, recovery, and sustained survivability of critical assets and operations, ensuring the DAF can continue to function effectively even in the face of sophisticated and persistent cyber threats. The efforts in this Project directly support the DAF's and DoD's imperative to secure and maintain dominance in the cyber domain, ensuring the operational continuity and effectiveness of military forces across all domains, both in peacetime and in conflict.$$, 12657000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603790A_691$$, $$0603790A$$, $$691$$, $$NATO Rsch & Devel$$, 5031000, $$This Project implements the provisions of Title 10 United States (U.S.) Code, Section 2350a, Cooperative Research and Development (R&D) Projects: Allied Countries. The objective is to improve, through the application of emerging technologies, the conventional defense capabilities of the U.S. and our cooperative partners, including the North Atlantic Treaty Organization (NATO), U.S. major non-NATO allies and Friendly Foreign countries through technology sharing and joint equipment development, thereby reducing U.S. acquisition costs. Cooperative efforts also improve multinational force compatibility with potential coalition partners through the development and use of similar equipment and improved interfaces. The Project focuses specifically on international cooperative technology demonstration, validation, and interoperability of Army weapon and command, control, communications and information (C3I) systems, including the NATO Defense Against Terrorism initiatives. Activities are implemented through international agreements with foreign partners that define scope, cost and work sharing arrangements, management, contracting, security, data protection and third-party transfers. Funds are used to pay for only the U.S. work share that occurs within the U.S. at U.S. Government and U.S. contractor facilities.$$, 5031000, NULL, NULL, NULL, NULL, 3987000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603790N_2293$$, $$0603790N$$, $$2293$$, $$NATO Cooperative R & D$$, 5234000, $$In accordance with Title 10 United States Code, Section 2350a, this PE provides funding for research and development (R&D) programs with approved allies under international agreements. These funds can only be applied to work efforts in the U.S. The Under Secretary of Defense, Acquisition and Sustainment (USD, A&S) must approve each international agreement. The program provides funds for multiple projects under separately approved international agreements as well as funds that support the establishment of such agreements. Each international agreement is summarized in a separate Summary Statement of Intent (SSOI) that also states why the project serves to increase the defense capabilities of the U.S. The SSOI is used to obtain project approval by the Department of the Navy and the Office of the Secretary of Defense. The North Atlantic Treaty Organization (NATO) R&D cooperative programs differ from other Research, Development, Test and Evaluation (RDT&E) programs because issuance of funding from this PE coincides with the signature of international agreements. This NATO Research and Development program funds U.S. activities to support the identification and implementation of International Agreements (IAs) intended to address Chief of Naval Operations (CNO) priorities and identified interoperability gaps. - Projects depend on commitment of U.S. and allies, and are subject to imprecise staffing timelines (funding typically provided when international agreement is signed, often later in the Fiscal Year (FY)). - Funds must be identified/committed early (1-2 years prior) to indicate support during processing (in Summary Statement of Intent). - These funds only constitute a portion of U.S. project funding.$$, 5234000, NULL, NULL, NULL, NULL, 127366000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603795N_2038$$, $$0603795N$$, $$2038$$, $$ADVANCED MINOR CALIBER GUN$$, 1056000, $$Project 2038: The 25mm MK 38 MOD 2 and MOD 3 Machine Gun Systems (MGS) provide Anti-Surface Warfare (ASUW) and Anti-terrorism and Force Protection (AT/ FP) capability as a simple, stabilized, low-cost solution to outfit near-term deployers to counter small boat threats. Over 360 U.S. Navy-owned systems are installed on U.S. Navy AS, CG, CVN, DDG, LCC, LHA, LHD, LSD, OSV, PC class ships, MK VI Patrol Boats and U.S. Coast Guard Fast Response Cutters. Established in order to respond to Joint Urgent Operational Need Statement (JUONS) CC-0558 for Counter Unmanned Aerial Systems (C-UAS), the MK 38 MOD 3 MGS's electro-optical/infra- red sensor, hardware, and software are being upgraded to counter emerging unmanned aerial threats. Initial C-UAS capability was fielded in Q1FY 2020. Incremental improvements are being made to this C-UAS capability, for cybersecurity and to address operability issues. The 30mm MK 38 MOD 4 Gun Weapon System, will introduce greater accuracy, lethality, and effective range for C-UAS and Counter Unmanned Surface Vehicle (C-USV) capability with integration to highly accurate fire control system, 30mm gun, targeting sensor and AEGIS combat system. The MOD 4 will be fielded on all DDG 51 Flight IIA and Flight III AEGIS Destroyers. Project 2038 provides qualification and logistics development of the 30mm MK 38 MOD 4. This will include Function Integration Testing, Functional Acceptance Testing, AEGIS Light-off, Structural Test Firing, and an at-sea Quick Reaction Assessment (on board DDG 89). Upgrading fielded 25mm MK 38 MGS to MOD 3 with C-UAS and concurrently developing and fielding the MK 38 MOD 4 Gun Weapon System (GWS) on all current and future DDG 51 Flight IIA and Flight III Destroyers is the fastest and most cost-effective way to field critical C-UAS ship self-defense capability. MK45 C-UAS MK160/MK20 development to utilize a Hypervelocity Projectile (HVP) munition that was developed for the Army and that capability is being developed to operate within a Naval environment using existing systems. The capability includes developing a low-cost C-UAS solution into the five-inch MK 34-gun weapon system on DDGs. This effort includes development of the fire control software, development of a datalink from the ship, hardware in the loop simulation, system integration testing, and at sea live fire testing. FY2024 CENTCOM Operations Transfer, Israel Security Supplemental (P.L. 118-50, Division A., Sec. 101).$$, 1056000, NULL, NULL, NULL, NULL, 33903000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603801A_B47$$, $$0603801A$$, $$B47$$, $$Future Vertical Lift$$, NULL, $$The Future Vertical Lift (FVL) Project's funding provides for the development of a Future Long Range Assault Aircraft (FLRAA) Capability Set Three weapon system within the FVL family of systems. FLRAA will conduct air assault, urban assault/security, maritime interdiction, medical evacuation, humanitarian assistance/disaster relief, tactical resupply, direct action, noncombatant evacuation operation, and combat search and rescue operations. FLRAA will support the Army, including Special Operations Command (USSOCOM) and the Joint Force, in a contested, near peer threat environment. The FLRAA weapon system will retain the Army's ability to project combat power with transformational increases in range, speed, mobility, and payload over current Army and USSOCOM aircraft. FLRAA achieved a Materiel Development Decision approval in October 2016 and the Office of Secretary of Defense granted a sufficiency determination of the Analysis of Alternatives (AoA) in July 2019. In Fiscal Year (FY) 2025, funding transitioned to Budget Activity 6.5 PE 0605241A/Future Long Range Assault Aircraft Development, Project DG5/ Future Long Range Assault Aircraft, for execution of Engineering and Manufacturing Development and to support Budget Activity guidance for programs achieving Milestone B.$$, NULL, NULL, NULL, NULL, NULL, 990100000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603801A_F12$$, $$0603801A$$, $$F12$$, $$Future Attack Reconnaissance Aircraft$$, NULL, $$The Capability Set 1 (CS1) Future Attack Reconnaissance Aircraft (FARA) was part of the Future Vertical Lift (FVL) Family of Systems. FARA was intended to restore crewed attack/reconnaissance dominance with sweeping improvements in lethality, agility, reach, survivability, and sustainability. FARA was intended to mitigate enemy long-range capabilities to allow joint force commanders to fight and operate from relative sanctuary while creating lethal effects from outside enemy sensor/weapons range. Funding supported the development and integration of Government Furnished Equipment (GFE). FARA would have been powered by Improved Turbine Engine (ITE), with maximum cruise airspeed greater than or equal to 180 KTAS, an integrated Area Weapons System (AWS), Modular Effects Launcher (MEL) for Launched Effects (LE) and Long Range Precision Munition (LRPM), and Modular Open System Approach (MOSA) digital backbone. The FVL Capability Set 1 Initial Capabilities Requirements Document (ICRD) was approved in July 2018 under the name Future Attack Reconnaissance Aircraft (FARA). An Abbreviated Capability Development Document (A-CDD) was approved on 9 Apr 2021 and updated on 15 Aug 2022. The Acquisition Approach and Determination and Findings for Other Transaction Authority for Prototyping (OTAP) agreements were approved on 1 February 2019 by the Acting Under Secretary of Defense (Acquisition and Sustainment) to execute a Competitive Prototyping (CP) effort. Prior to the Army's decision in February 2024 to discontinue FARA program funding beyond FY 2024, FARA was conducting a Competitive Prototyping (CP) design and demonstration in parallel with the Weapons System (WS) Preliminary Design to inform a Milestone B decision. FARA received full FY 2024 funding authorization to complete closeout activities with the OTAP performers, conduct orderly ramp down of the FARA program office, closeout existing FARA contracts, disposition GFE and transition of technology investments to the Army Aviation enterprise.$$, NULL, NULL, NULL, NULL, NULL, 418212000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603801N_1108$$, $$0603801N$$, $$1108$$, $$METEOR$$, 0, $$Navy surface combatants have Capability/capacity gaps to defend against high volume attacks in Integrated Air and Missile Defense (IAMD). The objective of METEOR is to demonstrate tactically significant, non-kinetic, High Power Microwave (HPM) payload integration onto Naval platforms to defeat, track, engage and assess operational threats while assessing integrated sensors and weapon control options. The METEOR HPM weapon development will provide capability with low cost- per-shot, deep magazine, tactically significant range, short time engagement for multi-target approach, dual deception and defeat capability. This Innovative Naval Prototype (INP) will assess the military utility of a ship-based Integrated Air and Missile Defense (IAMD) HPM weapon, to develop performance requirements via effects and lethality studies, to evaluate current HPM prototype hardware for those requirements, and to mature promising HPM technologies. To assess military utility as part of layered defense in stressing scenarios, METEOR will quantify effectiveness against priority threats, evaluate Battle Damage Assessment (BDA) techniques, and perform mission modeling.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603801N_2731$$, $$0603801N$$, $$2731$$, $$High Energy Laser Counter ASCM$$, 0, $$The High Energy Laser Counter ASCM Project (HELCAP) will expedite the development, experimentation, integration and demonstration of critical technologies to defeat crossing Anti-Ship Cruise Missiles (ASCM) by addressing the remaining technical challenges, e.g.: atmospheric turbulence, automatic target identification and aim point selection, precision target tracking with low jitter in high clutter conditions, advanced beam control, and higher power HEL development. HELCAP will assess, develop, experiment, and demonstrate the various laser weapon system technologies and methods of implementation required to defeat ASCMs in a crossing engagement. HELCAP activities in this project (0603801N) include technology assessments, laser lethality investigations, and advanced beam control. Component and Subsystem level operability is being conducted under this project specifically the Beam Control subsystem including active tracking and advanced atmospheric compensation using Adaptive Optics. The Beam Director subsystem testing will occur in a simulated environment (land based) against surrogate ASCM targets. Other subsystems being developed and tested under this project include the automated engagement sequencing, HEL targets and diagnostics subsystems, and an HEL interface compatible with a range of competing HEL source technologies. This project passes technology to follow on HELCAP activities under Program Element (PE) 0603925N Directed Energy and Electric Weapon Systems.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603801N_3400$$, $$0603801N$$, $$3400$$, $$Innovative Naval Prototypes (INP)$$, 0, $$The efforts described in this Project address the Advanced Technology Development associated with the Innovative Naval Prototypes (INP) Program. These investments represent game-changing technologies with the potential to revolutionize operational concepts. They are disruptive in nature, as they would dramatically change the way naval forces fight. Due to high technical risk, INPs typically have long duration but have no more than three years between decision points. They mature technologies from a Technology Readiness Level (TRL) of 2 or 3 to a TRL of 6. As such, INPs require both Budget Activity (BA) 2 and BA3 funding. The BA3 INP funds are specified in a separate Program Element (PE), 0603801N Innovative Naval Prototypes (INP) Adv Tec Dev. INPs do not develop hardware for service use; rather they provide feeder technology that can be demonstrated in prototypes in the 6.3 portion of the INP program. Developing INPs requires a systematic expansion and application of knowledge to develop useful materials, devices, and systems oriented toward the design and development of prototypes applicable to specific mission area requirements. The efforts funded within this PE is focuses on continuing the technology development from the BA2 efforts in order to develop full-scale technology/ operational demonstrations. The Department of the Navy would have to make significant acquisition decisions to integrate the new technological capabilities into naval warfighting systems. INPs are selected by a process that involves senior leadership in the Department of the Navy.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603801N_3452$$, $$0603801N$$, $$3452$$, $$ELEKTRA$$, 0, $$Complex multi-domain threats can overwhelm the operator and individual platforms ability to defend the force. The ELEKTRA INP effort is developing "Human on the Loop" Artificial Intelligence (AI) enabled algorithms to perform force level kinetic/non-kinetic kill chain optimization and coordination across multiple domains at machine to machine speeds to increase the lethality and survivability of the Force. ELEKTRA will demonstrate AI/ML ability to coordinate kinetic/non kinetic effects autonomously with heterogeneous platforms, the ability to operate in degraded environments for hours and the ability to coordinate and execute domain kill chains simultaneously. It will deploy artificial intelligent (AI) and machine learning (ML) architecture, neural networked computing and large data handling to enable real time, force level effects assignment, coordination and resource management. The Activity identified in Project Unit 3452 specifically addresses Advanced Technology Development in support of the ELEKTRA INP effort.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603801N_3455$$, $$0603801N$$, $$3455$$, $$MINERVA$$, 0, $$The need to operate in a multiple domain environment against highly capable peers requires improved decision quality and reduced decision timelines. MINERVA will develop AI and Machine-Learning (ML) capabilities to improve mission planning, intelligence gathering, execution and assessment. Minerva will deliver next- generation decision aids by combining operations research with emerging AI capabilities to create learning, self-adaptive automation that supports Composite Warfare Commander's (CWC) and their staffs at the Fleet, Force and Group echelons. It will establish a DevOps environment that includes warfighter staffs in the development and integration of new capabilities. The Activity identified in Project Unit 3455 specifically addresses Advanced Technology Development in support of the MINERVA INP effort.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603801N_3456$$, $$0603801N$$, $$3456$$, $$Full Spectrum Undersea Warfare$$, 0, $$The Full Spectrum Undersea Warfare (FSUW) Project will develop new technology for offensive and defensive warfare conducted on the seabed, in the sea (i.e. subsea), and from the sea. This INP focuses on Theatre Undersea Warfare (TUSW), Joint Targeting and Strike, and Subsea and Seabed Warfare (SSW). There are five thrust areas of the FSUW INP that are key to enabling Chief of Naval Operations Guidance (CNOG), Distributed Maritime Operations (DMO), and the Commandant's Stand in Force with manned and unmanned warfighting capability. These thrust areas were specifically chosen in direct collaboration with STRATCOM, INDO-PACOM, Fleet and Undersea Warfare Commanders and validated with regular Flag engagements. These advanced technology developments will enable future undersea weapon systems (e.g., Maritime Strike Tomahawk and ADCAP variants), COCOM campaign, and operational plans. FSUW thrust areas include 1) Undersea effectors, 2) Integrated expeditionary subsea system of systems, 3) Multi-Vehicle Torpedo Tube Development System (MVTTDS) for payload A, 4) Undersea UAV for Over- The-Horizon (OTH) effects and 5) Undersea Launched Devices to enable Commanding Officers and Regional Combatant Commander effects. The thrust areas are technically an operational interconnected. Selected concepts from advanced research will be integrated into viable representative prototypes for field experimentation in a relevant environment. Lessons learned from field experimentation will inform continued applied research spirals to remedy technical shortcomings, expand capability, or define an alternate approach. The Activity identified in Full Spectrum Undersea Warfare, Project 3458, specifically addresses Advanced Technology Development in support of the Full Spectrum Undersea Warfare INP effort. The Applied Research Budget Activity (BA) 2 funding is in a separate Program Element (PE) 0602792N FSUW INP, Project 3456. Information security concerns preclude fully detailed descriptions of project efforts, research activities, and technology development plans. Specific information on each project and activity will be provided separately to the Congressional oversight committees.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603801N_3457$$, $$0603801N$$, $$3457$$, $$Long Range Targeting$$, 0, $$Long Range Targeting emphasizes the specific naval use of HF Over the Horizon Radar (OTHR) on maritime platforms and forward-based positive identification technologies to fill gaps in long-range fires kill chains. Technologies within this activity will enable integrated long range naval fires. Investments include technologies for OTH radar antennas, HF antenna arrays, signal processing, and electronic surveillance. Activity identified in Project Unit 3457 specifically addresses Advanced Technology Development in support of the LRT INP effort.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603801N_3459$$, $$0603801N$$, $$3459$$, $$Super Swarm (SS)$$, 0, $$Swarming is a concept that allows for multi-domain, heterogeneous swarms of unmanned systems capable of rendering the counter's ability to scale either inadequate or irrelevant and includes offensive and defensive operations, own and adversarial employment, and a physical battlespace ranging from open ocean to ashore. The Super Swarm (SS) INP effort will develop an autonomous control system for multiple USV's consisting of cooperative task allocation, cooperative route planning/behaviors and shared situational awareness. The Swarm autonomy technology is leveraged by other programs including the Medium Displacement Unmanned Surface Vehicle (MDUSV) and the Autonomous USV FNC program. It will consist of the employment of sustainable large-scale robotic swarm warfare across all domains ahead of our adversaries to obviate costly and vulnerable legacy platforms and to gain a competitive advantage. The Activity identified in Project Unit 3459 specifically addresses Advanced Technology Development in support of the Super Swarm INP effort.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603801N_3461$$, $$0603801N$$, $$3461$$, $$MASS$$, 0, $$The rising use of air, surface, and sub-surface unmanned and autonomous systems requires a paradigm shift in the development, production, and life-cycle management of these systems in order to gain a competitive advantage against adversarial capabilities as well as allow for fielding of significant numbers (1000's to 10,000's) in an increasingly budget-constrained acquisition environment. The growth in rapid prototyping and additive manufacturing technologies presents an opportunity to capitalize on these advances though technical development and demonstration efforts focused on scale-up both in terms of rapid production of relevant quantities as well as greatly increasing the physical size of platforms produced far beyond what is currently achievable. Manufacturing of Autonomous Systems at Scale (MASS) efforts will utilize wide range of advanced manufacturing methods combined with adaptive digital design processes with "Design for Low-Cost Platform Attriteability" as a major attribute to avoid the platform cost growths normally associated with exquisite systems development. This also represents the ability to rapidly modify platform attributes based on evolving operational needs and quickly insert into build process without costly retooling. Secondary goals focus on increasing commonality of critical components across platforms and design of these in modular fashion in order to manage supply chain vulnerability. Lastly, the project will look at ability to place manufacturing capability as far forward/afloat as possible to reduce the logistics tail and speed delivery of capability at-scale into the fleet. The activity identified in Project Unit 3461 MASS specifically addresses Advanced Technology Development in support of the MASS effort.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603801N_3462$$, $$0603801N$$, $$3462$$, $$DEALRS$$, 0, $$Adversary Anti-Access and Area Denial (A2/AD) capabilities continue to improve but remain focused on targeting specific US and joint force capabilities. The Deployment and Employment of Autonomous Long Range Systems (DEALRS) project will develop technologies that sidestep, operate below the threshold, or deplete adversary A2/AD capabilities. DEALRS will specifically develop technologies to enable low-cost unmanned systems that can maneuver across theater-level ranges to penetrate, operate within, and launch strikes from within adversary A2/AD system coverage. This project will develop technologies to increase the range and endurance of autonomous systems while maintaining tactically relevant speeds, loiter times, and signatures with low cost. It will also address technologies that enable the marsupial launch of terminal engagement autonomous unmanned systems across all domains from larger and/or longer-range host systems that bring them to the launch area and the associated technologies needed to ensure roboticized and autonomous startup and launch of the marsupial systems without human intervention. The Activity identified in Project Unit 3462 DEALRS specifically addresses Advanced Technology Development in support of the INP effort.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603801N_3463$$, $$0603801N$$, $$3463$$, $$MATes$$, 0, $$Traditionally, the utilization of autonomous systems is either operationally segregated from manned operations or requires a significant amount of human oversight when operating in conjunction with manned assets, which mitigates some of the advantage from using them. The goal of the Manned and Autonomous Teams (MATes) project is to develop autonomic robotic technology and collaborative autonomous behaviors that seamlessly operate across all domains in conjunction with manned units, allowing for real-time adaptation and optimization in a manner that streamlines the element of human interaction needed to share mission goals. This technology will monitor human or manned system teammate state, behavior, mission, and adversary threat status to anticipate and act in a tactically appropriate manner that is predictable, communicable, and trusted by the human/manned teammates and which enables autonomous system optimization in coordination with the human/ manned teammate and mission objectives. Intuitive human/autonomous system interfaces will be developed to allow focus on higher-order decision-making tasks by the operators allowing for large numbers of autonomous systems (100's or 1000's) to be managed in support of manned operations. The activity identified in Project Unit 3463 MAtes specifically addresses Advanced Technology Development in support of the MATes effort.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603801N_3464$$, $$0603801N$$, $$3464$$, $$REDCAT$$, 0, $$Remote Electromagnetic Disruption of Critical Advanced Threats (REDCAT) will demonstrate High Power Microwave (HPM) integration onto Naval platforms for air defense missions. The objective of the REDCAT rapid prototyping effort is to demonstrate that the REDCAT system is able to detect, track, engage, defeat and assess advanced threats to the ship in a maritime environment. This HPM payload capability will supplement and conserve the ships kinetic defensive weapons. In addition to advancing the HPM source and antenna technologies, this program will also enhance sensor systems well as common weapon console with ongoing laser programs. REDCAT will also develop novel Radio Frequency (RF) waveforms to improve HPM effectiveness. When combined with other non-kinetic capabilities and integrated with the ship's command and control (C2), REDCAT will provide a low cost-per-shot, deep magazine capability for significantly expanding the self-defense capabilities of US Navy platforms. Rapid engagement of targets for large threat raid defeat is a major feature of the system. The system will demonstrate full kill chain integration from find to assess. The payoffs for the REDCAT program include integrated non-kinetic air defense systems to improve the layered defense, optimized use of defensive kinetic weapons and improved sensor and control systems.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603801N_3507$$, $$0603801N$$, $$3507$$, $$Chimera$$, 0, $$Details at a higher classification$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603801N_5899$$, $$0603801N$$, $$5899$$, $$Precision Fire Control$$, 0, $$The Precision Fire Control (PFC) effort will develop a fire control architecture that delivers high precision, high update rate guidance solutions to enable cruise missile defense with small, low-cost interceptors and dramatically increase number of interceptors per ship or Expeditionary Advanced Base. It will develop fire control capability for multiple interceptors (missiles and gun projectiles) that contribute to layered defense of surface combatants, expeditionary forces, and homeland protection. Develop PFC-enabled low-cost missile (LCM) based on existing 2.75" rocket components. The Activity identified in Proj: 5899 Precision Fire Control (PFC) specifically addresses Advanced Technology Development in support of the PFC INP effort.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603801N_9999$$, $$0603801N$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional add projects not included in other efforts.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603804A_526$$, $$0603804A$$, $$526$$, $$Marine Orien Log Eq Ad$$, 2716000, $$This project supports current Army Watercraft Systems (AWS) that provide the Combatant, Multi-Domain Operations (MDO) and Joint All Domain Operations (JADO) Commanders with an organic waterborne lift capability to enable Dynamic Force Repositioning (DFR) in support of unified land operations. AWS provides the waterborne transportation capability to deliver combat-configured equipment with personnel, vehicles and sustainment cargo (Bulk Water and Fuel), through fixed, degraded and austere ports, inland waterways, remote and unimproved beaches and coastlines for missions across the spectrum of military operations. AWS bridges the gap between strategic sealift and sustains lethality in littoral areas or where mature ports and road networks are unavailable. Watercrafts are a key enabler to Army and Joint force in support of Title 10 and DODD missions of providing logistics to joint operations and campaigns, including DODD missions of providing logistics to joint operations and campaigns, including joint logistics over-the-shore and intra-theater transport of time sensitive, mission-critical personnel and equipment, and in support of amphibious and riverine operations (DODD 5100.01). This Army Watercraft funding supports initiatives to enhance the seaworthiness, safety, and survivability while increasing the lethality, tactical mobility, and operational capability of the Army Mariner to preserve the Combatant Commanders requirement of "freedom of seas" access in all areas of the world particularly the littorals, to support maneuver operations in all Areas of Responsibility. All modification and services efforts are critical enablers for the success Army's Watercraft Systems Transformation Strategy (AWSTS) and continued fulfillment of the AWS Title 10 mission. Funded engineering efforts will address critical gaps in these areas for the current AWS for regaining capability, while at the same time researching, developing and testing emergent technologies. To support future acquisitions and future fleet planning, funding efforts will include conducting trade studies, Business Case Analyses to inform the requirement development process, and support Analysis of Alternatives (AoA). The funding enables Army's compliance with the National Defense Authorization Act of 1996 and 502(6) of the Clean Water Act and compliance with Environmental protection Agency (EPA) emission standards. FY 2026 RDTE dollars in the amount of $2.716 million supports modernization of the current Army Watercraft fleet by investigating technology insertions, including, but not limited to: force protection, prognostics & preventative maintenance, vessel electronics, autonomous operations and other emerging technologies. Funding also supports developing initial prototypes to enable refinement of operational requirements and early user feedback to support future sustainment and operational movement operating concepts. All Army Watercraft modernization efforts will incorporate Predictive Logistics which includes digital updates across commercial solutions which will improve readiness, predictive maintenance, unplanned emergency repairs.$$, 2716000, NULL, NULL, NULL, NULL, 2345000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603804A_EW8$$, $$0603804A$$, $$EW8$$, $$Armored Engineer Vehicles$$, 9942000, $$This project supports the prototype development, test and evaluation of a robotic capability Remote Control System (RCS) for the Assault Breacher Vehicle (ABV), to include prototype fabrication, developmental testing and logistics development / user test events. Funding supports modernization of Army Bridging and Armored Engineer Vehicle fleets by investigating technology insertions including, but not limited to condition- based maintenance, increased military load capacities, autonomous operations and other emerging technologies. Funding also supports developing initial prototypes and testing to enable refinement of Operational Requirements and early user feedback to support future sustainment and operational movement operating concepts. FY 2026 Base dollars in the amount of $9.942 million supports Assault Breacher Vehicle Remote Control System (ABV RCS) which adds remote control capability to the ABV, allowing Soldiers to conduct minefield breaching operations remotely, removing Soldiers from the breach where 50% casualty rates are expected. FY 2026 Base dollars support engineering and logistics development, developmental testing and program support.$$, 9942000, NULL, NULL, NULL, NULL, 4981000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603804A_G11$$, $$0603804A$$, $$G11$$, $$Adv Elec Energy Con Ad$$, 2777000, $$As the DoD's Lead Standardization Activity for Tactical Electric Power (TEP), Project Manager Expeditionary Energy & Sustainment Systems (PM E2S2) matures and integrates technology that will improve the next generation of standard tactical power sources in support of all Services. It supports technical maturation of TEP systems that will extend Army operational mission reach and duration in support of the Army Operating Concept and Multi-Domain Battle. Funding supports modernization of the current Tactical Electric Power capability with technology insertions including, but not limited to advanced power technology capabilities through the Universal Power Gateway (UPG) system, light-weight power solutions, vehicle/tactical microgrid interoperability and Tactical Microgrid Standard (TMS). Funding also supports developing initial prototypes to enable refinement of Operational Requirements and early user feedback to support future sustainment an operational energy concepts. This project is a Congressional Interest Item. Congressionally provided funds will support analysis and planning for potential transition to the Army of the mobile micro-reactor prototype and capability. FY26 RDTE dollars in the amount of $2.777 million supports Advanced Power Technology for the Universal Power Gateway (UPG) requirement.$$, 2777000, NULL, NULL, NULL, NULL, 15520000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603807A_808$$, $$0603807A$$, $$808$$, $$DoD Drug & Vacc Ad$$, 423000, $$This Project funds development of candidate medical countermeasures for endemic infectious diseases of military relevance. These efforts are in: vaccines, drugs, diagnostic kits/devices. These funds support human clinical effectiveness (capacity to produce a desired size of an effect under ideal or optimal conditions) trials of the drug/vaccine in larger groups that are designed to assess how well the drug/vaccine works and continue safety assessments in a larger group of volunteers. Funding supports both technical evaluations and human clinical testing to assure the safety and effectiveness of medical diagnostic kits and devices. This work, which is performed in military laboratories or civilian pharmaceutical firms, is directed toward the prevention of disease, early diagnosis, and accelerated recovery time once diagnosed to enhance battlefield readiness. All clinical trials are conducted in accordance with United States (U.S.) Food and Drug Administration (FDA) regulations, a mandatory obligation for all military products placed into the hands of medical providers or service members. Product development priorities are determined based upon four major factors: (1) the extent and threat of the disease within the Combatant Commands theater of operations, (2) the clinical severity of the disease, (3) the technical maturity of the proposed solution, and (4) the affordability of the solution (development and production).$$, 423000, NULL, NULL, NULL, NULL, 404000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603807A_836$$, $$0603807A$$, $$836$$, $$Field Medical Systems Advanced$$, 577000, $$This Project funds the demonstration and validation of medical products for enhanced combat casualty care and follow-on care. This Project funds human clinical trials to test the safety and effectiveness of biologics (products derived from living organisms) and devices necessary to meet medical requirements. The Project Manager (PM) also considers factors to reduce the medical logistics footprint through smaller weight, volume, and equipment independence from supporting materials. All clinical trials are conducted in accordance with U.S. FDA regulations. Products from this project will transition to PE 0604807A (Medical Materiel/Medical Biological Defense Equipment - Eng Dev) /Project 832 (Field Medical Systems Engineering Development).$$, 577000, NULL, NULL, NULL, NULL, 5614000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603827A_CF2$$, $$0603827A$$, $$CF2$$, $$Integrated Soldier Systems$$, 3572000, $$Develop a long-term Soldier/Squad as a System integration platform in connection with the Close Combat Integration Enterprise (CCIE) to ensure interoperability as part of the integrated Joint Forces. Verify and develop prototype digital engineering tools that provide Systems Engineering, Configuration Management, and Evaluation in a virtual and physical environment. Using enhancements to the Adaptive Squad Architecture (ASA) digital tools verify development of interface controls documents, and connection points to support the rapid integration of the CCIE programs with all other dismounted Soldier equipment. Prototype capabilities for evaluation and integration include new measurements and methodologies from S&T programs and future requirements. Funding for this program aligns with the Army's priorities in support of Digital Engineering and Transformation and is a Soldier Lethality Cross Functional Team priority.$$, 3572000, NULL, NULL, NULL, NULL, 3554000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603827A_ET8$$, $$0603827A$$, $$ET8$$, $$Personnel Airdrop System$$, 1936000, $$Funding in this project supports Army Modernization priorities. Project ET8, Personnel Airdrop System Development, improves Low Altitude and High-Altitude personnel parachutes and associated equipment to include canopy improvement based on integration of new technology with the goal of enhancing the insertion capability and the safety of the airborne Soldier and increasing the performance, reliability, and durability of personnel airdrop equipment. This project will transition capabilities from our Science and Technology partners to increase performance and safety of Soldier equipment. It will continue to support cross-service initiatives to improve commonality.$$, 1936000, NULL, NULL, NULL, NULL, 2127000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603827A_S53$$, $$0603827A$$, $$S53$$, $$Clothing And Equipment$$, 7849000, $$Funding in this effort supports Defense Digital Transformation and Army Modernization Priorities to evaluate and integrate technologies and prototypes that expedite Product Manager Soldier Clothing and Individual Equipment (PdM SCIE) technology transitions from the laboratory to operational use. Efforts focus on achieving commonality across all services to provide footwear, uniforms and clothing systems consisting of all layers required to accommodate Warfighters in all environments resulting in integrated systems for the Airborne, Arctic, Arid, Jungle, and Temperate Soldier. PdM SCIE efforts include female Warfighter specific items and sizing. This effort funds the transition of new, improved technologies and domestically available fabrics with capabilities such as Flame Resistance (FR), moisture wicking, vector protection and innovative multi-service efforts to advance camouflage technologies to mitigate multi-spectral signature detection. This effort also funds integration of fabrics, uniforms, load bearing items and Soldier mobility equipment, for use in all environments. PdM SCIE will transition capabilities from our Science and Technology partners to increase performance of Warfighter clothing and equipment and identify emerging technologies to integrate advanced material capabilities into combat uniforms and equipment. Additional advances in existing technologies to improve survivability by focusing on reducing weight and improving performance, mobility and comfort. PdM SCIE will continue to support multi-service commonality and modernization initiatives through technology that enables combat operations and enhances lethality.$$, 7849000, NULL, NULL, NULL, NULL, 4528000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603827A_S54$$, $$0603827A$$, $$S54$$, $$Small Arms Improvement$$, 21044000, $$The Small Arms Improvement Advanced Component Development and Prototypes (ACD&P) program provides funds to mature, demonstrate, test and evaluate emerging technology from Budget Activity (BA) 3 Program Element (PE) 0603607A Joint Service Small Arms Program (JSSAP) Project 627 Defense Advanced Research Projects Agency (DARPA), Department of Energy National Laboratories, Research Development & Engineering Centers (RDECs) and other domestic and foreign sources for small arms weapon systems and technology. Small Arms Improvement supports the Army Modernization priorities through enhancement of Joint Lethality in contested environments by minimizing and eliminating erosion of close combat capability relative to peer competitors in complex terrain as outlined in the National Defense Strategy (NDS). Small and medium weapon systems include weapons ranging up to 40 millimeter in caliber, recoilless rifles, remote weapon systems and chain guns. These efforts focus on improving and maturing designs to enhance lethality, target acquisition and tracking, fire control, usability, training effectiveness and reliability improvements to include ammunition and counter unmanned aerial system technologies when developing and/or evaluating standard and non-standard weapon systems. Maturing of technologies through testing and evaluation of sub-system or system prototypes includes lightweight materials, thermal solutions, passive range finders, observation/situational awareness improvements, human-systems integration, robotic armament capability, non-lethal capability, advanced laser protection for optics, and equipment enhancements. Benefits include continuous improvements to small arms weapon systems, remote weapon systems, fire control equipment, optics, gun barrels, training devices, suppressors, component mounts, weapon mounts, ancillary items and weapon/ammunition/fire control interfaces.$$, 21044000, NULL, NULL, NULL, NULL, 22762000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603827A_VS4$$, $$0603827A$$, $$VS4$$, $$Soldier Protective Equipment$$, 7455000, $$Funding in this project supports the Army Modernization priority. This Project supports efforts to evaluate integrated technologies and representative or prototype systems that help expedite Personal Protective Equipment (PPE) technology transition from the laboratory to operational use. This project will transition capabilities from our Science and Technology partners to increase performance and safety of Soldier protective equipment. This project will continue to support cross-Services initiatives to increase commonality.$$, 7455000, NULL, NULL, NULL, NULL, 8580000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603838D8Z_730$$, $$0603838D8Z$$, $$730$$, $$Concepts and Capabilities$$, 211027000, $$Concepts & Capabilities (C&C) focuses on executing advanced operational prototypes with the Joint Services and Combatant Commands (CCMD). C&C validates warfighting concepts and accelerates new capabilities faster than the traditional defense acquisition process. C&C emphasizes delivering major system components and/or single fieldable systems for joint warfighting application, while informing Service programs of record. The delivery of these operational prototypes is typically 12 to 36 months. C&C drives prototyping investments to address the joint warfighter’s most pressing operational capability gaps and accelerates new capability development in conjunction with the Joint Services and CCMD. Based on established needs, C&C sponsors joint efforts to mature operational prototypes through approved developmental portfolios. Office of the Under Secretary of Defense for Research & Engineering (OUSD(R&E)) portfolio managers provide government oversight and execute collective development with operational leads from the Service and CCMDs; pool technical resources from the Service research, engineering laboratories, program executive offices; leverage academia and industry expertise as needed; require Service cost-sharing partnerships; and execute the necessary planning steps for future transition early within the developmental life cycle. This execution strategy represents a time-proven catalyst for collaborative development and accelerates delivery of operational prototypes to the joint warfighter.$$, 211027000, NULL, NULL, NULL, NULL, 204902000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603838D8Z_731$$, $$0603838D8Z$$, $$731$$, $$Innovation and Modernization$$, NULL, $$Innovation and Modernization (I&M) focuses on addressing the Department of Defense's (DoD) current priority challenges in near real-time, through innovation discovery and leap-ahead prototyping. Activities include early exploration of low-cost potentially game-changing technologies and concepts, harnessing non-traditional performers and small business innovation to address DoD modernization and capability challenges. I&M acts as an innovation accelerator by funding discovery efforts and the development of prototypes to identify and mature solutions for joint capability gaps. I&M supports DoD modernization through multi-year projects with targeted technology and capability thrusts that are identified, selected, and executed within the year of execution. These efforts support technology maturation and lead to transition through partnerships with Services, Combatant Commands (CCMDs), and other defense agencies to enable effective, affordable, and critically needed early- stage prototype technologies. I&M achieves this through a tailored execution model that: • Creates an innovation pipeline to support key experimentation and transition efforts, such as the Rapid Defense Experimentation Reserve (RDER), targeting DoD priorities and capability gaps • Is informed by Department-level strategies and priorities including the interim National Defense Strategy, Joint Warfighting Doctrine, CCMD priorities, and the OUSD(R&E) critical technology areas • Leverages and coordinates innovation from all sources, including Service laboratories, Federally Funded Research and Development Centers (FFRDCs)/University Affiliated Research Centers (UARCs), the defense industry, small businesses, non-traditional performers, and academia • Responds rapidly with the ability to identify and fund prototypes within the year of execution to accelerate the rate of innovation and address emerging opportunities and threats • Leverages Service, defense agency, and industry investments through partnerships that share risk and increase alignment with OUSD(R&E) priorities • Incorporates transition sponsor participation during project development, prototyping, and evaluation With funds available throughout the year of execution, I&M enables the OUSD(R&E) to identify, accelerate, and rapidly transition innovation from all sources that otherwise, would not be realized through traditional research and development pathways. This execution model causes I&M to lag traditional RDT&E obligation and execution benchmarks, however, since inception I&M has achieved an unbroken 100% obligation rate. Accordingly, I&M can be responsive and flexible to the DoD and joint warfighter needs, supporting rapid prototyping to meet immediate capability needs or game-changing technologies that maintain technological superiority and create enduring change. I&M’s focus on innovation discovery with a flexible execution model allows for rapid innovation through new technology and capability thrusts supported by joint and interagency partnerships with clearly defined milestones and risk reduction. Prototyping efforts are identified throughout the year by leveraging engagements with industry, Service laboratories, FFRDCs, and other innovation centers. Individual projects generally span 12 to 24 months, typically at a cost of less than $2.000 million.$$, NULL, NULL, NULL, NULL, NULL, 80000000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603851D8Z_514$$, $$0603851D8Z$$, $$514$$, $$Environmental Security Technology$$, 123981000, $$The Environmental Security Technology Certification Program (ESTCP) demonstrates and validates innovative technologies for military installations, while its sister program, the Strategic Environmental Research and Development Program (SERDP), invests in applied research to develop these solutions. ESTCP tests promising technologies in relevant operational environments across DoD installations, providing decision-makers with reliable performance and cost data before widespread implementation. By validating solutions under real-world conditions, ESTCP reduces adoption risks and accelerates technology transfer to end users. The program has an excellent track record of return on investment, with many solutions deployed directly to installations without further development. ESTCP conducts formal demonstrations at DoD facilities in operational settings to document and validate improved performance and cost savings. To ensure real impact, ESTCP collaborates with end users and regulators throughout the development and execution of each demonstration. Transition challenges are overcome with rigorous and well-documented demonstrations that provide the information needed by all DoD partners for technology adoption. The program employs a competitive selection process to ensure high-quality demonstrations, issuing solicitations for proposals from government, academia, and industry. Each project develops a formal test and evaluation plan, and demonstration results undergo rigorous technical reviews to ensure conclusions are accurate and supported by data. This process ensures installations receive solutions that address current operational needs and deliver measurable benefits to the Department of Defense.$$, 123981000, NULL, NULL, NULL, NULL, 838544000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603851F_641020$$, $$0603851F$$, $$641020$$, $$ICBM Guidance Applications$$, 25422000, $$The Guidance Applications Program (GAP) studies and assesses both legacy and future ICBM Guidance System technology applications. Efforts are focused on current and future requirements and technologies, reduced life-cycle costs, and increased nuclear safety and surety. Activities leverage the efforts of the science and technology community and are coordinated with the Navy strategic applications program to enhance synergy and avoid duplication. Key elements include developing responsive technologies with common applications for future strategic guidance capabilities. This program also includes any needed nuclear surety, certification, and system vulnerability assessments. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 0M was expended for civilian pay expenses in this program element, and in FY 2025 0M is forecasted for civilian pay expenses in this program element.$$, 25422000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603851F_641022$$, $$0603851F$$, $$641022$$, $$ICBM Reentry Vehicle Applications$$, 44973000, $$The Reentry Vehicle Applications Program (RVAP) ensures the ICBM force is equipped with the safe, reliable, survivable reentry systems, and explores options for common, multi-mission capabilities. The program enables a responsive engineering infrastructure by developing modeling/simulation and ground/flight test platforms to support reentry system qualifications. The program ensures the availability of long-lead components and materials while identifying life-cycle cost reduction opportunities. In addition, the program matures and tests advanced reentry system technologies and designs to meet future capability requirements. This includes conducting any necessary studies and assessing technology applications relevant to Mk12A, Mk21, Mk21A, and future ICBM reentry systems by maturing technologies and demonstrating/validating concepts and leveraging investments by the science & technology community and Navy reentry systems applications program. Testing may occur on a space-available basis on Air Force and Navy Force Development Evaluation (FDE) flights. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 0M was expended for civilian pay expenses in this program element, and in FY 2025 0M is forecasted for civilian pay expenses in this program element.$$, 44973000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603890C_MT23$$, $$0603890C$$, $$MT23$$, $$Enabling - Test$$, 44962000, $$The Enabling Test project includes Missile Defense System test planning, execution, and post-test analysis and assessment, and the Modeling & Simulation (M&S) tools and framework required to prepare for and execute ground and flight tests. This includes test design, target requirement definition, and collaboration with the Service Operational Test Agencies (OTA) to incorporate operational test requirements into Missile Defense System events. This ensures Missile Defense System tests collect essential System data and confirm proper System operation. It also provides data to anchor system and element models and simulations for use in simulations to characterize System performance across the battle space, including areas where no live-fire-testing is performed. Resources for the planning, design, execution and management of this testing are provided in accordance with the most current version of the Integrated Master Test Plan (IMTP).$$, 44962000, NULL, NULL, NULL, NULL, 304569000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603891C_MD27$$, $$0603891C$$, $$MD27$$, $$Special Programs$$, 498630000, $$This program is reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program Annual Report to Congress.$$, 498630000, NULL, NULL, NULL, NULL, 4190494000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603851F_641024$$, $$0603851F$$, $$641024$$, $$ICBM Command & Control (C2)$$, 10563000, $$The Command and Control Applications Program (C2AP) supports ICBM weapon system connectivity to the President and National Command Authorities. C2AP studies and assesses both legacy and future C2 system technologies. C2AP evaluates and develops assured, survivable, and secure communications and battlespace awareness between the missile Launch Control Centers and Launch Facilities essential for mission execution. Efforts include identifying and developing current and future technologies, as well as concepts that exploit state-of-the-art communications and information transfer techniques to both current and future ICBM systems. Products include studies, demonstrations, and tests such as ICBM Advanced C2 Capabilities architectures, networks, and systems to meet nuclear C2 requirements. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 0M was expended for civilian pay expenses in this program element, and in FY 2025 0M is forecasted for civilian pay expenses in this program element.$$, 10563000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603851F_644209$$, $$0603851F$$, $$644209$$, $$Long Range Planning (LRP)$$, 9138000, $$The Long Range Planning (LRP) effort identifies, analyzes, and evaluates potential modifications to current and future ICBM Weapon Systems required to meet warfighter objectives related to executing flight tests, long-term sustainment, technology insertion, battle space awareness, employment, force structure, and future systems. The studies will focus on system supportability, operability, reliability, innovation, and maintainability. Options/concepts generated by these studies are evaluated for feasibility, system impacts, and cost. LRP supports and conducts testing in support of future weapon system development and deployment. Pre-milestone activities may be conducted for current and/or future ICBM weapon systems, which may include entry criteria for milestone activities enabling a rapid response to evolving warfighter priorities and emerging requirements. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 0M was expended for civilian pay expenses in this program element, and in FY 2025 0M is forecasted for civilian pay expenses in this program element.$$, 9138000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603851M_2319$$, $$0603851M$$, $$2319$$, $$Non-Lethal Weapons$$, 9832000, $$This project Non-Lethal Weapons (NLW) develops and fields NLW intermediate force capabilities between presence and lethal effects in support of national interests.$$, 9832000, NULL, NULL, NULL, NULL, 710889000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603860N_2329$$, $$0603860N$$, $$2329$$, $$JPALS$$, 41978000, $$This budget reflects the Department of Defense certified Component Cost Position of the restructured Joint Precision Approach and Landing System (JPALS) program that funds the developmental, testing, and integration activities to implement and field JPALS ship systems that deliver the primary precision approach, landing, on- deck inertial alignment, surveillance, and auto-land capability for current and future low observable manned and unmanned platforms onboard all CVN and LHA/D ships. JPALS provides for development, integration, installation, and test of JPALS on CVN and LHA/D ships in accordance with the Joint Requirements Oversight Council (JROC) May 2018 approved JPALS Capability Production Document (CPD). JPALS Engineering Development Model (EDM) articles have been delivered to support JPALS EMD activities. JPALS will continue to invest in software development in direct support of precision approach and auto-land capabilities for the F-35B/C, MQ-25A, and future air platforms. JPALS effort includes addressing broadened CyberSecurity requirements to remain compliant with software CyberSecurity directives and Information Assurance mandates. Remaining costs are associated with the completion of the test and support to fielded EDM units and to develop, test, and transition JPALS to use GPS M-Code. Additionally, costs are to enhance Precision Ship-Relative Navigation (PS-RN) for Navy and Marine Corps unmanned, and potentially manned, platforms, via the Landing Autonomous Navigation Technology for Enhanced Recovery to Navy Ships (LANTERNS) Future Naval Capabilities (FNC) and other system improvements.$$, 41978000, NULL, NULL, NULL, NULL, 1443916000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603881C_MC07$$, $$0603881C$$, $$MC07$$, $$Cyber Operations$$, 3253000, $$Cyber Operations sustain the Missile Defense Agency (MDA) Risk Management Framework (RMF) and Controls Validation Testing (CVT) activities; analysis of validation results, risk assessments; reviews of proposed Program Manager/Information Assurance Manager Plans of Action and Milestones for MDA Terminal High Altitude Area Defense (THAAD) mission systems; and supports THAAD authorizations to operate in the Missile Defense System.$$, 3253000, NULL, NULL, NULL, NULL, 68899000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603881C_MD06$$, $$0603881C$$, $$MD06$$, $$Patriot Advanced Capability-3$$, 0, $$PAC-3 is an operational, land-based weapon built upon the proven United States (U.S.) Army Phased Array Tracking Radar Intercept on Target (PATRIOT) air and missile defense infrastructure. The Army is responsible for production and further development of the PAC-3 System and Missile Segment Enhancements (MSE); the Missile Defense Agency (MDA) remains responsible for any Missile Defense System interoperability and integration efforts. The Army will utilize MDA funds to further the integration of PATRIOT with the Missile Defense System. Previously this project included the Army's portion of the Joint Emergent Operational Need including: 1) PATRIOT launch on remote to utilize Terminal High Altitude Area Defense's (THAAD's) capability to detect and track threat ballistic missiles at longer ranges and utilize MSE's full kinematic capability. 2) THAAD/MSE Integration Part 1 that integrates MSE launchers and missiles into the THAAD weapon system enabling a more tightly integrated upper/lower tier defensive capability.$$, 0, NULL, NULL, NULL, NULL, 412210000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603884C_MC11$$, $$0603884C$$, $$MC11$$, $$Cyber Operations$$, 19931000, $$Sustain the Department of Defense Instruction (DoDI) 8510.01 Risk Management Framework (RMF) for Department of Defense (DoD) Information Technology (IT) requirement for the Missile Defense Agency (MDA) and conduct Security Control Assessments (SCA) activities, analysis of validation results, risk assessments, and reviews of proposed Program Manager/Information System Security Manager (PM/ISSM) Plans of Action and Milestones (POA&M) for MDA Ground Sensors mission and support systems. It also includes support for external cybersecurity assessments and penetration testing of the Ground Sensors mission systems, both in laboratory developmental testing and during ground test activities, in accordance with Director, Operational Test and Evaluation directives and the Integrated Master Test Plan. It maintains the Assessment and Authorization (A&A) data repository, capturing the RMF documentation (artifacts, validation results, Cybersecurity Risk Assessment results, cybersecurity scorecard, and Authorizing Official (AO) authorization decisions) and POA&M for all MDA information systems. It positions Ground Sensors assets to complete the transition to National Institute of Standards and Technology Special Publication 800-53 Revision 5 requirements (i.e. RMF 2.0) once DoD requirements and timelines are finalized. This project supports aligning, developing, and implementing an integrated Tier 2 Cyber Security Service Provider (CSSP) capability on the Ground Sensors mission systems under the DoD Cybersecurity Discipline Implementation Plan and DoDI 8530.01 Cybersecurity Activities Support to DoD Information Network Operations. Provides the monitoring, prioritization, and tracking of Cybersecurity mitigation detailed in Information Technology security POA&Ms. The activities include preparation of A&A documentation and accreditation recommendations to the MDA Senior Information Security Officer/SCA and AO. Independent Verification and Validation team actions ensure the availability, integrity, authentication, confidentiality, and non-repudiation of the MDA mission, test, and administrative systems. These activities are necessary to comply with the Federal Information Security Management Act.$$, 19931000, NULL, NULL, NULL, NULL, 94619000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603881C_MD07$$, $$0603881C$$, $$MD07$$, $$THAAD$$, 481636000, $$The THAAD system provides a capability to intercept and destroy short-range, medium-range, and limited intermediate-range missile threats inside or outside the atmosphere during the terminal phase of flight. THAAD continues the development and integration of multiple, independent system builds to address the evolving threat, improve reliability, availability and readiness, defense planning, and improved capability to engage Short-Range Ballistic Missile, Medium-Range Ballistic Missile, and limited Intermediate-Range Ballistic Missile threats. THAAD Development executes the iterative development and integration of multiple, independent system builds to deliver enhanced system capabilities and expand the defense of allies and deployed forces from short to limited intermediate-range threats and the integration of the THAAD weapon system into the Army IBCS architecture. Program Operations provides strategic planning, program integration, cost estimating, contracting, financial management, internal reviews and audits, earned-value management, and program assessments for the THAAD Program Office. Project Redwood details are provided at a Higher Classification reported in accordance with Title 10, United States Code, Section 119 (a)(1) in the Special Access Program Annual Report to Congress. THAAD Program Support provides communications and interoperability efforts to support the Materiel Release process, maintaining safety and mission assurance and enabling the ability to operate on multiple networks.$$, 481636000, NULL, NULL, NULL, NULL, 2749925000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603881C_MD40$$, $$0603881C$$, $$MD40$$, $$Program-Wide Support$$, 24009000, $$PWS contains non-headquarters management costs in support of Missile Defense Agency (MDA) functions and activities across the entire Missile Defense System. These functions include Government Civilians and Contract Support Services. This effort provides integrity and oversight of the Missile Defense System as well as supports MDA in the development and evaluation of technologies that will respond to the changing threat. Additionally, PWS includes personnel to support global deployments performing deployment site preparation and activation, and provides facility capabilities for MDA Executing Agent locations worldwide. Other MDA wide costs include: physical and technical security; civilian drug testing; audit readiness; the Science, Technology, Engineering, and Mathematics (STEM) program; legal services and settlements; travel and agency training; office, equipment, vehicle, and warehouse leases; utilities and base operations across multiple geographic locations; commercial and ancillary facility services; management of all facility aspects regardless of lifecycle stage; supplies and maintenance; compliance with statutory environmental requirements; data and unified communications support; materiel and readiness and central property management of equipment; Facilities Sustainment, Restoration and Modernization (FSRM) program (formerly Real Property Maintenance) to keep the Department's inventory of facilities in good working order; and similar operating expenses. PWS is allocated on a pro-rata basis across most Agency PEs; therefore, fluctuates per PE by FY based on the total Agency budget in that FY.$$, 24009000, NULL, NULL, NULL, NULL, 148767000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603882C_MC08$$, $$0603882C$$, $$MC08$$, $$Cyber Operations$$, 30318000, $$The GMD Cyber Operations project provides cybersecurity and cyber resiliency to maintain and operate all mission and mission support systems. The GMD systems must maintain Network and System Certification and Accreditation for operation on all GMD networks and nodes. Cybersecurity and Cyber Resiliency efforts harden the GMD system against a cyber-attack and reduces system vulnerabilities. The strategy implements cybersecurity and cyber resiliency systems throughout the lifecycle to flow requirements to the Ground Based Interceptor, Next Generation Interceptor, and GMD Weapon System to influence system development. In addition, Cybersecurity and Cyber Resiliency efforts include developmental cyber testing and assessments to reduce cyber vulnerabilities prior to fielding.$$, 30318000, NULL, NULL, NULL, NULL, 263733000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603882C_MD08$$, $$0603882C$$, $$MD08$$, $$Ground Based Midcourse$$, 767520000, $$The Ballistic Missile Defense Midcourse Defense Segment enables the Ground-Based Midcourse Defense (GMD) Weapon System (GWS) to provide the combatant commands, including USNORTHCOM, with a continuously available (24 hours a day, 7 days a week, 365 days a year) Homeland Defense Weapon System. The GWS contributes to the Missile Defense System by acquiring, developing, demonstrating, deploying, and sustaining an operational Weapon System with Ground Based Interceptors, development of a GWS with a mixed-fleet of Ground Based Interceptors and Next Generation Interceptors, improved Warfighter capabilities, and Interceptor Fleet Management. The GWS leverages integration of Missile Defense sensors from across the globe and enables the Ground Based Interceptor to deliver a single kill vehicle to counter allocated threats in space during the midcourse phase of the threat's ballistic trajectory. The Ground Systems consist of the GFC, GMD Communications Network (GCN) / GWS Network Infrastructure (GNI), IDT, and GSS. The GFC consists of two (2) GFC nodes at Fort Greely, Alaska (FGA) and at the Missile Defense Integration and Operations Center in Colorado Springs, Colorado. The GFC plans midcourse engagements and provides the human-in-control interface to the Warfighter. As a critical component of Ground Systems, the GFC supports decision-making and command execution. The GCN is the communications network for the GWS and network connection to the Missile Defense System. The GNI serves as a common secure platform improving real-time cyber integration and the ability to detect and respond to cyber events. The IDTs are located at FGA (2); Vandenberg Space Force Base, California (VSFB) (2); Eareckson Air Station, Alaska (1); and Fort Drum, New York (1). The IDTs provide secure communications from the GFC to the in-flight interceptors. The GSS consists of the Launch Support System and Missile Field / Launch Site Components located at FGA and VSFB and provides the hardware and software interfaces between the GFC and the interceptors. The Ground-Based Midcourse Defense Program provides USNORTHCOM with a solution that is lethal across the specified threat space, upgradeable to address future and advancing threats, and fully integrated into the Missile Defense System as demonstrated through flight and ground testing. In addition, product improvements will provide USNORTHCOM with the capability to operate the GWS with a mixed fleet of Ground Based Interceptors and Next Generation Interceptors while maintaining a$$, 767520000, NULL, NULL, NULL, NULL, 9245140000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603882C_MD40$$, $$0603882C$$, $$MD40$$, $$Program-Wide Support$$, 28081000, $$PWS contains non-headquarters management costs in support of Missile Defense Agency (MDA) functions and activities across the entire Missile Defense System. These functions include Government Civilians and Contract Support Services. This effort provides integrity and oversight of the Missile Defense System as well as supports MDA in the development and evaluation of technologies that will respond to the changing threat. Additionally, PWS includes personnel to support global deployments performing deployment site preparation and activation, and provides facility capabilities for MDA Executing Agent locations worldwide. Other MDA wide costs include: physical and technical security; civilian drug testing; audit readiness; the Science, Technology, Engineering, and Mathematics (STEM) program; legal services and settlements; travel and agency training; office, equipment, vehicle, and warehouse leases; utilities and base operations across multiple geographic locations; commercial and ancillary facility services; management of all facility aspects regardless of lifecycle stage; supplies and maintenance; compliance with statutory environmental requirements; data and unified communications support; materiel and readiness and central property management of equipment; Facilities Sustainment, Restoration and Modernization (FSRM) program (formerly Real Property Maintenance) to keep the Department's inventory of facilities in good working order; and similar operating expenses. PWS is allocated on a pro-rata basis across most Agency PEs; therefore, fluctuates per PE by FY based on the total Agency budget in that FY.$$, 28081000, NULL, NULL, NULL, NULL, 331069000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603884C_MD11$$, $$0603884C$$, $$MD11$$, $$BMDS Radars$$, 156128000, $$The Missile Defense System Radars project includes developing future Army Navy/Transportable Radar Surveillance and Control-2 (AN/TPY-2), U.S. Space Force (USSF) COBRA DANE (CD), Long Range Discrimination Radar (LRDR), Sea Based X-Band (SBX), and USSF Upgraded Early Warning Radars (UEWR) capabilities through system engineering, software development, and testing support. Modeling and Simulation (M&S) efforts include enhanced sensor models, development of Radio Frequency scene generators, integration of simulations into the Missile Defense System M&S architecture, and Verification, Validation, and Certification of radar models. This project also funds participation and support for Missile Defense System ground and flight test campaigns and Warfighter games and exercises. This project provides the development of discrimination advanced algorithms for Missile Defense System radars to counter evolving threats. The discrimination improvement effort will develop and field integrated element capabilities to improve the Missile Defense System's ability to identify lethal and non-lethal objects. This project will continue the development of discrimination improvement midterm design and test support for Missile Defense System radars and far-term trade analysis and planning.$$, 156128000, NULL, NULL, NULL, NULL, 2804489000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603884C_MD40$$, $$0603884C$$, $$MD40$$, $$Program-Wide Support$$, 21582000, $$PWS contains non-headquarters management costs in support of Missile Defense Agency (MDA) functions and activities across the entire Missile Defense System. These functions include Government Civilians and Contract Support Services. This effort provides integrity and oversight of the Missile Defense System as well as supports MDA in the development and evaluation of technologies that will respond to the changing threat. Additionally, PWS includes personnel to support global deployments performing deployment site preparation and activation, and provides facility capabilities for MDA Executing Agent locations worldwide. Other MDA wide costs include: physical and technical security; civilian drug testing; audit readiness; the Science, Technology, Engineering, and Mathematics (STEM) program; legal services and settlements; travel and agency training; office, equipment, vehicle, and warehouse leases; utilities and base operations across multiple geographic locations; commercial and ancillary facility services; management of all facility aspects regardless of lifecycle stage; supplies and maintenance; compliance with statutory environmental requirements; data and unified communications support; materiel and readiness and central property management of equipment; Facilities Sustainment, Restoration and Modernization (FSRM) program (formerly Real Property Maintenance) to keep the Department's inventory of facilities in good working order; and similar operating expenses. PWS is allocated on a pro-rata basis across most Agency PEs; therefore, fluctuates per PE by FY based on the total Agency budget in that FY.$$, 21582000, NULL, NULL, NULL, NULL, 154927000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603890C_MC30$$, $$0603890C$$, $$MC30$$, $$Cyber Operations$$, 73997000, $$Cyber Operations supports Defense Modernization and Missile Defense Agency (MDA) Chief Information Officer (CIO) priorities to fully support network command, control and communications and Cybersecurity, increase system reliability to build warfighter confidence, and address advanced cyber threats. MDA's Office of the CIO has prioritized four program topics: (1) Detect, Analyze and Mitigate Intrusions; (2) Preventing Malicious Cyber Activity; (3) Planning, Policy, Workforce Development and Management; and (4) Continuous Monitoring Tools. In order to support the prioritized program topics, MDA must implement a multi-tiered cybersecurity monitoring and risk management capability to protect critical Missile Defense System data and systems from rapidly evolving internal and external threats.$$, 73997000, NULL, NULL, NULL, NULL, 468024000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603890C_MC31$$, $$0603890C$$, $$MC31$$, $$Engineering Cyber Operations$$, 19335000, $$Engineering and Cyber Operations provides monitoring and tracking of Cybersecurity mitigations detailed in Information Technology security Plan of Action and Milestones. Activities include preparation of certification and accreditation documentation and accreditation recommendations to the Missile Defense Agency (MDA) Senior Information Assurance Officer/Certification Authority and Designated Approving Authority. Independent Verification and Validation team actions ensure the availability, integrity, authentication, confidentiality and non-repudiation of the MDA mission, test and administrative systems. Activities are necessary to comply with the Federal Information Security Management Act. Engineering and Cyber Operations implements Risk Management Framework system engineering principles as specified within the Department of Defense (DoD) Instruction DoD 8510.01 to acquire, design, test, implement and field technical solutions throughout the systems architecture to ensure sufficient protections exist from a threat and risk-based approach. MDA's goal is to ensure Cybersecurity engineering principles flow into system requirements and design specifications early to provide the most cost benefit and ensure security controls are aligned with the National Institute of Standards and Technology 800-53a security controls as applicable to systems categorized as National Security Systems. Technical Intelligence Cybersecurity provides comprehensive cybersecurity risk reduction functions and services in support of both internal and external MDA stakeholders in order to strengthen confidence in MDA systems. This effort includes working with DIB partners to ensure protection of MDA critical information, and implementation of an Agency-wide Supply Chain Risk Management program. The Trusted Workforce Security program identifies, deters, and mitigates potential insider threats. These Presidentially and DoD-mandated efforts include a Counter- Insider Threat Program, a Personnel Security Program and a Special Security Office.$$, 19335000, NULL, NULL, NULL, NULL, 153302000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603890C_MD21$$, $$0603890C$$, $$MD21$$, $$Homeland Cruise Missile Defense$$, 0, $$In response to United States Northern Command's requirements for Cruise Missile Defense of the Homeland (CMD-H), The Missile Defense Agency developed systems architecture and conducted a Joint Tactical Integrated Fire Control (JTIFC) demonstration. The effort included developing systems engineering requirements, software modifications, models and simulations, and integration of joint sensors and shooters into a fire control network for the JTIFC demonstration in fiscal year (FY) 2023 and completion of related demo analysis in FY 2024.$$, 0, NULL, NULL, NULL, NULL, 25771000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603890C_MD24$$, $$0603890C$$, $$MD24$$, $$System Engineering & Integration$$, 179651000, $$System Engineering & Integration (SE&I) defines, designs, tests and integrates the Missile Defense System, and provides analysis, decision support and planning activities for real-world operations to the National Command Authority, Joint Staff, Military Services, Combatant Commanders, Operational Test Agencies, Director of Operational Test and Evaluation, Allies, and others. SE&I Major Program Goals: - Plan, design, develop, integrate, and test a layered Missile Defense System that provides the required performance. - Provide System-level engineering to Missile Defense System Elements, and lead collaborative cross-Element, cross-Component engineering. - Maintain the Capability Gap Tracker (CGT) to systematically track and prioritize the capability gaps in the Missile Defense Agency (MDA) Program of Record (POR), with respect to forecasted threat. - Plan, design, develop future architecture plans into integrated engineering requirements. - Analyze architecture alternatives and new technologies, and develop requirements to respond to the proliferation of short, medium, and long-range advanced missile threats. - As technical authority for IAMD, provide a consistent, disciplined systems engineering process using a multi-Service team to integrate Joint IAMD systems. - Provide System-level forums to track, assess, and improve hardware and software reliability. - Assess Missile Defense System capabilities and limitations. - Develop performance assessment requirements and evaluate new capabilities in support of fielding decisions. - Identify critical conditions and data required to develop test campaigns to demonstrate Missile Defense System performance. - Identify System issues occurring in ground and flight tests and lead the effort to resolve. - Ensure the Missile Defense System is complementary to and interoperable with North Atlantic Treaty Organization (NATO) and other theater systems. - Develop and field integrated Element capabilities to improve the capability to identify lethal reentry vehicles and non-lethal threat objects.$$, 179651000, NULL, NULL, NULL, NULL, 1711162000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603890C_MD28$$, $$0603890C$$, $$MD28$$, $$Intelligence & Security$$, 60258000, $$The Intelligence and Security program provides multi-disciplinary intelligence, security, and engineering for Missile Defense System acquisition, development, test and deployment. The Intelligence and Security Major Program Goals are: - Ensure the Intelligence Community (IC) understands and fulfills the Missile Defense Agency's (MDA's) current and future prioritized intelligence requirements; advocate Missile Defense development and test intelligence requirements. - Leverage available National and Department of Defense (DoD) Counterintelligence resources. Ensure counterintelligence products and services are fully integrated into all Research, Development, Test, and Evaluation programs and activities to protect classified information and critical technologies and to protect MDA and Missile Defense System personnel, facilities, information and activities. - Provide cross-Agency acquisition security oversight and support for robust acquisition program protection, to include the identification and protection of Critical Program Information. Implement MDA's information security and declassification programs. Strengthen Test and Operations Security across the Agency. Manage Agency regulatory declassification and information security program. Provide physical security policy for Missile Defense System weapon/sensor deployments, including Foreign Military Sales. - Produce threat definitions and model packages, Adversary Data Packages, and Flight Test Target Requirements and Target System Performance Specifications; provide Real World Event analysis. These efforts provide critical information regarding threat missile system capabilities; protection of personnel, activities, and technology from espionage and terrorism; and identification and mitigation of Missile Defense System vulnerabilities.$$, 60258000, NULL, NULL, NULL, NULL, 446282000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603890C_MD30$$, $$0603890C$$, $$MD30$$, $$BMD Information Management$$, 145342000, $$The Missile Defense System Information Management Systems budget project funds information technology mission critical functions necessary for the efficient operations and safeguarding of Missile Defense System information in compliance with Department of Defense (DoD) policies and in keeping pace with the ever- growing cyber threat which is one of the most serious economic and national security challenges we face. IT is critical to the day-to-day functions of MDA personnel to communicate (classified and unclassified) with each other, Congress, senior DoD and other United States Government agency personnel, Combatant Commanders, North Atlantic Treaty Organization partners, and other industry partners. Communication among these organizations facilitates the MDA mission of developing and fielding an integrated Missile Defense System to defend the United States, our deployed forces, allies, and friends against all ranges of enemy ballistic missiles in all phases of flight. MDA information management systems capabilities support rigorous missile defense Research, Development, Test and Engineering (RDT&E) and facilitate the development of technologies to guard against evolving missile threats. Communications are vital for missile defense to continue a viable homeland defense against rogue threats and to provide the integration required to defend deployed forces, allies, and friends against theater threats. Missile Defense System information management consists of MDA Special Purpose Processing Nodes (SPPNs), IT systems, data centers, operations and monitoring centers which are vital to support the strategic mission of the Agency and necessary to meet disaster recovery and continuity of operations requirements. This infrastructure is required to sustain access to the Secret Internet Protocol Router Network, Non-secure Internet Protocol Router Network, MDA classified and unclassified networks, classified and unclassified video teleconferencing services, test and business knowledge data centers, and the Defense Research Engineering Network (DREN). These mission critical functions provide for the efficient operation and safeguarding of all agency information in locations supporting MDA around the world. Project MD30 is aligned into the following inter-agency mission critical IT services and the associated plans in accordance with the Federal Information Technology Shared Services Strategy. 1. End User Support. 2. SPPNs. 3. IT Planning and Solutions.$$, 145342000, NULL, NULL, NULL, NULL, 912077000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603890C_MD31$$, $$0603890C$$, $$MD31$$, $$Modeling & Simulation$$, 61729000, $$The Missile Defense Agency's (MDA's) Modeling and Simulation (M&S) program consists of system and product planning, development, integration, and operation; threat model development, verification, and analysis; and integration and deployment of improved M&S capabilities. Models and simulations are tailored to the specific needs of the Agency's test events and to match Missile Defense System components in their various stages of development, ranging from low-to-medium fidelity analyses supporting concept definitions studies, to high-fidelity models used to support engineering level activities. MDA validates and accredits System-level models and simulations by anchoring them to ground and flight test events, per the Integrated Master Test Plan (IMTP), to enable accurate and comprehensive assessments. MDA's M&S systems and products provide analysis, decision-making, and planning capabilities for Real-World Operations to inform the National Command Authority, Joint Staff, Military Services, North Atlantic Treaty Organization, Combatant Commanders (CCMDs), Operational Test Authority (OTAs), Director of Operational Test & Evaluation (DOT&E), and Allies. MDA's M&S Program executes a single, integrated, and synchronized program to manage M&S development and sustainment; improves System Flight and Ground Test execution and provides a digital assessment venue; leverages MDA test activities to collect data to anchor models and simulations; and supports Warfighter training and tactics validation. The M&S program also addresses the following key elements of DOT&E assessments: Ensure that future M&S architectures are composable and flexible, and simplify the integration process to conserve resources and improve capabilities; Ensure that future M&S architectures incorporate and require the use of consistent truth representations (phenomenology, lethality, environmental factors, threat simulations, etc.); Improve cross-organizational system engineering processes to optimize requirements generation and ensure the inclusion of all stakeholders; Develop refined M&S accreditation criteria between MDA and the OTA; Enable top-down systems engineering and management of agency-wide M&S federations.$$, 61729000, NULL, NULL, NULL, NULL, 679067000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603890C_MD32$$, $$0603890C$$, $$MD32$$, $$Quality, Safety, and Mission$$, 34546000, $$Quality, Safety, and Mission Assurance ensures that the Missile Defense System and all of its elements are designed, tested and operated in a reliable, safe, and effective manner. Quality and Mission Assurance: Responsible for ensuring the reliable and effective design, test and operation of the Missile Defense System and all of its elements. Develops and ensures implementation of quality and mission assurance requirements. Mitigates quality and mission assurance risks to the lowest practical level. Provides in-plant Missile Defense Agency (MDA) Assurance Representatives at MDA government and contractor facilities to provide quality and mission assurance oversight of contractor manufacturing and integration. Performs Quality and Mission Assurance Assessments to ensure contractual requirements, internal requirements, and industry best practices are implemented at prime contractor and lower tier suppliers. Reviews and approves all new and modified parts, materials and critical processes for Missile Defense System elements. Assess Missile Defense industrial base and determine critical manufacturing technologies. Conduct assessments of critical component supply base and update critical technologies database. Collaborate with national security space components on investment strategies for critical technologies. Develop engineering management tool to characterize supply chain risks. Utilize supply chain risk identification and mitigation tracking system to mitigate manufacturing supply issues for critical components. Safety: Responsible for ensuring the safe design, test and operation of the Missile Defense System and all of its elements. Develops and ensures implementation of safety requirements. Mitigates safety risks to the lowest practical level. Ensures a safe workplace for all MDA employees and contractors by implementing a Safety program. Missile Defense System Safety Officers provide on-site support at the Missile Defense Integration and Operations Center 24 hours a day, 7 days a week, 365 days a year to ensure operational safety of the Missile Defense System.$$, 34546000, NULL, NULL, NULL, NULL, 420301000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603890C_MD40$$, $$0603890C$$, $$MD40$$, $$Program-Wide Support$$, 26219000, $$PWS contains non-headquarters management costs in support of Missile Defense Agency (MDA) functions and activities across the entire Missile Defense System. These functions include Government Civilians and Contract Support Services. This effort provides integrity and oversight of the Missile Defense System as well as supports MDA in the development and evaluation of technologies that will respond to the changing threat. Additionally, PWS includes personnel to support global deployments performing deployment site preparation and activation, and provides facility capabilities for MDA Executing Agent locations worldwide. Other MDA wide costs include: physical and technical security; civilian drug testing; audit readiness; the Science, Technology, Engineering, and Mathematics (STEM) program; legal services and settlements; travel and agency training; office, equipment, vehicle, and warehouse leases; utilities and base operations across multiple geographic locations; commercial and ancillary facility services; management of all facility aspects regardless of lifecycle stage; supplies and maintenance; compliance with statutory environmental requirements; data and unified communications support; materiel and readiness and central property management of equipment; Facilities Sustainment, Restoration and Modernization (FSRM) program (formerly Real Property Maintenance) to keep the Department's inventory of facilities in good working order; and similar operating expenses. PWS is allocated on a pro-rata basis across most Agency PEs; therefore, fluctuates per PE by FY based on the total Agency budget in that FY.$$, 26219000, NULL, NULL, NULL, NULL, 279398000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603892C_MC09$$, $$0603892C$$, $$MC09$$, $$Cyber Operations$$, 6581000, $$Sustain the Department of Defense (DoD) Risk Management Framework (RMF) Certification and Accreditation (C&A) process and Controls Validation Testing (CVT) activities, analysis of validation results, risk assessments and reviews of proposed Program Manager/Information Systems Security Manager. This project supports the monitoring and tracking of Cybersecurity mitigation detailed in Information Technology Security Plan of Action and Milestones. Activities include preparation of Certification and Accreditation documentation and accreditation recommendations to the Missile Defense Agency Authorizing Official. Independent Verification and Validation team actions ensure the availability, integrity, authentication, confidentiality and non-repudiation of the Aegis mission and non- mission systems, which includes test and remote site administrative systems. Activities in the Project are necessary to comply with the Federal Information Security Management Act. The Standard Missile-3 (SM-3) Block IB and IIA missiles and corresponding Aegis Ballistic Missile Defense (BMD) weapon systems communication requires hardware and software development and integration testing to enable new cyber security capabilities. Activities include Encoder/Decoder, Plate 3 Circuit Card Assemblies (CCA) and Mission Computer CCA updates. After missile and baseline specific efforts are complete, significant integration testing is required.$$, 6581000, NULL, NULL, NULL, NULL, 52945000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603892C_MD09$$, $$0603892C$$, $$MD09$$, $$Aegis BMD$$, 397053000, $$Aegis Based Defense continues development of a Sea-Based Ballistic Missile Defense (BMD) capability in support of the Missile Defense Agency (MDA) mission to protect the homeland, deployed forces, friends and allies from ballistic missile threats of all ranges and in all stages of flight. Systems Engineering and Integration performs requirements development, engineering analysis, capability integration, and performance verification for Aegis BMD development and Missile Defense System integration. Aegis BMD Technology Design and Insertion enables cross-baseline specification management and capability assessments to ensure consistent application of technical standards, processes, and procedures across the Aegis BMD program. Aegis BMD specific efforts include: systems engineering and architecture (process and execution); Modeling and Simulation (M&S); Verification and Validation (V&V) test and evaluation support; ship integration; and quality, safety, and mission assurance. V&V efforts in this accomplishment are performed at the Aegis BMD element level, which feed into the overall Missile Defense System level. Aegis Baseline (BL) 5.4.1 (BMD 4.2) is a joint effort with the United States (U.S.) Navy that refurbishes existing ship AN/SPY-1 radar arrays with the installation of antenna Low Noise Amplifiers (LNAs). As a result of cost growth and schedule delay, MDA and Navy jointly realigned the LNA program to include hardware and software upgrades with no LNA hardware procurements. The restructured program referred to as BMD 4.1.3 will develop spiral capability for the non-LNA upgrades beginning in FY 2024 to include Sea Based Terminal Increment 2 Capability Upgrade, Hypersonic Tracking and Reporting, Mission Planner Console update, and Threat Database re-architecture. This capability will deliver to 21 Flight I/II Guided Missile Destroyer (DDG) ships beginning in FY 2025. Aegis BL 9 (BMD 5.1.5 and 5.2 (previously BMD 5.1.6)) software spiral aligns with U.S. Navy Aegis BL 9 Capability Package (CP) 2024 and Aegis BL 9.C3. The software spiral provides enhanced detection, track, report, and defeat capabilities of additional medium, intermediate, and long-range threats with increasingly complex engagement scenes and increased raid sizes. Through a series of unique Capability Insertion Packages, BMD 5.X capability spirals provide continuous software updates to the original BMD 5.1.0 architecture to incorporate emerging Missile Defense System capabilities, War fighter improvements, SM-3 software updates, and improved Weapon System performance necessary to pace the threat. Aegis BL 9 (BMD 5.1.5 and 5.2) software spiral includes support for technology maturation and prototyping that will demonstrate enhanced Missile Defense tracking performance against longer range and more sophisticated threats in challenging and complex environments.$$, 397053000, NULL, NULL, NULL, NULL, 4150586000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603892C_MD40$$, $$0603892C$$, $$MD40$$, $$Program-Wide Support$$, 31507000, $$PWS contains non-headquarters management costs in support of Missile Defense Agency (MDA) functions and activities across the entire Missile Defense System. These functions include Government Civilians and Contract Support Services. This effort provides integrity and oversight of the Missile Defense System as well as supports MDA in the development and evaluation of technologies that will respond to the changing threat. Additionally, PWS includes personnel to support global deployments performing deployment site preparation and activation, and provides facility capabilities for MDA Executing Agent locations worldwide. Other MDA wide costs include: physical and technical security; civilian drug testing; audit readiness; the Science, Technology, Engineering, and Mathematics (STEM) program; legal services and settlements; travel and agency training; office, equipment, vehicle, and warehouse leases; utilities and base operations across multiple geographic locations; commercial and ancillary facility services; management of all facility aspects regardless of lifecycle stage; supplies and maintenance; compliance with statutory environmental requirements; data and unified communications support; materiel and readiness and central property management of equipment; Facilities Sustainment, Restoration and Modernization (FSRM) program (formerly Real Property Maintenance) to keep the Department's inventory of facilities in good working order; and similar operating expenses. PWS is allocated on a pro-rata basis across most Agency PEs; therefore, fluctuates per PE by FY based on the total Agency budget in that FY.$$, 31507000, NULL, NULL, NULL, NULL, 90642000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603892C_MM09$$, $$0603892C$$, $$MM09$$, $$Aegis BMD SM-3 Development$$, 27493000, $$Provides development of SM-3 Missiles, Upgrade Modifications, and Integration into the Aegis Weapon System and support Golden Dome for America expeditionary sites. The SM-3 Block IB improves Aegis Based Defense ability to expand the BMD battlespace, engage longer range, more sophisticated ballistic missiles that may deploy countermeasures and launch in larger raid sizes. The SM-3 Block IB Kinetic Warhead's two color infrared seeker and advanced signal processor provides a real-time discrimination and characterization capability while improving sensitivity for longer range targets. SM-3 Block IB provides capability in the exo-atmospheric region at a reduced cost, allowing SM-3 Block IIA All-Up Rounds to attack the more complex missile threats. The SM-3 Block IB missile is a vital piece of the layered Missile defense that Aegis Based Defense provide our nation. The SM-3 Block IIA consists of an upgrade to a 21-inch diameter SM-3 missile and expands beyond the SM-3 Block IB battlespace to counter Intermediate Range Ballistic Missile. SM-3 Block IIA provides an increased kinematic envelope through improved infrared discrimination and divert capability that provide performance against the European Phased Approach phase III expanded threat set. When combined with Aegis BMD 5.1 weapon system modifications, the SM-3 Block IIA will provide Engage on Remote (EoR) capability, which allows the use of remote off board sensor information to launch and guide the SM-3 Block IIA to final intercept. Aegis BMD 5.1 EoR capability with SM-3 Block IIA also frees up radar resources and increases the number and type of threats to be engaged simultaneously over previous baselines.$$, 27493000, NULL, NULL, NULL, NULL, 1052968000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603898C_MC03$$, $$0603898C$$, $$MC03$$, $$Cyber Operations$$, 170000, $$This program verifies and validates that cybersecurity and/or cybersecurity-enabled products (firewalls, data/network encryption devices, routers, Intrusion Detection Systems, etc.) used within the Missile Defense Agency (MDA) infrastructure have a current and Evaluated Assurance Level (EAL) certification and rating. They assure that validated information technology (IT) products are listed on the Department of Defense (DoD) Approved Products List Integrated Tracking System (APLITS). There is an additional requirement to routinely identify findings and prepare a report with recommendations. This support is required in the IT product evaluation. Activities in the Project are necessary to comply with the Federal Information Systems Modernization Act of 2014.$$, 170000, NULL, NULL, NULL, NULL, 752000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603892C_MX09$$, $$0603892C$$, $$MX09$$, $$Aegis BMD Development Support$$, 125806000, $$Provides Government, contractor, and Federally Funded Research and Development Center (FFRDC) workforce that manage the overall Aegis Based Defense program and enables the program to develop, build, and test standard missiles and associated Aegis Weapons Systems. Aegis Based Defense, in accordance with negotiated agreements between the Unites States (U.S.) Navy and the Missile Defense Agency (MDA) has identified and segregated funding for Developmental Support of Aegis Based Defense specific elements resident aboard Aegis capable U.S. Navy ships. Computer Program Support consists of, but is not limited to, reviews of Technical Observation Reports (TORs) that are generated by ship crews during exercises or deployments, determination of root causes and preparation of Computer Program Change Request (CPCR) to correct TORs, updates to the in-service computer program to apply, test and certify multiple CPCRs, and tests installation of Aegis Weapon System (Army/Navy Surface Radar Surveillance and Control Radar/Fire Control System) alignment updates as required. Aegis Based Defense provides support to Annual Integration Events to ensure any updated Aegis Combat System computer programs do not degrade BMD equipped ships and provides distance and technical support for Ballistic Missile Defense (BMD) equipped ships. Provides Fleet operations and mission support to enable the conduct of sustained BMD operation.$$, 125806000, NULL, NULL, NULL, NULL, 1113288000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603896C_MC01$$, $$0603896C$$, $$MC01$$, $$Cyber Operations$$, 8313000, $$Command and Control, Battle Management & Communication (C2BMC) Cyber Operations sustain the Missile Defense Agency (MDA) Risk Management Framework (RMF) and Security Controls Assessments/Controls Validation Testing activities, analysis of validation results, risk assessments, and reviews of proposed Program Manager/Information System Security Manager Plan of Action and Milestones (POA&Ms) and Cybersecurity Tools for MDA C2BMC mission systems. Activities in this Project are necessary to comply with the Federal Information Systems Modernization Act.$$, 8313000, NULL, NULL, NULL, NULL, 100249000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603896C_MD01$$, $$0603896C$$, $$MD01$$, $$Command & Control, Battle$$, 390298000, $$Provides incremental development, deployment, and operational support of C2BMC capabilities required for Missile Defense System planning, situational awareness, sensor management, and engagement coordination. The FY 2019 National Defense Authorization Act section 869 recognized C2BMC for its implementation of this iterative practice and directed C2BMC's inclusion in a Community of Practice to advise on agile or iterative development. C2BMC delivers capabilities incrementally with each software build (named as a Spiral or Capability Build), adding to or enhancing the capability of the previous build. C2BMC incremental delivery of Spiral 8.2 provides critical Homeland Defense for increased Ground-based Midcourse Defense (GMD) battlespace, improved threat tracking using multiple sensors communicating via Link-16, enhanced sensor tasking to meet track quality and discrimination timeliness requirements, Space Domain Awareness (SDA) tasking support, and improved cyber capabilities. Enhanced Homeland Defense also integrates the Ballistic Missile Defense System Overhead Persistent Infrared (OPIR) Architecture (BOA) with the Missile Defense System to enhance system level missile-tracking capabilities through earlier cueing of radars and weapon systems. European Phased Adaptive Approach Phase 3/Engage-on-Remote (EOR) (Spiral 8.2-3) provides critical sensor management capability, greater engagement flexibility, improved OPIR-based cueing, and enhanced Aegis Ballistic Missile Defense (BMD) defended area by enabling Aegis to use Army Navy/Transportable Radar Surveillance and Control-2 Radar (AN/TPY-2) data for EOR engagements, providing a five-fold increase in defended area coverage in the United States (U.S.) Central Command and U.S. European Command area of responsibility compared to individual weapon system organic capability. Spiral 8.2-3 also includes SDA and integrates Mobile Sensor Integration Phase 1 and BOA data into the Missile Defense System.$$, 390298000, NULL, NULL, NULL, NULL, 3747486000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603896C_MD40$$, $$0603896C$$, $$MD40$$, $$Program-Wide Support$$, 35199000, $$PWS contains non-headquarters management costs in support of Missile Defense Agency (MDA) functions and activities across the entire Missile Defense System. These functions include Government Civilians and Contract Support Services. This effort provides integrity and oversight of the Missile Defense System as well as supports MDA in the development and evaluation of technologies that will respond to the changing threat. Additionally, PWS includes personnel to support global deployments performing deployment site preparation and activation, and provides facility capabilities for MDA Executing Agent locations worldwide. Other MDA wide costs include: physical and technical security; civilian drug testing; audit readiness; the Science, Technology, Engineering, and Mathematics (STEM) program; legal services and settlements; travel and agency training; office, equipment, vehicle, and warehouse leases; utilities and base operations across multiple geographic locations; commercial and ancillary facility services; management of all facility aspects regardless of lifecycle stage; supplies and maintenance; compliance with statutory environmental requirements; data and unified communications support; materiel and readiness and central property management of equipment; Facilities Sustainment, Restoration and Modernization (FSRM) program (formerly Real Property Maintenance) to keep the Department's inventory of facilities in good working order; and similar operating expenses. PWS is allocated on a pro-rata basis across most Agency PEs; therefore, fluctuates per PE by FY based on the total Agency budget in that FY.$$, 35199000, NULL, NULL, NULL, NULL, 238323000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603896C_MT01$$, $$0603896C$$, $$MT01$$, $$C2BMC Test$$, 59744000, $$Command and Control, Battle Management and Communications (C2BMC) Test supports system flight and ground testing, wargames, and exercises as detailed in the Missile Defense Agency (MDA) Integrated Master Test Plan (IMTP) to ensure C2BMC capabilities delivered are consistent with the Prioritized Capabilities List and are interoperable with other Missile Defense System components. MDA gains efficiencies and minimizes laboratory resource requirements (footprint, personnel, and hardware) by utilizing the C2BMC Test Facility and the Overhead Persistent Infrared Architecture (OPIR) Capabilities Lab (OCL) test infrastructure as the laboratory environment supporting System Test, Development, and Sustainment. For System Ground and Flight Test, the labs are used for pre-test analysis, test execution, and post-test analysis. For Development, the labs are utilized for software verification and validation testing and system integration testing. For Sustainment, the labs are used to assist with root cause determination for issues discovered on the fielded system and validation of any required software patches.$$, 59744000, NULL, NULL, NULL, NULL, 601075000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603896C_MX01$$, $$0603896C$$, $$MX01$$, $$Command & Control, Battle$$, 140629000, $$Command and Control, Battle Management and Communications (C2BMC) Development Support provides operations engineering, integrated logistics, warfighter integration, deployment, and disposal of the current operational system and/or systems fielded in United States Strategic Command, United States Northern Command (USNORTHCOM), United States Indo-Pacific Command (USINDOPACOM), United States European Command (USEUCOM), United States Central Command (USCENTCOM), and U.S. Space Command (USSPACECOM) and the operation of the C2BMC Control Center. This activity provides continuous support of the development, deployment, sustainment of the C2BMC training systems, and updates training material to stay current with fielded capabilities.$$, 140629000, NULL, NULL, NULL, NULL, 1223758000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603898C_MD03$$, $$0603898C$$, $$MD03$$, $$Joint Warfighter Support$$, 20174000, $$There are seven primary functions in Joint Warfighter Support (MD03): (1) Missile Defense Operations Support. (2) Combatant Command Integration. (3) Military Service Integration. (4) Operational Missile Defense System Verification and Validation. (5) Warfighter Training and Education Support. (6) Joint Staff Integration. (7) Reserve Integration. Detailed descriptions and accomplishments are provided in section B. Accomplishments/Planned Program.$$, 20174000, NULL, NULL, NULL, NULL, 188323000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603898C_MD40$$, $$0603898C$$, $$MD40$$, $$Program-Wide Support$$, 1584000, $$PWS contains non-headquarters management costs in support of Missile Defense Agency (MDA) functions and activities across the entire Missile Defense System. These functions include Government Civilians and Contract Support Services. This effort provides integrity and oversight of the Missile Defense System as well as supports MDA in the development and evaluation of technologies that will respond to the changing threat. Additionally, PWS includes personnel to support global deployments performing deployment site preparation and activation, and provides facility capabilities for MDA Executing Agent locations worldwide. Other MDA wide costs include: physical and technical security; civilian drug testing; audit readiness; the Science, Technology, Engineering, and Mathematics (STEM) program; legal services and settlements; travel and agency training; office, equipment, vehicle, and warehouse leases; utilities and base operations across multiple geographic locations; commercial and ancillary facility services; management of all facility aspects regardless of lifecycle stage; supplies and maintenance; compliance with statutory environmental requirements; data and unified communications support; materiel and readiness and central property management of equipment; Facilities Sustainment, Restoration and Modernization (FSRM) program (formerly Real Property Maintenance) to keep the Department's inventory of facilities in good working order; and similar operating expenses. PWS is allocated on a pro-rata basis across most Agency PEs; therefore, fluctuates per PE by FY based on the total Agency budget in that FY.$$, 1584000, NULL, NULL, NULL, NULL, 25065000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603898C_MT03$$, $$0603898C$$, $$MT03$$, $$Joint Warfighter Support Test$$, 23830000, $$Joint Warfighter Support Test provides support to Missile Defense System Wargames and Exercises. Wargames and Exercises: - Support the Warfighter to plan and conduct worldwide Wargames and Exercises supporting Missile Defense System development and fielding. - Enable the Warfighter to define, test, deploy, and employ new missile defense capabilities. - Support Joint Functional Component Commander (JFCC) for Integrated Missile Defense (IMD) Missile Defense System Table Top Exercises (TTX) to facilitate the global missile defense capability and to refine the European capability concept of operations through low-fidelity demonstration Models & Simulation (M&S). - Continue test planning for Wargames and Exercises.$$, 23830000, NULL, NULL, NULL, NULL, 215222000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603904C_MC22$$, $$0603904C$$, $$MC22$$, $$Cyber Operations$$, 701000, $$The MDIOC conducts Cyber Defensive Operations through Key Management Infrastructure and Information Assurance Training which interfaces with the Information Technology/Information Assurance Enterprise to provide secure communications, network health and status monitoring, mission critical restoral capability, and technical expertise.$$, 701000, NULL, NULL, NULL, NULL, 5680000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603904C_MD22$$, $$0603904C$$, $$MD22$$, $$Missile Defense Integration and$$, 52493000, $$The MDIOC sustains and operates a 24 hours a day, 7 days a week, 365 days a year mission complex for research, development, testing, training, and operations for Missile Defense System activities. The MDIOC supports the Ground-based Midcourse Defense Mission Control Center Facility, as well as the Command, Control, Battle Management, and Communications (C2BMC) Integration and Test Centers and the C2BMC Experimentation Laboratories. It provides infrastructure support for the Space Sensors Missile Defense Space Center and the Targets and Countermeasures Mission Control Center - Targets. The MDIOC also provides developmental support to the Enterprise Sensors Laboratory composed of a common satellite ground station and sensor netting test bed for designated Missile Defense System elements. The MDIOC supports Missile Defense System test events based on the Integrated Master Test Plan. It supports Missile Defense System Critical Engagement Conditions testing and analysis through the operation of the Test Execution Control node for distributed Missile Defense System ground tests. During system flight tests, the MDIOC provides infrastructure (power; Heating, Ventilation and Air Conditioning; and communications) support to the Flight Test Director and crew, and ensures the protection of facility and test assets throughout the test window. Further, the MDIOC provides the facilities that support operations of the Missile Defense Element, manned by the U.S. Army 100th Missile Defense Brigade, the United States Northern Command, C2BMC Command and Control Center, and the United States Space Command's (USSPACECOM's) Joint Functional Component Command for Integrated Missile Defense. In addition, the MDIOC supports the Missile Defense Agency (MDA) Operations Support Center, which provides situational awareness on the health and status of the end-to-end Missile Defense System. The MDIOC hosts Missile Defense System wargames and exercises in support of the warfighter, and delivers the requisite infrastructure to integrate the modeling and simulation assets that form system-level constructive simulations for full-envelope Missile Defense System performance assessments, with surrogate capability for Missile Defense System ground tests. The MDIOC maintains a technical repository of Missile Defense System Implementation Architectures for real-time operations and configuration control; provides state change management and asset management technical support for the Missile Defense System; and provides the technical environment for Missile Defense System Watch Officers, Safety Officers, and Information Assurance Officers to perform their assigned duties. The MDIOC also supports the operations of the Joint Early Warning Laboratory, which provides USSPACECOM with quick response analyses of real-world launches, and rapid anomaly identification and resolution.$$, 52493000, NULL, NULL, NULL, NULL, 519979000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603904C_MD40$$, $$0603904C$$, $$MD40$$, $$Program-Wide Support$$, 1903000, $$PWS contains non-headquarters management costs in support of Missile Defense Agency (MDA) functions and activities across the entire Missile Defense System. These functions include Government Civilians and Contract Support Services. This effort provides integrity and oversight of the Missile Defense System as well as supports MDA in the development and evaluation of technologies that will respond to the changing threat. Additionally, PWS includes personnel to support global deployments performing deployment site preparation and activation, and provides facility capabilities for MDA Executing Agent locations worldwide. Other MDA wide costs include: physical and technical security; civilian drug testing; audit readiness; the Science, Technology, Engineering, and Mathematics (STEM) program; legal services and settlements; travel and agency training; office, equipment, vehicle, and warehouse leases; utilities and base operations across multiple geographic locations; commercial and ancillary facility services; management of all facility aspects regardless of lifecycle stage; supplies and maintenance; compliance with statutory environmental requirements; data and unified communications support; materiel and readiness and central property management of equipment; Facilities Sustainment, Restoration and Modernization (FSRM) program (formerly Real Property Maintenance) to keep the Department's inventory of facilities in good working order; and similar operating expenses. PWS is allocated on a pro-rata basis across most Agency PEs; therefore, fluctuates per PE by FY based on the total Agency budget in that FY.$$, 1903000, NULL, NULL, NULL, NULL, 33481000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603906C_MD35$$, $$0603906C$$, $$MD35$$, $$Regarding Trench$$, 29608000, $$This program is reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program Annual Report to Congress.$$, 29608000, NULL, NULL, NULL, NULL, 152334000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603914C_MT04$$, $$0603914C$$, $$MT04$$, $$BMDS Test Program$$, 428214000, $$The Test Program provides consolidated Missile Defense Agency (MDA) capabilities and resources to support the management and execution of Missile Defense System and Element-level testing. The MDA Test Program is responsible for all Missile Defense System testing and relies on Missile Defense System Engineering to provide the system test objectives that define the test architecture by developing, updating, coordinating, and assessing the IMTP. The MDA Test Program plans and executes Missile Defense System test events and develops the necessary test policy, test plans, and test infrastructure to conduct an effective test program. The goals of this budget project are to sustain and improve a robust testing program and to enhance Modeling and Simulation (M&S) efforts to provide, in conjunction with flight and ground testing, confidence to the Combatant Commanders that the Missile Defense system works. Activities are grouped into six major areas: Golden Dome, Program Planning and Operations, Flight Test, Ground Test, Test Infrastructure, and Engineering & Test Analysis.$$, 428214000, NULL, NULL, NULL, NULL, 3582106000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603907C_MD40$$, $$0603907C$$, $$MD40$$, $$Program-Wide Support$$, 5761000, $$PWS contains non-headquarters management costs in support of Missile Defense Agency (MDA) functions and activities across the entire Missile Defense System. These functions include Government Civilians and Contract Support Services. This effort provides integrity and oversight of the Missile Defense System as well as supports MDA in the development and evaluation of technologies that will respond to the changing threat. Additionally, PWS includes personnel to support global deployments performing deployment site preparation and activation, and provides facility capabilities for MDA Executing Agent locations worldwide. Other MDA wide costs include: physical and technical security; civilian drug testing; audit readiness; the Science, Technology, Engineering, and Mathematics (STEM) program; legal services and settlements; travel and agency training; office, equipment, vehicle, and warehouse leases; utilities and base operations across multiple geographic locations; commercial and ancillary facility services; management of all facility aspects regardless of lifecycle stage; supplies and maintenance; compliance with statutory environmental requirements; data and unified communications support; materiel and readiness and central property management of equipment; Facilities Sustainment, Restoration and Modernization (FSRM) program (formerly Real Property Maintenance) to keep the Department's inventory of facilities in good working order; and similar operating expenses. PWS is allocated on a pro-rata basis across most Agency PEs; therefore, fluctuates per PE by FY based on the total Agency budget in that FY.$$, 5761000, NULL, NULL, NULL, NULL, 55730000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603907C_MX46$$, $$0603907C$$, $$MX46$$, $$Sea Based X-Band Radar$$, 161052000, $$This project provides radar capability development, operations, and support for the Sea Based X-Band Radar (SBX) and its three major sub-systems: the self-propelled vessel, the X-Band Radar (XBR), and the communications network.$$, 161052000, NULL, NULL, NULL, NULL, 1331502000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603913C_MD26$$, $$0603913C$$, $$MD26$$, $$Arrow Weapon System$$, 173000000, $$Israeli AWS: This system includes block upgrades to the AWS components which enhances capabilities against evolving medium range threats by increasing the total defended area. AWS elements include the Arrow-2 and Arrow-3 missiles and launchers, Citron Tree Battle Management Center (BMC), Green Pine (GP) and Super Green Pine (SGP) Radars, Lego Shield data interfaces, and Hazelnut Tree Launcher Control Centers (LCC). AWS Block 5 development incorporates a Long Range Detection Suite that consists of an Airborne Early Warning System (ABEWS) for enhanced sensor tracking, discrimination, and raid size capacity. In addition, the Sharp Eye ground-based sensor suite, the Arrow-4 interceptor and the Pine Woods Radar are being developed for integration into future AWS Blocks. The program also includes the continued development of Arrow's interoperability with U.S. Missile Defense System. The U.S. and State of Israel entered into a Memorandum of Understanding on September 2016, in which "Such funding, should over a ten year period beginning in FY 2019 and ending in FY 2028, be provided at a level of $500 million per year." (U.S. contributions only). These funds will be distributed between the Israeli Programs in Research Development Test & Evaluation and Procurement Funds.$$, 173000000, NULL, NULL, NULL, NULL, 1352645000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603913C_MD34$$, $$0603913C$$, $$MD34$$, $$Short Range Ballistic Missile$$, 127000000, $$Israeli SRBMD, also known as the DSWS, is designed to counter short range rockets, air breathing threats, medium caliber rockets, and theater ballistic missiles, and is integrated into the Israeli Missile Defense Architecture. The DSWS includes the Stunner Interceptor (Electro-Optical and All Weather variants), a Missile Firing Unit (MFU), a Multi-Mission Radar - Next Generation (MMR-NG), a Launch Site Controller, a Ground Data Link (GDL), and the Golden Almond Battle Management Center (GA BMC). The DSWS can be deployed in a variety of configurations to support the intended mission. The DSWS Block 3 capability expands the range and threat versatility of the system by adding the All Weather Stunner Interceptor, improving the MMR-NG, upgrades to GDL and increasing the capacity of the GA BMC. The U.S. and State of Israel entered into a Memorandum of Understanding on September 2016, in which "Such funding, should over a ten year period beginning in FY 2019 and ending in FY 2028, be provided at a level of $500 million per year." (U.S. contributions only). These funds will be distributed between the Israeli Programs in Research Development Test & Evaluation and Procurement Funds.$$, 127000000, NULL, NULL, NULL, NULL, 1705746000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603914C_MC04$$, $$0603914C$$, $$MC04$$, $$Cyber Operations$$, 6682000, $$Missile Defense Agency (MDA) Risk Management Framework (RMF) Standards, Computer Network Defense Service Provider and Controls Validation Testing activities: validation results; risk assessments; and reviews of proposed Program Manager/Information Systems Security Manager Plans of Action and Milestones (POA&Ms) for MDA Missile Defense Test Program. It maintains the Certification and Accreditation (C&A) data repository, capturing the RMF documentation (artifacts, validation results, and Cyber Risk Assessment results, and Authorizing Official (AO) accreditation decisions) and POA&Ms on all MDA information systems. This project supports the monitoring and tracking of cyber mitigations detailed in Information Technology security POA&Ms. Activities include preparation of C&A documentation and accreditation recommendations to the MDA Senior Information Systems Security Officer/Security Controls Assessor and AO. Independent Verification and Validation team actions ensure the availability, integrity, authentication, confidentiality and non-repudiation of the MDA mission, test and administrative systems. Activities in the Project are necessary to comply with the Federal Information Systems Modernization Act of 2014. The MDA Information Technology Networks and Systems and Cross Domain Solution (CDS) provide oversight and guidance for implementing standard CDS security policies across the Missile Defense System.$$, 6682000, NULL, NULL, NULL, NULL, 89676000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603914C_MD40$$, $$0603914C$$, $$MD40$$, $$Program Wide Support$$, 28183000, $$PWS contains non-headquarters management costs in support of Missile Defense Agency (MDA) functions and activities across the entire Missile Defense System. These functions include Government Civilians and Contract Support Services. This effort provides integrity and oversight of the Missile Defense System as well as supports MDA in the development and evaluation of technologies that will respond to the changing threat. Additionally, PWS includes personnel to support global deployments performing deployment site preparation and activation, and provides facility capabilities for MDA Executing Agent locations worldwide. Other MDA wide costs include: physical and technical security; civilian drug testing; audit readiness; the Science, Technology, Engineering, and Mathematics (STEM) program; legal services and settlements; travel and agency training; office, equipment, vehicle, and warehouse leases; utilities and base operations across multiple geographic locations; commercial and ancillary facility services; management of all facility aspects regardless of lifecycle stage; supplies and maintenance; compliance with statutory environmental requirements; data and unified communications support; materiel and readiness and central property management of equipment; Facilities Sustainment, Restoration and Modernization (FSRM) program (formerly Real Property Maintenance) to keep the Department's inventory of facilities in good working order; and similar operating expenses. PWS is allocated on a pro-rata basis across most Agency PEs; therefore, fluctuates per PE by FY based on the total Agency budget in that FY.$$, 28183000, NULL, NULL, NULL, NULL, 33947000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603915C_MC05$$, $$0603915C$$, $$MC05$$, $$Cyber Operations$$, 1990000, $$Cybersecurity Operations sustains Missile Defense Agency (MDA) Targets and Countermeasures (TC) Risk Management Framework (RMF) standards, Computer Network Defense (CND) Local Control Center, and Controls Validation Testing (CVT) activities. TC cybersecurity operations maintain the Authorization and Accreditation Enterprise Mission Assurance Support Service (eMASS) repository, capturing the RMF documentation (artifacts, validation results, and Cybersecurity Risk Assessment results, Authorization Official accreditation decisions, and Plans of Action and Milestones (POA&Ms) on all MDA TC information systems non-compliance activities). The TC Cybersecurity operations support the monitoring and tracking of Cybersecurity mitigations detailed in the cybersecurity POA&Ms within eMASS. The CND Local Control Center validates Assured Compliance Assessment Solution vulnerabilities, Endpoint Security Solution compliance, ArcSight deployment, and ensures distribution and tracking of Cybersecurity Tasking Orders for the entire TC cybersecurity portfolio. The Independent Verification and Validation group testing ensures the integrity and compliance of the MDA TC cybersecurity compliance for all TC cybersecurity portfolio. These validation activities include the analysis of validation results from compliance monitoring, risk assessments and reviews of proposed Program Manager/Information Systems Security Manager POA&Ms for the MDA Targets and Countermeasures program. Activities in the Project are necessary to comply with the Federal Information Security Management Act, Department of Defense (DoD), and MDA cybersecurity standards/requirements.$$, 1990000, NULL, NULL, NULL, NULL, 12977000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603915C_MD40$$, $$0603915C$$, $$MD40$$, $$Program Wide Support$$, 17796000, $$PWS contains non-headquarters management costs in support of Missile Defense Agency (MDA) functions and activities across the entire Missile Defense System. These functions include Government Civilians and Contract Support Services. This effort provides integrity and oversight of the Missile Defense System as well as supports MDA in the development and evaluation of technologies that will respond to the changing threat. Additionally, PWS includes personnel to support global deployments performing deployment site preparation and activation, and provides facility capabilities for MDA Executing Agent locations worldwide. Other MDA wide costs include: physical and technical security; civilian drug testing; audit readiness; the Science, Technology, Engineering, and Mathematics (STEM) program; legal services and settlements; travel and agency training; office, equipment, vehicle, and warehouse leases; utilities and base operations across multiple geographic locations; commercial and ancillary facility services; management of all facility aspects regardless of lifecycle stage; supplies and maintenance; compliance with statutory environmental requirements; data and unified communications support; materiel and readiness and central property management of equipment; Facilities Sustainment, Restoration and Modernization (FSRM) program (formerly Real Property Maintenance) to keep the Department's inventory of facilities in good working order; and similar operating expenses. PWS is allocated on a pro-rata basis across most Agency PEs; therefore, fluctuates per PE by FY based on the total Agency budget in that FY.$$, 17796000, NULL, NULL, NULL, NULL, 130679000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603915C_MT05$$, $$0603915C$$, $$MT05$$, $$BMDS Targets Program$$, 495118000, $$The mission of the Missile Defense System Targets Program is to provide an economical and reliable inventory of targets that are representative of feasible future threats. These targets enable demonstration of Missile Defense System capabilities in operationally realistic scenarios. The Missile Defense System Targets Program develops and acquires five target types across four target classes. The classes include: Short Range Ballistic Missiles (SRBM), Medium Range Ballistic Missiles (MRBM), Intermediate Range Ballistic Missiles (IRBM), and Intercontinental Ballistic Missiles (ICBM). The target types (Type 1-5) designate the complexity of the target within its class. Type-1 (T1) targets are simple baseline configurations. Type-2 (T2) targets have increased capability or complexity. Type-3 (T3) targets have unique configurations. Type-4 (T4) targets are subscale targets. Type-5 (T5) targets are advanced targets. The Missile Defense System Targets Program develops and provides Modified Ballistic Re-Entry Vehicles (MBRV) and Countermeasures that can be used across the spectrum of target types and classes. The Missile Defense System Targets Program provides target digital models that enable the Missile Defense Agency (MDA) weapon system program offices to simulate end to end sensor and interceptor performance during pre-mission analysis. The Missile Defense System Targets Program also provides maintenance, aging surveillance, refurbishment, and routine testing of government furnished equipment boosters and target components. The Missile Defense System Targets Program carefully plans the year of execution to assure the best use of appropriated funds. However, the Missile Defense System Targets Program must be flexible in its execution of the program in order to respond to emerging real world threats or changes in the intelligence community estimates of when a threat will be deployed. The Missile Defense System Targets Program must also work with missile defense systems engineers on a continuing basis to align the targets program to the Missile Defense System need to demonstrate capabilities as reflected in the Missile Defense System IMTP. The Missile Defense System Targets Program makes every effort to reduce instability in contracts, production base and budget while managing in this dynamic work environment. The Missile Defense System Targets Program develops and builds targets and countermeasures at multiple locations including: Orlando, FL; Huntsville, AL; and Chandler, AZ. Storage and maintenance facilities are also located throughout the country including: Huntsville, AL; White Sands, NM; Ogden, UT; Tooele, UT; and Cape Canaveral Air Force Station, FL. The Missile Defense System Targets Program consists of four major areas: Consumables, Program Planning and Operations, Resources, and Flight Test Execution.$$, 495118000, NULL, NULL, NULL, NULL, 5370667000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603920A_CD5$$, $$0603920A$$, $$CD5$$, $$Humanitarian Demining$$, 9349000, $$This project develops, demonstrates and validates cost-effective technologies for use in humanitarian demining via Outside Continental United States (OCONUS) operational field evaluations. This project's low-cost and highly effective technology reduces the landmine and unexploded ordnance (UXO) / improvised explosive device (IED) threat to deployed United States (US) forces and the local population. This project coordinates with the Department of State's Weapons Removal and Abatement Program, the Department of Defense (DoD) Humanitarian Mine Action (HMA) programs of the Geographic Combatant Commands (GCCs), international mine action organizations, and foreign militaries. New technology requirements and areas of emphasis are identified and validated at annual Requirements Workshops and UXO/IED Working Group Meetings. Technology investments are prioritized using the results of these meetings and GCC security cooperation and theater campaign plan HMA objectives. This Project advances the state-of-the-art of demining technologies and evaluates these technologies utilizing host nation humanitarian demining partners. This project supports and bolsters the GCC stability operations mission as directed under Department of Defense Instruction (DODI) 3000.05 to foster mil-to-mil engagement and bolster economic security and development with partner nations worldwide. Additionally, this project fosters nations' mine action capacity while improving DoD's visibility and access, generating long-term positive perceptions of DoD and the US, and fostering collaborative relationships with host nation governments. This project utilizes a development plan based on operational data gained through Operational Field Evaluations (OFEs). These OFEs provide this project a unique capability to collect data against live mines/UXO in actual minefields around the world. This data is not available to any other DoD organization. This OFE data drives future humanitarian demining investment decisions and is shared and leveraged by the Army Futures Command to further improve U.S. forces' technologies. In addition, this project provides mine and UXO detector training to the GCCs at the Humanitarian Demining Training Center (HDTC) in support of Military-to-Military training and partnerships. This Project supports the DoD's strategic guidance to address instability and reduce the demand for significant US force commitments to stability operations. This is in accordance with US Title 10 Section 407 (Humanitarian Demining Assistance), DOD Instruction 3000.05 (Stability Operations), and Chairman of the Joint Chiefs of Staff Instruction (CJCSI) 3207.01C (Department of Defense Support to Humanitarian Mine Action) to reduce the social, economic, and environmental impact of landmines and unexploded ordnance. This Project will be executed by the Army Futures Command (AFC).$$, 9349000, NULL, NULL, NULL, NULL, 22737000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603925N_9999$$, $$0603925N$$, $$9999$$, $$Congressional Adds$$, 0, $$Project 9999 (PU C357) - Congressional Add - 100kW Directed Energy Production is a Congressionally directed effort to advance the manufacturing readiness of 'weapon grade' subsystems for 100kW class High Energy Lasers (HELs) including the Main Optical Bench (MOB) for beam combining and beam control. Additionally, these funds will support Navy plans to develop and refine weapon integration processes and system performance qualification and evaluation. In order to expand mass production of weapon grade Laser Fiber Amplifiers (LFAs), manufacturing processes currently utilized need refinement and improvement. This will result in higher production capabilities at a reduced cost per LFA for the United States (US) Government.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603923D8Z_923$$, $$0603923D8Z$$, $$923$$, $$Coalition Warfare$$, 10090000, $$The Coalition Warfare Program (CWP) supports the Department of Defense (DoD) organizations that: 1) work with foreign partners to collaboratively address strategic technology gaps for current and future missions; 2) develop interoperability solutions for coalition operations; and 3) develop and strengthen defense relationships. It comprehensively supports the Interim National Defense Strategic Guidance (INDSCG) direction to engage allies and partners, implementing guidance to "fully engage all countries and institutions to cooperate on shared threats” and “redouble our efforts to deepen our cooperation with like-minded partners." The CWP provides a broad base of technological, operational, and logistical support for military operations and eases the U.S. financial and manpower burdens associated with meeting military goals and objectives. Coalitions and relationships with international partners are high priorities for the nation and the DoD. The CWP supplements U.S. Government proponents' funding for cooperative efforts, ensuring U.S. funds are sufficient to complete research and development activities with foreign partners. When CWP funds are used to help fund a cooperative project, that project leverages technical and financial contributions of the foreign partners and accelerates the development and delivery of technical solutions to the warfighter. For every $1 the CWP has invested in cooperative projects with 81 partners since 2001, the program has leveraged $3 in foreign partner resources and $2 in other U.S. Government resources. The CWP funding enables the DoD project teams to transition technology to operational use, further development, or integration into other systems. These projects may also form the basis for future cooperation with international partners.$$, 10090000, NULL, NULL, NULL, NULL, 118195000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603924D8Z_924$$, $$0603924D8Z$$, $$924$$, $$High Energy Laser Advanced$$, 114577000, $$This project is part of an overall Department of Defense strategy in Joint directed energy advanced technology development. Efforts within this project will focus on scaling the output power of directed energy weapon systems to reach operationally effective power levels applicable to broad mission areas across the Department of Defense. Additionally, efforts will pursue improvements in common directed energy system components to enable scalable architectures and increase lethality. These efforts complement, and will be closely coordinated with, other Department efforts directed at specific Service and Agency missions. This project builds upon other investments in directed energy advanced technology development by the Services and Agencies to harmonize Department efforts and eliminate duplication. In support, efforts in this project have been coordinated with the Department of Defense Directed Energy and Non-Lethal Weapons Science and Technology Community of Interest. This project is executed via two technical programs and a new initiative within the JDETO. The first technical program is the Directed Energy Applied Tech Program, which enables (1) advanced technology development in high energy laser and high power microwave systems that support eventual prototype-level integration and (2) proof of concept tech demonstrations in a laboratory or field environment with Joint-international participation. The second technical program is the Directed Energy Tech Maturation Program, which enables (3) advanced prototypes in support of demonstrating mission-driven lethality and survivability and (4) test and evaluation in a relevant field environment with Joint-international participation. Note that (1)-(4) are in alignment with the near-, mid-, and long-term goals of Department of Defense Directed Energy Roadmap and enable transition. The new initiative is the Pulsed High Energy Laser Scaling Initiative. This initiative is also in alignment with the near-, mid-, and long-term goals of the Department of Defense Directed Energy Roadmap and is the result of mandatory funding in FY 2026.$$, 114577000, NULL, NULL, NULL, NULL, 190038000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603925N_2731$$, $$0603925N$$, $$2731$$, $$High Energy Laser Counter ASCM$$, 0, $$The High Energy Laser Counter-ASCM Project (HELCAP) will accelerate the integration of High Energy Laser (HEL) technologies and prototype HEL weapon systems through demonstrations of critical technologies integral to defeating Anti-Ship Cruise Missile (ASCM) targets with non-kinetic weapon systems. HELCAP has developed a High Energy Laser (HEL) source capable of ASCM defeat while also enabling target acquisition, identification, and atmospheric correction abilities through advanced beam control subsystem maturation. The Directed Energy Testing Against Missiles (DETAM) effort will utilize the Laser Weapon Testbed (LWT) and other Directed Energy (DE) assets to initiate a Test & Evaluation (T&E) campaign focused on transitioning Naval HEL technologies to operational use by evaluating them in a realistic operating environment. DETAM will promote advanced laser component development while testing prototype weapon systems against surrogate ASCMs and advanced operational threats to ensure rapid integration of HEL weapon systems with the Naval Fleet.$$, 0, NULL, NULL, NULL, NULL, 67912000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603925N_3402$$, $$0603925N$$, $$3402$$, $$Surface Navy Laser Weapon System$$, 0, $$Project 3402 - Surface Navy Laser Weapon System (SNLWS): Program supports the National Defense Strategy (NDS) of building a more lethal force by leveraging maturing technology to deliver proven laser weapon capability to the Fleet as part of the Navy Laser Family of Systems (NLFoS) initiative with the objective of providing the fleet with incrementally developed laser weapon system capabilities. Additionally, accelerated learning through incorporation of laser weapon Concept of Operations (CONOPs), employment and maintenance validates warfighting requirements for laser weapon systems to address a variety of threats. The High Energy Laser with Integrated Optical-Dazzler and Surveillance (HELIOS) system provides a low cost-per-shot capability to address Anti-Surface Warfare and Counter-Intelligence, Surveillance and Reconnaissance (C-ISR) gaps with the ability to dazzle and destroy Unmanned Aerial Systems (UAS) and defeat Fast Inshore Attack Craft (FIAC) while integrated into the AEGIS Combat System on a Flt IIA Destroyer. SNLWS, a Non-Program of Record (POR), provided an industry-developed and government integrated capability to the Fleet in as short a timeframe as possible, thereby addressing the NDS direction to foster a culture of innovation. SNLWS included the development of a laser weapon system in the 60 kW class. SNLWS leveraged technology available at that time to deliver an initial laser weapon system capability to the Fleet. Mk 5 Mod 0 HELIOS development leveraged the previous AN/SEQ-3 Laser Weapon System (LaWS) and the Mk 2 Mod 0 Laser Weapon System Demonstrator (LWSD) efforts.$$, 0, NULL, NULL, NULL, NULL, 320062000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603925N_5898$$, $$0603925N$$, $$5898$$, $$Directed Energy Components for$$, 0, $$Project 5898 - Directed Energy Components for High Energy Lasers: Supports Industrial Base Analysis and Sustainment (IBAS) program efforts for the improvement of the production capability of the industrial base in order to produce Laser Weapon Beam Director (LWBD) components and sub-systems; reduce production lead times of Laser Weapon System Optics; improve quality and reduce production times of Fast Steering Mirror (FSM) and deformable mirrors. Project 5898 funding completes in FY24.$$, 0, NULL, NULL, NULL, NULL, 13553000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603925N_9823$$, $$0603925N$$, $$9823$$, $$Lasers for Navy applicat$$, 0, $$Project 9823 - Lasers for Navy Applications: Optical Dazzler Interdictor Navy (ODIN) development provides directed energy, shipboard Counter-Intelligence, Surveillance, and Reconnaissance (C-ISR) capabilities to the Fleet to dazzle Unmanned Aerial Systems (UASs) and other platforms that address the Urgent Operational Needs (UONs) statement provided by the Fleet. ODIN, as a non-Program of Record, was developed and fielded with RDT&E,N funding and was initially envisioned as a Non-Permanent Change (NPC). FY 2018 was the first year of funding which supported the design, development, procurement, and installation of 8 ODIN standalone units deployed on DDG 51 Flt IIA surface combatants. Eight (8) ODIN units are now operational in the Fleet. Project 9823 R&D funding converted to OPN in FY25 & FY26 and O&MN FY24 - FY26 for the sustainment of 8 ODIN units.$$, 0, NULL, NULL, NULL, NULL, 189458000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603941D8Z_090$$, $$0603941D8Z$$, $$090$$, $$Nuclear Test$$, 11079000, $$The Nuclear Test (NT) project mission addresses national test capability gaps by providing accurate, robust, and efficient T&E solutions to successfully develop, validate, and inform the employment of a modernized nuclear enterprise. The Department of Defense (DoD) is prioritizing investments to modernize the nuclear enterprise while sustaining and increasing the resiliency of legacy systems. Current developments focus on deploying capabilities and systems to validate new designs and new materials in a complex threat-representative environment. Current testing infrastructure and methodologies to assess nuclear enterprise systems and microelectronics resilience against emerging threats is limited. Many test capabilities used in the past for acquisition are no longer available, either stopped by policy decisions or dismantled for cost savings. The NT project addresses test technology needs for adequate assessment of nuclear enterprise resiliency and aligns with the DoD S&T priority investments. The NT project is supporting the development of a strategic roadmap and investment strategy to establish nuclear test environments for microelectronics, ground test environments for system level testing, and flight test range enhancements for end-to-end testing needs. The NT project develops technologies to enable robust, accurate, and timely T&E of a modernized nuclear enterprise, and to ensure system suitability and survivability.$$, 11079000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603941D8Z_091$$, $$0603941D8Z$$, $$091$$, $$High Speed Systems Test$$, 79223000, $$High-speed/hypersonic weapons are being developed to ensure the continued military superiority and strike capability of the United States including freedom of movement and freedom of action in areas protected by anti-access/area denial defenses. Current weapon system demonstrations and technology development programs include high-speed and hypersonic air-breathing missiles, maneuvering reentry and boost-glide weapons, hypersonic gun-launched projectiles, and air- breathing space access vehicles. These systems require development of conventional and high-speed turbine, ramjet, scramjet, and combined cycle engines; high temperature materials; thermal protection systems (TPS); and thermal management systems. The High Speed Systems Test (HSST) project addresses test technology needs including propulsion, aerodynamic and aerothermal testing, so the test community has the technology to support the required test scenarios for concepts under development in the S&T community. The technology developments within the HSST project align with the Department of Defense (DoD) S&T priority investments. As such, the HSST project is developing, validating and transitioning advanced T&E technologies for ground test, open-air range flight test, and advanced computational tools, along with instrumentation and diagnostics systems for use in both ground tests and flight tests of high speed systems. The HSST project develops technologies to enable robust, accurate, and timely T&E of these future weapon systems. DoD acquisition regulations require weapon systems to undergo a thorough T&E process to detect deficiencies early and to ensure system suitability and survivability. However, the extreme environments in which these weapons operate preclude accurate determination of their performance and operability with today’s T&E assets. Current national test capabilities have deficiencies in data accuracy, flight condition replication and simulation, test methods, productivity, modeling and simulation (M&S) fidelity, and range safety. The HSST mission is to address these national test capability gaps by providing test technology solutions that will enable high-speed and hypersonic weapon systems to be successfully developed through accurate, robust, and efficient T&E.$$, 79223000, NULL, NULL, NULL, NULL, 883147000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603941D8Z_092$$, $$0603941D8Z$$, $$092$$, $$Spectrum Efficient Technology$$, 9397000, $$Weapon systems have become increasingly complex in recent years, resulting in the need for significantly more data to be passed among these systems as well as between the systems and our test infrastructure. A vast amount of data must be collected, transmitted, and analyzed, which requires a large amount of radio frequency (RF) spectrum resources. However, the amount of RF spectrum designated to support test and evaluation (T&E) is decreasing, most notably due to reallocation of spectrum for commercial use. The combination of decreasing RF spectrum and increasing data requirements results in an urgent need to develop test technologies that maximize the use of spectrum resources for the Department of Defense (DoD) T&E operations. The L- and S- Band frequencies are the traditional spectrum allotted for military T&E use. The explosive need for spectrum in the commercial sector has resulted in reallocation of portions of these bands to industry. To compensate, the DoD is now authorized to use the C-Band spectrum which offers numerous benefits, including the potential for a large increase in available bandwidth, but the C-Band spectrum comes with technical challenges and regulatory constraints. Most notably, our current test infrastructure for telemetry is not designed to accommodate C-Band and the band is heavily shared for alternate uses. Technologies are required to implement innovative techniques that efficiently facilitate our use of C-Band without a major overhaul to our national test infrastructure. For instance, commercial telemetry transmitters operate in C-Band but do not have the form factor (size, weight and power) nor ruggedized packaging to survive airborne test applications. Traditional telemetry applications employ streaming telemetry where data is moved one-way from the instrumented system under test to our test range infrastructure. Modern network based telemetry and cellular based telemetry capabilities enable more robust, efficient bidirectional transfer of data. The DoD strategy is to create technologies for implementing a telemetry capability in C-Band, using the legacy L- and S-Bands for both streaming and networked telemetry, and researching the feasibility of using higher frequency bands to augment telemetry operations. The Spectrum Efficient Technology (SET) project is developing test technologies that enable more efficient use of legacy telemetry bands and expansion into non- traditional areas of the RF and optical spectra at DoD test ranges. The technology development efforts within the SET project have been prioritized to align with the Department of Defense guidance on science and technology priority investments. As such, the SET project is focusing on growing data requirements of warfighting systems and the limited availability of spectrum for testing. The SET project is structured to develop test technologies to advance range communications, networked and cellular based telemetry capabilities, and enhanced management of spectrum at DoD test ranges.$$, 9397000, NULL, NULL, NULL, NULL, 157958000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603941D8Z_093$$, $$0603941D8Z$$, $$093$$, $$Electronic Warfare Test$$, 19427000, $$In order to establish dominance in the modern battlespace, our offensive and defensive electronic warfare systems must be capable against advanced radio frequency (RF) directed threats and electro-optic (EO) guided threats, which include infrared (IR) guidance. Ensured dominance in these areas requires more robust test and evaluation (T&E) with technologies that are rapidly adaptable to changing threats. Readily available, IR seeking, man-portable air defense systems (MANPADS) are difficult to detect and pose an imminent and lethal threat to military aircraft of all types. Our ability to counter such threats is essential to owning the battlespace in theater. Therefore, the ability to test missile warning systems (MWS), hostile fire indicator (HFI) systems, IR countermeasures (IRCM), and advanced threat sensors is critical to our national defense. Additionally, a new generation of enemy RF missile seekers is both currently fielded and in further development, requiring a correspondingly new generation of test technologies to test the latest countermeasures. The T&E community is required to test IRCM and RF countermeasure systems in a repeatable manner with ground-truth data before and after integration into warfighting systems. Without new test technologies, the Department of Defense (DoD) will be unable to perform adequate T&E of advanced warning and countermeasure systems. The Electronic Warfare Electronic attack and Electronic protect (EP) community is developing jammers and EP measures that are more sophisticated and take advantage of newer technology that allows adaptive waveforms and artificial intelligence and autonomy to respond to threats more rapidly and robustly. In addition, the testing of these systems in realistic many on many environments that are more threat representative requires new technology investment. The technology development efforts within the Electronic Warfare Test (EWT) project have been prioritized to align with DoD guidance on science and technology priority investments. As such, the EWT project is focusing on the test needs in both the EO, including IR, and the RF threat domains. Additionally, development of core test technologies in this area can be leveraged to meet other EO and RF test requirements, such as in fire control systems; intelligence, surveillance and reconnaissance (ISR) sensors, and weapon seekers. The EWT project develops test technologies to stimulate IRCM and RF system sensors through the high-fidelity simulation of scenes viewed by the sensors. Stimulation can be as simple as testing to see if a system under test responds to an image or as complex as simulating complex battle space phenomena to measure the response of a system under test in a more relevant, cluttered scenario. Simulations and stimulations are used at open-air ranges and in installed system test facilities (ISTF), and in hardware-in-the-loop (HWIL) test beds.$$, 19427000, NULL, NULL, NULL, NULL, 649730000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603941D8Z_112$$, $$0603941D8Z$$, $$112$$, $$MACH-TB$$, 734000000, $$Hypersonic development remains a top priority for the Department. The Multi-Service Advanced Capability for Hypersonics Test Bed (MACH-TB) accelerates delivery of advanced hypersonic and strategic capabilities to the warfighter by leveraging commercial space launch and non-traditional test beds to provide DoD, other Federal agencies, industry, and academia the capability to affordably and rapidly conduct hypersonic experiments and test hypersonic system components.$$, 734000000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603941D8Z_094$$, $$0603941D8Z$$, $$094$$, $$Advanced Instrumentation Systems$$, 18847000, $$The Advanced Instrumentation Systems Technology (AIST) project addresses the test technology gaps resulting from emerging weapon systems that need to be assessed at the Department of Defense (DoD) installed systems test facility and hardware-in-the-loop testing (ISTF/HITL) and open-air range test facilities (including tropospheric, land-based, open-ocean, and undersea ranges). Instrumentation requirements for systems under test are increasing exponentially for new weapons systems. System-borne, warfighter-wearable, and remote sensing instrumentation packages are required. This instrumentation is for sensing and collecting critical performance data; determining accurate time, space, position information (TSPI) and attitude information; interfacing with command and control data links; monitoring and reporting system-wide communications; recording human operator physical and cognitive performance; and storing and transmitting data. The technology development efforts within the AIST project have been prioritized to align with the DoD guidance on science and technology (S&T) communities of interest (COIs). The AIST project is focused on developing technologies for advanced TSPI instrumentation (especially with limited or no availability of Global Positioning System (GPS)), advanced sensors, advanced energy and power systems for instrumentation, micro-electronics, mitigating range encroachment issues, and measuring warfighter physical and cognitive performance. The AIST project addresses requirements for miniaturized, non-intrusive instrumentation suites with increased survivability in harsh environments. Such instrumentation is an urgent need because minimal space is available to add instrumentation to new or existing weapon systems subsequent to their development; furthermore, additional weight and power needs for instrumentation can adversely affect weapon system signature and performance. Instrumentation for humans-in-the-loop, especially dismounted warfighters, must not adversely affect performance, induce artificiality in the test environment, or create any operational burdens. New technologies can be exploited to integrate small, non-intrusive instrumentation (micro-technology) into emerging platforms during design and development, and, in some cases, into existing platforms. This class of instrumentation will provide critical system performance data during operational test (OT) and continuous assessment throughout a system’s lifecycle. Technology developed under AIST can also benefit training and combat missions by enabling a continual feedback loop between the developer, training staff, operators, and commanders.$$, 18847000, NULL, NULL, NULL, NULL, 156659000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603941D8Z_095$$, $$0603941D8Z$$, $$095$$, $$Directed Energy Test$$, 10133000, $$The Department of Defense (DoD) is exploring the military utility, safety, and suitability of directed energy weapons. A robust test capability to assess directed energy weapons is essential to understanding their effectiveness and limitations, including determining their effectiveness in performing counter improvised explosive device (C-IED) operations and counter UAS operations. Such assessments will depend upon knowledge acquired through the test and evaluation (T&E) of directed energy technologies and testing of operational concepts. Directed energy weapon technologies, primarily consisting of high energy lasers (HEL) and high powered microwaves (HPM), are outpacing available test capabilities. Traditional test techniques for evaluating conventional munitions (with flight times ranging from seconds to minutes) are not sufficient for the T&E of directed energy weapons that place energy on target instantaneously. Consequently, new test technology solutions are needed to ensure that adequate developmental, live-fire, and operational test capabilities are available when directed energy programs are ready to test. Directed energy system and component testing requires three principal assessments: (1) energy or power on target; (2) the effects on the target; and (3) the propagation of the directed energy to the target through the atmosphere. In addition, the vulnerabilities of DoD systems to directed energy threats are required to be characterized, such as those requirements captured in Military Standard (MIL-STD)-464C. Equally as important, current test capabilities do not provide the detailed data required to understand U.S. directed energy system performance and effects. The technology development efforts within the Directed Energy Test (DET) project have been prioritized to align with DoD guidance on science and technology priority investments. As such, the DET project is developing the technologies necessary for quantitative assessment of United States (U.S.) HEL and HPM performance, as well as the vulnerability of DoD weapon systems to enemy directed energy threats.$$, 10133000, NULL, NULL, NULL, NULL, 144675000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603941D8Z_096$$, $$0603941D8Z$$, $$096$$, $$C4I & Software Intensive Systems Test$$, 13577000, $$The Command, Control, Communications, Computers, Intelligence (C4I) and Software Intensive Systems (SIS) (C4T) project addresses test technology for next generation resilient, survivable, federated networks and information systems (information superiority) from the tactical level up to strategic planning. The technology development efforts within the C4T project have been prioritized to align with DoD guidance of S&T Communities of Interest (CoIs) and the interim National Defense Strategy. Gaps are driven by more complex warfare environments and distributed systems; large quantities of data and intelligence (e.g., Big Data, Artificial General Intelligence (AGI) and Machine Learning Algorithms (MLA)); and more software intensive systems (e.g. F-35, CVN, IBCS)). C4T addresses gaps in Big Data Analytics technologies to gain knowledge from massive amounts of structured and unstructured data collected over a single test, but also expanded to look at the systems’ performance over the acquisition lifecycle. The technologies are required when testing sensor platforms, command and control systems and weapon platforms that support the kill chain in a Joint multi-domain operation. These systems must be evaluated for their ability to provide the accurate, timely transfer of data (e.g., target tracks, weapons allocation, mission tasking, and situational awareness) as the data passes among the Services, Warfighting Domains, and Coalition Partners. C4T also addresses gaps in Live and Simulated Environments, these technologies are required to increase the use of a distributed test environment for new warfare concepts leveraging simulated entities (e.g. modeling and simulation) for more thorough joint mission context platform T&E (e.g., Anti-Access Arial Denial (A2AD) and Manned and Unmanned Systems (MUM-T)). The technologies within C4T will remove undesired distributed testing biases while improving test agility and the tester’s ability to effectively support knowledge management, rapid analysis of “Big Data," and automated test reporting. The C4T project advances these test technologies as well as Big Data collection, analysis, and visualization that enable the virtual integration of Department of Defense (DoD) weapon laboratories and open-air ranges. Using Modeling and Simulation (M&S) along with hardware-in-the-loop (HWIL) laboratories, the effectiveness of Joint missions can be assessed in terms of system- of-systems interoperability and effectiveness in executing Joint mission operations, including testing of weapons and C4I and SIS systems accessing and providing information. Lastly, C4T addresses technologies to support C2 Analysis in Multi-Domain Operations (MDO), specifically at scale and density to fully assessed the mission kill web with new test design, planning and assessment technologies utilizing artificial intelligence and machine learning to not only plan assessments within a domain, but also to enable assessments of “what-if” testing cascading across the other domains of warfare. This will enable full assessment of multi-domain operations to ensure information superiority to accomplish mission objectives. New intelligent testing technologies are required for assessment of MDO missions for our future warfighter AI/ML-enabled C2 Warfighter Systems to ensure the battlefield will not be the testing field. These new MDO focused technologies are vital to creation of a robust operationally relevant Joint Service All Domain Test Range.$$, 13577000, NULL, NULL, NULL, NULL, 206289000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603941D8Z_097$$, $$0603941D8Z$$, $$097$$, $$Autonomy and Artificial Intelligence$$, 43491000, $$The emergence of Artificial Intelligence (AI) brings a host of revolutionary capabilities that will profoundly influence warfare, and bring special challenges for testers of Artificial Intelligence systems. The Autonomy and Artificial Intelligence Test (AAIT) project addresses current and emerging challenges associated with the test and evaluation (T&E) of unmanned systems, particularly in testing autonomy, artificial intelligence, and machine learning. As such, AAIT is developing test technologies to simulate, stimulate, instrument, measure, and assess an autonomous system’s ability to perceive its environment, process information, adapt to dynamic conditions, make decisions, and effectively act on those decisions in the context of mission execution. AAIT will provide the test technologies to effectively measure performance and characterize risk, thereby increasing warfighter trust in autonomous systems and artificial intelligence tools. This program will improve DoD test capabilities and methodologies to address the testing of increasingly autonomous units operating in unstructured, dynamic, battlespace environments. Furthermore, advancements are being made in developing collaborating, system-of-autonomous-systems that will work in concert as a swarm or pack, and in close proximity with humans. New test technologies are needed to stress the collective set of autonomous systems under realistic conditions, predict emergent behavior of autonomous systems, emulate the complex environment, and assess mission performance of these highly coupled and artificially intelligent systems.$$, 43491000, NULL, NULL, NULL, NULL, 193537000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603941D8Z_098$$, $$0603941D8Z$$, $$098$$, $$Cyberspace Test$$, 155762000, $$The Department’s ability to use cyberspace for rapid communication and information sharing in support of operations is a critical enabler of DoD military missions. Advancements in utilizing cyberspace are outpacing the technologies needed for test and evaluation (T&E). The Cyberspace Test Technology (CTT) project develops advanced technologies and methodologies to test and evaluate DoD capabilities and information networks to defend and conduct full-spectrum military operations across cyberspace. This program will improve cyberspace T&E capabilities to support the continual experimental, contractor, developmental, operational, and live- fire testing requirements of warfighter systems operating in cyberspace. Many of the test tools and infrastructure items required for systems in cyberspace will require advancement and maturation of nascent test technologies. The CTT project will address test technology shortfalls in cyberspace testing, including planning cyberspace tests, creating representative cyberspace threats and test environments, executing cyberspace tests, and performing cyberspace test analysis and evaluation.$$, 155762000, NULL, NULL, NULL, NULL, 109209000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603941D8Z_099$$, $$0603941D8Z$$, $$099$$, $$Space Test$$, 836000, $$The space domain has become a competitive, congested, and contested environment dominated by global economics and key to national security. With the creation of the United States Space Force, the Department of Defense (DoD) is prioritizing investments to maintain space superiority and increase resiliency of space systems. Current testing infrastructure and methodologies to assess space system resilience against emerging threats is limited. The Space Test (ST) project mission is to address national test capability gaps by providing accurate, robust, and efficient T&E solutions to successfully develop, validate, and inform the employment of new space control systems. The ST project addresses test technology needs for adequate realism for space systems and aligns with the DoD S&T priority investments and is developing a strategic roadmap and investment strategy to establish live and virtual range environments, develop space and ground-based threat emulation capabilities. The ST project seeks to develop technologies that will enable robust, accurate, and timely T&E of future space weapon systems.$$, 836000, NULL, NULL, NULL, NULL, 32000000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603945D8Z_079$$, $$0603945D8Z$$, $$079$$, $$AUKUS$$, 133788000, $$This program supports the Department’s initiatives to: (1) deter strategic attacks against the United States, and its Allies and partners; (2) deter aggression while being prepared to prevail in conflict when necessary; and (3) build enduring advantages for the future Joint Force. Specifically, the Enhanced Trilateral Security Partnership among Australia, the United Kingdom, and the United States (AUKUS) will deepen defense capability and technological cooperation by developing and providing joint advanced military capabilities to promote security and stability in the Indo-Pacific region. This program provides funding to pursue operationally relevant advanced capability co-development, co-production, and/or co-sustainment; support integration of multi- national capabilities to act as a force multiplier;, and test and evaluate promising solutions found across the AUKUS innovation ecosystem. The program portfolio aligns with the critical technology areas and operational requirements. As new AUKUS projects are considered in FY2026, the intent is to consider proposals submitted from the DoD Components and industry and academia partners. The appropriate leadership will select proposals using a merit-based process that identifies the most promising solutions to operational challenges with an emphasis on transitioning technologies to current or future programs of record.$$, 133788000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603945D8Z_353$$, $$0603945D8Z$$, $$353$$, $$DIANA$$, 35761000, $$To combat the evolving threat and development of critical technologies, the North Atlantic Treaty Organization (NATO) established the Defence Innovation Accelerator for the North Atlantic (DIANA) to leverage dual-use technological advances in Allied centers of innovation to achieve the Alliance’s operational requirements, including accelerating the development, testing, and fielding of security technology solutions to achieve an advantage over the evolving threat. The NATO DIANA program only provides non-traditional business partners from Alliance nations with funding to accelerate new technical solutions and commercialization specifically where the technology holds a dual use (commercial and defense in nature) potential. Advanced development and testing to facilitate adoption into U.S. defense programs requires supporting funding for our own labs and test centers to pull that technology into our Defense acquisition ecosystem. This project enables the Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)) to assist in accelerating military capability development for U.S. forces as well as our NATO Allies and will expose new U.S. industries to the European markets. Fielding of critical technologies in the proposed areas will have significant positive impact on detecting the enemy first, ensuing effective communications and data exchange between coalition partners, as well as systems developed by different original equipment manufacturers (OEMs), and enabling robotic and autonomous systems to remain on station longer periods of time for greater operation impact. NATO DIANA advances access to technology across larger security challenges. These enhancements will contribute to increasing lethality across the U.S. and NATO military capabilities. The NATO DIANA initiative will fund dual-use technologies identified through the NATO DIANA challenges found sufficiently mature with the potential for meaningful impact for U.S. forces on the battlefield for continued development, testing, integration, and experimentation and proposes to fund each technology for capability maturation.$$, 35761000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603945D8Z_354$$, $$0603945D8Z$$, $$354$$, $$International S&T Engagement$$, 3499000, $$To keep pace with the rapidly evolving technological landscape, advancing science and technology (S&T) cooperation with our Allies and partners remains important. This project will incentivize the DoD Components, include the Military Services, to engage and/or expand their S&T cooperation with existing partners and with those partners with who they may be engaged in policy or operational activities but not in the S&T realm. In addition, this project will allow DoD to meet new and expanded requirements for substantive, administrative, and operational activities in support on international defense S&T cooperation. The intent is to consider proposals submitted from the DoD Components. The appropriate leadership will select proposals using a merit-based process that identifies the most promising solutions to operational challenges with an emphasis on transitioning technologies current or future programs of record.$$, 3499000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603950D8Z_439$$, $$0603950D8Z$$, $$439$$, $$National Security Innovation Network$$, 2263000, $$DIU will execute a range of programs and activities to enhance DoD’s access to technologists and entrepreneurs for the purposes of improving its talent pool, enable collaboration with universities and the early-stage venture community to develop novel concepts and solutions for end-user problems and requirements, and prototype and test new technologies to place them on the path to becoming programs of record or integrated with existing platforms.$$, 2263000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0603950D8Z_845$$, $$0603950D8Z$$, $$845$$, $$National Security Innovation Network$$, NULL, $$DIU will execute a range of programs and activities to enhance DoD’s access to technologists and entrepreneurs for the purposes of improving its talent pool, enable collaboration with universities and the early-stage venture community to develop novel concepts and solutions for end-user problems and requirements, and prototype and test new technologies to place them on the path to becoming programs of record or integrated with existing platforms.$$, NULL, NULL, NULL, NULL, NULL, 188098000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604001F_646020$$, $$0604001F$$, $$646020$$, $$NC3 Advanced$$, 15910000, $$Nuclear Command, Control, and Communications (NC3) Advanced Concepts are required for analysis, development and prototyping of next generation NC3 systems and subsystems. This program ensures a responsive design and development engineering infrastructure to address evolving Nuclear Deterrence Operations (NDO) mission requirements; emerging issues and technology insertion/technology application on the NC3 Weapon System (WS), future strategic systems/capability, and other common strategic areas where appropriate; and develop enhanced multi-use capabilities. The NC3 Advanced Concepts Program will provide technology maturation and risk reduction activities to support the AF NC3 Weapon System (AN/USQ-225). Activity will reduce life cycle costs, inform technology maturation & risk reduction efforts, improve system performance, mitigate evolving threats, and ensure both viability and durability of the AF NC3 Weapon System. Additional details can be provided at a higher classification. The FY 2026 request was reduced by [0.060] million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0.000M was expended for civilian pay expenses in this program element, and in FY 2025 $0.000M is forecasted for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                             Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604001F / NC3 Advanced Concepts Component Development & Prototypes (ACD&P)$$, 15910000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604002SF_645353$$, $$0604002SF$$, $$645353$$, $$SF Weather Services$$, 857000, $$This budget activity funds the development necessary to evaluate integrated technologies and models for future operationalization into segments of the Space Force Weather Services (SFWS) in support of three lines of effort. To improve readiness for a more lethal force, SFWS provides timely, accurate, resilient and relevant environmental information, to include space and terrestrial weather, for global battlespace situational awareness for Air Force (AF), Army, Special Operations Forces (SOF), Space Force (USSF), combatant commands, the Intelligence Community (IC), and other government agencies. SFWS capabilities at home station and deployed provide critical environmental information in support of decision makers to gain the asymmetric advantage during the full spectrum of air and space combat operations. SFWS development enhances the lethality, effectiveness, and survivability of AF & SF weapon systems and precision munitions by modernizing capability and seeking the military advantage to accurately predict friendly and foe environmental impacts to optimize mission execution and planning, targeting, weaponeering, battle damage assessment, and space systems operations. To strengthen alliances and partnerships, SFWS development efforts integrate Department of Defense (DoD), government agency, commercial, and international partner environmental data with SFWS information system equipment for processing, storing, exploiting, and disseminating all- domain weather information for analysis, forecasting, mission integration, and greater interoperability. To ensure greater performance and affordability for the AF and SF, SFWS systems are being modernized through improvements to architecture and system efficiency, cybersecurity, joint all-domain command and control (JADC2) and sensing grid integration, migration to cloud computing, and expanding agile software development practices. SFWS aligns activities under four capability areas: Weather Data Collection, Weather Data Analysis and Dissemination, Weather Forecasting, and Product Tailoring/ Warfighter Applications (PTWA). This alignment ensures an integrated and systems-oriented approach to program management decisions. A portion of the Weather Forecasting capability is addressed by RDT&E, BA 04, PE 0604002S, Project 645353 - Space Force Weather Services Research. Weather Forecasting provides global and regional advanced scientific numerical weather prediction capabilities for automated, high-resolution forecast products for mission planning and execution. Space weather modeling assists in characterizing and forecasting the near-earth environment to the sun and enables space weather anomaly and space weather impact assessments. Weather Forecasting includes activities for Numerical Weather Modeling (NWM) and Space Weather Analysis and Forecast System (SWAFS). SWAFS is a software suite of 47 models and applications to ingest, process, and store space environmental data, run space environmental models to specify and forecast the near-earth environment, and run space effects characterization applications. This program element may include necessary civilian pay expenses required to manage, execute, and deliver SFWS for weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 1206392SF and 1206398SF. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 4:              PE 0604002SF / Space Force Weather Services Research Advanced Component Development & Prototypes (ACD&P) This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, 857000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604003F_640141$$, $$0604003F$$, $$640141$$, $$Advanced Battle$$, 1040475000, $$ABMS is the PE funding architecture and systems engineering (ASE), digital infrastructure, software and applications, aerial networking, deployable systems, and long range fires for the DAF's primary contribution to the Combined Joint All-Domain Command and Control (CJADC2) warfighting concept, which the DAF formally refers to as the DAF BATTLE NETWORK. The DAF Program Executive Office for Command, Control, Communication, and Battle Management (DAF PEO C3BM) has the lead role in battle management and Command and Control (C2) capabilities for the DAF. This entails not only directing technical integration throughout the DAF but also holding acquisition authorities to develop and implement organic materiel solutions. These solutions aim to establish resilient and widely distributable command and control capabilities within the DAF BATTLE NETWORK. The ABMS PE portfolio funds specific programs over which the DAF PEO C3BM exercises direct oversight in terms of cost, schedule, and performance. This encompasses both the management of these programs and the necessary architectural and systems engineering efforts to ensure effective technical coordination across the broader DAF infrastructure. Additionally, DAF PEO C3BM has identified an initial array of approximately 50 core programs spanning various PEOs, whose organizations collectively form the C3BM Enterprise. These programs represent an evolving collection of systems that, when integrated together, are pivotal in contributing to the development of the DAF BATTLE NETWORK. Collaborating closely with the PEOs overseeing these core programs, DAF PEO C3BM will orchestrate technical integration of the DAF BATTLE NETWORK. This integration is essential to achieve the requisite operational decision advantage crucial for the triumph of the USAF, USSF, joint, and coalition forces in the face of evolving challenges. These inter-PEO initiatives encompass a spectrum of activities, such as technical and programmatic cooperation, comprehensive reporting, and seamless integration. With authority over technical architectures spanning the C3BM enterprise, DAF PEO C3BM will deliver C2 capabilities. To provide a "best of breed” capability across the DAF and facilitate accelerated delivery of the DAF BATTLE NETWORK, DAF PEO C3BM has aligned activities within the ABMS PE portfolio with six major thrust areas: Thrust Area 1: "Architecture and Systems Engineering (ASE)” will 1) conduct Digital Engineering to support technical development activities, 2) conduct mission domain architecture development and analysis and perform enterprise integration through domain-specific Mission Integration Teams (MITs), 3) leverage an Operational Response Team (ORT) to facilitate quick reaction prototyping and experimentation in response to warfighter-led efforts and new relevant technologies. The culmination of these activities will entail the identification, capture, refinement, and formalization of capability gaps, requirements, standards, and interface specifications, as well as potentially novel technologies, collectively paving the way for a blueprint to successfully deliver an all-encompassing integrated DAF BATTLE NETWORK architecture that informs execution of the following 3 thrust areas listed below. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604003F / Advanced Battle Management System (ABMS) Component Development & Prototypes (ACD&P) Thrust Area 2: "C3BM Digital Infrastructure (DI)" leverages the analysis, technical specifications and associated standards/formats produced by ASE to deliver a suite of fixed and deployable digital infrastructure solutions to enable global C2 and Battle Management (BM). To accomplish this, the following tasks are performed: 1) The Enterprise Systems Engineering Team (ESET) manages the ABMS Consortium to define the technical implementation of network architectures, style guides and standards that will facilitate integration of the larger DAF BATTLE NETWORK with ABMS (and vice versa); 2) build out of the physical DI Processing Nodes and DI Network (Software Defined Wide Area Network (SD-WAN), Tactical and Enterprise Cross Domain Solutions (CDS), and other similar requirements) that will enable the operational use of data and software to perform modern C2 functions at scale. DI activities include the ABMS Battle Lab to allow warfighters direct interaction with ABMS software development teams and prototypes in development, speeding up the feedback loop and product maturity. Thrust Area 3: "C3BM Software and Applications" provides a suite of battle management command and control (BMC2) applications and tools, conducted via two categories of activity. 1) Cloud-Based Command and Control (CBC2) is a suite of BMC2 applications and microservices in development for NORAD and USNORTHCOM & PACAF. CBC2 efforts include line of effort (LOE) #1 for a SW Integrator, LOE #2 for Agile Software Development at scale with an Integrated Digital Environment (IDE) for Model-based systems engineering (MBSE), and LOE #3 for Continuous Integration and Continuous Deployment (CI/CD) software pipelines, platform, data ingest, fusion, transport, storage, and access. CBC2 depends on the fixed DI activities of Thrust Area #2 and expects to begin scaling to support additional combatant commanders in FY26. 2) Distributed Battle Management Applications (DBMA) will continue development and extension of CBC2 functionality to other DAF BATTLE NETWORK entities (e.g. the Tactical Operations Center Family of Systems, or TOC FoS) in line with Air Combat Command's (ACC) Common BMC2 Interface concept, via the newly named CBC2+ program. Integral to the C3BM Software and Applications Thrust Area is the imperative to seamlessly align and integrate with various efforts, including multiple DoD & DAF software factories, centers of excellence dedicated to artificial intelligence and machine learning, and the DAF data fabric. Thrust Area 4: "C3BM Aerial Networking" will develop key technologies for the "final leg” connection of C3BM DI and Software and Applications to DAF aerial assets. Aerial Networking activities include: 1) Phalanx Griffon (PG), to extend C3BM aerial networking capabilities to tactically relevant aircraft. Major Release (MR) 2 will initiate and support initial capability delivery to long-range fires platforms by FY27. Phalanx Griffon will include continued development and maturation of multi-function processors, multi-function arrays, edge node hardware and software to host mission applications, and platform integration options to ease implementation and scaling. 2) The joint development of a SOSA-aligned, liquid and air-cooled integrated hybrid SATCOM chassis for rapid integration of PG capability by FY27, and 3) the C3 Hybrid SATCOM (C3HST) product line with a start date of FY26. The C3HST product line will consist of transition of the Global Lightning (GL) prototypes from AFRL to modernize and align those solutions to meet architectural requirements for multiple AF organizations. Thrust Area 5: "C3BM Deployable Systems" thrust to include Distributable Battle Management Node (DBMN) was previously captured under the C3BM Digital Infrastructure (DI) thrust area. The Deployable Systems effort will develop and deliver the Tactical Operations Center - Light (TOC-L) system. The TOC-L is a light, expeditionary BMC2 system designed to rapidly generate battle management effects tailored to mission needs, enabling the C2 warfighter to conduct independent, pulsed operations. The TOC-L enables tactical C2 elements to rapidly relocate, establish datalinks, connect to a variety of sensors, and operate in theater mission partner environments. TOC-L… [truncated]$$, 1040475000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604004F_640020$$, $$0604004F$$, $$640020$$, $$Advanced Engine Technologies$$, 0, $$Advanced Engine Technology activities expand industrial base knowledge and skills enabling future advanced propulsion system architectures and designs; propulsion systems include the inlet, engine and nozzle. Activities include: - Addressing manufacturing producibility, affordability, quality, risks and issues throughout the development process to improve product quality; enhance manufacturing processes; and strengthen the supply chain. - Maturing alloy, coatings, and composites to meet next generation component requirements through composite trials and component testing. - Developing Model Based Inspections techniques and increasing digital collaboration between Government and Industry to expand capability and capacity for future application. - Expanding use of Model Based Systems Engineering and incorporating learnings into advanced combat engine model development.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604004F_643608$$, $$0604004F$$, $$643608$$, $$Advanced Engine Dev$$, 0, $$Advanced Engine Development (AED) activities include all efforts necessary to develop and evaluate all thrust classes of advanced propulsion system architectures, designs, enabling advanced materials, component technologies, and manufacturing processes in realistic environments. AED also includes all efforts to define and evaluate modifications to commercial and military off the shelf propulsion systems for use in existing and future, aircraft and munitions. Prototyping and assessments of the prototypes at sea-level, simulated altitudes, and durability assessments across multiple power settings provide data to validate performance, calibrate engineering models, and ensure appropriate manufacturing and technology readiness for future propulsion system development and platform integration as well as potential insertion into already fielded propulsion systems. This project advances propulsion technologies from Advanced Technology Development (ATD) into Engineering and Manufacturing Development (EMD) when appropriate; some propulsion technologies may transfer directly from ATD into EMD.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604005F_640860$$, $$0604005F$$, $$640860$$, $$Nuclear Command$$, 67081000, $$The DAF nuclear enterprise has historically used unique closed systems to provide the high degree of mission assurance and security needed for this mission. Furthermore, the rapid development of the nuclear enterprise required the fielding of the most advanced technology of that time, and in most cases utilized technology that was well ahead of the commercial sector. Today the technological world is very different and in cases such as satellite communications and information technology (IT) systems the commercial sector has raced ahead of government unique systems. Commercial Leveraging for the nuclear enterprise will explore a range of key technologies that are either commercial, or commercial entwined with government system to quantitatively determine whether these capabilities provide increased resilience, improved reconstitution, or lower cost for applications within the DOD nuclear enterprise. It is not intended to replace baseline systems but rather will be prototypes to augment existing capabilities. The program will reduce risk in leveraging emerging commercial-based technologies by partnering with industry while providing access to Government analysis, testing and certification capabilities. Prime investments focus on Government-Industry partnerships to influence and militarize emerging commercial capabilities to ensure US competitive advantage in key technology areas. Experimentation efforts will be employed to explore new concepts and their applications in future operating environments within a system-of-systems context taking risks early in the acquisition process to drive a more optimized and efficient acquisition approach significantly reducing overall acquisitions costs. Prototyping of commercially derived technologies into government systems, followed by operational experimentation of the performance and security, will enable these candidate technologies to move into warfighting capability faster and at a lower cost, based on demonstrated low-risk prototypes. Efforts include a focus on communications, secure data flow, and incorporating commercial approaches for a coarse navigation capability. Communications will focus primarily on satellite links by prototyping terminals that can gain access and switch across multiple commercial and government links from a common terminal. Multiple commercial vendors will be competitively awarded contracts for these prototypes and will work with the government partners to interface with selected platforms across the enterprise. Secure data flow will test various techniques across commercial and DOD partners to smartly utilize multiple communications paths to increase Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604005F / NC3 Commercial Development & Prototyping Component Development & Prototypes (ACD&P) resilience, and to integrate with hybrid architectures under USSF and across terrestrial networks. Coarse navigation will explore, test and prototype commercially derived approaches to resiliently provide a very coarse navigation capability to disadvantaged users. This capability does not replace GPS or other advanced precision DOD Position-Navigation-Timing capabilities or approach their exquisite capabilities but will instead provide a back-up option for a coarse capability for a scenario when no other options are available to the DOD user. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F, 0605831F, and/or 0606017F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, 67081000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604007F_644413$$, $$0604007F$$, $$644413$$, $$E-7A$$, 199676000, $$Funds the E-7 program. The E-7 program replaces the unsustainable E-3 Airborne Warning and Control System (AWACS). The E-3 AWACS, first fielded in the 1970s, is at the end of its service life, and costly to maintain. The E-7 will serve as the USAF's principal airborne platform for airborne command and control and airborne moving target indicator, providing a reliable, persistent critical node in the long range kill chain for the Joint Force Air Component Commander (JFACC). The E-7 will provide increased capabilities to the USAF and the Joint Services to include the ability to detect and track highly maneuverable, small radar cross-section airborne targets (modern and emerging threats), the ability to real-time process and create a precise air picture, and the ability to battle manage (e.g. command and control) under a wide range of operational conditions. The E-7A is a highly modified Airborne Battle Management and Command and Control aircraft integrating a Boeing 737-700 Next Generation (737NG) airframe with a reinforced fuselage Section 46, a Northrop Grumman Multi-Role Electronically Scanned Array (MESA) Radar mounted on the aircraft's Section 46, and two 180-kVA generators added to commercial CFM-56 engines mounted beneath each wing. The E-7 will provide a reliable, operationally available, maintainable, and sustainable capability. E-7A consists of completing end items and modification components for aircraft to support test and evaluation; hardware and software modernization development efforts to ensure compliance with US cybersecurity and program protection standards; development efforts to ensure navigation and communication systems comply with GPS M-Code and Narrowband SATCOM mandates; development efforts to design and build flight planning terminals, deployable mission support systems, and mission crew trainers; design and build-out contractor and government System Integration Laboratories supporting development, integration, and test activities; and provide analysis and products supporting future requirements and airworthiness certification. E-7 Command and Control, Intelligence, Surveillance, and Reconnaissance (C2ISR): C2ISR system improvements investigate and develop future capabilities of the E-7 weapon system. These efforts also include but are not limited to advanced sensors, advanced communications, self-protection, enhanced cyber protection, the staffing and studying of cooperative development capabilities, and obsolescence resolution to ensure that the E-7 successfully integrates with joint and coalition forces in a net- centric environment. C2ISR primarily supports pre-systems acquisition in the areas of materiel solution analysis and technology development. This is accomplished by prototyping and demonstrating capabilities required by the warfighter. C2ISR also supports an analytical comparison of suitability, life-cycle cost, and system capabilities of alternative materiel solutions beyond the current E-7A that satisfy an established capability need identified in a User Requirements Document. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604007F / E-7 Component Development & Prototypes (ACD&P) This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, or 0606398F. In FY 2024 $4.970M was expended for civilian pay expenses in this program element, and in FY 2025 $8.059M is forecast for civilian pay expenses in this program element. The FY 2026 cost of the E-7A Middle Tier of Acquisition effort is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, 199676000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604009F_640856$$, $$0604009F$$, $$640856$$, $$AFWERX Operations and Support$$, 12648000, $$The AFWERX mission is to accelerate agile and affordable capability transitions by teaming innovative technology developers with Airmen and Guardian talent. AFWERX leverages Spark (the Airmen and Guardian talent base), AFVentures (the dual-use expanded technology base), and Prime (technology transitions) to scale and accelerate the capability. Funding in this project supports AFWERX research and development, innovation hubs, and information technology, public affairs, and marketing. The Spark mission is to inspire and enable Airmen and Guardians to unleash their collective talent and ingenuity. Spark connects innovators using virtual collaboration, immersive training, and networking opportunities to inspire ideas and cultivate a more lethal force. By connecting operators closer to acquisition processes, Spark provides both a voice and a conduit to accelerate powerful ideas into game-changing operational realities. This focus helps guide technologies through transition across the valley from idea to scaled and sustained capability. Beginning in FY 2024, Program 0604317F, Technology Transfer, Project 646030, AFWERX and Project 64317A, Technology Transfer Add were transferred to Program 0604009F, AFWERX Prime, Project 640856 AFWERX Operations and Support.$$, 12648000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604009F_640858$$, $$0604009F$$, $$640858$$, $$AFWERX Prime$$, 5851000, $$AFWERX Prime leverages an acquisition approach that uses government specific resources to reduce risk in emerging technology markets and enables transition into DoD capabilities. AFWERX Prime is dedicated to discovering emerging commercial technologies with the potential for use as military capabilities. AFWERX Prime partners Air Force resources with investors, commercial industry, non-traditional contractors, academic institutions, and inter-agency organizations to discover, develop, mature, test and transition dual use technologies. AFWERX Prime employs novel and rapid acquisition methodologies to facilitate accelerated, cost-effective, agile development of commercial and military capabilities. The technologies targeted by AFWERX include hybrid-electric powered Vertical and Short Take Off and Landing Aircraft; Scalable Aircraft Autonomy; Autonomous Logistics Systems; Expeditionary Combat Support Systems; Advanced Manufacturing; sUAS and Counter-sUAS; enhanced, low cost, distributed, scalable and digital Manufacturing and an AFWERX Autonomy Proving Ground. AFWERX Prime fosters the development of dual-use technologies through collaborative efforts and partnerships with investors, industry, interagency, and international partners for accelerated, affordable, and agile commercial and military capability. AFWERX Prime endeavors to strategically leverage commercial investments in technologies that facilitate mobility and sustainment within benign or contested environments to enable agile, cost-effective distributed logistics, humanitarian operations, personnel transport, disaster response initiatives, and enhanced communications capabilities. AFWERX Prime is pursuing efforts to assist in building robust, cost- effective capacity for swift evaluation, iteration, and maturation of emerging mission and applied autonomy technologies to deliver enhanced autonomy to assist in meeting the requirements of the Department of Defense (DoD). Prime technical focus areas, such as Agile Support, Autonomy Focus, and Manufacturing will leverage commercial technology and investment resulting in the advanced, agile, and accelerated deployment of commercial and military capabilities that bolster national security and domestic technological dominance.$$, 5851000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604010F_640864$$, $$0604010F$$, $$640864$$, $$Next Generation$$, 330270000, $$The Next Generation Adaptive Propulsion (NGAP) program builds upon advanced materials, technologies and manufacturing processes matured under the Adaptive Engine Transition Program (which ended in FY24) to enhance adaptive propulsion system performance and size scalability key to enabling future aircraft capabilities. Embedded adaptive propulsion systems combine the fuel efficiency of high-bypass turbofan engines used by commercial airlines with the performance demanded of military fighter engines with augmenters. Increased fuel efficiency reduces energy demand and aerial tanker dependency while increasing platform range and or time on station. During peacetime, these benefits translate to reduced aerial tanker dependency during exercises and a choice between increased aircrew readiness or cost savings due to the less fuel needed. NGAP prototyping will validate the performance and maturity of its enabling advanced technologies, platform agnostic engine architectures and designs, and manufacturing processes through prototype testing. NGAP will also drive digital transformation of the propulsion industrial base to reduce future integration risks while shortening development timelines. Prior to FY 2024, the NGAP program was reported in PE 0604004F, Advanced Engine Development, Project 643608, Advanced Engine Development. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 $5.669 million was expended for civilian pay expenses in this program element, and in FY 2025 $7.401 million is forecasted for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604010F / Next Generation Adaptive Propulsion Component Development & Prototypes (ACD&P)$$, 330270000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604011D8Z_171$$, $$0604011D8Z$$, $$171$$, $$5G Cross Functional Team$$, 22439000, $$Same as program level mission description.$$, 22439000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604011K_DIG$$, $$0604011K$$, $$DIG$$, $$5G Technology$$, 0, $$5G is the 5th generation mobile network. 5G wireless technology is meant to deliver higher multi-Gbps peak data speeds, ultra-low latency, more reliability, massive network capacity, increased availability, and a more uniform user experience to more users. 5G is a unified, more capable air interface. It has been designed with an extended capacity empower new deployment models and deliver new services. With high speeds, superior reliability and negligible latency, 5G will expand the mobile ecosystem into new realms.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604025F_640858$$, $$0604025F$$, $$640858$$, $$AFWERX Prime$$, 0, $$The Department of the Air Force's component of the Rapid Defense Experimentation Reserve (RDER) is executed within this program element (PE). To facilitate rapid modernization of the force, the RDER initiative was established in the Defense Planning Guidance for Fiscal Years 2023-2027, to encourage multi-component experimentation through a campaign of learning. Services, Agencies, and other participating organizations are to identify "best of breed” capabilities developed among the DoD prototyping programs, and execute approved projects through large-scale, cross- service experiments in order to refine and/or validate the Joint Warfighting Concept (JWC). Organizations nominate proposals to the Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)) that are multi-component — involving Joint Services, International partners and/or other government agencies and link to one or more of the four key supporting concepts ("functional battles”) of the Joint Warfighting Concept: Joint Concept for Fires, Joint Concept for Command and Control, Joint Concept for Contested Logistics, and Joint Concept for Information Advantage.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604014N_2069$$, $$0604014N$$, $$2069$$, $$F/A-18 Infrared Search and Track$$, 0, $$The AN/ASG-34A(V)1 F/A-18E/F Infrared Search and Track (IRST) system is a long-wave infrared sensor that provides a passive, out-of-band, alternate fire control system capable of detecting, tracking and engaging airborne targets, at long range, in a heavy electronic attack or radar-denied environment. IRST Block II is the primary out-of-band fire-control system for the F/A-18E/F, critical to organic passive air-to-air kill-chains required to compete with peer adversaries. Enables F/A-18E/F lethality by providing a passive means to detect, track, and target aircraft in highly contested environments in support of the objectives outlined in the National Defense Strategy. IRST enhances survivability by providing a fire-control solution without the need to radiate in the RF spectrum. The IRST system can autonomously, or in combination with other sensors, support the guidance of beyond-visual-range missiles including AIM-120C/D and AIM-9X Block II. The F/A-18E/F IRST system is an evolutionary Navy acquisition program with Block I and Block II capabilities. The USN is committed to further development of this component of the passive kill chain. This budget request supports Block II development and testing of a redesigned Infrared Receiver (IRR) and processor, enabling full Capabilities Development Document (CDD) capability over a larger field of regard.$$, 0, NULL, NULL, NULL, NULL, 451201000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604015F_643308$$, $$0604015F$$, $$643308$$, $$B-21 Development$$, 1589908000, $$This program is reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program Annual Report to Congress. Program overview provided below. The Long Range Strike - Bomber (B-21 Raider) is crucial to the nuclear modernization plan, forming the backbone of the Nation's future bomber force, providing both conventional and nuclear capability. The B-21 platform provides range, access, and payload to go anywhere needed, with the weapons required to deter and win our nation's wars. Its open system architecture will enable rapid integration of future capabilities, keeping the platform relevant and effective as the threat environment evolves. The Air Force requires a minimum of 100 B-21s as part of the long-term bomber force. The Engineering and Manufacturing Development (EMD) contract was awarded in 2015, followed by a Critical Design Review (CDR) completed in 2018. Test aircraft are executing the B-21 flight test campaign and an approved Milestone C decision with all statutory and regulatory documentation was completed in 2023. Subsequently, the first two production lots have been awarded. B-21 aircraft will be delivered to operational bases in the mid-2020s. The FY2026 request for the B-21 Development BPAC includes $1,589.908M of discretionary and $2,391.920M of mandatory/reconciliation ($1,721.920 enhancement & $670M transfer from discretionary) for a total of $3,981.828M. The enhancement funds expansion of capacity of B-21. Further information for this reconciliation request is provided in Section 20008 of the Reconciliation Exhibit. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability.$$, 1589908000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604015F_644044$$, $$0604015F$$, $$644044$$, $$B-21 Modernization$$, 757317000, $$This program is reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program Annual Report to Congress. Program overview provided below. The Long Range Strike - Bomber (B-21 Raider) is crucial to the nuclear modernization plan, forming the backbone of the Nation's future bomber force, providing both conventional and nuclear capability. The B-21 platform provides range, access, and payload to go anywhere needed, with the weapons required to deter and win our nation's wars. Its open system architecture will enable rapid integration of future capabilities, keeping the platform relevant and effective as the threat environment evolves. The Air Force requires a minimum of 100 B-21s as part of the long-term bomber force. The Engineering and Manufacturing Development (EMD) contract was awarded in 2015, followed by a Critical Design Review (CDR) completed in 2018. Test aircraft are executing the B-21 flight test campaign and an approved Milestone C decision with all statutory and regulatory documentation was completed in 2023. Subsequently, the first two production lots have been awarded. Modernization BPAC for tracking separately from EMD funding line created 2024. B-21 aircraft will be delivered to operational bases in the mid-2020s. The FY2026 request for the B-21 Modernization BPAC includes $757M of discretionary and $0M of mandatory (reconciliation) for a total of $757M. The mandatory funds expansion of capacity of B-21. Further information for this reconciliation request is provided in Section 20008 of the Reconciliation Exhibit.$$, 757317000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604016D8Z_015$$, $$0604016D8Z$$, $$015$$, $$Corrosion Protection Projects$$, 2545000, $$The DoD RDT&E corrosion prevention program, as defined in Public Law 107-314 in section 2228 of title 10 United States Code (section 2228(d)(2)), is the mechanism to change DoD’s reactive approach of corrective corrosion maintenance to a proactive approach to improve weapon system corrosion prevention reliability and maintainability through technology. The strategic goal of the DoD Corrosion Prevention Program is to demonstrate the ability to improve weapon system readiness through the implementation of targeted and effective material and nonmaterial solutions that reduce the corrosion impacts on reliability, maintainability, and cost of DoD weapon systems and infrastructure. Historically, the program’s projects have shown an opportunity to achieve a 17:1 return-on-investment. From 2001-2023, the Government Accountability Office (GAO), the Congressional Budget Office and the DoD IG have conducted multiple weapon systems and infrastructure audits and continue to find corrosion is a significant impact on availability and cost. GAO’s Aviation Sustainment Quick Look reports (GAO-18-678, GAO-21-101SP, and GAO-23-106217) consistently show that 33% of the audited aviation systems report corrosion as a factor in reduced aviation Operational Availability (Ao) rates. The F-35 program is a current example of current corrosion prevention acquisition decisions and resulting corrosion maintenance issues of the continued flawed approach to weapon system corrosion prevention. In addition, corrosion continues to be a major factor in Materiel Availability (Am) of weapon systems. Examples of the corrosion impact on materiel availability include: (a) F-22 Reliability and Maintainability Maturation Program total funding requirement increased 100% ($664 million to $1.3 billion) to correct unplanned corrosion issues (GAO-12-447, GAO-14-425) (b) The Department of the Navy is deferring shipyard corrosion repairs, allocating a 6%+ cost growth factor for future corrosion repair work. (GAO-22-105032) These materiel availability examples illustrate the continued reactive sustainment engineering approach to corrosion prevention during the operational and sustainment phase of fielded weapon systems. Furthermore, the Maintenance Availability Data Warehouse (MADW) data, maintained on DoD online data repository, shows a $20 billion total corrosion maintenance cost trend across DoD weapon systems and infrastructure. In perspective, the allocated FY 2025 budget for the DoD Corrosion Program represents an investment equivalent to 0.013% of the $20 billion annual corrosion maintenance cost of weapon systems and infrastructure.$$, 2545000, NULL, NULL, NULL, NULL, 156773000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604025F_640862$$, $$0604025F$$, $$640862$$, $$Rapid Defense Experimentation$$, 0, $$No funds requested in the 2026 President's Budget. Experimentation Efforts supported under Rapid Defense Experimentation Reserve (RDER) for FY 2025: -Angry Badger: experiment to develop capability for achieving force projection in highly contested environments utilizing existing aircraft fleet structure. --(previous: JRBL Cage: Consolidation of Best in Breed Podded technologies) -DEFEND Experimentation -Classified Projects (more information available in appropriate forums)$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605502D8Z_503$$, $$0605502D8Z$$, $$503$$, $$SBIR CR Program$$, 0, $$Under the authority defined in 15 U.S.C. 638 (y), Commercialization Readiness (CR) Program (CRP), OSD established the “OSD Transitions SBIR/STTR Technology (OTST) Program”. The CR Program is a dynamic, results-oriented response to the Congressional challenge to the DoD in 2006 to deliver more advanced SBIR/STTR technologies faster to our warfighters. The OTST program is an interim technology maturity phase (Phase II) inserted into the SBIR/STTR development process and is structured to be a technology pull to meet requirements that address potential and emerging requirements.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604017A_FD9$$, $$0604017A$$, $$FD9$$, $$Robotics Systems$$, 35082000, $$Robotics Development funding is to demonstrate new capabilities to meet current and future military needs and to determine integration potential across the Army Ground Robotics portfolio by testing and evaluating a variety of emerging technologies. Robotics Development (RD) improves robotic and autonomous program acquisition schedules by supporting the development of integrated and synchronized capability documents (e.g. JCIDS, Department Directed, etc.) and by maturing / transitioning technology. Research, Development, Test & Evaluation (RDT&E) funds enable support to capability development of emerging requirements. Activities include collaboration with industry and government, studies, assessments, and document development such as Technology Readiness Levels, Manufacturing Readiness Levels, Analysis of Alternatives / Letter of Sufficiency determinations, draft acquisition documents, and draft contract documents. RD also supports the Army modernization strategy of the current Ground Robotic fleets and current Army vehicles by investigating technology insertions including, but not limited to condition-based maintenance, vetronics, autonomous operations and other ground robotics technologies. FY 2026 Base RDTE funds in the amount of $35.082 million will continue to demonstrate and explore technologies that support the Army's Transformation Initiative published in 2025. Funding will also support expansion of the virtual test and evaluation capabilities for autonomous software and electronic warfare.$$, 35082000, NULL, NULL, NULL, NULL, 2912000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604019A_BU9$$, $$0604019A$$, $$BU9$$, $$IFPC High Energy Laser$$, 16416000, $$This funding line is directly aligned to the Army Air and Missile Defense Modernization Priority. The Directed Energy Integrated Fires Protection Capability (DE-IFPC) High Energy Laser (HEL) is an Air Defense capability consisting of an IFPC-HEL prototype with residual combat capability at the IFPC Battery Level in support of Multi-Domain Operations (MDO). IFPC-HEL will provide the Army prototype weapon system for defense of fixed and semi-fixed sites from Cruise Missiles (CM); Unmanned Aircraft Systems (UAS); Rocket, Artillery, and Mortar (RAM); Fixed Wing (FW); and Rotary Wing (RW) threats. This project will deliver an operationally effective rapid prototype capability in the near term. IFPC-HEL funds an improved mechanism to effectively confront emerging threats and advance the United States' military dominance in accordance with the National Defense Strategy. Efforts include development, acquisition, test and evaluation, assessment, maturation, and potential future transition of the prototype technology to an acquisition program. This PE supports transitioning the High Energy Laser Tactical Vehicle Demonstration S&T effort to manufacturing a combat ready rapid prototype system for delivery in FY 2026 and potential future transition to Program of Record.$$, 16416000, NULL, NULL, NULL, NULL, 58993000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604019A_CO6$$, $$0604019A$$, $$CO6$$, $$IFPC High Power Microwave (HPM)$$, 11773000, $$This funding line is directly aligned to the Army Air and Missile Defense Modernization Priority. The Directed Energy Integrated Fires Protection Capability (DE-IFPC) High Power Microwave (HPM) is an Air Defense capability consisting of the IFPC-HPM prototype with residual combat capability at the IFPC Battery Level in support of Multi-Domain Operations (MDO). The IFPC-HPM program will provide the Army with HPM prototype weapon systems for the short-range defense of fixed and semi-fixed sites from a single Unmanned Aircraft System (UAS) and swarms. This project will deliver an operationally effective rapid prototype capability in the near term. IFPC-HPM funds an improved mechanism to effectively confront emerging threats and advance the United States' military dominance in accordance with the National Defense Strategy. Efforts include development, acquisition, test and evaluation, assessment, maturation, and future transition of prototype technologies to an acquisition program.$$, 11773000, NULL, NULL, NULL, NULL, 50759000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604019A_DJ5$$, $$0604019A$$, $$DJ5$$, $$Multi-Domain Artillery Cannon System$$, 149948000, $$The Multi-Domain Artillery Cannon System (MDACS) mission is to defend Joint Force fixed and semi-fixed locations against attack by a broad spectrum of Unmanned Aerial Systems (UASs), Cruise Missiles (CMs), Fixed Wing (FW), Rotary Wing (RW), and other advanced air and missile threats and to complement existing air and missile defenses by operating in integrated or stand-alone operational scenarios. Additionally, MDACS may provide a future surface-to-surface long-range precision fires capability. As a potential component of Golden Dome of America, the Army will consider static deployment as part of the design. MDACS is a rapid prototype and Integrated Air and Missile Defense (IAMD) Battle Command System (IBCS) integrated system consisting of a Multi-Domain Artillery Cannon (MDAC), Multi-Function Precision Radar (MFPR), Multi-Domain Battle Manager (MDBM), Hypervelocity Projectiles (HVP), and ammunition handling vehicles. MDACS will build onto the Army Integrated Air and Missile Defense (AIAMD) open systems architecture allowing seamless sensor and shooter connectivity for a layered defense with a mission command structure integrated into the IAMD Battle Command System (IBCS). MDACS will increase battlefield flexibility and raid capacity, resulting in increased AMD effectiveness and efficiency and reduced attrition of advanced interceptor missiles in the Army's inventory. The Army will leverage current Office of the Secretary of Defense?(OSD) Strategic Capabilities Office (SCO) investments in the Hypervelocity Gun Weapon System (HGWS) to develop an Army design tailored to address Army requirements and assess MDACS at a Battery level in FY 2030. The prototype will inform an enduring capability requirement.?$$, 149948000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604020A_DC8$$, $$0604020A$$, $$DC8$$, $$Army Experimentation and$$, NULL, $$Army led programs and experimentation enable Joint All Domain Operations concepts applicable across multiple Combatant Commands (CCMD) to address OUSD R&E priority scenarios. Individual efforts bring together layered solutions to compete with peer and near-peer adversaries through the development of capabilities that support fires, command and control, logistics, and capabilities that will drive information advantage. These activities will accelerate joint warfighting capabilities to quickly demonstrate and assess innovative technologies resulting in follow-on Office of the Secretary of Defense (OSD), Army, and other Service efforts for accelerated transition of the technologies to CCMD required operations. The cited work is consistent with the Under Secretary of Defense for Research and Engineering priority focus areas and the Joint Warfighting Concepts.$$, NULL, NULL, NULL, NULL, NULL, 61779000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604119A_BR2$$, $$0604119A$$, $$BR2$$, $$Advanced Component$$, NULL, $$The Advance Component Development & Prototype budget line includes multiple efforts across the Army's Battlefield Operational Systems necessary to evaluate integrated technologies in the most high fidelity and realistic operating environment as possible to assess the performance or cost reduction potential of advanced technology. Projects focus on proving component and subsystem maturity prior to integration in major and complex systems and may involve risk reduction initiatives. Efforts also includes advanced technology demonstrations to expedite technology transition from the laboratory to operational use, with the goal of transitioning systems into the acquisition process within the FYDP.$$, NULL, NULL, NULL, NULL, NULL, 204914000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605502N_2240$$, $$0605502N$$, $$2240$$, $$SBIR ADMIN - USMC$$, 0, $$Small Business Innovation Research (SBIR) Administration funds to manage the program, technical efforts, and award contracts related to SBIR.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604025M_2352$$, $$0604025M$$, $$2352$$, $$Rapid Defense Experimentation$$, 99000, $$The Marine Corps component of the Rapid Defense Experimentation Reserve (RDER) initiative aligns with this program element (PE). Established in the Defense Planning Guidance for Fiscal Years 2023-2027, this initiative aims to accelerate the modernization of the force by fostering a culture of multi-component experimentation. Through a campaign of learning, the RDER initiative enables participating organizations including services, agencies, and other stakeholders to identify top-tier capabilities derived from Department of Defense (DoD) prototyping programs. Approved projects are executed via large-scale, cross-service experiments designed to validate and refine the Joint Warfighting Concept (JWC). Organizations are encouraged to submit proposals that involve multi-component collaboration with Joint Services, International partners, and other government agencies. Proposals should target one or more of the four key supporting concepts of the Joint Warfighting Concept: Joint Concept for Fires, Joint Concept for Command and Control, Joint Concept for Contested Logistics, and Joint Concept for Information Advantage.$$, 99000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604027N_3253$$, $$0604027N$$, $$3253$$, $$Common Weapon Datalink Radio$$, 0, $$The details of this program element are classified SECRET and are submitted annually to Congress in the classified budget justification books.$$, 0, NULL, NULL, NULL, NULL, 22517000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604027N_3255$$, $$0604027N$$, $$3255$$, $$Decision Support Tools and AI$$, 80053000, $$The details of this program element are classified SECRET and are submitted annually to Congress in the classified budget justification books.$$, 80053000, NULL, NULL, NULL, NULL, 82741000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604027N_3425$$, $$0604027N$$, $$3425$$, $$Digital Warfare$$, 71218000, $$The details of this program element are classified SECRET and are submitted annually to Congress in the classified budget justification books.$$, 71218000, NULL, NULL, NULL, NULL, 182463000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604027N_9999$$, $$0604027N$$, $$9999$$, $$Congressional Adds$$, 0, $$The details of this program element are classified SECRET and are submitted annually to Congress in the classified budget justification books.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604028N_1036$$, $$0604028N$$, $$1036$$, $$TETRA$$, 984000, $$(U) The TETRA program is a continuation of efforts, realigned from Program Element (PE) 0604029N (UUV Core Technologies) Project Unit (PU) 4053 (UxS Platform) to PE 0604028N (Small/Medium Unmanned Undersea Vehicles) PU 1036 (TETRA) in FY25, and also includes payload development addressing emergent operational requirements. (U) This is the sole project unit that enables deployment of TETRA, which is an operationally relevant Remotely Operated Vehicle (ROV) that is launched, and recovered, from submarine torpedo tubes. TETRA is a ROV with the capacity for multiple mission payloads as a key enabler to Subsea Seabed Warfare (SSW) to locate, identify, and provide real-time payload employment to effect objects of interest as identified in the SSW Initial Capabilities Document (ICD). As a tethered system, TETRA will provide real-time operational data back to the platform and enable man-in-the-loop intervention to maximize the efficiency of a sortie. Experimentations will be conducted with Unmanned Undersea Vehicle Squadron One (UUVRON ONE), Special Reconnaissance Team - 2 (SRT 2), and Naval Special Warfare Group 8 (NSWG 8) utilizing government test events, lake testing, and barge tests to provide Fleet and acquisition stakeholders with relevant payload and vehicle employment to inform Concept of Operations (CONOP) and fielding decisions using platforms of opportunity. (U) This project line is utilized for the development, and integration, of payloads into the TETRA ROV. Funding is also required to begin integration into Submarine Warfare Federated Tactical System (SWFTS) to reduce TETRA's stowage footprint. The majority of TETRA's operator training will be accomplished at the M241 barge, which includes a mock shutterway to practice Torpedo Tube Launch and Recovery (TTL&R) from a moving platform. Funding is required for training time on the M241 Barge. This funding line will support TETRA's transition from the Rapid Fielded Temporary Alteration (RF TEMPALT) to the Submarine of Opportunity (SOO) system, which increases configuration management, decreases the amount of time required to install on a platform, and allows for local minor changes to equipment. (U) The BootStrap program is an operational capability addressing specific Combatant Commander's evolving and emergent operational requirements. BootStrap is a classified program.$$, 984000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604028N_2482$$, $$0604028N$$, $$2482$$, $$Small Unmanned Undersea Vehicles$$, 0, $$As part of the Expeditionary UUV Family of Systems (FoS) the LIONFISH UUV Program of Record develops advanced SUUVs to support myriad missions across warfare domains. The missions include; expeditionary mine countermeasures, expeditionary data collection and surveillance, and intelligence preparation of the environment (IPOE). Equipment includes vehicles and associated systems support equipment. Planned block upgrades include increased detection range capability, communications upgrades, automated target recognition, cybersecurity, autonomy and command and control improvements, additional launch and recovery abilities, increased operational depth, and payloads as required. FY2026 Supports planned improvements for the vehicles now in full rate production, to include RDTE for advanced sensor packages, software development/ integration, automatic target recognition, and usability upgrades.$$, 0, NULL, NULL, NULL, NULL, 22793000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604028N_2483$$, $$0604028N$$, $$2483$$, $$Medusa$$, 3124000, $$MEDUSA is a medium class UUV capable of offensive mining capabilities deployed from a submarine. MEDUSA features torpedo tube launch capability, long range, high payload placement accuracy, and can support heavy payloads. A demonstration system was developed and tested in FY21 with dummy payloads using a land- based launch facility and surface launched in-water demonstrations. Lessons learned from the demonstration informed a program start in FY 2022 and competitive award to Industry in FY 2024 to develop and produce tactical prototype systems.$$, 3124000, NULL, NULL, NULL, NULL, 12513000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604028N_3123$$, $$0604028N$$, $$3123$$, $$SMCM UUV$$, 0, $$As part of the UUV Family of Systems (FoS) and in support of the Mine Countermeasures (MCM) Mission Package (MP), the Surface Mine Countermeasures Unmanned Undersea Vehicle (SMCM UUV) Program, also referred to as Knifefish, develops advanced medium class UUVs to support clandestine mine detection capability against volume, bottom, and buried mines, in high clutter environments. Equipment includes UUVs and associated system support equipment. The program achieved Milestone C in FY 2019 and entered into Low-Rate Initial Production (LRIP) for five (5) Block 0 systems in FY 2019. The prime contractor for Knifefish is General Dynamics Mission Systems (GDMS) located in Quincy, MA. In FY 2021, GDMS was awarded a contract to retrofit the LRIP systems with Block 1 capabilities and upgrade a number of performance characteristics to meet Navy bottom and buried mine hunting requirements. The Navy will conduct a limited validation of these capabilities during system acceptance testing and sell off to the government in Q1-Q3FY24. Upon delivery of these systems to the Navy, they will be available for limited Fleet operations from LCS or Vessels of Opportunity (VOO).$$, 0, NULL, NULL, NULL, NULL, 97229000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604120A_ED5$$, $$0604120A$$, $$ED5$$, $$Assured Positioning, Navigation and$$, 8686000, $$APNT Modernization development prototypes for a layered/tiered PNT solutions on clients and vehicular platforms. APNT Modernization will fully implement a Modular Open Systems Approach (MOSA), support future integration of Military GPS User Equipment (MGUE) Increment 2, and improve complimentary PNT capability that provides a layered, accurate position and time in the absence of GPS for extended missions. This enables the Science & Technology transitions of incremental and disruptive technologies to fieldable Positioning, Navigation and Timing (PNT) solutions to pace or overmatch current and evolving threats and in accordance with National Defense Authorization Act (NDAA) Guidance (2021 NDAA: Section 1611). Fiscal Year (FY) 2026 Base funds in the amount of $8.686 million continues prototype hardware/software development, systems engineering, and program management for the APNT Modernization efforts.$$, 8686000, NULL, NULL, NULL, NULL, 2903000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604028N_3785$$, $$0604028N$$, $$3785$$, $$Razorback$$, 579000, $$A part of the Family of UUVs, Razorback is a medium class UUV capable of persistent, autonomous, ocean sensing and data collection in support of Navy Intelligence Preparation of the Operational Environment (IPOE) mission. The Razorback has two variants, the Razorback MK19, formerly referred to as Razorback Dry Deck Shelter (DDS), and the Razorback MK20, formerly referred to as Razorback Torpedo Tube Launch and Recovery (TTL&R). The Razorback MK19 variant procurement began in FY 2017 and Fleet operational deployments began in FY 2021. Development of requirements and submarine integration efforts commenced in FY 2019 for MK20 variant, which was competitively sourced to industry in FY 2022. Razorback training development begins in FY 2026. Razorback MK20 leverages risk reduction efforts for torpedo launch and recovery and host submarine integration performed under PE 0604029N UUV Core Technologies. In order to deploy Razorback or other small or medium class UUVs from a host submarine platform with sufficient endurance to perform a desired mission, high energy density sources such as lithium-ion batteries are used. Consequently, safety is paramount and mitigation systems must be in place to prevent or stop a high energy casualty event. Shock and Fire Enclosure Capsule (SAFECAP) is being developed as an active mitigation strategy that includes a shock qualified capsule that aides in the launch and recovery of small and medium sized UUVs through the torpedo tube, including Razorback. SAFECAP effort was transferred from PE0604028N PU3785 to PE0604029 PU4053 in FY 2025.$$, 579000, NULL, NULL, NULL, NULL, 86291000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604028N_4023$$, $$0604028N$$, $$4023$$, $$Expeditionary Underwater Systems$$, 168000, $$Funding supports the development of unmanned systems for the Navy's expeditionary unmanned underwater Explosive Ordnance Disposal (EOD) and Mine Countermeasures (MCM) capability. Specifically, it provides for development of expeditionary, unmanned underwater systems to support Navy Expeditionary forces including EOD, Mobile Diving and Salvage, Underwater Construction Teams (UCT), Very Shallow Water (VSW), and Expeditionary Mine Countermeasures (ExMCM) mission operations. The equipment must be highly portable in order to support the Navy EOD technician to safely approach, render safe, recover, exploit, and dispose of underwater explosive threats to include sea mines, limpet mines, and unexploded ordnance. Provides support for the Navy's high priority missions of Maritime Homeland Defense and MCM, including reconnaissance and mine clearance in support of amphibious operations. Development of Expeditionary UUV systems to support localization render-safe and detailed intelligence gathering of unexploded ordnance (UXO) including Underwater Improvised Explosive Devices (IEDs). This project directly supports the requirements defined by the Maritime Expeditionary MCM UUV (MEMUUV) CDD. Viperfish UUV is an incremental increase in capability from MK 18 MOD 2. It will leverage volume and bottom mine hunting capabilities, increase endurance from the Mod 2 system, increased depth capability, and will have embedded automated target recognition (ATR).$$, 168000, NULL, NULL, NULL, NULL, 185088000, 2026) ON CONFLICT DO NOTHING;
