INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604030N_0385$$, $$0604030N$$, $$0385$$, $$Rapid Prototype Development$$, 0, $$To facilitate rapid modernization of the force, the RDER initiative was established in the Defense Planning Guidance for Fiscal Year 2023-2027, to encourage multi- component experimentation through a campaign of learning. Services, Agencies, and other participating organizations are to identify "best of breed" capabilities developed among the DoD prototyping programs and execute approved projects through large-scale experiments in order to refine and/or validate the Joint Warfighting Concept (JWC). Organizations are to nominate proposals to the Office of the Under Secretary of Defense for Research and Engineering (OUSD(R&E)) that are multi- component involving Joint Services, International partners and/or other government agencies and link to one or more of the four key supporting concepts ("functional battles") of the Joint Warfighting Concept: Joint Concept for Fires, Joint Concept for Command and Control, Joint Concept for Contested Logistics, and Joint Concept for Information Advantage.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
