INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604120A_EH8$$, $$0604120A$$, $$EH8$$, $$DISMOUNTED$$, NULL, $$There are no Base funds for project Dismounted (EH8) in Fiscal Year (FY) 2026. Dismounted Assured PNT (APNT) System (DAPS) meets congressional (10 USC 2281) and Department of Defense guidance to provide resilient, survivable, M-Code Global Positioning System (GPS) capable Ground User Equipment (MGUE) receivers and Alternative Navigation (ALTNAV). The DAPS will provide Soldiers Assured PNT (APNT) information utilizing various sources of PNT data to address multiple threats and ensure mission success where Global Positioning System (GPS) may be limited or denied. DAPS will deliver APNT in an optimized form factor that supports dismounted mission profiles in denied environments. - DAPS GEN II is leveraging the QRC and lessons learned. Initial Operational Capability completed 07 February 2025.$$, NULL, NULL, NULL, NULL, NULL, 10498000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604030N_6014$$, $$0604030N$$, $$6014$$, $$JTEN$$, 0, $$The Joint Tactical Edge Network (JTEN) is an overlay network and data architecture for tactical communications systems that seeks to enable information sharing across dissimilar message formats and heterogeneous datalinks (both IP and non-IP). JTEN's approach is to build the network by leveraging technology from three Service-funded programs: the USAF's Common Tactical Edge Network (CTEN), the USN's Communications as a Service (CaaS), and the USA's Modular RF (ModRF). The end result of integrating these projects under JTEN is a leave-behind capability that enables the Joint Warfighter to share relevant data across domains regardless of the underlying communications hardware they are operating on. This proposal provides resources to integrate each of the Service projects into JTEN, and conduct an experiment during a major Joint force exercise evaluating JTEN's use to close specific long range kill chains in the USINDOPACOM AOR. The intent is to leverage ongoing Navy, Air Force and Army JADC2-related projects to provide the opportunity to share time-critical data across the joint tactical grid created through JTEN. Each Service's project is currently funded with overall investment for all three estimated at $126.9M, with an additional $38.5M requested in this RDER proposal. An investment by the RDER program will enable the critical activities of integrating the three programs to provide Joint interoperability. Specifically, the RDER funds will be used to conduct live-fly demonstrations, extensive high-fidelity virtual constructive modeling and military utility assessments that will yield data in support of a commitment by each service to a production and fielding decision of JTEN to the operating forces.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604030N_6016$$, $$0604030N$$, $$6016$$, $$MIM$$, 0, $$The details of this program element are classified SECRET and are submitted annually to Congress in the classified budget justification books.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
