INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604031N_2094$$, $$0604031N$$, $$2094$$, $$Unmanned Underwater Vehicle$$, 0, $$The Snakehead Program was intended to be Navy's largest Submarine-launched UUV with a modular design, high accuracy mission sensors and communications links, as well as modular payload capabilities with well-defined interfaces for the purpose of implementing cost-effective upgrades in future increments to leverage advances in technology. The Snakehead LDUUV program was a CNO/ASN(RDA) approved Accelerated Acquisition that had a phased approach to grow capabilities at a manageable level of risk. As part of Phase I, a Government developed prototype was fabricated, subsystem-level testing began in FY 2021, and vehicle in-water testing began in FY 2022. Phase 2 efforts were stopped in FY 2022. The Snakehead Program is cancelled, starting in FY 2026. The Dragonfish LUUV is a rapid and iterative prototyping project that addresses a priority Fleet requirement for a below-water Intelligence, Surveillance, and Reconnaissance (ISR) task with classification of targets of interest and activation of a purpose-built payload. The system consists of a vehicle, a payload, and a support system. The Dragonfish LUUV is a follow-on effort to a Defense Innovation Unit (DIU) Commercial Solutions Opening (CSO) that assessed commercially available LUUVs. The project is rapidly prototyping with V1 vehicles and conducting in-water, system-level testing. This will inform prototyping for V2 vehicles, which are intended to be Minimal Viable Products (MVPs).$$, 0, NULL, NULL, NULL, NULL, 236224000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604031N_9999$$, $$0604031N$$, $$9999$$, $$Congressional Adds$$, 0, $$(U) Congressional Add for Commercially Available Long Endurance UUV - acquire, prototype, and experiment with commercially available Large Diameter Unmanned Undersea Vehicle (LDUUV) test platforms, ancillary equipment, and support services that can rapidly integrate a broad range of payloads and sensors to serve as test beds for organizations and expedite the delivery of these capabilities to the fleet.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604032F_640200$$, $$0604032F$$, $$640200$$, $$DE Prototyping$$, 0, $$The Air Force Life Cycle Management Center, Architecture and Integration Directorate Directed Energy Prototyping Program develops, acquires and evaluates prototype high energy laser, high power microwave and/or other electromagnetic radiation or particle beam technologies as a future integral component of Air Force missions. The Directed Energy Prototyping Program bridges the gap between lab based technology demonstration under a controlled environment, and demonstration of a system in realistic environments with the intent of establishing successful acquisition, and operation or operational capability implementation. This prototyping effort enables the ability to integrate the directed energy prototype systems with other operational systems required for the mission (e.g. radar, command and control, etc.), conduct test and evaluation activities, and mature emerging directed energy technology systems based on prototyping activities to enable rapid fielding to the warfighter. The Directed Energy Prototyping Program allows acquisition program managers (capability developers) and warfighters (capability recipients and end users) to prototype, integrate, evaluate, and demonstrate candidate weapon technologies and assess them in an operational environment with the intent of iteratively maturing directed energy technologies to a production representative design. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In Prior Year 2023, 1.046M was expended for civilian pay expenses in this program element, and in CY 2024 1.023M is forecasted for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604032F / Directed Energy Prototyping Component Development & Prototypes (ACD&P)$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604123D8Z_084$$, $$0604123D8Z$$, $$084$$, $$Management Innovation Pilots$$, 2247000, $$This is a continuation of the initial FY24 Management Innovation Pilot (H.R. 118-121) and seeks to improve warfighter lethality and DoD efficiency by using data, analytics, and AI to modernize business practices across CDAO and DoD.$$, 2247000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604123D8Z_786$$, $$0604123D8Z$$, $$786$$, $$Acquisition Ecosystem$$, 6949000, $$Funding for Acquisition Ecosystem leverages digital and AI technologies to improve acquisition processes and provides training to the acquisition workforce on how to procure digital and AI technologies more effectively. The goal is to develop, sustain, and share across the acquisition workforce acquisition approaches that enable greater agility, speed, and mission utility when procuring digital and software-based technologies.$$, 6949000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604033F_643882$$, $$0604033F$$, $$643882$$, $$Air-Launched Rapid Response$$, 0, $$The Air-Launched Rapid Response Weapon (ARRW) project integrated Air Force and DARPA enabled system technologies into a prototype that demonstrated the viability of this concept to be fielded as a long range prompt strike capability. ARRW designed, developed, manufactured, and tested, a number of prototype vehicles to inform decisions concerning ARRW acquisition and production. Future hypersonics development will incubate and mature new technology, processes, and resources for the development and demonstration of hypersonic technology including, but not limited to, infrastructure advancements, digital engineering, open systems architecture, modeling and simulation, analytics, and high performance computing environments. Investing in hypersonics development will enable the collection of valuable data, building of capacity and capability, allowing hypersonic programs to leverage and build upon each other, and project the overall technology forward. In FY 2022, PE 0101101F, Project ARRW00/AGM-183A Air-Launched Rapid Response Weapon, efforts were transferred to PE 0604033F, Hypersonics Prototyping, Project 643882, Air-Launched Rapid Response Weapon, in order to mitigate the testing shortfall (PE 0604033F remains RDT&E only). In FY 2026, ARRW Procurement is being added to PE 0101101F. The total cost of the ARRW Rapid Prototyping Middle Tier of Acquisition effort was 1,730.073 million, including RDT&E and procurement of prototype units. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024 $1.130 million was expended for civilian pay expenses in this program element, in FY2025 0.00 million was forecasted for civilian pay expenses.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604035A_BX7$$, $$0604035A$$, $$BX7$$, $$Low Earth Orbit (LEO) Satellite$$, 17063000, $$The United States Army Tactical Space Strategy provides tactical land component forces with space-based capabilities required to close the top three Large Scale Combat Operations (LSCO) gaps and counter adversarial surveillance and reconnaissance systems that affect friendly maneuver forces. National, DoD, commercial space-based, and High Altitude (HA) sensor data will be integrated into army and Joint ground architectures to provide resilient communications, assured Positioning, Navigation, and Timing (PNT), all domain sensing capabilities (including space, high altitude, aerial and terrestrial sensors, data transport, data fusion, data analytics), automated Processing Exploitation and Dissemination (PED) required in the targeting process (target recognition, machine learning and advanced algorithm development), and provide command and control (C2) of non-kinetic fires for counter ISR capabilities to enable maneuver force operations. These capabilities will enable rapid and responsive all-domain targeting applications required to engage and defeat A2/AD forces and enable force projection and freedom of maneuver in contested Multi-Domain Operations and continue to inform the Army and Joint Services Family of Integrated Targeting Cells (FIT-C). Provides prototyping, experimentation, and risk reduction activities for ground architecture, supporting wide-area, responsive, and deep-area sensing required for Beyond-Line-of-Sight (BLOS) targeting and C2 of non-kinetic fires for counter ISR operations, significantly reducing Sensor to Shooter (S2S) timelines and enabling freedom of maneuver for operational forces. It will enable Warfighters at echelon to conduct C2 of counter surveillance and reconnaissance operations and to dynamically task, receive and disseminate data to directly support live-fire S2S demonstrations and assessments. FY 2026 base funding in the amount of $17.063 million provides prototyping, experimentation, and risk reduction activities for the Army as it continues to develop and field prototypes to close the all domain capability gap and provide C2 of counter adversarial surveillance and reconnaissance systems. Complimentary AI/ ML technologies are assessed via various prototyping and ground station (FIT-C) architecture efforts. These Advanced Component Development and Prototypes efforts enable ground stations to dynamically task, receive, and disseminate data to directly support live-fire, Warfighting function system of system demonstrations and assessments, enabling wide-area, responsive, and deep-area sensing and force maneuver. Additionally, this funding supports C2 architecture prototyping and experimentation of counter ISR capabilities, along with Electronic Warfare (EW) and navigation warfare (NAVWAR) technology integration and Positioning, Navigation and Timing (PNT) technology development and assessments, including experimentation and prototyping in denied, degraded, intermittent, or limited (DDIL) operating environments.$$, 17063000, NULL, NULL, NULL, NULL, 37433000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604036A_BY9$$, $$0604036A$$, $$BY9$$, $$Multi-Domain Sensing System Adv$$, NULL, $$604036A / Project BY9 was established in FY 2022 to support sensor prototyping for initiation of the Army's Multi Domain Sensing System (MDSS), a layered approach of the Army's Aerial Intelligence, Surveillance, and Reconnaissance (A-ISR) systems which allows for the best ability to achieve Multi-Domain Operations (MDO) capable deep sensing. The A-ISR systems, MDSS family of systems (HADES, HAP-DS, ARGOS, and HERMES) and Launched Effects (LE), is comprised of a variety of platform/sensor combinations and MDO-capable, platform agnostic, scalable sensor programs that will provide for technical insertion into LE, Unmanned Aerial Systems (UAS), high-altitude platforms (including Micro High-Altitude Balloons (mHAB)), medium altitude manned systems, and unmanned stratospheric A-ISR systems. These capabilities are enabled by emerging Artificial Intelligence/Machine Learning (AI/ML) processing and automated target recognition, autonomous sensor cross-cueing, sensor data correlation and resilient Joint All-Domain Command and Control (JADC2) compliant communications which shorten the sensor to shooter kill chain. FY 2024 RDTE funding and execution is currently being realigned to 0604036A DD6. 0604036A BY9 has no funding request in FY 2026.$$, NULL, NULL, NULL, NULL, NULL, 13396000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604036A_DD6$$, $$0604036A$$, $$DD6$$, $$HADES Platform, Payloads/PED, and$$, 239813000, $$PE 0604036A / Project DD6 is the Army's first priority in the Multi-Domain Sensing System (MDSS) portfolio of systems and is the centerpiece of the Army's Aerial Intelligence, Surveillance, and Reconnaissance (A-ISR) transformation strategy. High Accuracy Detection and Exploitation System (HADES) is a commercial jet modified for military use with complex Outer Mold Line (OML) aerodynamic modifications and integrated with sensors which provide Communications Intelligence (COMINT), Electronics Intelligence (ELINT), and Synthetic Aperture Radar/Moving Target Indicator (SAR/MTI) (i.e. RADAR) capabilities, Aircraft Survivability Equipment (ASE), and other military mission equipment utilizing open system standards. HADES allows the Army to fly higher, faster, and farther, which directly impacts the warfighter's ability to see and sense deeper, delivering an organic capability in line with the Army's operational imperative for deep sensing. In FY 2026 three (3) prototype aircraft are concurrently in development, up from two (2) in FY 2025. These three developmental prototypes will inform future Army procurement decisions. HADES provides advanced aerial intelligence sensing capabilities for Multi-Domain Operations (MDO) against peer and near-peer adversaries, addressing Army deep sensing needs in all phases of operations and throughout the depth of the future battlefield. With higher airspeed, range and endurance, HADES will facilitate A-ISR coverage for a much larger geographical area than current capability and will facilitate global deployment within days instead of the current transitional period of several weeks for legacy aircraft. This will adversely affect our adversaries' ability to plan and maneuver. This is also aligned with the Headquarters Department of the Army Deputy Chief of Staff (HQDA DCS) G2 strategy that lethality begins with intelligence. HADES provides highly mobile, long endurance converged deep sensing through the collection of COMINT, ELINT, and SAR/MTI data. Subsequent increment upgrades can host Electronic Warfare (EW), Radio Frequency (RF)-enabled Cyber, and Launched Effects (LE) as well as additional system improvements. Aircraft performance and a Modular Open Systems Approach (MOSA) increases flexibility in rapid global deployment and postures to meet emerging operational needs. HADES will utilize an incremental acquisition strategy and an open system approach: Increment 1 (Prototypes #1 and #2): Initial capability includes COMINT, ELINT, SAR/MTI; and a MOSA digital backbone. Increment 2 (Prototype #3): Integration of advanced COMINT/ ELINT sensors and modernization upgrades, such as LE, EW, Artificial Intelligence/Machine Learning (AI/ ML). The FY 2026 cost of the HADES Middle Tier of Acquisition effort is $83.7 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. HADES is part of the Army Transformation Initiative (ATI).$$, 239813000, NULL, NULL, NULL, NULL, 172435000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604037A_BY4$$, $$0604037A$$, $$BY4$$, $$Tactical Intelligence Targeting Access$$, 3092000, $$Tactical Intelligence Targeting Access Node (TITAN) directly addresses the U.S. Army Combined Arms Center's (USACAC) Multi-Domain Operations (MDO) Gap #1: Lack of echelons above corps (EAC) multi-domain deep sensing, analysis, and processing, exploitation, and dissemination (PED) for indications and warning (I&W) and anti-access/area denial (A2/AD) targeting. Furthermore, TITAN indirectly addresses MDO Gap #2: No theater detect, decide, deliver, assess (D3A) and convergence of Long Range Precision Fires (LRPF) to disintegrate A2/AD and MDO Gap #3: Lack of EAC LRPF capacity to disintegrate A2/AD and shape the deep fight. TITAN supports these MDO gaps by providing the sensor data receipt and control, analysis, exploitation, and dissemination functions needed to enable LRPF. The FY26 RDTE Dollars in the amount of $3.092M will fund continued support efforts to prototype high altitude, aerial and terrestrial sensor data feed, processing and AI/ML operational platforms in the Prototype Maturation Phase (PMP). The FY 2026 cost of the Titan Intelligence Targeting Access Node (TITAN) Middle Tier of Acquisition effort is $23.7 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission.$$, 3092000, NULL, NULL, NULL, NULL, 10626000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604038N_3468$$, $$0604038N$$, $$3468$$, $$Maritime Targeting Cell$$, 147802000, $$The details of this program element are classified SECRET and are submitted annually to Congress in the classified budget justification books.$$, 147802000, NULL, NULL, NULL, NULL, 49600000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604038N_9999$$, $$0604038N$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional Add$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604124D8Z_068$$, $$0604124D8Z$$, $$068$$, $$Intelligence Support$$, 0, $$The CDAO’s DoD and IC Integration Division was chartered to create joint interoperability and to harness and scale AI across the DoD and IC jointly, especially within the Defense Intelligence Enterprise. The organizational purpose is to improve coordination and interoperability between DoD and the IC, minimize duplication while maximizing a common approach, and develop an innovated joint AI operational concept and capability, where appropriate. This funding is assigned to support algorithm development, data preparation, and integration experimentation to create joint DoD and IC capabilities. Further details are classified and available upon request.$$, 0, NULL, NULL, NULL, NULL, 70783000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604055D8Z_455$$, $$0604055D8Z$$, $$455$$, $$OECIF$$, 0, $$The OECIF project is the engine driving enhanced DOD operational effectiveness through targeted Science & Technology (S&T) investments. This project strategically prioritizes technologies enabling OE integration, supporting operations in contested environments and seamlessly embedding energy awareness into DOD command and control architectures. By harnessing energy data and information to improve decision-making, the OECIF project is developing a critical OE data layer as an integral part of JADC2 and, in-turn, transforming the battlespace. Specifically, S&T investments in this project are focused on: 1. Real-Time Power and Energy Performance Assessment: Providing state-of-the-art metering and monitoring of platform/system capabilities, delivering real-time performance assessment for optimized resource allocation. 2. Revolutionizing Mission Planning: Improving mission-planning tools and analytics while providing warfighters with unparalleled situational awareness and decision- making capabilities. 3. Empowering Operational Control: Increasing operational control and decision-making for power and energy at all warfighting echelons, enabling more agile and responsive operations with an emphasis on classification consideration. 4. Data-Driven Decision-Making: Developing next-generation OE modeling and simulation tools that quantify operational and business case impacts, empowering senior leaders to make informed decisions based on data-driven insights. 5. Informing Strategic Investments: Bringing power and energy innovation knowledge and analytics to warfighters and senior leaders, informing future acquisition, sustainment, and budget decisions and ensuring that investments are aligned with critical operational needs. 6. Cultivating Expertise: Delivering foundational training and education on power and energy innovation across the military and S&T communities, building a cadre of experts who can drive future innovation. All six technology areas within this project directly support the DOD’s OE Strategy Enterprise-wide Energy Visibility (EWEV) line of effort, contributing to a more resilient and effective force. Program-wide administrative costs are also part of this project code and include transparency and accountability tools for the program and the OE- Innovation community, inclusion of warfighters into the projects enhancing technology awareness and adoption, and power and energy subject matter expertise.$$, 0, NULL, NULL, NULL, NULL, 243527000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604055D8Z_456$$, $$0604055D8Z$$, $$456$$, $$Operational Energy Resilience$$, 0, $$This project is revolutionizing operational energy resilience, a critical force multiplier enabling operational flexibility, freedom of maneuver, and guaranteeing mission success in any environment. By driving innovations across key technical areas, this project is ensuring that U.S. Joint Forces have the energy they need, when and where they need it. The project's strategic focus areas include: • Next-Generation Capabilities: Powering the Future Battlespace: Investing in high-power weapons enablers, advanced energy storage devices, power and thermal management technologies, energy magazines, and energy innovations optimized for arctic operations, ensuring that U.S. forces maintain a decisive advantage in any environment, including the most challenging and contested. • Energy Diversification: Expanding the Energy Arsenal: Focusing on Space and Arctic storage and use technologies including hydrogen, and PEM fuel cell technologies; expanding the range of available energy sources through innovative production and distribution methods, and providing power, fuel, and heat from waste resources thereby reducing reliance on vulnerable supply chains. • Interoperability and Standardization: Creating a Seamless and Assured Energy Use: Investing in tactical micro-gridding, electrical and communication standards, and energy component commonality for multiplatform applications, ensuring seamless integration across the force and enabling more agile and responsive operations. By pursuing these strategic objectives, this project is transforming operational energy resilience, expanding warfighter capability and safety, and ensuring that U.S. forces are prepared to meet the challenges of the future.$$, 0, NULL, NULL, NULL, NULL, 77451000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604055D8Z_457$$, $$0604055D8Z$$, $$457$$, $$Operational Energy Demand$$, 0, $$The OE Demand Reduction project is revolutionizing operational energy management by driving innovations that: • Shrink the Logistical Footprint: Reduce operational energy demand, minimizing reliance on vulnerable supply lines and freeing up resources for other critical missions. • Maximize Performance in the Air and Space Domains: Increase efficiencies for aviation and space domains, enabling longer mission durations, greater payload capacity, and enhanced operational effectiveness. • Mitigate Critical Vulnerabilities: Reduce risks by providing next-generation power and energy delivery options, such as power beaming, creating a more resilient and adaptable force. • Dominate the Information Domain: Enable exploitation of critical power system signatures through Cyber-physical Power ISR Protection (C PIP), providing a decisive intelligence advantage by determining force capabilities and informing sustainment actions in both domestic and austere environments. To achieve these ambitious goals, the project focuses on: • Aviation Efficiency: Transforming Air Operations: Investing in innovations to gain efficiency and lower energy consumption through advances in aviation powerplants (e.g., uncrewed electrification, hybridization, etc.), flight software planning tools, inflight algorithms, composite airframe structures, and propulsion power options, enabling longer-range, more efficient, and more stealthy air operations. • Space Efficiency: Powering Dominance in Space: Investing in power and energy (generation, transmission, storage, and resupply) for space access (platform launch and orbital transfer), platform maneuver and station keeping/resupply, and platform operation capabilities that improve energy efficiency, reduce energy consumption, and/or increase range/endurance. The project also focuses on innovations that dramatically reduce the cost of production and/or launch weight of critical space components, ensuring U.S. dominance in this critical domain.$$, 0, NULL, NULL, NULL, NULL, 54783000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604055D8Z_458$$, $$0604055D8Z$$, $$458$$, $$Nuclear Power$$, 0, $$This project is at the forefront of a revolution in military power, spearheading DOD innovations in nuclear power (fission reactors and radioisotope power systems) and enabling joint operations across all domains. Recognized as a strategic priority, nuclear power is poised to redefine energy surety by: • Unleashing Unprecedented Power Density: Maximizing the energy density of existing power systems by approximately 1,000,000x, enabling prolonged operations, reducing logistical dependencies, and providing a decisive advantage in contested environments. • Extending Reach to the Most Remote Locations: Enhancing power system lifetime in remote and austere locations, guaranteeing reliable power for critical missions, regardless of the environment. • Liberating Personnel for Mission-Critical Tasks: Minimizing the operational burden on personnel compared to traditional power systems (e.g., chemical batteries and fossil fuels), freeing up valuable resources for other vital tasks and increasing overall operational effectiveness. The nuclear power portfolio's investments are focused on making nuclear technologies safer, lighter, more secure, more efficient, more economical, and more operational for the DOD, transforming the future of military power and ensuring U.S. dominance in the 21st century. To realize this vision, this project is driving critical technology improvements in the supply chain and power conversion efficiency of both small and large RPS and fission subsystems and components, as well as de-risking complete fission mobile nuclear reactor systems. These transformative technology development efforts include investments in cutting-edge materials like smart carbon/carbon, shielding optimizations, betavoltaics, alphavoltaics, alpha photovoltaics, Stirling energy conversion technology, and supercritical CO2 energy conversion loops (sCO2). The nuclear power portfolio also funds rigorous studies to ensure the safety and security of these revolutionary technology investments, prioritizing responsible and sustainable development.$$, 0, NULL, NULL, NULL, NULL, 74825000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604100A_EC7$$, $$0604100A$$, $$EC7$$, $$Analysis Of Alternatives$$, 9865000, $$This Project provides funding for analytical support of Analysis of Alternatives. Analyses of Alternatives are statutory requirements for Major Defense Acquisition Programs and regulatory for all other programs. Based on Department of Defense Instruction (DoDI) 5000.02, Analyses of Alternatives are required to be completed for a new start program prior to its first Milestone Decision. The Project provides analytical capability for Pre-Milestone A programs that emerge outside the normal budget or POM cycles. Normally these programs are without program managers and require analysis to support Congressional, Defense and Army Senior Leader's requirement and acquisition needs and priorities. The Analyses of Alternatives support the preparation of the Capability Development Document, Key Performance Parameters and Thresholds values and tradeoff analysis. The cited work is consistent with the Army Science and Technology priority focus areas and the Army Modernization Strategy and Guidance. The Army is projecting to start work on multiple Analyses of Alternatives beginning in Fiscal Year (FY) 2026, and will assess and fund the highest Congressional, Defense and Army Senior Leader's priorities during the year of execution.$$, 9865000, NULL, NULL, NULL, NULL, 10690000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604101A_BR6$$, $$0604101A$$, $$BR6$$, $$Small Unmanned Aircraft System$$, NULL, $$The Family of Small Uncrewed Aircraft systems are critical to the Army's Transformation in Contact. These systems ensure Army formations have the best existing and emerging technology at Battalion and below to allow ground-based forces to project power from land into other domains to defeat highly capable enemies, secure terrain, and consolidate gains. The Rucksack Portable Uncrewed Aircraft System (RPUAS) Family of Small Uncrewed Aircraft System (FoSUAS) requirements are transitioning to the Joint Small Uncrewed Aircraft System sUAS Capability Development Document (J-sUAS CDD) to solve current and emergent operational gaps by incorporating Modular Open Systems Approach (MOSA) including swappable payloads, advanced autonomy and software scalability. These systems provide battalion and below ground maneuver elements with critical situational awareness and enhanced force protection. The systems provide an organic and responsive reconnaissance and targeting capability with real-time Full Motion Video and sensor data. Each system will include aircraft, ground support equipment, ground control station and Uncrewed Vehicle Control (UVC) software. The Short Range Reconnaissance (SRR) provides organic maneuver platoons an uncrewed air vehicle designed to support Reconnaissance, Surveillance, and Target Acquisition. The system has an aircraft weight of less than 5 lbs, a range of 3-5 km, and an endurance of 30 minutes. The system includes modular payloads, obstacle avoidance, target recognition, automated following, and networked capability. The Long Range Reconnaissance (LRR) System will provide organic maneuver battalions an uncrewed air vehicle designed to support Reconnaissance, Surveillance, and Target Acquisition (RSTA) efforts. The system will have an aircraft weight of less than 55 lbs., a range of 40-60 km and endurance of 5-10 hours. System will include Assured Positioning, Navigation and Timing (APNT), Electro-Optical/Infra-Red (EO/IR), laser targeting/designating, and kinetic architectures in a contested environment. The Joint Tactical Autonomous Aerial Resupply System (JTAARS) is an autonomous aerial cargo delivery system, organic to the maneuver commander, that provides options for rapid and agile sustainment of highly mobile tactical combat forces, operating in a widely dispersed manner in the tactical support and close areas. JTAARS enables maneuver by reducing the tactical force's dependence on ground lines of communication and sustainment, reducing threats to manned convoys and manned aerial systems, lightening Soldier load, and shrinking the supply chain. JTAARS provides a lift capability of 125 lbs. over 13 km one way (26 km round trip).$$, NULL, NULL, NULL, NULL, NULL, 4956000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604102C_MC65$$, $$0604102C$$, $$MC65$$, $$Cyber Operations$$, 7280000, $$Guam on-island Cyber team coordinates local network defense activities and assumes responsibility to defend onsite assets from active or imminent cyberspace threats in the event of degraded communication conditions. This Budget Project provides the oversight and inter-Agency/Service coordination for Cyber activities needed for integrating a capability to defend Guam against ballistic, hypersonic, and cruise missile attack.$$, 7280000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604102C_MD40$$, $$0604102C$$, $$MD40$$, $$Program Wide Support$$, 5982000, $$PWS contains non-headquarters management costs in support of Missile Defense Agency (MDA) functions and activities across the entire Missile Defense System. These functions include Government Civilians and Contract Support Services. This effort provides integrity and oversight of the Missile Defense System as well as supports MDA in the development and evaluation of technologies that will respond to the changing threat. Additionally, PWS includes personnel to support global deployments performing deployment site preparation and activation, and provides facility capabilities for MDA Executing Agent locations worldwide. Other MDA wide costs include: physical and technical security; civilian drug testing; audit readiness; the Science, Technology, Engineering, and Mathematics (STEM) program; legal services and settlements; travel and agency training; office, equipment, vehicle, and warehouse leases; utilities and base operations across multiple geographic locations; commercial and ancillary facility services; management of all facility aspects regardless of lifecycle stage; supplies and maintenance; compliance with statutory environmental requirements; data and unified communications support; materiel and readiness and central property management of equipment; Facilities Sustainment, Restoration and Modernization (FSRM) program (formerly Real Property Maintenance) to keep the Department's inventory of facilities in good working order; and similar operating expenses. PWS is allocated on a pro-rata basis across most Agency PEs; therefore, fluctuates per PE by FY based on the total Agency budget in that FY.$$, 5982000, NULL, NULL, NULL, NULL, 1700000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604102C_MD65$$, $$0604102C$$, $$MD65$$, $$Defense of Guam Development$$, 115223000, $$This program develops a Missile Defense System for the Defense of Guam (DoG) against ballistic, hypersonic, and cruise missile threats as a high priority mission for the Department of Defense. The Missile Defense System will form a key part of strategic deterrence and supports the PDI. In FY 2022, the Missile Defense Agency (MDA) initiated studies and analysis, architecture development and siting analysis. FY 2023 continued architecture development and increased the development and modification of the distributed radar, Aegis Guam System support, environmental studies, site design, activation and advanced planning. In FY 2024, the program leveraged the results of studies and analysis and continued developing and fielding of distributed land-based launchers, distributed sensors, and integrated communications across Guam. The acquisition approach is to balance costs and associated risks in order to provide increased Aegis Weapon System development for Guam integration, site activation, environmental protection, engineering, and interoperability. FY 2025 continues the advancements of FY 2024, with the completion of an on-island flight experiment in early FY 2025, continued Environmental Studies and Mitigations, and the continuation of the software development phase of the Aegis and Radar components. The activities in FY 2026 include development and integration efforts between MDA, United States (U.S.) Army (USA), U.S. Navy (USN), and U.S. Air Force (USAF) systems, which includes a 360 degree persistent integrated air and missile defense Aegis Guam System with distributed Mk-41 Vertical Launching Systems, and a single Tactical Array Unit (TAU) Army Navy/Transportable Radar Surveillance and Control-6 (AN/TPY-6) and missile uplink/downlink communications system for the DoG. Aegis Guam System will develop capability to leverage track data from Army systems, that is provided via the Joint Track Management Capability - Bridge (JTMC-B), to support Standard Missile-6 (SM-6) Engage on Remote (EoR) capability. The Guam Architecture will be commanded and controlled from the Joint Command Center with additional Integrated Air and Missile Defense Battle Command System; Aegis Guam System; Command and Control, Battle Management and Communications mission node and Tactical Operations Center - Light providing local continuity of operations. Initial Aegis Guam System capability was demonstrated on Guam in calendar year (CY) 2024. Aegis Guam System with additional Terminal Defense capability will be delivered in CY 2029.$$, 115223000, NULL, NULL, NULL, NULL, 201353000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604103A_DG4$$, $$0604103A$$, $$DG4$$, $$NAVWAR SA$$, NULL, $$There are no Base funds for project Navigation Warfare (NAVWAR) Situational Awareness (SA) (DG4) in Fiscal Year (FY) 2026. Adversaries are aggressively developing and fielding counter- Positioning, Navigation, and Timing (PNT) technologies that significantly reduce the Army's ability to access the electromagnetic spectrum (EMS) to conduct military operations. The Army is actively pursuing Navigation Warfare (NAVWAR) Situational Awareness (SA) capabilities to produce NAVWAR SA solutions that leverage Electromagnetic Warfare (EW) and Signal Intelligence (SIGINT) capabilities while enabling distinctly NAVWAR SA outcomes and provide soldiers with PNT overmatch by denying adversary access to PNT services. NAVWAR SA provides commanders and soldiers with indications and warnings of PNT jamming to provide immediate notification to individual PNT users that their navigation and timing may be compromised by jamming or spoofing; detect, identify, and locate sources of PNT interference; allow command and control (C2) systems to display areas affected by interference with actionable information necessary to implement measures to mitigate or eliminate the threat. NAVWAR SA will create asymmetric opportunities to degrade and defeat an adversary's capabilities by denying their use of PNT and preserve PNT overmatch for friendly forces by creating a denied, degraded and/or disrupted operating environment for adversaries while opening windows of PNT superiority for friendly forces. NAVWAR SA supports Multi-Domain Operations (MDO) as an enabler to precision fires, movement and maneuver, force tracking, and a host of data networks that tie personnel and weapon systems together into a joint or coalition force. NAVWAR SA provides globally responsive arms teams with the ability to present multiple dilemmas to the enemy, limit enemy options and exploit enemy weaknesses. NAVWAR SA directly enhances multiple warfighting functions to include fires, aviation, mission command, and electromagnetic warfare. NAVWAR SA is a system of systems approach of detecting, geolocating, and determining the impact area of Global Positioning System (GPS) in a contested environment and the effects on PNT across the battlefield. NAVWAR SA will leverage the GNSS Operational Assessment Tool (GOAT) that was developed for an urgent requirement and be integrated with the Electronic Warfare Planning and Management Tool (EWPMT) X system.$$, NULL, NULL, NULL, NULL, NULL, 2260000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605502N_2241$$, $$0605502N$$, $$2241$$, $$SBIR ADMIN - SPAWAR$$, 0, $$Small Business Innovation Research (SBIR) Administration funds to manage the program, technical efforts, and award contracts related to SBIR.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
