INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605502N_2243$$, $$0605502N$$, $$2243$$, $$SBIR ADMIN - NAVAIR$$, 0, $$Small Business Innovation Research (SBIR) Administration funds to manage the program, technical efforts, and award contracts related to SBIR.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604112N_2208$$, $$0604112N$$, $$2208$$, $$CVN 21$$, 90354000, $$This project provides the development of aircraft carrier specific technologies, the infusion of the ship technology base into existing and future aircraft carriers, and the potential realization of subsystem design capabilities not currently feasible. All systems developed in this project support current or emerging requirements and other promising systems technologies for insertion into existing and new aircraft carrier designs. The emphasis is directed toward developing ship hull, mechanical, propulsion, electrical, aviation, and warfare systems to significantly improve aircraft carrier affordability, manpower requirements, survivability, and operational capabilities required to meet existing and pending regulations and statutes critical to the operation of future aircraft carriers. This project also encompasses those tasks required to support CVN 78 Class procurement, including, but not limited to engineering support, programmatic and program support, logistics support, modeling and simulation, test and evaluation, manpower and program related studies, and design support systems, such as the Integrated Digital Environment (IDE).$$, 90354000, NULL, NULL, NULL, NULL, 671839000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604112N_4004$$, $$0604112N$$, $$4004$$, $$EMALS$$, 22350000, $$The Electromagnetic Aircraft Launch System (EMALS) is an advanced technology system developed as part of, and integrated on new FORD Class Carrier ships, beginning with CVN 78. EMALS provides better control of applied forces, both peak and transient dynamic loads, improved reliability and maintainability, increased operational availability, and reduced operator and maintainer workload. The EMALS program will undergo future system improvements to address safety, obsolescence, and reliability, to include but not limited to Automated software testing, Electrical Isolation, Advancing Additive at Large Scale to Address Readiness and Sustainment (AALSTARS), Block Switch Controller (BSC) Complex Programmable Logic Device (CPLD), Software Support Activity (SSA), Autosuspends, Maintenance Laptop, Catapult Status Dashboard (CSD), and other emergent requirements. Automated software testing development provides for rapid, repeatable tests, resulting in higher quality software. Automated testing enables rapid diagnosis of system faults and decrease troubleshooting response time for the fleet. EMALS is a software intensive system and highly dependent on reliable software operation. The readiness and mission benefits include the ability to provide the fleet with affordable, quality, well-tested software capable of launching and recovering aircraft on Ford- Class carriers. Development of Electrical Isolation provides for EMALS capabilities to continue launch operations while being able to isolate catapults for regular maintenance, in turn improving maintenance cycle times. This provides readiness and mission benefits to enable continued operations and increases system mission capability. Implementing the AALSTARS initiative will demonstrate alternative manufacturing methods of select EMALS components. This will reduce manufacturing lead time and costs for highly complex, long lead time items. Developing BSC CPLD provides additional space on a critical control card to allow for future firmware and logic updates in order to ensure timely functionality and to support future changes. This also addresses a known obsolescence issue. Software Support Activity (SSA) development provides a high-level hybrid SSA planning document (Software Test Plan) to ensure software test activities are developed and implemented. In addition, the hybrid SSA will execute software investigations, Correction of Deficiencies, and the EMALS SSA lab design and upgrade plan in support of future EMALS systems improvements. Autosuspends effort is to develop software improvements for several key EMALS Computer Software Configuration Items (CSCIs) that will mitigate the EMALS Autosuspends associated with faults and communication dropouts, which terminates the launch process and causes delays to launch operations. These software improvements will significantly lessen the number of experienced Autosuspends and improve CVN launch operations in order to meet the operational need.$$, 22350000, NULL, NULL, NULL, NULL, 170678000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604113A_DH3$$, $$0604113A$$, $$DH3$$, $$Air Launched Effects (ALE)$$, NULL, $$Beginning in FY 2025, LE efforts were realigned from PE 0604113A/Future Tactical Unmanned Aircraft System (FTUAS), DH3/Air Launched Effects (ALE) to 0609346A/ UAS Launched Effects Agile Development , A54/Air Launched Effects (ALE) to better capture LE funding and reporting. This program is a part of the Department of Defense Capability Based (Agile) funding pilot, which provides enhanced capabilities by fostering innovation and accelerated deployment of promising technology. This funding is not a new start. Launched Effects (LE) extends the speed, range, lethality and survivability of maneuver formations through the integration of air vehicles, mission systems, payloads, and behaviors. LE will provides Army formations with the ability to expedite and strengthening the kill web, facilitate the penetration and dis-integration the enemy's Anti-Access Area Denial (A2AD) environment and extend the maneuver force's reach, lethality, and survivability. LE efforts are based on requirements from an Army Requirements Oversight Council (AROC) approved Abbreviated-Capability Development Document (A-CDD) approved 08 July 2024. In FY 2025, PM UAS will defer LE-Medium Range (MR) development to focus on LE launcher capability development for all LE variants in support of accelerate capability fielding to meet the The office of the Secretary of Defense (SECDEF) memo SUBJECT: Army Transformation and Acquisition Reform, dated 30 April 2025. In FY 2025, PM UAS will initiate Rapid Prototyping of the LE-Short Range (LE-SR) under the MTA pathway. This rapid prototyping effort involves the competitive selection of mature technologies to support two Lines of Effort (LOEs). LOE 1 focuses on providing an initial capability to 12 Army Divisions based on special user demonstration feedback. LOE 2 focuses on integrating additional capabilities on existing mature technologies. In FY 2026, PM UAS will initiate its LE-Long Range (LE-LR) program. This effort will include a Special User Demonstration in FY 2026, to include a Technology Maturation Event which will allow competitors in this space to offer their products (i.e., air vehicles and payloads) for evaluation of their components against the LE A- CDD requirement.$$, NULL, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604113A_EX8$$, $$0604113A$$, $$EX8$$, $$Future Unmanned Aircraft System$$, NULL, $$Program is a part of the Department of Defense Capability Based (Agile) Funding Pilot. FUAS funding is realigned to PE 0609346A A53 starting in FY26. Beginning in FY 2025, LE efforts were realigned within PE 0604113A / Future Tactical Unmanned Aircraft System (FTUAS) from Project EX8/Future Unmanned Aircraft System (FUAS) to project DH3/Air Launched Effects (ALE) to better capture LE funding and reporting. FTUAS development efforts are based on requirements from the AROC approved Abbreviated Capability Development Document (A-CDD) signed 12 August 2021. FTUAS provides the Brigade Combat Teams (BCTs) with transformational capabilities. Key capabilities of the FTUAS include vertical take-off and landing (VTOL), runway independence, enhanced transportability, rapid deployability, expeditionary maneuver, and mobility for adaptive and agile operations. Based on an A-CDD update for Army Requirements Oversight Council validation completed on 8 July 2024, one FTUAS system will consist of 6 air vehicles and 6 payloads, 6 control stations, and ancillary equipment. The aircraft subsystem will include the airframe, propulsion, avionics, communications, navigation, and software systems; aircraft- specific ground support equipment including power generation, transportation, or command and control equipment; aircraft software; and required engineering, logistics, programmatic support. The FY 2026 cost of the Future Unmanned Aircraft System (FUAS) Air Launched Effects (ALE) Middle Tier of Acquisition effort is $60.3 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission.$$, NULL, NULL, NULL, NULL, NULL, 67143000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604120A_BV4$$, $$0604120A$$, $$BV4$$, $$Area Protection and Alt Nav$$, NULL, $$There are no Base funds for project Area Protection and ALTNAV Technology Development (BV4) in Fiscal Year (FY) 2026. Alternative Navigation Ground Control Segment (ALTNAV GCS) is a global navigation solution providing warfighters with an alternative source of positioning and timing information. ALTNAV GCS is a complementary capability to Global Positioning System and may be used as contingency in the PNT PACE (Primary, Alternative, Contingency, Emergency) Plan that facilitates continued operations as GPS is degraded or denied in accordance with National Defense Authorization Act (NDAA) Guidance (2021 NDAA: Section 1611). The Area Protection and ALTNAV Technology Development project supports the ALTNAV capability and complementary PNT technologies. ALTNAV provides radio frequency (RF) and source diversity that enables Army users access to accurate and assured position and time information in GPS denied environments. ALTNAV Abbreviated Capabilities Development Document (A-CDD) was Army Requirements Oversight Council (AROC) Approved, 29 August 2022. The program received Middle Tier of Acquisition Rapid Fielding (MTA-RF) approval in May 2024. The total cost of the ALTNAV MTA-RF effort is $106.1M procurement from FY24-FY27 as a single global alternative PNT system. The $106.1M ALTNAV requirement is fully funded across the Future Years Defense Program.$$, NULL, NULL, NULL, NULL, NULL, 12489000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604114A_EX2$$, $$0604114A$$, $$EX2$$, $$Lower Tier Air Missile Defense$$, 196448000, $$The FY2026 request for LTAMDS includes $196,448 thousand of discretionary and $14,000 thousand of mandatory (reconciliation) for a total of $210,448 thousand. The discretionary funds will be used to continue LTAMDS RS Continuous Integration and Continuous Delivery (CI/CD) of software and hardware capability, support initiation of the LTAMDS Initial Operational Test & Evaluation (IOT&E) as part of the FY 2026 Integrated Fires Test Campaign, and continue development, modifications, and integration efforts for LTAMDS ancillary support equipment. The mandatory funds will develop and test new signal processing techniques and waveforms to enhance Electronic Attack and Electronic Protect techniques based on the evolving threat, further enhancing radar survival and effectiveness in contested complex environments. Further information for this reconciliation request is provided in Section 20003 (Missile Defense) of the Reconciliation Exhibit. This funding line is directly aligned to the Army Air and Missile Defense Modernization Priority. The Lower Tier Air Missile Defense Sensor (LTAMDS) is the Army's premier next generation radar intended to sense and track Tactical Ballistic Missiles and Air Breathing Threats; expand the lower tier air and missile defense battlespace and provide 360-degree sensing capability, surveillance, and fire control quality data. The LTAMDS Radar Set (RS) replaces the baseline Patriot RS (AN/MPQ-65A) in an Integrated Air and Missile Defense Battle Command System (IBCS) enabled Patriot Battalion mitigating risk associated with threat advances and decreases Operations and Support (O&S) costs due to growing obsolescence. Additionally, the LTAMDS RS capability maximizes the inherent PAC-3 Missile Segment Enhancement (MSE) Interceptor capabilities to engage threats at greater ranges addressing critical capability gaps, providing modernized technology, and increasing reliability and maintainability. Major LTAMDS Continuous Integration/Continuous Delivery (CI/CD) efforts include tactical software and model and simulation development, integration, and testing to increase overall LTAMDS capability against novel and stressing threats, thus providing the warfighter a leading advantage in a contested environment. Combat Identification/ Discrimination (CID) Updates: This includes CID development and upgrades to improve radar classification, discrimination, and optimization of multi-function capabilities to enhance performance against current and emerging threats in stressing environments. Upgrades play a critical role in increasing operational effectiveness by providing the warfighter enhanced command and control, effective resource allocation measures, and improved situational awareness. Advanced Threat Defeat: LTAMDS will continue to counter adversary threat evolution in complexity, capability, and capacity in simultaneous combatant commands. This development effort is required to continue to provide overmatch radar capability.$$, 196448000, NULL, NULL, NULL, NULL, 511014000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604115A_AX3$$, $$0604115A$$, $$AX3$$, $$Technology Maturation Initiatives$$, 267619000, $$This Project funds the Technology Maturation Initiative (TMI), which matures and integrates component technologies into early system and sub-system experimental prototypes for demonstration in relevant environments and tactical/operational scenarios. The focus is to improve technology transition to Programs of Record (PoR) supporting 3 categories of projects: (1) Super system projects that prototype, integrate, and demonstrate emerging technologies that fill requirements across traditional$$, 267619000, NULL, NULL, NULL, NULL, 244710000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604115C_MD98$$, $$0604115C$$, $$MD98$$, $$Directed Energy Demonstrator$$, 0, $$The Directed Energy Demonstrator Development (DEDD) project develops, integrates, and tests the component technologies required to scale electric lasers to hundreds of kilowatts. Laser scaling focused on maturing laser capability to levels sufficient to enter into the Office of the Undersecretary of Defense Research and Engineering High Energy Laser Road Map efforts. The DEDD project provided the necessary technology, test data, and operations familiarity to successfully transition to a higher power directed energy weapon. MDA continues to participate in the Department's Directed Energy Reviews.$$, 0, NULL, NULL, NULL, NULL, 503783000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604117A_CR9$$, $$0604117A$$, $$CR9$$, $$Directed Energy M-SHORAD / M-$$, 74835000, $$This funding line is directly aligned to Army Signature Modernization efforts and the Army Air and Missile Defense Modernization Priority. M-SHORAD Inc 2/DE M-SHORAD Prototypes 1-4 are a 50kW class laser weapon system integrated onto a Stryker combat vehicle in support of air defense units of action. These systems will provide air defense capability to defeat Rotary Wing (RW), Groups 1-3 Unmanned Aerial Systems (UAS), Rocket Artillery Mortar (RAM) and Intelligence, Surveillance and Reconnaissance (ISR) threats to a unit of action. The Army Rapid Capabilities and Critical Technologies Office (RCCTO) developed the prototype system known as DE M-SHORAD. RCCTO utilized an Other Transaction Authority (OTA) contract to complete the development of additional prototypes that will support the enduring Directed Energy (DE) campaign. As a result of enduring DE Integrated System Test, the Army will determine the best lethality and affordability across DE platforms for future acquisition activities. In addition, Enduring High Energy Laser (E-HEL) will begin development, test and evaluation, systems engineering and program management as well as the continuation of DE enhancements (i.e. subsystem development) to support modular, palletized and maneuverable capabilities.$$, 74835000, NULL, NULL, NULL, NULL, 125870000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604117A_CS1$$, $$0604117A$$, $$CS1$$, $$M-SHORAD Inc 3$$, 152677000, $$This funding line is directly aligned to the Army Air and Missile Defense Modernization Priority. The FY 2026 request for M-SHORAD Increment 3 includes 152,677 thousand of discretionary and 60,120 thousand of mandatory (reconciliation) for a total of 212,797 thousand. The mandatory funds each competing vendor up to the approved cost position for the engineering and delivery of developmental test missiles. Further information for this reconciliation request is provided in Section 20004 (Munitions and Supply Chain) of the Reconciliation Exhibit. Inc. 3 will provide a Next Generation Short Range Interceptor (NGSRI) to replace the existing Stinger missile. The new interceptor with support equipment will improve targeting capabilities to acquire targets with increased lethality and range, providing increased protection to the maneuver formations at a reduced cost. Additionally, the NGSRI will be compatible with the existing SGT STOUT platform, formerly known as M-SHORAD Inc. 1, and will provide a Soldier Portable Capability to meet the need for dismounted Air Defense. Inc. 3 will integrate the SGT STOUT platform with the NGSRI and the new 30mm Multi-Mode Proximity Airburst (MMPA) ammunition. FY 2026 funding supports Inc. 3 prototype and development effort. The FY 2026 funding also includes Test and Evaluation, initiates the NGSRI and 30mm MMPA integration effort with the SGT STOUT platform and provides Program Management support. The FY 2026 cost of the M-SHORAD Inc. 3 Middle Tier of Acquisition effort is $170.8 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission.$$, 152677000, NULL, NULL, NULL, NULL, 154570000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604117A_FI4$$, $$0604117A$$, $$FI4$$, $$Maneuver - Short Range Air Defense$$, 10735000, $$This funding line is directly aligned to the Army Air and Missile Defense Modernization Priority. The Maneuver Short Range Air Defense (M-SHORAD) SGT STOUT systems add commensurate mobility and survivability to the maneuvering forces through protection against enemy air threats. The system consists of existing capabilities integrated onto a Stryker A1 Double-V Hull (DVH) Infantry Carrier Vehicle (ICV). The Reconfigurable Integrated-weapons Platform (RIwP) and Mission Equipment Package (MEP) house multiple missile and gun effectors integrated onto the Stryker A1 DVH vehicle. FY 2026 funding supports development of upgrades and product improvements for SGT STOUT systems through individual material changes to address operational lessons-learned and other system performance improvements/enhancements providing capability overmatch against emerging threats.$$, 10735000, NULL, NULL, NULL, NULL, 9816000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605502N_2244$$, $$0605502N$$, $$2244$$, $$SBIR ADMIN - NAVFAC$$, 0, $$Small Business Innovation Research (SBIR) Administration funds to manage the program, technical efforts, and award contracts related to SBIR.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605502N_2248$$, $$0605502N$$, $$2248$$, $$SBIR ADMIN - SSPO$$, 0, $$Small Business Innovation Research (SBIR) Administration funds to manage the program, technical efforts, and award contracts related to SBIR.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604120A_EJ2$$, $$0604120A$$, $$EJ2$$, $$MOUNTED$$, NULL, $$There are no Base funds for project Mounted (EJ2) in Fiscal Year (FY) 2026. The Mounted Assured Positioning, Navigation and Timing System (MAPS) meets congressional (10 USC 2281) and Department of Defense guidance to provide resilient and survivable, M-Code Global Positioning System (GPS) capable Ground User Equipment (MGUE) receivers and Alternative Navigation (ALTNAV). The MAPS delivers systems that provide the Army's combat forces access to assured PNT information under conditions where space-based GPS may be limited or denied, enabling Army forces the ability to move, shoot, communicate, and provide situational awareness. MAPS addresses two critical capability gaps: Access and Integrity. Access is the ability to retrieve PNT information in a contested Electronic Warfare/Cyber environment. Integrity is the ability to trust the PNT information. PNT is a critical enabler of many Army Maneuver, Fire and Command and Control systems that are dependent on accurate Position and Timing. The MAPS will provide PNT when GPS is degraded or denied through military code (M-Code) GPS, Alternative Navigation (ALTNAV) signals, timing, sensor fusion, anti-jam antenna, and beam steering. This capability will deliver distributed assured PNT capabilities to Armored, Stryker and Infantry Brigade Combat Team (BCT) platforms in an iterative and affordable manner that allows for future modernization. - MAPS GEN II completed Milestone C in July 2022. - MAPS GEN II completed Initial Operational Test & Evaluation (IOT&E) in February 2024 and Full Rate Production authorized March 2025.$$, NULL, NULL, NULL, NULL, NULL, 13333000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604121A_CR2$$, $$0604121A$$, $$CR2$$, $$STE Information Systems (TSS, TMT)$$, 136339000, $$STE-Software (STE-SW) was previously referred to as STE-lnformation System (STE-IS). The Training Simulation Software/Training Management Tools (TSS/TMT) provides two of the three core functions for the Synthetic Training Environment - Software (STE-SW). TSS/TMT converges our current live, virtual, gaming and constructive environments to provide a single, unified training & management environment from Soldier/Squad to Army Service Component Command (ASCC). TSS/TMT provides the ability to train in a single or multiple live, virtual, gaming and constructive environment simultaneously. The Training Simulation Software (TSS), the core STE simulation engine, provides the physical and behavior models necessary to replicate the operational environment to enable collective training from Soldier/Squad through ASCC. The TSS provides entity, aggregate, and common services, as well as adjudicates interactions at the entity level (e.g., Computer-Generated Forces (CGF), and synthetic equipment). The Training Management Tool (TMT) enables units to quickly plan, prepare, execute, monitor, and assess collective training events for readiness. TMT provides an easy-to-use interface, combined with an Intelligent tutor to reduce help-desk support, time, and manpower currently required. TMT leverages training management (data) services and authoritative data sources to enable training on demand regardless of geographic location. In FY 2021, TSS/TMT entered the execution phase of the Software Acquisition Pathway. TSS/TMT facilitates rapid and iterative delivery of its capabilities through a Development, Security, and Operations (DevSecOps) process to support Soldier/Squad (Sq) to Brigade (BDE) level training which began fielding 3QFY2024. The STE- SW ICD was validated 1QFY2025 identifying the CSA's guidance to accelerate the NGC capability requirement beginning in FY 2026 that TSS/TMT will support. Next Generation Constructive (NGC) provides the constructive training environment to sufficiently train large scale combat operations (LSCO) in multi-domain operations, to include, joint, land, air cyber, space, and maritime. NGC enables collective training to be conducted for Army Service Component Command (ASCC) and below, while increasing efficiency in planning, preparing, and executing training events. NGC will provide the Army the ability to train and educate commanders and their staff across multiple domains (land, air, cyber, space, and maritime). NGC will enable joint and multinational forces to defeat a near-peer threats contesting the Joint Force across all domains. FY 2026 RDTE dollars for CR2 supports the following efforts: STE-SW (NGC and TSS/TMT) requirements reflected in the validated STE-SW Initial Capability Document (ICD) 1QFY2025 to address development, modeling, integration, architecture, infrastructure, and cloud migration for acceleration of initial NGC Capability Requirements (CRs) beginning in FY2025. STE-SW provides the$$, 136339000, NULL, NULL, NULL, NULL, 57615000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604121A_CR3$$, $$0604121A$$, $$CR3$$, $$STE Live$$, 61181000, $$The Synthetic Training Environment (STE) Live program develops live training systems in concert with the Cross Functional Team STE initiatives. The STE Live program converges live training with the STE, providing units the necessary training components to accelerate and sustain combined arms maneuver proficiency in support of Multi-Domain Operations (MDO). The STE Live program focuses on the development of a next generation live training architecture that leverages innovative technologies and standards to enable the realistic exercise of unit combat weapons up to brigade level in Multi Domain Operation Environments. The challenge today is the Army cannot train as it fights since 40% of Brigade Combat Team (BCT) platforms weapons effects are currently not simulated by today's live training system, Multiple Integrated Laser Engagement System (MILES). STE Live next generation systems will replicate the following new engagement types, improve sensory feedback, increase realism of direct fire engagement, increase realism of battle damage assessments, improve after action reviews and improve instrumentation at the Combat Training Centers and Home Stations: Indirect Fire, Counter-Defilade (M320, MK-19), Place Object (Mines), Thrown Objects (Grenades), Dropped Objects (Bombs), Guided Weapon (Missiles), Autonomous Weapon (Missiles, Smart Munitions), Direct Energy (laser), Radiant Energy (Sonic, Microwave), Chemical, Biological, Radiological, Nuclear, and Explosives (CBRNE) Plumes and Cyber. FY 2026 RDTE funds will continue to revolutionize Soldier Simulation and Training systems to include a Synthetic Training Environment for 12 engagement types: Direct Fire, Counter-Defilade Fire, Indirect Fire, Dropped Objects, Placed Objects, Thrown Objects, Guided Weapons, Autonomous Weapons, Cyber, Directed Energy, Radiant Energy, and Plume. The 5 instrumentation enablers are Calculations, Networks, Sensors, Terrains, and Transmitters. The FY 2026 cost of the Synthetic Training Environment-Live Training System (STE-LTS) Middle Tier of Acquisition (MTA) effort is $44.7 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission.$$, 61181000, NULL, NULL, NULL, NULL, 22969000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604121A_CR4$$, $$0604121A$$, $$CR4$$, $$STE One World Terrain (OWT)$$, 39075000, $$One World Terrain (OWT) supports the current National Security Strategy (NSS), National Defense Strategy, and National Military Strategy (NMS) as one of the Army's modernization efforts, and one of three core functions of the Synthetic Training Environment - Software (STE-SW). OWT provides a 3D global terrain capability and associated information services that support virtual replication of the physical Earth to reflect the complexities of the operational environment in support of Multi-Domain Operations (MDO) for use in training. OWT enables leaders, Soldiers, and units to train in simulated complex operational environments across the globe replicating dense urban, woodland, jungle, desert, and subterranean areas before the first fight begins. OWT modernizes the Army's terrain generation capability by automatically processing raw geospatial data into a format that is editable and consumable by standard commercial tools and technologies. It provides the tools to incorporate approved geospatial information updates and local terrain surveys into the OWT foundational repository and will be used by the Synthetic Training Environment (STE) to represent the terrain in a virtual environment. In FY 2021, OWT entered the Software Acquisition Pathway. As part of the STE family of programs, OWT provides rapid and iterative delivery of its capabilities to the Training Support System/Training Management Tool (TSS/ TMT) for integration into the STE-SW that supports the Reconfigurable Virtual Collective Trainer (RVCT), Next Generation Constructive (NGC), and future STE training systems. FY 2026 OWT RDTE funds will continue the development of capabilities that automatically process geospatial data into simulation ready 3D terrain for training use; provide geospatial data and models that are editable by standard commercial tools and technologies; and incorporate approved geospatial data updates and user- generated terrain captures into the OWT repository. FY 2026 RDTE funds will also address the OWT requirements codified in the STE-SW ICD, validated 1QFY2025, for One World Terrain (OWT) to accommodate the increased ingestion of terrain, common models, interoperability standards for the acceleration of initial NGC Capability Requirements (CRs) to conduct Joint and Multinational Operations (MDO), the ability to model MDO, and STE Core Services. This is critical to the modernization of the US Army's constructive simulation toolkit used to train Commanders and their staffs at echelon. OWT Program Office costs transitioned from OMA to RDTE based on utilization of the Software Acquisition Pathway.$$, 39075000, NULL, NULL, NULL, NULL, 12710000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604125D8Z_232$$, $$0604125D8Z$$, $$232$$, $$Advanced Manufacturing Components$$, 45513000, $$This project will mature manufacturing processes to support the transition of advanced manufacturing components and prototypes to address warfighter needs. With initial emphasis in the bioindustrial manufacturing area, the project will advance the scale up production of molecules of interest. Through the biotechnology Distributed Bioindustrial Manufacturing Program (DBIMP) – formerly known as the Manufacturing Enabled by Modular Bioindustrial & Reusable (MEMBR) assets initiative - the project will establish a network of flexible manufacturing facilities to scale-up promising biotechnology capabilities for integration into DoD missions.$$, 45513000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604121A_CR5$$, $$0604121A$$, $$CR5$$, $$STE Reconfigurable Virtual Trainer$$, 1362000, $$The Synthetic Training Environment-Software (STE-SW) and Reconfigurable Virtual Collective Trainer (RVCT) requirements, directly support the Army Collective Training Environment - Initial Capabilities Document (ACTE-ICD) as the Army's cornerstone for replicating the Operational Environment (OE) during training events enabling the Army to train as it fights. Separate, but interoperable, RVCT systems are required for both air and ground collective training. The Air RVCT will represent the U.S. Army, Army National Guard, and Army Reserves fleet of rotary wing aircraft. The Ground RVCT will represent ground track and wheeled vehicles from the U.S. Army and Army National Guard. The Reconfigurable Virtual Collective Trainer (RVCT) is the Army's next generation Virtual Training System for conducting collective maneuver training, collective gunnery training, mission rehearsal, and pre-deployment training; that will prepare units for Multi-Domain Operations (MDO). The RVCT includes aviation platforms (RVCT-A), ground platforms (RVCT-G), and dismounted infantry devices. The RVCT is transportable to the Point of Need (PoN) allowing units to train anywhere in the world. The RVCT will be enabled using the STE-SW, which provides a fully interactive, real time simulated battlefield. FY 2026 RDTE funds will provide new variant first article development, integration of lab assets and provide cybersecurity support for RVCT. The FY 2026 cost of the Reconfigurable Virtual Collective Trainer (RVCT) Middle Tier Acquisition (MTA) effort is $7.4 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission.$$, 1362000, NULL, NULL, NULL, NULL, 14724000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604121A_CR7$$, $$0604121A$$, $$CR7$$, $$STE Soldier Virtual Trainer (SVT)$$, 2942000, $$The Soldier Virtual Trainer (SVT) is enabled by the Synthetic Training Environment (STE) and is a virtual immersive trainer that combines and integrates several individual Soldier training capabilities: Weapon Skills Development (WSD), Joint Fires Training (JFT), and Use of Force (UoF). (1) WSD provides immersive capability to meet individual/crew weapons training in support of Army integrated weapon training strategies. (2) JFT provides certification and qualification of Joint Fires Observers (JFO). This includes the training of types II and III close air support according to the JFO Memorandums of Agreement. SVT will take a phased acquisition approach in developing the three capabilities beginning with WSD, JFT, and UoF respectively. SVT's acquisition strategy implementation and award will reduce impact of replacing currently fielded sustained Program of Records (Engagement Skills Trainer II (EST II) and Call for Fire Trainer III (CFFT III)). EST and CFFT PoRs are currently in sustainment awaiting to be replaced by SVT. FY 2026 RDTE funds for SVT furthers the development of prototype designs for SVT Core Integration, WSD - Increment 2, and JFT capabilities. The prototype designs will inform requirements, technology readiness level maturity, design of the SVT capabilities, and level of effort to integrate with STE Software. The FY 2026 cost of the Soldier Virtual Trainer (SVT) Middle Tier of Acquisition (MTA) effort is $37.4 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission.$$, 2942000, NULL, NULL, NULL, NULL, 7501000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604122D8Z_085$$, $$0604122D8Z$$, $$085$$, $$Data Integration Layer (DIL)$$, 26701000, $$The DIL funding line contains efforts to mature management of DoD operational data and deploy a tactical edge data mesh (EDM) to enable data integration among new and legacy systems. EDM is a resilient, interoperable data integration service connecting sensors, weapons, and other battlefield assets for enhanced situational awareness and coordination into a cloud environment. EDM leverages commercial software, a government-owned software development kit (SDK), and open application programming interfaces (APIs) to integrate government and vendor systems, facilitate tactical data sharing, and incorporate artificial intelligence/machine learning (AI/ ML) capabilities at the edge. EDM supports multi-domain operations across echelons, including enhanced C2 and fires in contested environments by optimizing data exchange among Denied, Disrupted, Intermittent, and Limited (DDIL) communication paths.$$, 26701000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604122D8Z_668$$, $$0604122D8Z$$, $$668$$, $$Mission Command Applications$$, 243928000, $$This effort integrates data, analytics, and AI in support of the seven Joint warfighting functions leveraging a common government owned/contractor operated data stack that adheres to Open DAGIR principles. Requested funding purchases licenses for Combatant Command (CCMD) and Joint Staff access to Maven Smart System (MSS) on multiple networks, engineering support to integrate new data sources and digitize workflows, maintenance of a DevSecOps pipeline to allow third party vendors to develop and field applications on MSS, funding for those third party vendors to close CJADC2 gaps, and cloud compute costs needed to run applications and workflows.$$, 243928000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604122D8Z_669$$, $$0604122D8Z$$, $$669$$, $$Global Experimentation (GIDE)$$, 27172000, $$The Global Information Dominance Experimentation (GIDE) series is an iterative, metrics-based approach to experimentation with Combined Joint All-Domain Command and Control (CJADC2) capabilities and concepts. The experimentation series leverages CCMD and Service exercises, as well as smaller data integration sprints called GIDE-Xs, to test new data integrations and digital workflows in the context of real mission use cases, on live networks, and with real data and users. Capabilities that prove successful in GIDE rapidly field to warfighters on the spot because they are software-based. GIDE workflows include cross-CCMD strategic and operational global integration, CCMD and Service workflows, and tactical-to-operational fires workflows in coordination with the Services.$$, 27172000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604123D8Z_067$$, $$0604123D8Z$$, $$067$$, $$Chief Technology Officer$$, 0, $$The CDAO eliminated the Chief Technology Officer (CTO) position as part of efficiencies in FY26.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604123D8Z_081$$, $$0604123D8Z$$, $$081$$, $$AI/ML Scaffolding$$, 0, $$The mission of the AI/ML Scaffolding project was developing, providing, brokering, and advising on the infrastructure, data, tools, services, and best practices needed to accelerate appropriate AI/ML development and adoption. For FY2026, AI/ML Scaffolding funds were realigned to PE 0604133D8Z (Alpha-1).$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604123D8Z_082$$, $$0604123D8Z$$, $$082$$, $$Digital Talent Management$$, 0, $$The Digital Talent Management project code supports CDAO’s role as the OSD Functional Community Manager (FCM) for the data and AI workforce, referred to as the Defense Digital Workforce (DDW). Funding enables education, training, and community management for the DDW.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604123D8Z_083$$, $$0604123D8Z$$, $$083$$, $$Foundation Enablers$$, 0, $$In FY25, Foundational Enablers funded a variety of CDAO projects and capabilities, which in FY26, moved to other project codes or PEs or concluded. The mapping follows: - Acquisition Ecosystem (FY26: remains in this PE, moved to code 786) - Advana Platform (FY26: moved to new BA08 Pilot PE0608140D8Z) - SUNet (FY26: moved to new BA08 Pilot PE0608140D8Z) - CDAO Centrally Managed Support (FY26: no funding, concluded activities) - Defense Digital Services (FY26: no funding, concluded activities) - Enterprise Platforms and Capabilities (EPC): Data Engineering, Data Operations, and Data Governance (FY26: moved to new BA08 Pilot PE0608140D8Z)$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604127N_0530$$, $$0604127N$$, $$0530$$, $$Mine Hunt Systems$$, 4087000, $$The Mine Hunt Systems project contains resources for systems, subsystems, and sensors integrated for use with the Mine Countermeasures Unmanned Surface Vehicle (MCM USV) for mine detection, classification, localization, identification, and neutralization capabilities. Research, development, test, and evaluation efforts are for increasing capability by decreasing time required to conduct Mine Countermeasures (MCM) operations, ensuring low risk to naval and commercial vessels, and removing the man from the minefield. Increased capability includes conducting minefield reconnaissance (mine density and location) at high area search rates, improving detection capability, decreasing sensor false alarm rates, and reducing post-mission analysis time for detection, classification, and identification. The AN/AQS-20C is a mine hunting and identification system with sensors housed in an underwater tow body. The AN/AQS-20C integrates the Wideband Forward Looking Sonar (WBFLS), multifunction Synthetic Aperture Sonar (SAS), and Digital Gap Fill Sonar (DGFS) for the detection, classification and localization of bottom, close- tethered, volume targets. Integration of the Electro-Optic Identification (EOID) sensor enables identification of bottom targets. The system can be deployed from the Littoral Combat Ship (LCS) as part of the MCM Mission Package (MP) or can be deployed from other Vessels of Opportunity (VOO). The MCM USV is the tow platform for the AN/ AQS-20C. Materiel reliability, obsolescence, and performance Engineering Change Proposal (ECP) efforts continue beyond FY 2027. In FY 2022, the AN/AQS-20 Program completed DT/OT with MCM USV, and supported the MCM Mission Package (MP) IOT&E. Due to successful completion of DT/OT for the AN/ AQS-20, Initial Operating Capability was declared in March of FY 2023. In FY 2025 and FY 2026 the AN/AQS-20 program will continue development of Automated Target Recognition (ATR), Acoustic Identification, ensure compliance with cybersecurity requirements, and resolve system obsolescence. Additional improvements are in development based on MCM MP IOT&E and MCM USV DT/OT results. Offshore integration and test will verify product development efforts, and design upgrades due to obsolescence.$$, 4087000, NULL, NULL, NULL, NULL, 38236000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604127N_1235$$, $$0604127N$$, $$1235$$, $$Mine Warfare Planning and Analysis$$, 14417000, $$The Mine Warfare Planning and Analysis project consists of two projects, the Mine Warfare and Environmental Decision Aids Library (MEDAL) and the Mine Warfare Integrated Synthetic Trainer (MIST). MEDAL is the U.S. Navy's single MIW tactical decision support system for integrated mission planning, evaluation, and situational awareness. MEDAL provides mine warfare planning and evaluation tools and databases to the Maritime Component Commander and is employed at the unit level to perform Mining and MCM planning and evaluation. MEDAL Enterprise Architecture (EA) is a family of systems, comprised of the following three components: MINEnet Global, MINEnet Tactical, and Minefield Planning (MFP). MINEnet Global is a shore-based website that provides MIW waterspace awareness functionality to support Navy non-MIW forces. MINEnet Global provides downloadable reference databases, MIW reference publications and links to MIW information. The MINEnet Tactical component is a software application which provides MCM tactical planning, situational awareness and post mission evaluation capabilities. It is fielded to standard Navy networks including, Consolidated Afloat Networks and Enterprise Services (CANES), Integrated Shipboard Network System (ISNS), and Navy Marine Corps Intranet (NMCI) servers and uses common web browsers as the user interface. MFP is a tactical software application which provides commanders the ability to plan and assess offensive, defensive, and protective minefields based on oceanographic and mine performance data and user specified objectives. MIW Integrated Synthetic Trainer (MIST) is a synthetic training aid that enables trainers to lead MIW staff and Warfare Tactics Instructors (WTIs) through end-to-end MCM simulations.$$, 14417000, NULL, NULL, NULL, NULL, 41961000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604133D8Z_081$$, $$0604133D8Z$$, $$081$$, $$Alpha-1 Development$$, 0, $$AI/ML development in the DoD has a high barrier to entry in terms of cost, certification to operate, workforce expertise, contracting, etc. DoD entities often independently solve the same problems and develop solutions that are not interoperable with other efforts. Alpha-1 provides enterprise services and capabilities that enable AI efforts across DoD organizations and mission areas.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604133D8Z_773$$, $$0604133D8Z$$, $$773$$, $$AI & Autonomy Enterprise Enablers$$, 441821000, $$The Alpha-1 PE provides enterprise digital enablers and prototyping efforts to enable the Joint force to access, develop, and adopt artificial intelligence (AI) in warfighting, readiness, and business use cases more easily, securely, reliably, and responsibly. Alpha-1 funding supports AI activities associated with computer vision, generative AI (GenAI), autonomy, and Responsible AI (RAI) adoption. It also includes funding to recruit, train, educate, and enable the DoD workforce to advance AI adoption. Specific activities include enterprise data acquisition and labeling, AI development pipelines, testing and evaluation tools and processes, RAI capability development and enablement, AI and autonomy modeling and simulation, access to proven and emerging AI models, and associated compute infrastructure costs. Investments in these enterprise digital enablers allow DoD to invest centrally in common enablers to ensure interoperability and drive efficiencies, while multiple organizations and platforms can then leverage the capabilities locally in their use cases.$$, 441821000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604134A_CD4$$, $$0604134A$$, $$CD4$$, $$Counter Improvised-Threat$$, 5491000, $$This Project develops prototypes and demonstrates technology for detecting and defeating Improvised Explosive Devices (IED). The goal of this Project is to mature technology to increase the ability of deployed forces to positively identify IEDs with minimal false alarms and increase the rate of advance of maneuver forces. An additional goal is to positively neutralize IEDs with minimal collateral damage. Driven by the current threat facing deployed U.S. forces, this project enables rapid development and delivery of capabilities that enable the detection, neutralization, and mitigation of IEDs and their effects. This Project is coordinated with the Under Secretary of Defense for Research and Engineering (USD/R&E) and the Defense Threat Reduction Agency (DTRA).$$, 5491000, NULL, NULL, NULL, NULL, 15826000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604135A_MR3$$, $$0604135A$$, $$MR3$$, $$Mid-Range Capability (MRC) Missiles$$, 231401000, $$The Common Autonomous Multi-Domain Launcher (CAML) mission is to provide elements across all echelons with a mobile, autonomous, optionally manned, versatile cross-domain (offensive and defensive) fires capability and capacity far greater than current formation launcher and resupply capabilities. CAML will support a wide range of munitions, including Tomahawk Land Attack Missiles (TLAM), Patriot Missile Segment Enhancement (MSE) interceptors, Multiple Launch Rocket System (MLRS) Family of Munitions (MFOM), and Indirect Fires Protection Capability (IFPC) interceptors. CAML reduces emplacement and displacement times, improves crew survivability, adds cross-country mobility, increases overall effectiveness, and allows commanders to mass lethal assets across multiple domains. The system is operated remotely via wireless communication or programmed for autonomous function.$$, 231401000, NULL, NULL, NULL, NULL, 25342000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604182A_HX4$$, $$0604182A$$, $$HX4$$, $$Common Hypersonic Glide Body$$, NULL, $$Funds the effort to field an experimental prototype Hypersonic Weapon System with residual combat capability at the Battery Level as part of the Long Range Fires Battalion in support of Multi-domain Operations by the end of FY 2023. Initial fielding of all ground support equipment and training canisters, less live rounds, was completed in FY 2021. The Long Range Hypersonic Weapon (LRHW) system will provide the Army a prototype strategic attack weapon system to defeat Anti Access/ Area Denial (A2/AD) capabilities, suppress adversary Long Range Fires, and engage other high payoff/time critical targets. The Army is working closely with the Navy in the development of the LRHW. Common with the Navy, the LRHW system includes a Common Hypersonic Glide Body (CHGB) and common 34.5 inch booster. Additionally, the LRHW will use an existing Command and Control (C2) Network, the Advanced Field Artillery Tactical Data System (AFATDS).$$, NULL, NULL, NULL, NULL, NULL, 12540000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604161D8Z_042$$, $$0604161D8Z$$, $$042$$, $$National Technical Nuclear Forensics$$, 8023000, $$Per NSPM 35, the DoD leads the USG post-detonation NTNF capability and directs the U.S. to maintain and advance NTNF capabilities leading to the attribution of the source of an actual or attempted nuclear attack in all environments. Per the 2022 NPR, greater investment in NTNF tools is required to ensure they remain responsive to the threat. Per DoDD S-2060.04, OUSD(A&S) is the DoD office responsible for DoD’s NTNF capabilities. Per the FY 2022 – FY 2026 NFAS Plan, accelerated timelines are required for the NTNF capability to collect, analyze, and evaluate both air and ground post-nuclear detonation samples. This Program Element is the only DoD RDT&E program focused on System Development & Demonstration for NTNF capabilities. Collecting, analyzing, and evaluating post-detonation prompt signals and nuclear debris is critical to ensure the USG can identify the source of nuclear material and holding those involved or supporting an attack accountable is critical to our national defense and security. Swift and accurate forensic and attribution capabilities are vital to supporting the President and Secretary of Defense in developing an appropriate, and timely, national response to a nuclear event and to prevent future attacks. An effective NTNF capability ensures potential adversaries, or those who support them, know that they will be held accountable if they use proxies or other non-traditional delivery (e.g., false-flag operations) of nuclear weapons against the U.S., U.S. interests, or allies. Both internal and independent studies indicate that continued improvement to the USG's NTNF capabilities is needed to sustain a credible deterrent against an attempted or actual nuclear attack. Additionally, this program sustains perishable U.S. technical expertise at the operational DoD laboratories required to respond to a post-detonation NTNF event. The DoD's laboratory capability in this area is limited by capacity and technical expertise. Increased support of the DoD’s NTNF mission is crucial to prevent attrition of current capabilities and knowledge base, ensure that this critical and unique deterrence capability is not lost, putting the security of the nation and the ability to deter specific kinds of nuclear attack at risk, and meeting a higher standard of timeliness and confidence as directed.$$, 8023000, NULL, NULL, NULL, NULL, 16050000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604161D8Z_163$$, $$0604161D8Z$$, $$163$$, $$Nuclear and Conventional Physical$$, 4851000, $$The Physical Security Enterprise and Analysis Program (PSEAP) pursues the development of nuclear and conventional physical security materiel solutions in response to the stated needs and requirements of the Combatant Commands and Military Services. This program leverages commonalities in physical security requirements in order to closely balance and integrate the needs of users. The PSEAP is responsible for avoiding duplication of effort, ensuring systems integration, and promoting interoperability and sustainability. The materiel solutions either (a) lead to a Program of Record, (b) become technology insertions into existing programs; or (c) advance to being a certified Commercial/Government off-the-shelf product.$$, 4851000, NULL, NULL, NULL, NULL, 92298000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604181C_MD29$$, $$0604181C$$, $$MD29$$, $$Hypersonic Defense$$, 185168000, $$Strategic competitors and both homeland and regional adversaries are heavily investing in hypersonics, both offense and defense, and currently have operational hypersonic strike and defensive systems deployed. These are challenging realities of the emerging missile threat environment that United States Missile Defense policy, strategy, and capabilities must address. These adversaries continue to expand the capability and capacity of their offensive and defensive hypersonic missile inventories for both strategic and regional hypersonic missiles. Near Peer/Peer nations have also demonstrated hypersonic missiles in flight tests. The HD program element includes executing systems engineering activities, upgrading existing systems, investing in new technologies and maturation, and developing new regional defensive capabilities. Missile Defense Agency's (MDA) counter hypersonic threats strategy includes leveraging existing systems, delivering an initial regional layered defense capability, and increasing defense capabilities in the future. Activities enabling this strategy are the following: - Develop a regional Glide Phase Intercept capability to engage hypersonic threats during the glide phase of flight and other threats of multi-mission areas. - Develop requirements to integrate into Golden Dome communication architecture. - Execute systems engineering for HD, including architecture analysis, technology prioritization, requirements development, planning, and analysis. - Partner with the Services and other agencies to leverage work on common technologies, test infrastructure, weapon development, testing, and war-gaming. - Cooperatively develop the Glide Phase Interceptor with Japan.$$, 185168000, NULL, NULL, NULL, NULL, 1646669000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604181C_MD40$$, $$0604181C$$, $$MD40$$, $$Program Wide Support$$, 15459000, $$PWS contains non-headquarters management costs in support of Missile Defense Agency (MDA) functions and activities across the entire Missile Defense System. These functions include Government Civilians and Contract Support Services. This effort provides integrity and oversight of the Missile Defense System as well as supports MDA in the development and evaluation of technologies that will respond to the changing threat. Additionally, PWS includes personnel to support global deployments performing deployment site preparation and activation, and provides facility capabilities for MDA Executing Agent locations worldwide. Other MDA wide costs include: physical and technical security; civilian drug testing; audit readiness; the STEM program; legal services and settlements; travel and agency training; office, equipment, vehicle, and warehouse leases; utilities and base operations across multiple geographic locations; commercial and ancillary facility services; management of all facility aspects regardless of lifecycle stage; supplies and maintenance; compliance with statutory environmental requirements; data and unified communications support; materiel and readiness and central property management of equipment; FSRM program (formerly Real Property Maintenance) to keep the Department's inventory of facilities in good working order; and similar operating expenses. PWS is allocated on a pro-rata basis across most Agency PEs; therefore, fluctuates per PE by fiscal year based on the total Agency budget in that fiscal year.$$, 15459000, NULL, NULL, NULL, NULL, 38811000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604182A_HX3$$, $$0604182A$$, $$HX3$$, $$All Up Round and Canister (AUR+C)$$, 25000000, $$The mission of Blackbeard Ground Launch (GL) is to attack/neutralize/suppress/destroy using hypersonic missile delivered precision fires (seeker based) against time sensitive moving targets and hardened targets at a much-reduced cost per missile than currently exists in the Army inventory. Blackbeard Ground Launch (GL) is an affordable, mass-produced hypersonic weapon designed for mid-range precision. The Army will leverage advancements in technology, materials, and cost- effective production methods to provide superior capabilities through fast, iterative design cycles, flexible hardware development, and modern manufacturing practices. Blackbeard GL will offer a complementary but enhanced survivable hypersonic precision strike capability, utilizing existing Army launcher platforms. Blackbeard GL is not a replacement to the Long Range Hypersonic Weapons (LRHW) as it will not reach similar velocities nor range. The goal of Blackbeard GL is to deliver approximately 80% of the Precision Strike Missile (PrSM) Increment 4 capability at a significantly reduced cost. Key features include integration into modified Multiple Launch Rocket Systems Family of Munitions (MFOM) pods and enhanced target discrimination capabilities. Funding will support development, system flight tests, software validation, and full integration into the High Mobility Artillery Rocket System (HIMARS) platform, which will expand HIMARS lethality. Blackbeard GL is a companion development to the Army's Common Autonomous Multi-Domain Launcher (CAML) effort which holds the potential to replace the base HIMARS launcher platform amongst other launchers. While envisioned as a primary munition for CAML, Blackbeard GL is designed to be compatible with existing HIMARS platforms as an interim solution.$$, 25000000, NULL, NULL, NULL, NULL, 118734000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604182A_HX5$$, $$0604182A$$, $$HX5$$, $$Ground Support Equipment (GSE)$$, NULL, $$Funds the effort to field an experimental prototype Hypersonic Weapon System with residual combat capability at the Battery Level as part of the Long Range Fires Battalion in support of Multi-domain Operations by the end of FY 2023. Initial fielding of all ground support equipment and training canisters, less live rounds, was completed in FY 2021. The Long Range Hypersonic Weapon (LRHW) system will provide the Army a prototype strategic attack weapon system to defeat Anti Access/ Area Denial (A2/AD) capabilities, suppress adversary Long Range Fires, and engage other high payoff/time critical targets. The Army is working closely with the Navy in the development of the LRHW. Common with the Navy, the LRHW system includes a Common Hypersonic Glide Body (CHGB) and common 34.5 inch booster. Additionally, the LRHW will use an existing Command and Control (C2) Network, the Advanced Field Artillery Tactical Data System (AFATDS).$$, NULL, NULL, NULL, NULL, NULL, 34310000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604182A_HX6$$, $$0604182A$$, $$HX6$$, $$Test and Evaluation$$, NULL, $$Funds the effort to field an experimental prototype Hypersonic Weapon System with residual combat capability at the Battery Level as part of the Long Range Fires Battalion in support of Multi-domain Operations by the end of FY 2023. Initial fielding of all ground support equipment and training canisters, less live rounds, was completed in FY 2021. The Long Range Hypersonic Weapon (LRHW) system will provide the Army a prototype strategic attack weapon system to defeat Anti Access/ Area Denial (A2/AD) capabilities, suppress adversary Long Range Fires, and engage other high payoff/time critical targets. The Army is working closely with the Navy in the development of the LRHW. Common with the Navy, the LRHW system includes a Common Hypersonic Glide Body (CHGB) and common 34.5 inch booster. Additionally, the LRHW will use an existing Command and Control (C2) Network, the Advanced Field Artillery Tactical Data System (AFATDS).$$, NULL, NULL, NULL, NULL, NULL, 35609000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604183F_644183$$, $$0604183F$$, $$644183$$, $$Hypersonic Attack$$, 802810000, $$Hypersonic Attack Cruise Missile (HACM) is an air-launched, air breathing hypersonic weapon capable of integration on fighter and bombers and enable the U.S. to hold fixed, high value, time-sensitive targets at risk in contested environments from standoff distances. The program leverages investment from the Southern Cross Integrated Flight Research Experiment (SCIFiRE), a bi-lateral U.S./Australian air-breathing hypersonic cruise missile prototyping effort. The HACM program will integrate advanced technologies and mature designs into an All-Up Round (AUR) prototype that will demonstrate a field-able long range prompt strike capability. HACM will design, develop, manufacture, and test prototype vehicles to inform future HACM acquisition decisions. HACM will mature hypersonic technologies and processes to include: subsystem integration, infrastructure and testing advancements, Digital Engineering (DE), Weapons Open Systems Architecture (WOSA), Modeling and Simulation (M&S), analytics, and high performance computing environments. Implements Digital Acquisition tenants of Open, Agile, and Digital; builds and establishes industrial base innovation around the program's enterprise for modularity and adaptability for the life cycle of the weapons system. Leverages common component development, in collaboration with other weapon systems, to reduce redundant costs between systems with similar subsystems requirements. Invests in analytical, data management, digital environments, networks, facilities, and security infrastructure upgrades supporting development of this program's capabilities, while leveraging DoD and DAF enterprise IT solutions. Expands program office staff, facilities, and security infrastructure to support the required classification levels for this program's activities. Engages with DoD, DAF, and industry stakeholders to refine threat analysis, refine inventory requirements, and plan upgrade requirements. Capitalizes on and incorporates successful laboratory research and development efforts applicable to this program's capability. The FY 2026 cost of Middle Tier of Acquisition for HACM is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify Future Years Defense Program (FYDP) funding in a future budget submission. The FY 2026 request was reduced by $0.624 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604183F / Hypersonics Prototyping - Hypersonic Attack Cruise Missile (HACM) Component Development & Prototypes (ACD&P) This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 8.255M was expended for civilian pay expenses in this program element, and in FY 2025 11.738M was forecasted for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, 802810000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604200F_653133$$, $$0604200F$$, $$653133$$, $$Armament Subsystems$$, 36125000, $$Future Advanced Weapon Analysis & Programs enables Air Force enterprise weapons capability planning through the generation and execution of new and emerging requirements and trade space analysis. Inclusively, this necessitates the studies of emerging weapons system gaps and technology insertion for legacy and future systems, responsive design and development engineering, and emerging weapon system gaps and technology insertion for legacy and future systems. These studies also support the determination, exploration, and execution of feasible solutions through advanced technology prototype development and rapid fielding. Additionally, projects in this program element implement the Digital Acquisition tenants of Open, Agile, and Digital in support of all Air Force weapons by conducting high fidelity Modeling, Simulation and Analysis (MS&A) to support the development, testing, and evaluation of future concept and legacy weapons. Efforts under this program element explore new and future concept developments and analyses in response to stakeholder engagements, technology transitions and common enterprise needs, experimentation, air to ground, ground to launch, and air to air fieldable demonstrations and solutions, and the delivery of quick reaction material solutions. The overall objective is to identify methods to improve weapon system performance, develop potential future designs, mitigate evolving threats, pursue low-cost/affordable weapons solutions, and reduce life cycle costs. These projects will also develop and expand MS&A and experimental platforms for weapon qualification activities, improve safety, identify technology gaps, and ensure viability and durability of future weapons programs. This effort includes design, development, test, integration, and implementation of appropriate modular open systems approach, related components, and efforts, such as, but not limited to electrical, logical, and physical interfaces defined in current and future updates to the Weapon Open System Architecture (WOSA) standard. This approach allows modular and severable subsystems, to include those that are software-defined, at the appropriate level to be incrementally added, removed, or replaced throughout the life cycle. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 $101 thousand was expended for civilian pay expenses in this program element, and in FY 2025 $134 thousand is forecast for civilian pay expenses in this program element. The FY 2026 request was reduced by $570 thousand for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                             Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0604200F / Future Advanced Weapon Analysis & Programs Development & Demonstration (SDD) This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, 36125000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604201A_C97$$, $$0604201A$$, $$C97$$, $$ACFT Avionics$$, NULL, $$Tasks in this Program Element support research, development, and test efforts in the Engineering and Manufacturing Development phases of Aircraft Avionics systems. Alternate capabilities, non-Global Positioning System (non-GPS), and/or complimentary Position, Navigation, and Timing (PNT) solutions are investigated, studied, evaluated, and developed as standalone or blended navigation functions. The Alternate Position, Navigation, and Timing (ALT-PNT) enables precise navigation and timing during Multidomain Operations (MDO) in the absence of Global Positioning System (GPS) by leveraging Alternate Navigation (ALT-NAV) signals of opportunity and Vision Based Navigation (VBN) efforts and providing a secure and reliable fused PNT solution utilizing new and existing high-grade sensors available on manned aviation aircraft. ALT-PNT utilizes Modular Open System Architecture (MOSA) standards allowing rapid and affordable platform integration, adopting of new technologies, and adjustment to changes in adversarial capabilities. In accordance with Section 1611 of the FY 2021 National Defense Authorization Act (RESILIENT AND SURVIVABLE POSITIONING, NAVIGATION, AND TIMING CAPABILITIES), ALT-PNT is necessary (A) to generate resilient and survivable alternative positioning, navigation, and timing signals; and (B) to process resilient survivable data provided by signals of opportunity and on-board sensor systems.$$, NULL, NULL, NULL, NULL, NULL, 9224000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604201A_VU3$$, $$0604201A$$, $$VU3$$, $$Networking And Mission Planning$$, 2696000, $$The Improved Data Modem (IDM) is a mission computer that requires software to provide functionality. The IDM is the common solution for digitizing Army Aviation and is fielded on every modernized, rotary-wing Army aircraft. IDM provides digital air-to-air and air-to-ground connectivity and transmission of air-to-air target data between IDM equipped aircraft using legacy radio and crypto equipment. IDM also serves as interface between aircraft mission computers, data capable radios, and Tactical Internet (TI). IDM manages Situational Awareness (SA) data, processes command and control messages, and incorporates protocols for sending and receiving mission command digital messages on the TI, Private Net, and Longbow Net using the protocols Air Force Application Program Development Net (AFAPD) and Variable Messaging Format (VMF). The IDM 401 requires updated technology to mitigate obsolescence and enable multi-core processing to meet requirements for air to ground communications. The IDM Open System REMAN (OSR) will serve as the steppingstone for a longer-term solution, the General-Purpose Computing Platform (GPCP). The Aviation Mission Common Server (AMCS) will become a General-Purpose Computing Platform (GPCP). The GPCP will provide a more capable, computing environment to process broader use cases and enable the Next Generation Command and Control (NGC2) on the Aviation fleet. The GPCP will utilize a Modular Open Systems Approach (MOSA) with a nonproprietary Open Systems Architecture (OSA) to keep pace with evolving threats in the Multi-Domain Battlefield. The GPCP will enable the hosting of software applications to communicate, navigate, sense, and deploy weapon systems across the Joint Force in support of future aviation operations. It will support the future Common Digital Backbone for the enduring and future Army Aviation fleets with the ability for further growth to host flight critical capabilities. The GPCP will begin development in FY28 and production in FY31. This Project funds the development of Networking and Mission Planning systems required to horizontally and vertically integrate the battlefield and the integration of those systems into Army aircraft. Tasks in this Project support research, development, and test efforts for these systems.$$, 2696000, NULL, NULL, NULL, NULL, 11949000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604201F_3600$$, $$0604201F$$, $$3600$$, $$Research, Development, Test & Evaluation, Air Force / BA 5: System$$, NULL, $$Positioning, Navigation, and Timing (PNT) solutions are critical to offensive and defensive operations, enabling delivery of precision fires, safe aerial navigation, and time coordination across multiple platforms and subsystems. PNT must be maintained in the face of emerging and continuously evolving adversarial electronic and cyber threats, requiring increased system resiliency and rapid adaptability. Evolving threats will drive upgrades such as Global Positioning System (GPS) receiver modernization, development of standard navigational system formats/interfaces, increased use of open system architecture design principles, incorporation of alternative navigation sources into navigational solutions, advanced anti-jam antennas, antenna electronics, radio frequency monitoring/locating/reporting capabilities, and precision clock improvements to maintain current and future force capabilities. Project 651030 includes Embedded GPS/Inertial Navigation System (INS) Modernized (EGI-M), Miniaturized Airborne GPS Receiver 2000 Modernization (MAGR-2K-M), Resilient GPS (R-EGI) development, PNT Software Defined User Equipment (PNT SDUE), anti-jam antenna/antenna electronics development, situational awareness devices, and other advanced/non-GPS PNT solutions. Activities also include, but are not limited to, current program planning, rapid prototyping/advanced technology and concept development, execution, and future program planning and support to other GPS enabled systems as required, covered within Budget Activities 6.3, 6.4, and 6.5. The PNT Resiliency, Mods, and Improvements (RMI) effort provides rapidly re-programmable application space for Alternate Satellite Navigation Systems User Equipment (UE), enabling agile and resilient response to GPS threat environments. Funds may be used to address emerging and short-notice Diminishing Manufacturing and Material Shortage (DMSMS) issues. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY2024 5.122M was expended for civilian pay expenses in this program element, in FY2024 6.001M was expended for civilian pay expenses in this program element, and in FY25, 10.899M is forecasted for civilian pay expenses in this program element. The FY 2026 cost of Middle Tier of Acquisition (MTA) effort PNT is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify Future Years Defense Program (FYDP) funding in a future budget submission. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0604201F / PNT Resiliency, Mods, and Improvements Development & Demonstration (SDD) This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604201F_651030$$, $$0604201F$$, $$651030$$, $$GPS Receiver$$, 125663000, $$Positioning, Navigation, and Timing (PNT) solutions are critical to offensive and defensive operations, enabling delivery of precision fires, safe aerial navigation, and time coordination across multiple platforms and subsystems. PNT must be maintained in the face of emerging and continuously evolving adversarial electronic and cyber threats, requiring increased system resiliency and rapid adaptability. Evolving threats will drive upgrades such as Global Positioning System (GPS) receiver modernization, development of standard navigational system formats/interfaces, increased use of open system architecture design principles, incorporation of alternative navigation sources into navigational solutions, advanced anti-jam antennas, antenna electronics, radio frequency monitoring/locating/reporting capabilities, and precision clock improvements to maintain current and future force capabilities. Project 651030 includes Embedded GPS/Inertial Navigation System (INS) Modernized (EGI-M), Miniaturized Airborne GPS Receiver 2000 Modernization (MAGR-2K-M), Resilient GPS (R-EGI) development, PNT Software Defined User Equipment (PNT SDUE), anti-jam antenna/antenna electronics development, situational awareness devices, and other advanced/non-GPS PNT solutions. Activities also include, but are not limited to, current program planning, rapid prototyping/advanced technology and concept development, execution, and future program planning and support to other GPS enabled systems as required, covered within Budget Activities 6.3, 6.4, and 6.5. The PNT Resiliency, Mods, and Improvements (RMI) effort provides rapidly re-programmable application space for Alternate Satellite Navigation Systems User Equipment (UE), enabling agile and resilient response to GPS threat environments. Funds may be used to address emerging and short-notice Diminishing Manufacturing and Material Shortage (DMSMS) issues. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY2024 5.122M was expended for civilian pay expenses in this program element, in FY2024 6.001M was expended for civilian pay expenses in this program element, and in FY25, 10.899M is forecasted for civilian pay expenses in this program element. The FY 2026 cost of Middle Tier of Acquisition (MTA) effort PNT is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify Future Years Defense Program (FYDP) funding in a future budget submission. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0604201F / PNT Resiliency, Mods, and Improvements Development & Demonstration (SDD) This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, 125663000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604212M_3406$$, $$0604212M$$, $$3406$$, $$Attack and Utility Replacement$$, 0, $$USMC Vertical Take-Off and Landing (VTOL) Family of Systems (FoS) is a United States Marine Corps (USMC) Future Vertical Lift (FVL) initiative addressing vertical lift capability requirements that are feasible and affordable in support of the USMC Warfighter. This is a supporting element of the USMC's Force Design 2030 guidance. USMC VTOL FoS will facilitate developmental and operational prototyping and demonstration of capabilities in alignment with co-developed mission focused areas supporting Assault/Support, Attack/Strike, and Aviation Sustainment. USMC VTOL FoS will continue the transition of science and technology efforts into meaningful Warfighter capability, which includes OSD Joint Capability Technology Demonstration (JCTD) and Rapid Defense Experiment Reserve (RDER) projects such as Long Range Attack Missile (LRAM) and Penetrating Affordable Autonomous Collaborative Killer- Portfolio (PAACK-P). The USMC VTOL FoS is closely aligned with the OSD- sponsored FVL FoS initiative and will look to leverage any aspects of the Joint Service programs that may benefit the USMC through accelerated development and/ or reduced life cycle costs. USMC VTOL FoS will be a force multiplier with superior performance, payload, survivability, agility, endurance, and reliability that enables warfighters to win in a future dynamic battlespace. USMC VTOL FoS will increase the Marine Air Ground Task Force's (MAGTF) capacity for long-range fires, Assault/ Support, Attack/Strike, and Aviation Sustainment through the development of capabilities such as a logistics connector. This directly supports and enables Force Design 2030 by enabling the support of the Stand-in Force (SiF), Expeditionary Advanced Basing Operations (EABO), and Littoral Operations in a Contested Environment (LOCE). USMC VTOL FoS will utilize Doctrine, Organization, Training, Material, Leadership and Education, Personnel, and Facilities and Policy (DOTmLPF-P) analyses that will include all facets of a program with particular focus on life-cycle cost reductions through common processes, support equipment, logistic support and component commonality utilizing non-materiel solutions, such as maintenance strategies, training solutions, and infrastructure requirements. Air vehicle capabilities will include primary mechanical, electrical, pneumatic, and structural components such as drivetrain, generators, landing gear, hydraulics, controls, seats, etc. The mission subsystems will include all on and off-board components with embedded control software for those components that provide all mission functionality, cockpit displays, cockpit hardware subsystem controllers and interfaces. The architecture will include the fundamental organization of the complete system, the processing method/ component(s), the platform software, the operating environment, and the on-aircraft infrastructure to facilitate integration of all subsystems and platform. JUSTIFICATION FOR BUDGET ACTIVITY: This program element is funded for Advanced Component Development & Prototype activities, including conducting prototyping and system demonstration tasks aimed at validating requirements.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604212N_1109$$, $$0604212N$$, $$1109$$, $$CH/MH-53$$, 987000, $$The H-53 helicopter is the premier heavy lift helicopter for the Marine Corps and the only operational airborne mine sweeping platform for the Navy. H-53 efforts will continue to develop and qualify components, prior to production and approval decisions, in order to replace obsolete system components. Emphasis will be placed on safety/readiness/supportability improvement modifications that will sustain the H-53 aircraft until the transition of the H-53K is complete. These efforts combined, will significantly improve the readiness of the H-53 fleet while reducing long term operational and supportability costs. Survivability efforts to address improved situational awareness to pilots. Modeling and simulation will be used to the maximum practical extent throughout this effort. Manned Flight Simulator will be utilized to develop, install and test interim modifications, while maintaining the original basic system footprint and functionality. As a part of this effort, a complete Electro Magnetic Vulnerability assessment will be required for the affected and/or modified systems.$$, 987000, NULL, NULL, NULL, NULL, 116901000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604270A_DN9$$, $$0604270A$$, $$DN9$$, $$Modular Electro-Magnetic Spectrum$$, 9153000, $$Modular Electro-Magnetic Spectrum System (MEMSS) is an Fiscal Year (FY) 26 New Start Electronic Warfare (EW) program. MEMSS is an EW capability providing Force Protection and Freedom of Maneuver through Radio Frequency (RF) Technical Effects, an over arching cover term for classified capability. MEMSS will provide accelerated delivery of innovative RF technical effects solutions tailored to Army requirements. The program will prioritize iterative development, incorporating vendor Research and Development (R&D) investments and readily available Commercial-Off-The-Shelf (COTS) components. Further advocacy for MEMSS capabilities exists in support of the Joint community, Operational Needs Statements (ONS), Transformation in Contact (TiC) initiatives, Presidential Directives, and other Combatant Command requests.$$, 9153000, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604214M_0652$$, $$0604214M$$, $$0652$$, $$AV-8B$$, 0, $$This program provides for AV-8B Design, Development, Integration and Test of the following improvements: Engine Life Management Program (ELMP), Operational Flight Programs (OFPs) and Avionics/Weapons Integration, Escape System, readiness and obsolescence management. The ELMP is a comprehensive plan to increase safety of flight and operational readiness of the AV-8B F402-RR-408 Engine and Gas Turbine Starter (GTS), as well as other critical engine components. The Program Office will accomplish this mission through the Component Improvement Program (CIP), which entails Engineering Project Description investigations to derive safety and reliability improvements to the engine and engine components. H7.2, H7.3, and H7.4 will continue to build upon the evolutionary acquisition strategy for OFPs and will improve pilot situational awareness, make pilot interface and weapon selection, and Link16 functionality improvements via OFP and Mission Planning updates, and will integrate required Display Computer processing improvements to enable these functionalities. OFP and integration improvements, to include continued use of current weapons as they are upgraded to modernized GPS capability, and use of components with modern crypto is vital to the Harrier's continued combat relevance to the Marine Expeditionary Unit and Global Response Force Combatant Commanders. Other efforts include compliance with crypto modernization requirements, testing compatibility with GPS-modernized weapons, peculiar integration and flight test requirements such as weapons and countermeasures OFP updates, weapons integration and testing, sensors, and countermeasures integration and stores expansion to include APKWS, radio/communication systems upgrades, AIM-9X, ALE-43, standoff weapons such as JSOW, and unique flight test, study and component redesign efforts of other avionics, sensors, structural components, aircraft subsystems, weapons systems, or emergent tactical requirements as they arise. Efforts also include engineering activities for development, design and test to support aircraft safety, flight clearance and concept exploration for resolution of emergent safety, service life, escape systems, compatibility, obsolescence, and readiness issues as well as response to fleet urgent operational requirements.$$, 0, NULL, NULL, NULL, NULL, 587626000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604215N_1857$$, $$0604215N$$, $$1857$$, $$Calibration Standards$$, 4540000, $$Navy-wide program which addresses Metrology related RDT&E issues for navy weapon systems, shipboard platforms, Naval Air, and Fleet Ground Marines. It supports development of calibration standards (equipment, procedures and technical data) required to resolve METCAL related safety, obsolescence, new and emerging technology support and cost reduction issues. It funds Navy unique and lead service responsibilities in DoD and Joint Services Metrology Research Programs to develop calibration solutions. The line supports development of measurement requirements to verify performance of all test systems used to validate the operation of Navy Weapon Systems with calibration standards traceable to the National Institute of Standards and Technology to calibrate, sustain and ensure performance accuracy. This program also provides benefits and efficiencies in a joint collaborative environment within the Tri-Services. Projects are identified and defined so that they will meet the universal requirement. Development efforts are integrated in order to achieve the common capabilities required at minimum cost. This is also a regular and common business practice within the Navy Metrology Community where R&D efforts are communicated and integrated into the multiple testing and Monitoring Systems. This is done in support of Program Managers, Sponsors, and Principle Executive officers. As a result, common requirements are established, duplication of efforts are eliminated, and best value, high quality METCAL products are produced for the Navy.$$, 4540000, NULL, NULL, NULL, NULL, 38188000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604216N_1707$$, $$0604216N$$, $$1707$$, $$MH-60 Development$$, 64838000, $$The MH-60R/S program pursues upgrades and enhancements that pace the rapidly evolving threat and improve safety-of-flight for its pilots and aircrew. These efforts include improvements to existing sensors, network capabilities, weapon systems, avionics, communications, and navigation systems as well as integration of modern precision guided air-to-ground missiles, fixed-forward and crew-served weapons, the Sensor Operator Console, and data-fusion capability. The program is also evaluating Diminishing Manufacturing Sources and Material Shortages (DMSMS) and making incremental improvements to various airframe, flight safety, and mission- planning systems. The program will continue development of architecture to support integration of secure, over-the-horizon communications in addition to modern en route navigation and terminal approach systems. MH-60R/S research and development initiatives include the evaluation and validation of the platform's cybersecurity posture and development of federated systems to rapidly field new capabilities. The MH-60R/S program is pursuing capability studies on open hardware and software architectures, avionics, mission systems, and air-vehicle performance. FY 2026 budget request funds the following: 1. System Configuration (SC) capability increases, Modernized Tactical Networks (to include Enhanced Throughput (ET) and Tactical Targeting Network Technology (TTNT) (i.e. mesh networks)), Radar Hardware and Software enhancements in support of Minotaur Family of Systems (MFoS), and Air Vehicle, Mission Systems and Avionics DMSMS solutions, to include MH-60 Displays, Embedded Global Positioning System (GPS)/Inertial Navigation System (INS) (EGI), Radar technical refresh, and Advanced Flight Control Computer (AFCC) obsolescence redesign. 2. Integration of Link 16 Advanced Capabilities, Multi-Functional Information Distribution System (MIDS) Joint Tactical Radio Systems (JTRS) Concurrent Multi Network (CMN)-4, and Tactical Networks (i.e. mesh network) to enable over-the-horizon targeting, enhance target sorting, and serve as a force multiplier in network enabled and long range maritime targeting weapon engagements. 3. DMSMS engineering, replacement part development, and qualification testing for known and forecasted Avionics (Displays), Mission Systems (sensors, i.e. passive detection/modern Radar Warning Receiver (RWR), Air Vehicle systems (AFCC), survivability and other obsolete parts. These DMSMS solutions will provide considerations for cost reduction and improvement in reliability and performance. The obsolescence solutions will align with the Future Capabilities Roadmap to minimize duplication and align the mid-life block upgrade configuration changes with the needed solutions. 4. Radar Hardware and Software refreshment will enable the MH-60R to input into MFoS capabilities. Integrated third-party applications will provide enhanced Battlespace Awareness and enriched over-the-horizon targeting support through improved national and tactical sensor integration via common data exchanges through enhanced Tactical Networks in support of Distributed Maritime Operations concepts. 5. Developmental activities including capability studies, interoperability studies, and open hardware and software architectures definition in support of MH-60 mid-life block upgrades. 6. Continued development and integration of the MH-60 Collaborative Mission Planning Continuum (CMPC). 7. Continued development of federated systems that address the rapidly evolving threat environment.$$, 64838000, NULL, NULL, NULL, NULL, 1732977000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604216N_9999$$, $$0604216N$$, $$9999$$, $$Congressional Adds$$, 0, $$FY 2025 Congressional Capability Upgrade funding of $5.000 million will fund the development, integration and testing of the proliferated Low Earth Orbit (pLEO) Skyhook System and the Kraken 18 Communication Pod as federated systems onto the MH-60.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604221N_3016$$, $$0604221N$$, $$3016$$, $$Fatigue Life Mgmt Program$$, 0, $$Fatigue Life Management Program was required to manage P-3/EP-3 inventory fatigue life and included ongoing structural analysis, analyzing emergent structural issues, conducting engineering studies, assessing Fleet impact, and applying new technologies such as Non-Destructive Inspection techniques.$$, 0, NULL, NULL, NULL, NULL, 27413000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604222F_654236$$, $$0604222F$$, $$654236$$, $$Engineering Analysis$$, 2714000, $$The AFNWC is the executing agency for the Engineering Analysis (EA) program that supplies and maintains technical expertise on all AF nuclear weapons and systems by ensuring model based digital engineering integration into systems engineering and mission engineering processes through the application of modular designs / approaches. The EA program develops a digitally informed workforce, increases assurance for fielded systems in a cost-effective and efficient manner, and increases the integration of nuclear weapons systems with war-fighter mission capability assessment. The EA program supplies resources for technical and programmatic activities which include performing independent analyses on all stages of AF nuclear weapon systems life-cycles including weapons development, sustainment, interoperability, compatibility, training, safety, security, reliability, cybersecurity, and AF legacy nuclear stockpile management /retirement. The program provides for the development and maintenance of a nuclear enterprise architecture to ensure alignment and integration of nuclear weapon system capabilities and interfaces. The data management and information technology modernization efforts increase quality and flexibility of design, development, and fielding of nuclear capabilities to the war-fighter by leveraging design and sustainment data across the enterprise aligned to an AFNWC wide data strategy. The implementation of digital engineering and Model Based System Engineering (MBSE) efforts will facilitate the rapid testing, analysis, and delivery of nuclear weapon systems to address evolving threats. Digital transformation tools - automation, machine learning, artificial intelligence - and technological solution implementation will improve AFNWC business processes efficiency and effectiveness to address current government operational needs and focus on higher-value activities. The EA digital engineering efforts also include cloud-based implementation technologies that will be configured to ensure all data analysis and visualizations reach back to a single authoritative data source of truth. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0M was expended for civilian pay expenses in this program element, and in FY 2025 $0M is forecasted for civilian pay expenses in this program element.$$, 2714000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604222F_654807$$, $$0604222F$$, $$654807$$, $$Nuclear Weapon System$$, 74437000, $$The AFNWC is the executing agency for the Nuclear Weapon System Technology and Integration (NWST&I) program that ensures the safety, survivability, security, and effectiveness of AF nuclear weapon systems in direct support to the military warfighters and force providers. Emphasis is placed on ensuring nuclear weapon system compatibility, validating nuclear safety designs, generating weapon system safety rules, developing flight profiles for safe and effective nuclear weapons delivery, exposing vulnerabilities which could compromise the authorized use of nuclear weapons, and developing mitigations to any nuclear weapon system safety, security, or effectiveness shortfalls (to include future concept development). These requirements are met through in-depth technical, operational, and intelligence evaluations, demonstrations, modeling and simulation (M&S), test and evaluation (T&E), trade studies, requirements analysis, and recommendations to planning, policy, and doctrine. Additionally, the program conducts DoD-required certification for legacy, modernized, and new nuclear weapon systems. The Air Force Safety Center (AFSEC), provides guidance, direction, and oversight of all matters pertaining to emerging weapons technologies including nuclear surety of all nuclear weapons and weapon systems in Air Force custody and facilities, from storage and assembling, testing, transporting, and delivering it on target. AFSEC collaborates with DAF nuclear stakeholders to implement a nuclear weapons systems safety and surety program as part of the overall Air Force Nuclear Surety Program, as directed by DoDD 3150.02, DoD Nuclear Weapons Surety Program and Department of Defense Manual 3150.02, DoD Nuclear Weapon System Safety Program Manual. Emphasis is placed on ensuring nuclear weapon system prevention of loss (safety), validating nuclear safety designs, coordinating interagency weapon system safety rules for OSD, exposing vulnerabilities which could compromise the authorized use of nuclear weapons, and developing compensatory measures to any nuclear weapon system safety, security, or operational non-compliance (to include future concept development and cybersecurity and zero-trust implications on surety). AF and DOD requirements are met through in-depth technical, operational, demonstrations, modeling and simulation (M&S), test and evaluation (T&E), trade studies, requirements analysis, and recommendations to acquisition execution, schedule, and guidance using all available information to include Artificial Intelligence for increasing efficiency. Additionally, the program conducts DoD-required certification for legacy, modernized, and new nuclear weapon systems and maintains a Special Access Program (SAP) and Unauthorized Launch (UL) and Safety Privilege information Secure Compartmentalized Information Facility (SCIF) to ensure efficient access to interagency nuclear weapons enterprise program data for the Air Force Safety enterprise and Department of Defense stakeholders. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0M was expended for civilian pay expenses in this program element, and in FY 2025 $0M is forecasted for civilian pay expenses in this program element.$$, 74437000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604222F_655708$$, $$0604222F$$, $$655708$$, $$Nuclear Weapons Support$$, 2161000, $$The modernization of legacy nuclear systems, development of new nuclear-capable aircraft and munitions, and the creation of the new Weapon Generation Facilities (WGF) within Air Force Global Strike Command (AFGSC) may require new support equipment capabilities to meet system and mission requirements. Additionally, the WGF introduces a new concept of operations by integrating maintenance and storage mission sets into one facility. To support mission generation requirements, support equipment and capabilities related to the nuclear enterprise must be studied, reviewed, modified, or in extreme cases, re-developed to maintain operational readiness. In FY25, user requirements increased the 3K aerial stores lift truck capability to 4K due to increased length/weight of new munitions. Examples of equipment under review include but are not limited to: (a) next-generation 4K and 7K aerial stores lift trucks; and (b) the Electric Manually Operated Lift Truck (EMOLT) to replace the aged MHU-194 Manually Operated Lift Truck (MOLT). The Next Generation Large Munitions unit, also known as the MHU-TSX, will integrate advanced technology such as machine vision and supervised autonomy and agile maneuverability to reduce the time associated with loading and transporting weapons both internally (threshold) and externally (objective) on AFGSC aircraft. The review, analysis, and potential modification of existing equipment ensures mission generation remains executable. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0M was expended for civilian pay expenses in this program element, and in FY 2025 $0M is forecasted for civilian pay expenses in this program element.$$, 2161000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604230N_1130$$, $$0604230N$$, $$1130$$, $$Expeditionary Loitering Munitions$$, 731000, $$The Expeditionary Loitering Munitions Portfolio consists of two Navy loitering munition programs (air and surface) designed to meet an urgent Geographic Combatant Command Requirement. Air and Surface Expeditionary Loitering Munitions will leverage and continue prior development efforts including an Office of Naval Research (ONR) Innovative Naval Prototype (INP). The Navy is pursuing commercial-off-the-shelf solutions with autonomous government-provided software and auxiliary systems. The systems will be expeditionary and deployable by small teams to support operations in various environments. The air system has transitioned from Low-Rate Initial Production to Full-Rate Production with the initial vendor solutions and is now expanding the industrial base for this capability by integrating government-owned technology with other vendor platform solutions. The surface system has transitioned from the ONR INP and is now in Low-Rate Initial Production.$$, 731000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604230N_1234$$, $$0604230N$$, $$1234$$, $$Unmanned Surface Vehicle (USV)$$, 899000, $$New Start USV development: The Program funding for development of the Unmanned Surface Vessel (USV) System Development, reflecting the Navy's vision of eventually fielding the USV across all unmanned surface platforms.$$, 899000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604230N_3326$$, $$0604230N$$, $$3326$$, $$NSW Rapid Capabilities$$, 8618000, $$The Rapid Capabilities Development (RCD) program supports the Naval Special Warfare (NSW) Branch by identifying and assessing available technologies that confront current and future irregular and expeditionary warfare challenges. Program development efforts focus on the enhancement/advancement of existing technologies to fill urgent and emergent or other capability gaps for NSW. Program funding provides for the development, integration, testing, validation, combat demonstration, and evaluation of identified technologies to meet operational requirements; service-common and NSW program technology challenges; and technology obsolescence issues of developed capabilities. The RCD program develops expeditionary/operational capabilities that enable NSW forces to conduct joint cross-domain special reconnaissance, counterterrorism, direct action, amphibious and irregular warfare, and fulfill urgent/emergent needs within a 9-36 month timeframe.$$, 8618000, NULL, NULL, NULL, NULL, 45564000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604230N_3445$$, $$0604230N$$, $$3445$$, $$Visual Augmentation System$$, 0, $$The United States Navy Service Common Visual Augmentation Systems (VAS) Program of Record manages, procures, and maintains night vision devices, thermal detection devices, day/night weapons optics, and lasers in support of Navy combat capabilities with regard to the detection, recognition, classification, tracking, and destruction of hostile air and surface forces. The USN VAS Program also manages research into the future of visual augmentation systems and engages with Navy and DoD VAS stakeholders to ensure the Navy maintains competitive advantage over near-peer adversaries. Research, Development, Test and Evaluation, Navy funding provides the United States Navy Service Common Visual Augmentation Systems (VAS) Program of Record with the ability to maintain competitive advantage over the nation's near peer adversaries by leveraging the military research community, other DoD VAS programs, academia and commercial industry in order to transition mature technologies (active, passive, multi-domain imaging sensors, laser systems, display systems, optics, image processing) that align with US Navy and DoD priorities.$$, 0, NULL, NULL, NULL, NULL, 2321000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604230N_3446$$, $$0604230N$$, $$3446$$, $$Expeditionary sUAS Development$$, 862000, $$The Navy Family of Small Unmanned Aircraft Systems (FoSUAS) program supports Navy Expeditionary Combat Command (NECC), Expeditionary Exploitation Unit ONE (EXU-1), and Naval School Explosive Ordnance Disposal (NAVSCOLEOD). The program procures existing and emerging technologies (including enhancement kits/payloads) in Fixed Wing (FW) and Vertical Take Off and Landing (VTOL) solution sets for core mission requirements and are critical in providing force protection, reconnaissance and surveillance, and repair of battle-damaged facilities and other infrastructure. FoSUAS includes Short Range/Short Endurance (SR/SE) and Medium Range/ Medium Endurance (MR/ME) categories of Small Unmanned Aircraft Systems (SUAS) with each category tailored toward specific mission needs/profiles. As such, a mix of Type/Model/Series (T/M/S) SUAS makes up the FoSUAS Program of Record (POR) as addressed in the Navy's FoSUAS Top Level Requirement (TLR) document. In addition to supporting the requirements in the Navy FoSUAS TLR, RDTE funding for the FoSUAS program conducts activities including, but not be limited to, engineering analysis of commercial systems, operational assessments, Field User Evaluations (FUEs), support of Urgent Universal Needs Statements (UUNS), cyber/IA assessments, development of SUAS Reusable Architectures (SRA) and other efforts to inform future Navy systems procurements.$$, 862000, NULL, NULL, NULL, NULL, 1493000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604233F_676035$$, $$0604233F$$, $$676035$$, $$T-6 Operational System$$, 63271000, $$T-6 Operational System Development continues follow on development activities to Joint Primary Aircraft Training System (JPATS) including but not limited to studies and development efforts, instructional courseware, and logistics support to include Diminishing Manufacturing Sources (DMS) and development activities related to DMS. Included is development for the Crash Survivable Recorder, Avionics Replacement Program (ARP), Enhanced Mission Cockpit (EMC) and associated upgrades. There are currently 443 aircraft (442 AETC & one TA-D Test aircraft) in the Air Force inventory. Remaining service life is through Dec 2049. Funding contained in this platform's documentation directly aids Air Education Training Command (AETC) flying training enterprise and increase overall pilot production and reduce USAF pilot shortage. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $1.742 million was expended for civilian pay expenses in this program element, and in FY 2025 $2.919 million is forecasted for civilian pay expenses in this program element.$$, 63271000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604230N_3447$$, $$0604230N$$, $$3447$$, $$Mine Expeditionary Response$$, 899000, $$Funding realigned from Lightweight Reusable Underwater Recon Vehicle. Funding supports the development of unmanned systems for the Navy's expeditionary unmanned underwater Explosive Ordnance Disposal (EOD) and Mine Countermeasures (MCM) capability. Specifically, it provides for development of affordable expeditionary remote stand-off underwater systems to support Navy Expeditionary forces including EOD, Mobile Diving and Salvage, Underwater Construction Teams (UCT), and Expeditionary Mine Countermeasures (ExMCM) mission operations. The equipment must be highly portable in order to support the Navy EOD technician to safely detect, approach, render safe, recover, exploit, and dispose of underwater explosive threats to include sea mines, limpet mines, maritime IEDs, and unexploded ordnance. Provides support for the Navy's high priority missions of Maritime Homeland Defense and MCM. This project directly supports Department of the Navy Strategic Roadmap for Unmanned Systems promulgated in March 2018 and addresses capability gaps defined by the Joint Service EOD (JSEOD) Initial Capabilities Document (ICD), Serial Number 671-75-05 of 3 June 2005, Joint Improvised Explosive Device (IED) Defeat Initial Capabilities Document (ICD) of 23 February 2006/ JROCM 070-06, and the Expeditionary MCM ICD of June 2017. This project is being executed in accordance with approved CNO N9I Requirement #056-95-19, "Capability Development Document (CDD) for Maritime Expeditionary Standoff Response Family of Systems (MESR)," July 23, 2019. Additional efforts continue to execute the open competition process necessary to acquire and verify an EOD Response ROV capability focusing on user effectiveness and operational suitability to provide a ROV based target interdiction capability to address the capability gaps assessed in the previously conducted Expeditionary UUV Neutralization System (EUNS) AoA. This next generation capability is developed to decrease risk when reacquiring/investigating a potential threat (i.e. sea mine or maritime IED). In response to emergent maritime threat assessments ISO of INDOPAC Global Power Competition (GPC) scenarios, the MESR Program of Record (PoR) will initiate and conduct a Proof-of-Concept effort to demonstrate the potential ability to counter deep-water explosive threats as an ExMCM enabling capability ISO Joint Force Maneuver.$$, 899000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604230N_4011$$, $$0604230N$$, $$4011$$, $$Naval Coastal Warfare Surv and C4I$$, 2925000, $$Identity Dominance System (IDS) supports the Navy's Visit, Board, Search and Seizure (VBSS) teams conducting Expanded Maritime Interception Operations (MIO) with a biometric capability. IDS provides the Navy with a means to collect and process identity information in the conduct of maritime and expeditionary operations. There are three key aspects of this capability: 1) Enable forces to rapidly identify unknown individuals encountered in the conduct of operations. 2) Verify an unknown individual's claimed identity. 3) Enable forces to update, manage, and share identity information on friendly, neutral, and enemy individuals in support of identity operations (IdOps). To support IdOps and achieve identity dominance for expeditionary and naval forces, the future biometrics collection and processing equipment needs to be smaller, lighter, and more efficient with respect to computing power and speed when compared against the current system. The equipment needs to take advantage of enhanced communications capabilities, be able to store the appropriate amount of data to collect biometric samples, match the samples against an internal database and reach near real time operations with connectivity to the DoD biometrics database. In addition to Navy VBSS MIO, IDS also supports the Expeditionary Exploitation Unit One (EXU-1) expeditionary missions. IDS must continue to mature and adapt to the changing threat environment and emerging requirements to support these missions. Biometrically Enabled Access Control - Husbanding (BEACH) is an authentication capability to improve identity and authentication assurance for entrance to OCONUS Navy-Controlled and non-Navy Controlled ports.$$, 2925000, NULL, NULL, NULL, NULL, 52501000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604230N_9999$$, $$0604230N$$, $$9999$$, $$Congressional Adds$$, 0, $$C366 - Military Sea Lift Command and United States (US) Navy is exploring using a long-haul, Hybrid/Vertical Takeoff and Landing (VTOL), autonomous unmanned aircraft for delivery of critical parts. The autonomous movement of critical parts and supplies within a Carrier Strike Group increases operational readiness and warfighting capability of embarked ships or aircraft. Development of these technologies will enhance operations by reducing workload on manned aviation and allow delivery of parts in contested environments where manned aviation could be at high risk.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604230N_9C86$$, $$0604230N$$, $$9C86$$, $$Combatant Craft Replacement$$, 844000, $$Navy Expeditionary Combat patrol boats, Fleet Expeditionary Security combatant craft, Underwater Construction Team (UCT) and Explosive Ordnance Disposal (EOD) replacement will provide second generation Multi Mission Craft that will replace in-service Force Protection Large, Force Protection Small, Underwater Construction and EOD craft. Boat and craft replacements will: conduct Maritime Security Operations across the full spectrum of naval, joint, and combined operations enabling access and freedom of action throughout the sea-to-shore and inland operating environments as well as conduct maritime Mine Countermeasures (MCM), counter Improvised Explosive Devices (IEDs), Weapons of Mass Destruction (WMD), and all other types of weaponry, for protection of naval and joint assets required for sea control and power projection. Specific mission and capabilities will be identified in an Initial Capabilities Document (ICD), Analysis of Alternatives (AoA), Capabilities Production Document (CPD) and required milestone documentation. RDT&E funding will fund procurement and material solution studies, advanced technology development and studies, design development and test and evaluation and transition Small Business Innovative Research Programs, Rapid Innovation Fund Programs and other technology programs expeditionary science & technology objectives as follows: RDT&E funding will fund procurement and material solution studies, advanced technology development and studies, expeditionary science & technology objectives, design development and test and evaluation and transition Small Business Innovative Research Programs, Rapid Innovation Fund Programs and other technology programs.$$, 844000, NULL, NULL, NULL, NULL, 14486000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604231N_0486$$, $$0604231N$$, $$0486$$, $$Tactical Support Center$$, 13525000, $$TacMobile is the Ground Station that brings Enterprise Command, Control, Communications, Computers and Intelligence, Surveillance and Reconnaissance (C4ISR) to the Maritime Patrol and Reconnaissance Force (MPRF) community. TacMobile is a long-running, multi-year acquisition program that provides Command, Control, Communications, Computers, and Intelligence (C4I) for Navy's MPRF. From within Tactical Operations Centers (TOC) at well-supported airfields, TacMobile provides theater Anti-Submarine Warfare (ASW) and Intelligence Surveillance Reconnaissance (ISR) commanders a common tactical picture while providing pre-flight and post-flight support to manned and unmanned MPRF aircraft. From within Mobile Tactical Operations Centers (MTOC), TacMobile supports manned MPRF aircraft at the tactical edge of operations. TacMobile Fly-Away Kits (FAK) support manned MPRF aircraft in short-duration expeditionary settings. Services provided include analysis and correlation of diverse sensor information; data management support; command decision aids; rapid data communication; mission planning, evaluation and reach-back dissemination of surveillance data and threat alerts to operational users ashore and afloat, and to the Maritime Intelligence Surveillance and Reconnaissance Environment. The TacMobile program uses an evolutionary development strategy consisting of Capability Packages to meet new and emergent Fleet requirements, while retaining current capabilities. These capability packages consist of a three phase approach: Capability Package One (CP-1) which addresses SECRET domain only (planned fielding in FY25); Capability Package Two (CP-2) meets the Minimum Viable Product (MVP) (Initial Operational Capability (IOC) in FY28); and Capability Package Three (CP-3) will meet full Capability Production Document (CPD) requirements. These Capability Packages are planned and resourced to support the MPRF Family of Systems aircraft: P-8A Poseidon aircraft modernization and upgrades; and Advanced Airborne Sensor (AAS). In FY 2026, TacMobile begins shifting from its current TacMobile Inc 2.1 baseline to a modernized and modular hardware and software architecture (Inc. 3.0 baseline), leveraging Model Based Systems Engineering, and increased cloud, virtualization, micro-services, and container based technology. Transition of development environments, personnel, and processes to a cloud-based Development, Security, and Operations (DevSecOps) approach to meet fleet Size Weight and Power (SWaP) and cyber resiliency requirements. Conduct Increment 3 Critical Design Review (CDR) and finalize documentation. Procurement of hardware to support development of the engineering development model (EDM) to meet fleet requirements to support Higher Than Secret (HTS) operations with expeditionary HTS shelters. Initiate Interim Authority To Test (IATT) preparation for HTS Lab and System accreditation. Commence EDM integration. Incorporate a program Test Lead and integrate Commander Operational Test and Evaluation Force (COTF) involvement for Test and Evaluation (T&E) oversight of Developmental Test activities. Commence transition of Mission Planning Software from legacy End-Of-Life Joint Mission Planning System (JMPS) to Next-Generation Open Mission Systems (NOMS) architecture.$$, 13525000, NULL, NULL, NULL, NULL, 165513000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604231N_2343$$, $$0604231N$$, $$2343$$, $$Tactical METOC Applications$$, 12230000, $$The Tactical Meteorology and Oceanography (METOC) Applications Project provides cyber secure operational effects decision aid capabilities for Navy and Marine Corps warfighters in the context of Joint Operations in a net-centric environment. This project funds the agile software development of the Naval Integrated Tactical Environmental System - Next Generation (NITES-Next) program of record. The NITES-Next program identifies and transitions state-of-the-art decision support software technologies from the government and commercial industry's technology base, and then demonstrates and validates these capabilities before fielding. These software decision support tools provide platform, sensor, communications, and weapon systems performance assessments for warfighters in terms of their littoral and deep-strike battlespace environments. These assessments allow mission planners and warfighters, from Unit to Theater level, to optimize their sensor employment on airborne, surface, and subsurface platforms in support of Naval Composite Warfare mission areas including Undersea Warfare (USW), Anti-Submarine Warfare (ASW), Mine Warfare (MIW), Amphibious Warfare (AMW), Anti-Surface Warfare (ASUW), Anti-Air Warfare (AAW), Strike Warfare (STW), Expeditionary Warfare (EXW), Electronic Warfare (EW), Information Operations (IO), Intelligence Operations (INT), Non-Combat Operations (NCO), Command, Control, Communication (CCC), and Naval Special Warfare (NSW). Performance assessments leading to improvements in operational and tactical control are conducted through a two-tiered approach: 1) METOC Decision Aids and, 2) Operational Effects Decision Aids (OEDAs). METOC Decision Aids consist of a series of analysis tools which characterize the physical environment conditions of the battlespace based on the best set of physical environment data available at the time (i.e., some combination of historical and/or real-time (or near real-time) in-situ, and numerically modeled forecast data). OEDAs use the METOC Decision Aid information by fusing it with relevant, often-classified, sensor and target data to predict how weapons and sensor systems will perform. Performance results are displayed in tabular and graphic formats integrated into net-centric visualization tools for use by mission planners, and combat/weapon system operators to develop localization plans, USW/AAW/ASUW screens, STW profiles, and AMW ingress and egress points. METOC Decision Aids and OEDAs use data obtained through direct interfaces to Navy combat systems. Cyber secure capabilities are a current emphasis required to characterize and/or predict sensor and weapons system performance in the highly complex littoral environments in support of regional conflict scenarios. It addresses multi-warfare areas, particularly shallow water ASW, NSW, and missile and air defense/strike capabilities. Funding supports development and integration efforts for METOC systems to generate and collect METOC data and fuse multiple intelligence inputs to more robustly characterize and predict tactical atmospheric and oceanographic conditions. This integrated METOC picture will support real-time battlespace awareness of propagation conditions affecting signals across the electromagnetic spectrum. METOC data will be fused with other intelligence data and automatically provided to shipboard combat systems to inform kinetic and non-kinetic fires. FY2026 funding supports the development and integration efforts of NITES-next providing METOC production center data to programs and platforms in support of denied, disrupted, intermittent, and limited (DDIL) environments. Funding will continue the software development of highest priority capabilities as outlined in the Software Acquisition Pathway (SWP) Capability Prioritization Meetings (CPMs) to include the Forecaster Toolkit Ashore, continued expansion into the cloud and JWICS enclave, and lightning capability.$$, 12230000, NULL, NULL, NULL, NULL, 47743000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604231N_2345$$, $$0604231N$$, $$2345$$, $$Fleet METOC Equipment$$, 161000, $$The Littoral Battlespace Sensing - Unmanned Undersea Vehicles (LBS-UUV) project provides for the engineering and manufacturing development of sensors, communication interfaces, processing and display meteorological and oceanographic (METOC) equipment. This equipment is designed to provide future mission capabilities for war fighters to measure, ingest, store, process, distribute and display METOC parameters and derived products. This project also exploits new government off-the-shelf/commercial off-the-shelf technologies, tactical sensors and web enablement for the Navy's computer-based tactical shipboard and shore capability used to predict and assess the operational effects of the physical environment on the performance of platforms, weapons and sensor systems. This project includes development of warfare specific mission planning modules to support unmanned systems with integration of data from environmental and tactical sensor systems, model forecast information and Geospatial Information & Services Databases. This project also supports development of autonomous environmental sensing systems for situational awareness and tactical decision aid/mission planner support, as well as iridium and advanced satellite communication integration in METOC sensor, vehicle control and mission planning systems that will be required to achieve Chief of Naval Operations (CNO) objectives for information dominance and decision superiority. Major emphasis areas include Littoral Battlespace Sensing - Unmanned Undersea Vehicles (LBS-UUV) and the Environmental Satellite Receiver Processor (ESRP) program (comprised of ESRP AFLOAT (formerly AN/SMQ-11) and ESRP ASHORE (formerly AN/FMQ-17) systems). FY2026 funding for LBS - UUV will continue to implement improvements found in the engineering studies conducted over recent years. These improvements will aid in the continued advancement of the Gliders (LBS-G) including improved electrical, software, mechanical, sensor, and/or system enhancements for Littoral Battlespace Sensing. These enhancements are critical to the sustainment and performance of LBS-G platforms in the field and meeting operational objectives FY2026 funding for ESRP will continue to support new technology assessments for ESRP modernization.$$, 161000, NULL, NULL, NULL, NULL, 3620000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604264N_0606$$, $$0604264N$$, $$0606$$, $$Aircrew System Development$$, 40237000, $$AIRCREW SYSTEMS: Aircrew Systems include Enhanced Visual Acuity (EVA), MH-60R/S Head and Neck Injury Mitigation (HNIM), Improved Joint Helmet Mounted Cueing System (IJHMCS), Next Generation Survival Radio (NGSR), Recovery Locator Device (RLD), Aircrew Hearing Protection (AHP), Rotary Wing/Tilt Rotor (RW/TR) Survival Vest Systems Improvement (SVSI), Parachute Survival Ensemble (PSE), Cold Weather/Anti-Exposure Systems (CWAES), and Next-Generation Rotary Wing Helmet (NGRWH). EVA provides advanced day/night vision/Helmet-Mounted Display (HMD) capability to address critical capability gaps in low and no light illumination levels (night vision). EVA will be integrated on current aircraft through a common interface allowing an incremental, modular approach to fielding full capability and future upgrades. HNIM will leverage work conducted during the Gunner Seat replacement program to reduce aircraft vibrations through incorporation of vibration damping into MH-60 R/S cockpit seats, reducing fatigue and enhancing mission endurance. Solutions will reduce short-term and long-term biomechanical injury due to vibration. IJHMCS will mitigate aircrew back and neck strain/fatigue and replace the JHMCS Helmet Mounted Day Display and Night Vision Cueing Device (NVCD) with a single day/night, digital color-capable helmet-mounted display. IJHMCS will integrate onto the helmet solution identified in the Helmet Mask Regulator (HMR) program. NGSR will address communication security (COMSEC) modernization directives and current obsolescence issues, providing a secure two-way Beyond Line-of-Sight (BLOS) communications capability between isolated personnel and rescue coordination and recovery forces. The RLD program will develop, qualify, procure, and field a small, precise signaling device to support personnel recovery. This device will transmit a secure, geo-locatable distress signal in a GPS-denied environment over existing US government and other communications architectures. The AHP program will leverage technology advancements in hearing conservation and speech intelligibility to mitigate aircrew hearing loss and clarity of mission-critical communication. The SVSI program provides for an improved RW/TR aircrew survival vest to address safety and performance issues with the currently fielded solution. Vest systems include, at a minimum, aircrew life support equipment and armor carrier, hoisting capability, mobile aircrew restraint, and life preserver. The PSE program will update the currently fielded ensemble to include modern technologies reducing size/weight and increasing accessibility for in-flight bladder relief. PSE modernization will reduce fatigue during normal missions and increase ease of egress during bailout situations. The CWAES program will design, test, and qualify improved cold weather/anti-exposure systems. System components will provide reduced thermal burden, increased mobility, and superior water intrusion resistance while maintaining protection levels. The improved system will reduce fatigue and dehydration, enable operating at optimum performance during extended missions, provide protection from exposure, and provide improved survivability during extended recoveries. NGRWH mitigates aircrew back and neck injury by providing a lighter-weight helmet solution with improved Center of Gravity (CG) and serves as the platform for future day/night digital HMD solutions. AIRCREW SAFETY IMPROVEMENT PROGRAM: Aircrew Safety Improvement Program (ASIP) provides continuing development and qualification in response to high priority, emergent aircrew systems deficiencies, capability gaps, obsolescence, and readiness issues. ASIP addresses critical safety and performance issues while enhancing safety and survivability with solution improvements across the aircrew systems portfolio. Efforts are prioritized according to fleet demand signals.$$, 40237000, NULL, NULL, NULL, NULL, 237290000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604231N_3050$$, $$0604231N$$, $$3050$$, $$Deployable JT Command and$$, 2096000, $$Deployable Joint Command and Control (DJC2) provides a self-contained, standardized, rapidly deployable, modular, scalable, and reconfigurable joint command and control (C2) capability to designated Geographic Combatant Commands (GCCs). DJC2 is the materiel solution to Defense Planning Guidance that called for the development of standing Joint Task Forces (JTFs) with a deployable C2 capability. DJC2 will ensure that Joint Force Commanders (JFC) are equipped, as well as trained and organized, to carry out their C2 responsibilities. DJC2 provides GCCs and JFCs a mission critical, integrated family of systems with which to plan, control, coordinate, execute, and assess operations. It is designed to deploy rapidly, set up within hours, and quickly provide necessary C2 mission and collaboration functionality across the full spectrum of JTF operations. The DJC2 has also been deployed in support of Humanitarian Assistance and Disaster Relief (HA/DR) efforts. The capability is intended for all levels of conflict and will be reconfigurable to meet specific GCC and JTF mission requirements. This capability is interoperable with higher and adjacent echelons of command (to include coalition allies) as well as with supporting elements to include joint forces. FY26 funding supports development efforts for systems engineering, integration, and DJC2 Test Bed. Focus areas include emerging cyber security technologies and cloud hosting environments.$$, 2096000, NULL, NULL, NULL, NULL, 11901000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604231N_3260$$, $$0604231N$$, $$3260$$, $$Naval Operations Business Logistics$$, 33653000, $$Naval Operational Business Logistics Enterprise (NOBLE) is the logistics information technology family of systems (FoS) comprised of the Naval Operational Supply System (NOSS), the Naval Maintenance, Repair, and Overhaul (N-MRO), and supporting capabilities to include a common platform hosting environment and data exchange solutions, and the Logistics Integrated Data Environment (L-IDE) which supports and align readiness data systems to ensure that trusted, critical logistics data is widely available to or accessible by mission commanders, warfighters, decision-makers, and mission partners in a real-time, useable, secure, and linked manner to enable analytics, and support broader DoD/DON data efforts. NOBLE enables combat lethality by generating and sustaining Navy and Marine Corps force readiness for operational commanders afloat and ashore, providing the foundational capability to keep ships driving, planes flying, and weapons firing from an equipment Operational Availability (Ao) perspective. NOBLE is the centerpiece of the Fleet's strategic imperative to improve Sailor, unit and group maintenance self-sufficiency combat operations in a communications and access-denied arena. NOBLE's mission is to provide the Navy and Marine Corps with an integrated, scalable, and cyber-secure capability that supports the management of logistical information, material, and funds required to maintain and operate ships, submarines, and aircraft. NOBLE FoS will provide direct support to warfighter readiness with maintenance, supply, and financial capabilities, and a federated data environment to enable information integration for decision making in contested environments, and real-time data driven operational and ashore readiness analytics. These capabilities include enhanced situational awareness, planning, execution, personnel administration, and management of maintenance and supply logistics and business functions to ships/ submarines, aviation squadrons, shore operational sites, and expeditionary units with a total user base exceeding 150,000. The NOBLE FoS will support Aviation and Maritime organizational, intermediate, and depot level maintenance activities and facilities. The NOBLE architecture will meet current and emerging demands for cyber security, enable Financial Improvement and Audit Readiness (FIAR), drive efficiency into Navy logistics and aviation and maritime maintenance mission requirements, enable analytics, and eliminate over 700 application/database servers. NOBLE FoS will deploy to the Consolidated Afloat Networks and Enterprise Services (CANES) afloat, Non-CANES platforms, Department of the Navy (DON) commercial cloud computing environments ashore, and US Marine Corps operating environments. The Logistics Integrated Data environment (L-IDE) will provide the single enterprise Logistics and Sustainment information domain data environment across Echelon II/ III Navy System Commands to support Department of Navy (DON) Chief Information Officer (CIO) data strategy, architecture, and integration with DoD and DON level enterprise data environments in support of mission commanders, warfighters, decision makers, and mission partners.$$, 33653000, NULL, NULL, NULL, NULL, 364473000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604231N_3324$$, $$0604231N$$, $$3324$$, $$Navy Air Operations Command and$$, 719000, $$Navy Air Operations Command and Control (NAOC2): NAOC2 tests and integrates U.S. Air Force program of record systems - Theater Battle Management Core System (TBMCS) and its replacement Kessel Run Applications Kit for Enterprise Navy (KRAKEN) which provides an integrated and scalable planning system for standardized, secure, and automated decision support for Air Force, Joint, and Allied commanders worldwide - to operate in the Navy enterprise network environment such as Consolidated Afloat Networks and Enterprise Services (CANES). These programs provide automated air operations planning, execution management and intelligence capabilities for fleet commanders, Commander Carrier Strike Groups, Commander Expeditionary Strike Groups, Commander Landing Forces, and Joint Task Force Commanders. KRAKEN (when fielded) will provide rapid, agile delivery of capabilities to the fleet by commercial cloud infrastructure using Development, Security, Operations (DevSecOps) cloud native applications. KRAKEN is comprised of multiple tactical software applications that will provide continuous iterate delivery of software to shipboard and shore users. It will also align with the Joint C2 Reference Architecture (JC2RA) such as CANES. KRAKEN is not natively compatible with Navy Information Technology (IT) infrastructure, such as CANES, and requires a significant level of system integration. Continuation of Navy integration and test efforts will significantly enhance the ability of the Joint Force Air Component Commander and Combined Air Operations Center personnel to plan daily air operations including strike, airlift, offensive/defensive air, missile defense, and refueling missions in support of combat operations. Developmental Testing is continuous and operates in parallel with the DevSecOps construct. KRAKEN will be continued for new technology insertion into Navy infrastructure network and software in support of Naval Air C2 and Net Enabled Weapons system integration. KRAKEN addresses the requirement of warfighter distributed planning and execution processes along with significantly improving Joint interoperability. TBMCS continues a hardware transition to CANES. Currently, TBMCS is the key system that is used to conduct real world air planning in the Joint and Navy environments. KRAKEN will replace TBMCS while bringing more flexibility to the war fighter. FY26 funding supports KRAKEN integration and development of Kubernetes based containers from the United States Air Force (USAF) into the CANES environment, with the development of the Commander Operational Test & Evaluation Force (COMOPTEVFOR), USAF, and Air Force Operational Test and Evaluation Center (AFOTEC) joint testing and certification. FY26 funding also supports, writing automated functional evaluation tests to validate Navy requirements and automate the process of integrating the containers to work with the CANES Agile Core Services (ACS) authentication and service mesh architecture.$$, 719000, NULL, NULL, NULL, NULL, 18404000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604231N_9123$$, $$0604231N$$, $$9123$$, $$FORCEnet$$, 2163000, $$FORCEnet Funding supports IW Portfolio Health Assessments (PHAs) of Navy mission areas and identifies gaps in Information Warfare (IW) capabilities in the context of assessed mission areas. Funding supports vignettes, technical baselines, architecture products, and briefings developed to support sponsor decision making processes.$$, 2163000, NULL, NULL, NULL, NULL, 252500000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604233F_674101$$, $$0604233F$$, $$674101$$, $$Undergraduate Remotely Piloted$$, 2782000, $$This effort supports Air Education and Training Command's (AETC) implementation of Undergraduate Remotely Piloted Aircraft (RPA) Training (URT). URT produces RPA pilots and Sensor Operators from accession sources to man RPA squadrons. Success of the program is heavily dependent on multiple training systems to prepare undergraduate students for entry in RPA Formal Training Units (FTU). 19AF/CC approved a significant system upgrade along with a change in software. This change allowed for a more flexible and adaptable training system that can carry URT into the future. Funding will be used to develop organic software capabilities, update obsolete equipment, and develop new training tools. The goal of these changes is to build a more capable set of training systems focused on reducing costs while ensuring RPA training is ready to support the National Defense Strategy from today into tomorrow. Funds may be used to address emerging and short-notice Diminishing Manufacturing Sources and Material Shortage (DMSMS) issues. Diminishing Manufacturing Sources efforts include removal of end-of-life software/hardware within simulators systems and move to a modular, common open system architecture that is sustainable and cyber-resilient. Implementation requirements and standards are defined under the Simulator Common Architecture Requirements and Standards (SCARS) initiative. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program elements 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0.143 million was expended for civilian pay expenses in this program element, and in FY 2025 $0.144 million is forecast for civilian pay expenses in this program element.$$, 2782000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604233F_676037$$, $$0604233F$$, $$676037$$, $$T-38 Operational System$$, 147000, $$The T-38 RDT&E budget is focused on modifications needed to overcome Diminishing Manufacturing Sources & Material Shortages (DMSMS), of aging of critical components, emerging safety concerns, and cybersecurity risks. Operational Flight Program (OFP) block upgrades incorporate software improvements for the aircraft and aircrew training devices (ATDs) to address flight safety issues, and to comply with new capabilities mandated by Department of Defense, Federal Aviation Administration, or National Airspace System. RDT&E includes but is not limited to the following: Terminal Avionics Replacement Program (TARP). F3I components requiring RDT&E include, but are not limited to, the Electronic Engine Display (EED), Multi-Function Display (MFD), Video Data Transfer Unit (VDTU), and Head-Up Display Camera (HUDC). Failure to fund these efforts will result in fleet-wide T-38C non-serviceability starting in Apr 2026. Canopy Open Warning (COW) is a safety modification to the T-38C and is currently in development and will provide an aural warning to the pilot(s) that the canopy is unsecure prior to and during flight. This modification will be incorporated into the aircraft concurrent with the HUDC and VDTU development and installation. Low-cost Avionics Modernization Program (LAMP I) is complete as of FY24 and was required to develop, integrate, and replace the Attitude Director Indicator (ADI), Horizontal Situation Indicator (HSI). LAMP I may also require a follow-on contract for the replacement of the Attitude Gyro Control Assembly, Rate Switching Gyro, Rate Gyro Transmitter, Servo-Amplifier, and Flight Director Computer for the T-38A/AT-38B. This effort will require both RDT&E and procurement funds to mitigate ongoing component failures and meet operational needs. The T-38 Studies and Development effort captures ongoing and emerging RDT&E requirements, to include budget for flight test, OFP updates, and emerging obsolescence or safety issues. Additional revisions may occur under this effort. Failure to fund these efforts will prevent the T-38 program from rapidly responding to emerging RDT&E requirements. Current requirements include but are not limited to, Block Upgrades, T-38A/B/C Electronic Flight Bag DC Power Supply, T-38A/B/C Beacon Light Assembly, T-38A/B/C Landing Taxi Light Assembly, T-38C Emergency Locator Transmitter, T-38A/B Control of Both Radios, Flight Director Computer, and T-38C 5G Band Pass Filter. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F,$$, 147000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604234N_3051$$, $$0604234N$$, $$3051$$, $$E-2D Adv Hawkeye$$, 350324000, $$The DSSC build schedule is outlined below along with the capabilities that are planned to comprise each DSSC build. 1. DSSC-5.1 will provide a Counter Electronic Attack (CEA) capability which will allow the E-2D radar system to maintain performance in an advanced hostile intentional electromagnetic interference environment. CEA will ensure continuous E-2D effectiveness is maintained in an Electronic Attack environment supporting the Navy Integrated Fire Control (NIFC) capability and overall Navy and Joint Integrated Air and Missile Defense strategy. 2. DSSC-5.1 and 5.2 will provide phased E-2D Data Fusion Improvements for a fusion engine to blend on and off-board sensor derived track data (e.g. Electronic Surveillance, Satellite Receiver System data, Fighter to Fighter backlink data) with already blended radar, Identify Friend or Foe and Cooperative Engagement Capability track files, enhancing situational awareness and tactical decision making. Integrating Link-16 Network Participation Group 20 messages improves interoperability between E-2D and participating US Navy fighters, including 5th generation aircraft. This enhances the combat effectiveness of the E-2D, increases situational awareness and shortens kill-chain timeliness (including NIFC). Successful E-2D NIFC employment depends on a clear/unambiguous tactical picture. 3. DSSC-5.2 provides phased E-2D Cooperative Engagement Capability (CEC) Signal Data Processor (SDP) processing capacity and cryptographic upgrades required to implement the NIFC capabilities integrated into DSSC-5. CEC utilizes the SDP to encrypt tactical data and control the antenna during transmission of the data. This capability will correct obsolescence deficiencies based on processors, encryption, and capacity and establish the baseline architecture for expanded capability in CEC. The fully integrated E-2D Communication-as-a-Service (CaaS) will enhance CEC improvements to ensure resilient communication paths for tactical information throughout the battlespace. CEC Block II capabilities will ensure continued interoperability with the rest of the carrier strike groups and enable new CEC capabilities necessary to counter expected advances in threat capabilities. Initial integration of CEC Block II capabilities must be conducted on time to maintain interoperability and keep pace with expected threats. 4. DSSC-5.1 and 5.2 will provide phased E-2D Sensor Netting capabilities which provide fusion of data from off-board sources via a high bandwidth network that will allow E-2D to support NIFC increment 3 requirements. Additional details are classified. 1. E-2D Hawkeye Cockpit Technical Refresh (HECTR) involves a redesign of critical components of the current E-2D Integrated Navigation Control and Display System (INCDS) driven by component obsolescence and fleet identified deficiencies. The effort includes the integration of these components with remaining cockpit hardware, integration of new software applications, and integration with Theater Combat Identification (TCID) weapon system architecture. HECTR will bring a Required Navigation Performance Area Navigation (RNP RNAV) capability to the E-2D platform, to improve reliability, to address current human machine interface (HMI) deficiencies and to address obsolescence of the current cockpit. All current functions of the INCDS will be included in the HECTR cockpit, to include unique non-navigation functions such as landing gear and gross take-off weight, which are currently housed in the Avionics Flight Management Computer.$$, 350324000, NULL, NULL, NULL, NULL, 6530598000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604234N_9999$$, $$0604234N$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional Add. The E-2D Advanced Hawkeye and associated APY-9 radar meet the requirements specified in the Capabilities Development Document (CDD), including detection ranges, detection velocities, and tracking accuracies, verified through extensive developmental and operational flight testing and deployed operations. Program increase for E-2D advanced radar development to stay ahead of the evolving threat.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604245M_3359$$, $$0604245M$$, $$3359$$, $$H-1 Improvements$$, 62240000, $$The objective of H-1 Improvements is to provide follow-on Research, Development, Test and Evaluation efforts in support of all H-1 aircraft. Air Vehicle and Engine improvements include analysis of structural data to formulate Damage Limits and Tolerances for structural components in order to reduce life cycle costs and maintenance workload; development and test of structural components. These improvements include tail boom, fuselage, and airframe components, minimizing excessive and premature wear, increased reliability, decreased component fatigue and improve existing design deficiencies. Air Vehicle aircraft components will develop solutions to develop an auxiliary fuel cell capability and Rotocraft Station Control Unit (RSCU) Software development. RSCU efforts will encompass software development, testing, cybersecurity, and acquisition of test assets. All air vehicle and engine improvements include related Software Configuration Set (SCS) development updates and address hazard reports including software, test assets, cybersecurity, and testing. Avionics improvements target digital inter-operability, integrated avionics, safety and survivability, and situational awareness for both the pilot and aircrew safety. This includes Degraded Visual Environment (DVE), cockpit displays, precision and Global Positioning System (GPS) non-precision landing capability, collision avoidance, improved Embedded Global Positioning System (EGI), Radar Altimeter (RADALT), Inertial Navigation System (INS), Health and Monitoring System Upgrade (HMU), and mission computer software development. H-1 capability improvements include improved digital operations and transfer of data, digital interoperability, digital video recording, video and data networking, and information integration with aviation combat elements and Marine Air Ground Task Force elements. Mandated capability efforts include - Communications and COMSEC modernization to include Tactical Secure Voice/Second generation Anti-Jam Tactical Ultra-High frequency Radio for NATO (TSV/SATURN), Navigation and Surveillance system/Air Traffic Management (CNS/ ATM), Required Navigation Performance/ Area Navigation (RNP/RNAV), Automatic Dependent Surveillance - Broadcast (ADS-B), Crash Survivable Flight Incident Recorder and information technology/protection of the platform. Mobile User Objective System (MUOS) allows the H-1 to retain satellite communication capabilities. Efforts include the integration and test of Beyond Line of Sight (BLOS) satellite systems. Digital Interoperability (DI), the expansion of DI to include integration of Adaptive Network Wideband Waveform (ANW-2), Net enables weapons control, Integrated Aircraft Survivability Equipment (iASE), leveraging Proliferated Low Earth Orbit (pLEO) communications, advanced Flite Scene mapping and mission planning updates shortens the kill chain and improves information and intelligence sharing on the battlefield. DI incorporates a family of systems that includes ANW-2, Advanced Data Transfer System (ADTS), Full Motion Video (FMV), Radio Frequency Identification (RFID), Small Tactical Terminal (STT), and Cross Domain Solution (CDS). Improvements to address hazard reports against avionic platform systems which may include attitude trim performance, flight control systems performance, communication and navigation systems performance, data link and waveform systems performance, display and recorder systems performance, and aircraft health data system performance. All avionics improvements include related SCS development updates and address hazard reports including software, test assets, cybersecurity, and testing. Sensors, Weapons, Aircraft Survivability Equipment (ASE), and Helmet Mounted Display System improvements include manufacturing process improvements, hardware and software redesign to improve reliability, improve production methodologies, implement program security initiatives and increase the collective capability to address emerging battlefield threats. These improvements address reliability and obsolescence. The technical interfaces between the aircraft sensor, helmet, and weapons$$, 62240000, NULL, NULL, NULL, NULL, 260599000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604250D8Z_250$$, $$0604250D8Z$$, $$250$$, $$Advanced Innovative Technologies$$, 749452000, $$The Strategic Capabilities Office (SCO) develops, demonstrates, and transitions operationally impactful capabilities and effects to shape and counter emerging threats and increase the lethality of the Joint Force in contested environments. The SCO combines innovation with concepts of operation and information management to develop novel capabilities solving critical national security challenges in partnership with the Services, Defense Agencies, Combatant Commands (CCMDS), Joint Chiefs of Staff, Intelligence Community, and the Office of the Secretary of Defense (OSD). SCO's FY 2026 Pacific Deterrence Initiative (PDI) spending under Exercises, Training, Experimentation, and Innovation includes $639.296 million discretionary and $167.000 million mandatory for a total of $806.296, an increase of $150.786 million from FY 2025, with five new capability projects transitioning into Execution in FY 2026.$$, 749452000, NULL, NULL, NULL, NULL, 7712804000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604256A_976$$, $$0604256A$$, $$976$$, $$Army Threat Sim (ATS)$$, 74767000, $$This Project supports the design, development, acquisition, integration, and fielding of realistic mobile threat simulators and realistic threat simulation products utilized in Army/Department of Defense test and evaluation and developmental and operational tests. This Project originally funded simulators representing Soviet equipment, but scope was expanded to address emerging world threats. Army Threat Simulator and Threat Simulation products are utilized to simulate operational environments and populate test battlefields for the United States Army Test and Evaluation Command, to conduct developmental and operational tests, and to support Program Executive Office for Simulation, Training and Instrumentation required user testing in System Integration Laboratories and hardware/simulation in-the-loop facilities. These operational environment and battlefield simulators represent adversary systems (e.g. intelligence, surveillance and reconnaissance, missile systems, command, control and communication systems, electronic warfare systems, etc.) in order to portray a realistic full-spectrum threat environment during testing of U.S. weapon systems. Base funding will establish enterprise level business processes and services to develop, operate, and secure air and ground testing capabilities in accordance with OSD and Army Digital Engineering and Software Modernization Strategies. Efforts will promote synergies between the training and testing enablers to improve product development, integration, and cyber activities, and to promote re-use of common assets and services to meet Army modernization priorities. Information and Decision Advantage Threat Simulation: Supports Army's capability and capacity to provide realistic information dimension threat representative across the conflict continuum. Threat realism focuses on the adversary's ability to sense, collect, analyze and act upon Army critical information or critical program information. Army Threat Simulator and Threat Simulation products developed or fielded under this Project support Army-wide, non-system-specific threat product requirements. Each capability is pursued in concert and coordination with existing Army/DoD and Tri-Service capabilities to eliminate duplication of effort. Simulator development is responsive to Office of the Secretary of Defense and Government Accountability Office guidance for the Army to conduct operational testing in a realistic threat environment. Actual threat equipment is acquired when appropriate (in lieu of development) and total package fielding is still required (i.e., instrumentation, operations and maintenance, manuals, new equipment training, etc.) Threat simulator development is accomplished under the auspices of the Project Manager for Cyber Test and Training and the Director, Operational Test and Evaluation Threat Simulator Investment Working Group.$$, 74767000, NULL, NULL, NULL, NULL, 71587000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604256F_662907$$, $$0604256F$$, $$662907$$, $$Electronic Combat Intel Support$$, 2994000, $$This project provides funding to support Foreign Materiel Operational Test and Evaluation (FMOT&E), which ensures the ability of operational commands to test and develop effective Electronic Attack/Electronic Protection (EA/EP) techniques and tactics. Funds are required for: deployment of systems to test facilities; travel of personnel to the test sites to evaluate and validate test results; range and laboratory costs; test consumables; costs for instrumentation of systems; and contracted engineering support for the conduct of tests and subsequent reporting. Funding for this program is required to prevent future aircraft losses due to improper and inaccurate aircrew tactics (e.g., lack of evasive action or proper tactics training to avoid missile attacks). This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, 2994000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604264N_9099$$, $$0604264N$$, $$9099$$, $$Physiological Episodes$$, 4060000, $$Physiological Episodes includes Physiological Monitoring (PhysMon) and Helmet Mask Regulator (HMR). PhysMon: This program provides funding to aircrew performance by developing and fielding a system that monitors aircrew physiological and cognitive parameters and warns of state of health or performance degradation that may result in loss of the ability to safely conduct flight. HMR: Improved helmets, masks, and regulators are required to mitigate physiological episodes. This program determines what improvements are needed and develops the material solution. The closeout of RCCA action items is paramount to the Naval Aviation Enterprise's efforts in mitigating physiological episodes, restoring confidence in the aircraft, and most importantly, keeping our USN and USMC aircrew safe.$$, 4060000, NULL, NULL, NULL, NULL, 12131000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604256F_663321$$, $$0604256F$$, $$663321$$, $$Electronic Warfare Ground Test$$, 27910000, $$The AF requires a comprehensive set of test facility modernizations to improve Electronic Warfare (EW) which includes Directed Energy (DE) weapons Test and Evaluation (T&E) capabilities. This funding is used to improve and modernize threat system simulators, stimulators, emitters and supporting infrastructure to sufficiently and cost effectively test and evaluate current and future weapon systems' ability to perform in realistic EW threat representative environments. The National Radar Cross Section (RCS) Test Facility (NRTF) at Holloman AFB, NM, provides timely, accurate, and secure RCS and antenna measurements for tri-service and joint program offices, DoD laboratories, Defense Advanced Research Projects Agency (DARPA) and industry. The NRTF tests fielded and developmental systems and technologies to meet Low Observable (LO) and EW customer requirements. The Guided Weapons Evaluation Facility (GWEF) at Eglin AFB, FL, and the Digital Integrated Air Defense System (DIADS) at Edwards AFB, CA, provide the ability to realistically evaluate hardware and software components of US weapon systems against manned hardware threat representations throughout the acquisition process. The GWEF provides simulations of advanced Infrared (IR) Surface-to-Air Missiles (SAMs) and Air-to-Air Missiles (AAMs), IR and Laser countermeasure functions, and the integration of actual threat hardware and ground clutter into advanced threat IR missile simulations. DIADS provides mission level simulations of both algorithm-based and man-in-the-loop-based enemy command and control (C2) capabilities that integrate early warning radar detection, SAM engagement capabilities, and limited ground-controlled fighter intercepts. The Benefield Anechoic Facility (BAF) at Edwards AFB, CA, and the Joint Preflight Integration of Munitions and Electronic Systems (J-PRIMES) facility at Eglin AFB, FL, both provide threat-representative EW emitters and stimulators to replicate a variety of land, sea and airborne threats in a controlled RF environment to evaluate full-scale weapon systems. The BAF additionally provides an ability to perform Electromagnetic Interference/Compatibility (EMI/EMC) testing to ensure radars, jammers, radios, and other flight-critical electronic systems will not interfere with each other during a mission. The Central Inertial and GPS Test Facility (CIGTF) at the 704th Test Group at Holloman AFB, NM provides threat-representative GPS jammers and laydowns in both lab and open-air environments to test avionics systems' performance when under various GPS-denial conditions. Provides EW test process support, conducting requirements analyses and other studies in support of AF T&E investments in test infrastructure and capabilities. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, 27910000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604256F_667500$$, $$0604256F$$, $$667500$$, $$Foreign Materiel Acquisition/$$, 10221000, $$This project's specific purpose is to support DAF Foreign Materiel Program requirements through the acquisition and analysis of foreign materiel. Due to the unique capabilities of the DAF FMP, both USAF and USSF work cooperatively to support DAF FMP requirements. Items considered for these Foreign Materiel Acquisition (FMA) funds are included in the prioritized Service's FMA Top 50 list established each year. Annually, the MAJCOM and Field Commands create integrated prioritized lists of their top 50 requirements. The requirements lists are integrated and prioritized into a classified Service requirement list. System analyses are based on and driven by acquisitions. The DAF FMP provides assessments and data for threat systems to all DoD components. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, 10221000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604256N_0602$$, $$0604256N$$, $$0602$$, $$Electronics W/F Env Simulation$$, 17026000, $$The objective of this project is development of necessary simulation facilities and approaches to allow determination of the effectiveness of Electronic Warfare (EW) in real world engagement situations and to support the introduction of modern, effective EW systems into Naval Aviation platforms. The heavy use of test resources by all Services demonstrates the importance of these assets. The Electronic Warfare Environment Simulation project is unique because it is the only program within the Department of Defense which develops and provides Naval anti-air warfare threat assets for Test and Evaluation (T&E). This project directly supports the T&E resource requirements for all Naval Air EW development programs, to include radio frequency situational awareness and countermeasures. Programs in development and future programs include: Joint Strike Fighter, EA-18G, Low Band Transmitter, Next Generation Jammer, Advanced Anti-Radiation Guided Missile (AARGM), Long Range Anti-Ship Missile (LRASM). This project provides for the development of an Integrated Air Defense T&E capability to be fielded at each of the three sites comprising the Navy's Tri-Center complex: Naval Air Warfare Center Weapons Division, China Lake and Point Mugu in CA, and Naval Air Warfare Center Aircraft Division, Patuxent River, MD.$$, 17026000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604256N_0672$$, $$0604256N$$, $$0672$$, $$Effect Nav E/W (ENEWS)$$, 8107000, $$The objective of the Effectiveness of Naval Electronic Warfare (EW) Systems (ENEWS) project is the development, maintenance, upgrade and application of critical simulation assets to determine the effectiveness of Electronic Warfare (EW) for the surface Navy in simulated real-world engagement scenarios. ENEWS provides the Surface Navy with Anti-Ship Missile (ASM) simulators, Modeling and Simulation (M&S) and state-of-the-art evaluation facilities to support the introduction of modern, effective shipboard and off-board EW systems and tactics for EW Programs of Record (POR). ENEWS develops, maintains, and operates hardware simulators, digital simulations (M&S) of legacy, modern, and advanced threat ASMs that provide EW PORs an integrated simulation capability through at-sea captive carry field trials with flyable simulators, digital ASM models, and the Central Target Simulator (CTS) hardware-in-the-loop evaluation facility. The reliance of ENEWS assets by the Naval Sea Systems Command, Commander, Operational Test and Evaluation Force (COMOPTEVFOR), Office of Naval Research (ONR), and other EW Research, Development, Test and Evaluation (T&E) agencies speaks to the overall importance of this project. The project provides support and effectiveness evaluations for EW system designs, Engineering Test (ET), Development Test (DT), Operational Test (OT) events including the development and utilization of techniques and tactics. In the past, ENEWS quick reaction capabilities have provided significant support and solutions in crisis situations such as the Libyan crises, Iran threat, Persian Gulf crisis, Operation Desert Shield/Storm, the ongoing Ukrainian Crisis in the Black Sea, and the crisis in the Red Sea. Simulation Display (SIMDIS) is a modeling tool developed under the ENEWS project to support visualization of test events. SIMDIS has been adopted by most Department of Defense (DoD) T&E ranges as an effective tool that provides two and three dimensional graphical and video displays of live and post-test event data for EW T&E. One of the primary threats to surface ships is ASM systems. The ENEWS project is unique in that it is the only project within DoD dedicated to developing and providing realistic ASM assets to test and evaluate the effectiveness of shipboard EW systems and tactics against these types of threats. The ENEWS project is a critical part of the Office of the Secretary of Defense Test Resource Master Plan. This plan employs many ENEWS assets for planning, analysis, testing, and verification of shipboard and off-board EW techniques and tactics. As part of its normal activities, ENEWS provides Development Test and Evaluation (DT&E), Operational Test and Evaluation (OT&E), and Follow-on Operational Test and Evaluation (FOT&E) support to the surface Navy for all ship classes. ENEWS provides support to multiple surface Navy programs including Surface Electronic Warfare Improvement Program (SEWIP), Advanced-Offboard Electronic Warfare (AOEW), Nulka, Long Endurance Electronic Decoy (LEED), Scaled Onboard Electronic Attack (SOEA), advanced Infrared (IR) decoys, decoy placement, ship Infrared signature and radar cross section measurements for surface combatants and other ship self-defense initiatives, including the Future Naval Capability process. In addition, ENEWS assets support effectiveness evaluations for North Atlantic Treaty Organization (NATO) ships' EW systems in joint allied exercises and joint EW exercises such as Rim of the Pacific (RIMPAC) and Northern Edge test events.$$, 8107000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604257F_642001$$, $$0604257F$$, $$642001$$, $$Next Gen Sensors Tech$$, 29924000, $$The NGS-RR program is a platform-agile suite of sensor development and demonstration technologies designed for the best flexibility and capability for an ever- changing scale of ISR missions. NGS-RR furthers maturation and risk reduction of select technologies initiated under I&TS and other low TRL maturation efforts culminating in operational prototype demonstrations. The power behind the NGS-RR program is an open architectural system design that enables rapid third- party software and line replaceable unit insertion/replacement. NGS-RR implements foundational sensor development technologies including the MEDUSA flight demonstration platform, Digital Engineering (DE), Model-Based Systems Engineering (MBSE), and a software environment and repository (AURORA). In FY 2026, NGS-RR will continue flight tests of fully integrated podded payloads, integration of maturation of NAVAIR and other maritime automated target recognition algorithms and support collaborative teaming demonstrations. Demonstrations include, but are not limited to, capabilities developed with funding in the I&TS BPAC, Airborne SIGINT Enterprise PE (0304260F), and Airborne Reconnaissance Systems PE (0305296F). Additionally, RESOLUTE SENTRY will transition from the AF Research Laboratory to NGS-RR for technical maturation and integration into the first operational platform in FY 2026. RESOLUTE SENTRY is an AI-driven, multi-platform, sense-making tool for predictive analytics and orchestration at the tactical edge. It provides real-time, high-quality detection, identification and tracking to close kill chains and predict adversary activity. The program delivers a platform-agnostic, edge-hostable software solution to ingest and fuse multi-INT data across multiple platforms at the tactical edge. The data will then be used to generate actionable information on the highly contested environment for Blue Force commanders and national decision making. RESOLUTE SENTRY will execute in this PE from FY26 to FY27, then will transition to ARS PE 35206F in FY28. R3 and R4 data will be updated upon award of the follow-on contract. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 0.000M was expended for civilian pay expenses in this program element, and in FY 2025 0.000M is forecast for civilian pay expenses in this program element.$$, 29924000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604269N_3063$$, $$0604269N$$, $$3063$$, $$EA-18G Development$$, 184921000, $$The EA-18G development program upgrades the Airborne Electronic Attack (AEA) capability to detect, identify, locate and suppress hostile emitters; provides enhanced connectivity to National, Theater and Strike assets; and provides passive organic precision emitter targeting for employment of precision strike weapons and onboard suppression weapons (High-speed Anti-Radiation Missile family) to fulfill operational requirements. The EA-18G is the only tactical AEA platform for the joint force and is continually called upon to provide effects for USN, USMC, and USAF assets. There is no planned replacement for the EA-18G and improvements will fill capability gaps for the Air Wing of the Future North Star effort.$$, 184921000, NULL, NULL, NULL, NULL, 2660894000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605502N_3201$$, $$0605502N$$, $$3201$$, $$SBIR CRP - NAVAIR$$, 0, $$Originally established in Section 252 of the 2006 NDAA Public Law No. 109-163, the Commercialization Readiness Program (CRP) may not use more than up to 1% of the SBIR to be used for payment of expenses incurred to administer CRP. 15 USC 638(y) authorizes the DoD to administer a Commercialization Readiness Program to accelerate the transition of SBIR/STTR-developed technologies, products, and services to Phase III, including the acquisition process.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604257F_644818$$, $$0604257F$$, $$644818$$, $$Imaging and Targeting Support$$, 10855000, $$In FY 2026, I&TS plans to transition 3 projects (GMTI mode, AIR, RUBBER DUCKIE) to an OAFP, complete development of 2 FY24 projects (BB8, Collaborative Teaming), continue development of 1 FY25 project (ATRIUM) and begin 5 new projects approved by the GCWG in June 2025. Details of the GMTI mode, AIR, RUBBER DUCKIE, BB8, Collaborative Teaming, and ATRIUM projects were provided to Congress previously and are available upon request at the appropriate classification levels. Due to delays in the President's Budget submission, the ATS team can provide the detailed information on FY 2026 projects below. Additional information is available upon request at the appropriate classification levels. Cost and schedule information (R3 and R4) will be updated upon contract award. For FY 2026, the GCWG Focus Area included: 1. Find, Fix, and Track Group 1-3 UASs. 2. Improve surveillance and reconnaissance (e.g. longer range, greater accuracy, etc.) through cooperative or networked sensors and software. 3. Develop low Size, Weight, Power, and Cost (SWAP-C) scalable multi-INT sensors for small attritable or expendable UASs demonstrated in an autonomy package for leading edge swarms. The projects planned to initiate in the FY 2026 include: • AIR for SAR: Extends the FY 2024 Automatic Image Registration (AIR) capability to support Synthetic Aperture Radar (SAR) for an OAFP. • TALON CEREBRAL: Develop a collaborative, multiple-intelligence, evidence-based target identification tool that generates human-readable information to include measurements, target descriptions, and evidence. • ABBA: Integrates the previously developed BirdBox capability with Big Iron within the Agile Mission Suite (AMS) Government Reference Architecture to provide a flight ready, rapidly deployable multi-modality sensor exploitation system for multiple OAFPs • RESOLUTE MINIONS: Develops an airborne, multi-intelligence capability to detection, identify, and track group 1-3 UASs. • Frontline Perception System: Develops localized mesh networking and data orchestration to enable fusion on small UAS swarms in communication denied environments. Includes multimodal ATRs for swarm platforms and on-board processing for airborne platforms to maintain target custody. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024, 0.000 was expended for civilian pay expenses in this program element, and in FY 2025 0.000 is forecast for civilian pay expenses in this program element.$$, 10855000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604258A_238$$, $$0604258A$$, $$238$$, $$Aerial Targets$$, 12463000, $$This Project supports Army readiness and Multi-Domain Operations through the development, acquisition, operation, and modernization of aerial targets. Multi-spectral Aerial Targets include realistic surrogates, actual high-performance threat aircraft, and virtual target computer models. Current and emerging weapons systems require test, evaluation, and training using threat-representative aerial targets to assess weapons system's effectiveness in the operational environment. This project encompasses a portfolio of full-scale, miniature, and subscale fixed-wing/rotary-wing targets, virtual targets, ancillary devices, and associated control systems. For accurate threat portrayal that properly stresses weapons systems during test and evaluation, aerial targets must exhibit flight characteristics, threat signatures, and other performance factors to represent or emulate relevant and validated threats. This Project funds: the long-range planning necessary to determine future target needs and development of coordinated requirements; the management of target research, development, test and evaluation, production, and modernization; execution of the validation process to ensure that aerial targets accurately represent the threat; as well as storage and repair parts. The Army is the Test Enterprise Reliance lead for Rotary Wing Targets and Towed Target development.$$, 12463000, NULL, NULL, NULL, NULL, 30613000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604258A_459$$, $$0604258A$$, $$459$$, $$Ground Targets$$, 3541000, $$This Project funds Army efforts to support the test and evaluation (T&E) of advanced weapon systems and supports Army Modernization, Multi-Domain Operations, and Tri-Service readiness by developing ground target surrogates, acquiring foreign equipment, and developing virtual target computer models of ground vehicle targets. These products are required to adequately stress weapon systems undergoing T&E. The United States Army is the Tri-Service lead for providing mobile ground targets for T&E. This tasking includes long-range planning to determine future target needs and development of coordinated requirement documents; the centralized management of the ground target research, development, test and evaluation processes; execution of the validation process; acquisition of foreign equipment; and continuing maintenance, storage, and development/enhancement/update via engineering services of developed and acquired targets to ensure availability for T&E customers. This project also manages the use of current assets and operates a centralized spare parts program.$$, 3541000, NULL, NULL, NULL, NULL, 3327000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604258N_0609$$, $$0604258N$$, $$0609$$, $$Aerial Target System Dev$$, 10912000, $$The Aerial Target Systems Development program designs and develops threat representative subsonic and supersonic targets and associated payloads to emulate threat weapon systems and aircraft. In addition to representative air vehicles, this includes development of Target Control (TC) systems and associated Target Augmentation and Auxiliary Systems (TA/AS) which are used to replicate specific threats. Targets and auxiliary payloads are developed to support test and evaluation of combat systems required to defend fleet surface and air units in a hostile environment. As to specific hardware development, this project includes: - Supersonic Targets: Portfolio includes GQM-163A Supersonic Sea-Skimming Target (SSST) and AQM-88 Supersonic Air Launch Target (SALT) programs. Supersonic targets represent supersonic anti-ship cruise missile threats. The design and development of GQM-163A capabilities provide threat representative targets that are used in direct support of Developmental Test and Evaluation, Operational Test and Evaluation, and Live Fire Test and Evaluation of major combat weapons programs and support fleet training. Critical live-fire Test and Evaluation events are supported for AEGIS CG and DDG Mods, DDG-51 Flight III, LHA 8, CVN-79 LPD Flight II, SM-6, SM-2, RAM, and ESSM. The GQM-163A is a non-recoverable supersonic sea skimming aerial target, capable of speeds in excess of Mach 2.5 and cruise altitudes from 13.0 to 52K feet. The GQM-163A has also demonstrated higher altitude diving threat profiles. Funding may also be used to begin development of potential future supersonic targets to keep pace with emerging threats. - Subsonic Targets: Portfolio includes BQM-177A, BQM-34S and BQM-167 subsonic target programs. The BQM-177A SSAT primarily represents subsonic anti-ship cruise missile threats. The BQM-177A SSAT provides threat representation for developmental and operational test & evaluation events of major combat weapons systems programs and in support of fleet training events. Specifically, the BQM-177A SSAT provides critical live-fire test and evaluation events for AEGIS CG and DDG Mods, DDG-51 Flight III, CVN-79, LHA-8, LPD Flight II, JSF, E-2D, SM-6, SM-2, RAM, and ESSM. BQM-34S are undergoing product improvement program efforts to address component obsolescence and improve current performance to meet evolving requirements. The BQM-167A is utilized by operational aviation squadrons that participate in Navy Weapon System Evaluation Program (NWSEP) at Tyndall Air Force Base, FL. NWSEP is the traditional mechanism for aviation squadrons to accomplish Training and Readiness (T&R) requirements provided by Non-Combat Expenditure Allocation (NCEA) of air-to-air weapons as part of Fleet Readiness Plans (FRP) prior to deployment. - Target Augmentation and Auxiliary Systems (TA/AS): Includes Target Threat Simulation Program (TTSP), Target Mission Support Systems (TMSS), and Target Control (TC). The TTSP portfolio provides the payload equipment required to electronically enhance aerial targets to provide threat representative radio frequency signatures, specifically the electronic attack and threat radar emissions (active emitters). Development of threat representative simulation components is on-going and required to keep pace with evolving threats and ensure that the Navy's threat simulation capabilities remain relevant against emerging threats. TC provides command and control of targets to enable the safe execution of threat-representative mission profiles. TA/AS also includes the design, development and qualification of various TMSS projects including but not limited to: Target RF datalink hardware, ground control hardware and software, scorer transponders, scoring ground stations, telemetry antennas, radar and locator beacons, identification, friend or foe transponders, and associated test sets. TA/AS enables each target to be uniquely$$, 10912000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604258N_0612$$, $$0604258N$$, $$0612$$, $$Surface Targets Development$$, 1497000, $$This project develops seaborne targets and their related target augmentation systems in support of air-to-surface and surface-to-surface weapons test and evaluation and fleet training.$$, 1497000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604258N_2159$$, $$0604258N$$, $$2159$$, $$ASW TARGET$$, 1782000, $$RDT&E,N Budget provides funding for multiple lines of improvement across the Navy's portfolio of reusable and expendable undersea warfare targets. 1. Provides funding for sprint speed and frequency expansion to improve performance capability for the MK 39 Mod 3 Expendable Mobile ASW Training Target (EMATT). This effortsupports the transition of the Sprint Speed and Low Frequency Improvement into MK 39 Mod 3 EMATT production and starts to investigate Continuous Active Sonar (CAS) capability to provide better detection performance and provide operators with a continuous track. Sprint Speed and Frequency Expansion upgrade allows EMATT to more closely represent submarine tactics for evasion and will make it compatible with new ASW sensors like the FFG Constellation Class Variable Depth Sonar. 2. Provides funding for a Long Endurance Variant of MK 39 Mod 3 Expendable Mobile ASW Training Target (EMATT) to support 24+ hour missions. This effort supports development of Long Endurance module for the MK 39 Mod 3 EMATT. The Long Endurance module will allow the EMATT to support training of multiple aircrews in a single, coordinated extended tracking exercise and facilitate the training of multiple watch sections on surface ships and submarines in an extended tracking exercise. 3. Provides funding for a Low Frequency Variant of MK 39 Mod 3 Expendable Mobile ASW Training Target (EMATT) to support narrowband tracking requirements for USN submarines. This effort supports the development of a Low Frequency module for the MK 39 Mod 3 EMATT. The Low Frequency Variant upgrade allows EMATT to better emulate low frequency signatures of modern threat submarines. 4. Provides funding for MK66 Heavweight USW Training Target (HUTT) [MK30 ASW Target Replacement]. This effort supports non-recurring engineering efforts associated with the new MK66 HUTT production and develops performance improvements and peculiar support equipment modifications to support integration of the target with existing range support equipment.$$, 1782000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604270A_CR8$$, $$0604270A$$, $$CR8$$, $$Army Reprogramming Analysis Team$$, NULL, $$Current military operations are conducted in a rapidly changing threat environment, where Improvised Explosive Devices (IEDs), Infra Red (IR) man-portable air defense systems (MANPADS) seekers, radar guided surface-to-air-missiles (SAM), laser guided weapons, anti-helicopter mines, and targeting sensors are proliferating and evolving. Integrated solutions are required to counter increasingly sophisticated EW threats. The ARAT reprogramming infrastructure supports the tactical Commander by providing timely rapid reprogramming of mission software and information dissemination for Army supported, Joint and allied services. ARAT supports integrated reprogramming of target acquisition, target engagement, vehicle survivability, and Aircraft Survivability Equipment (ASE). ARAT rapid-reprogramming infrastructure supports tactical requirements for deployed aircraft and ground-based (e.g. Counter Radio-Controlled Improvised Explosive Device (CREW)) survivability systems. ARAT identifies and analyzes threat signature changes which affect EW systems; determines the impact of observed signature changes; develops new mission software to adapt the system to the changes; disseminates the mission software; and provides methods to upload the new mission software into the affected EW systems. Each element within the ARAT infrastructure plays a specific role within the program's rapid reprogramming process, providing the Soldier with the capability to install mission and target identification software at the lowest possible level, thus maximizing flexibility for tactical commanders. ARAT participates in the operational and developmental test design of Army EW systems, and supports Joint Service Reprogramming Exercises in all theaters. ARAT Research and Development enables continuous development of: 1) automated threat analysis tools to rapidly detect (flag) threat changes within the intelligence system, 2) tools to minimize the time to develop Mission Software and Products (MSP), 3) tools and technology to minimize the time required to test and validate MSPs, 4) improved communications conduits to rapidly transmit mission software to upload into supported EW systems. These efforts allow for rapid threat analysis, threat modeling and simulation, mission software development and testing, distribution and uploading of mission software directly to the supported Soldier in the field. Additionally, beginning in FY 2026 ARAT CR8 will begin mission support to the Terrestrial Layer System (TLS) in support of PM EW&C mission. ARAT CR8 will develop the capability to produce system techniques, integration, test, archive, and distribute mission software to forward deployed combat forces.$$, NULL, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604261N_0480$$, $$0604261N$$, $$0480$$, $$ASW Sensors & Proc$$, 41688000, $$The Anti-Submarine Warfare (ASW) Sensors and Processing project provides tools and methods necessary to maintain maritime superiority by preventing near-peer threat submarines from completing their hostile missions or disrupting the U.S. Navy's ability to control sea lanes of communication. Project 0480 provides funding for Engineering & Manufacturing Development and follow-on Production and Deployment of new and/or improved passive and active air ASW family of systems that enable cuing, search, detection, localization, track, and attack of subsurface targets. Smaller and quieter threat submarines drive requirements for continued advancement in ASW sensor capabilities for both open-ocean and littoral environments in order to overcome challenges associated with reduced target acoustic signatures and increased background clutter caused by the water depth, high volume of shipping, and commercial radio frequency interference. Multistatic Active Coherent Enhancements (MAC-E): PE 0604261N funds the incorporation of the capability into the P-8A Acoustic Operating Flight Program (AOFP), integration of the AOFP into the P-8A Mission suite and associated training system and Post Flight Analysis (PFA) tool updates. The remainder of the integration into the P-8A platform is accomplished via PE 0605504N. UnderSea Advantage (USA): USA is the next generation of multistatics. USA incorporates an incremental improvement upon the existing system and will be accomplished via three blocks. The first block will be funded in the following manner: Early development and technology maturation efforts are funded under PE 0603254N, and PE 0604261N funds the incorporation of the capability into the P-8A AOFP and integration of the AOFP into the P-8A Mission suite. 0604261N also funds the associated training system and Post Flight Analysis (PFA) tool updates. The remainder of the integration into the P-8A platform is accomplished via PE 0605504N. Project 0480 also provides funding for the Advanced Product Build (APB) program which integrates Office of Naval Research (ONR) Future Naval Capabilities (FNCs), Small Business Innovation Research (SBIR), and University Affiliated Research Center (UARC) products and mature technologies into the processing baseline. Efforts incorporate clutter reduction techniques, automation, improved displays and controls, and improved communication links to enable reduced operator workload, increased target detection opportunities, and improved classification techniques. Sonobuoy test articles in FY24-FY30 support software and hardware integration flights tests, data collection, and analysis for the acoustic program in order to develop updated fleet release software. APB also includes an Air ASW Engineering Measurement Program (AAEMP) that collects ASW operational performance data to identify areas where improvements can be incorporated across Air ASW platforms. Finally, project funding provides initial and interim training of new capabilities to test and fleet aircrew.$$, 41688000, NULL, NULL, NULL, NULL, 635031000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604261N_3224$$, $$0604261N$$, $$3224$$, $$High Altitude ASW$$, 10861000, $$High Altitude ASW project provides Key Enablers/Sonobuoy Enhancements (KESE) that increase P-8A operational flexibility and effectiveness throughout the kill chain. Funding addresses key enablers such as, uplink/downlink sonobuoy communications assurance, AELS/over-the-horizon (OTH) communications, acoustic communications (ACOMMS) and sonobuoy enhancements that include: digitization, cyber protection and the integration into the AOFP software.$$, 10861000, NULL, NULL, NULL, NULL, 140421000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604261N_9999$$, $$0604261N$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional Add. Implement sonobuoy modernization.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604262N_1425$$, $$0604262N$$, $$1425$$, $$V-22$$, 16351000, $$The V-22 Osprey is an Acquisition Category IC Joint Program led by the Department of the Navy for the purpose of developing, testing, evaluating, procuring and fielding a tilt rotor, vertical takeoff and landing aircraft for Joint Service application. The V-22 program is designed to provide an aircraft to meet the amphibious/vertical assault needs of the Marine Corps, the Carrier Onboard Delivery needs of the Navy, and the special operations needs of the Air Force and the United States Special Operations Command (USSOCOM). The MV-22 variant replaced the CH-46E in the Marine Corps and the CMV-22 variant will replace the C-2A in the Navy. The CV-22 variant replaced the MH-53J and MH-53M and augments the C-130 in the Air Force and USSOCOM. The V-22 is capable of flying over 2,100 nautical miles, with a single refueling, giving the services the advantage of a vertical/short take-off and landing aircraft that can rapidly self-deploy to any location in the world. This program is funded under Engineering Manufacturing and Development for correction of deficiencies and includes Block B upgrades which encompassed engineering and manufacturing development of new end-items prior to the production incorporation decision as well as Block C suitability and effectiveness development upgrades. Currently converting all Block B to Block C configuration. Capability Development Document interoperability requirements were addressed through a spiral upgrade acquisition strategy. It was the first spiral upgrade providing Key Enabling Department of Defense mandated open systems architecture upgrades for the mission computer hardware and software while simultaneously addressing required interoperability common avionics upgrades and current avionics obsolescence issues. Future development efforts will include pre-planned-product-improvements in the capability development document and re-design efforts to correct critical Reliability, Maintainability and Availability issues in support of readiness Operational Safety Improvement Program as prioritized by the United States Marine Corps (USMC) or an Urgent Universal Needs Statement. FY 2026 continues to support development efforts for the CMV-22 such as: Obsolescence, Modular Avionics/Cyber Security Implementation and Fuel Cell obsolescence. Begin the non-recurring engineering development of the Cockpit Alert Indicator for the Osprey Drive System Safety Health Indicator (ODSSHI) safety initiative. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under OPERATIONAL SYSTEMS DEVELOPMENT because it includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate funding in the current or subsequent fiscal year.$$, 16351000, NULL, NULL, NULL, NULL, 10054799000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604262N_3090$$, $$0604262N$$, $$3090$$, $$V-22 Improvement Program$$, 108607000, $$The V-22 Osprey provides a dual-piloted, multi-engine, Vertical/Short Takeoff and Landing, medium lift aircraft for worldwide combat, combat support, combat service support, and Special Operations missions. V-22 Product Improvements addresses requirements necessary to meet the aircraft capabilities specified in the approved Capability Development Document. Efforts included in this Project provide near and long-term improvements to the fleet, addressing deficiencies, systems safety, obsolescence, readiness, reliability, supportability, and relevance in any designated battlespace. Efforts include hardware and software development associated with increased performance capability, avionics upgrades and improvements, increased system processing capability, and the integration with other organic and non-organic systems. FY 2026 continues Airframe Hardware Development in support of V-22 Block upgrades, electrical system capacity efforts, digital interoperability, time on wing/reliability improvements efforts, Aircraft Mission Maneuvering Envelope Expansion and Safety Improvement efforts. Continues engineering, logistics, flight test, flight test support and addresses correction of deficiencies and obsolescence. Continues software development/mission computer obsolescence initiatives. Continues efforts to resolve Fuel Cell obsolescence issues. Begin the development of the Cockpit Alert Indicator for the Osprey Drive System Safety Health Indicator. FY 2026 continues Propulsion/Mission Care Hardware Development to fund the flight/engine hours that are necessary for the design, development, validation and verification of the V-22 propulsion and power systems at the Patuxent River squadron. Rolls-Royce will continue to provide engine support and development of V-22 flight testing. FY 2026 continues Flight Control System (FCS) re-design. Flight control re-design improves safety and handling of platform by reducing workload in critical places like degraded visual environment/reduced visual landing, aerial refueling, shipboard operations, and inclement weather situations through hardware and software changes. FCS is a V-22 top safety initiative and supports return to mission. FY 2026 continues Open Systems Architecture/Cyber Security research, requirements analysis and development of obsolescence mitigation solutions for aging V-22 avionics systems to overcome obsolete hardware availability. Replacement systems will be designed to provide compatibility with all legacy interfaces and functions while resolving deficiencies, meeting expanding needs, and leveraging emerging hardware and software technologies to mitigate future obsolescence. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under OPERATIONAL SYSTEMS DEVELOPMENT because it includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate funding in the current or subsequent fiscal year.$$, 108607000, NULL, NULL, NULL, NULL, 53124000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604262N_9999$$, $$0604262N$$, $$9999$$, $$Congressional Adds$$, 0, $$The V-22 Osprey is an Acquisition Category IC Joint Program led by the Department of the Navy for the purpose of developing, testing, evaluating, procuring and fielding a tilt rotor, vertical takeoff and landing aircraft for Joint Service application. The V-22 program is designed to provide an aircraft to meet the amphibious/vertical assault needs of the Marine Corps, the Carrier Onboard Delivery needs of the Navy, and the special operations needs of the Air Force and the United States Special Operations Command (USSOCOM). The MV-22 variant replaced the CH-46E in the Marine Corps and the CMV-22 variant will replace the C-2A in the Navy. The CV-22 variant replaced the MH-53J and MH-53M and augments the C-130 in the Air Force and USSOCOM. The V-22 is capable of flying over 2,100 nautical miles, with a single refueling, giving the services the advantage of a vertical/short take-off and landing aircraft that can rapidly self-deploy to any location in the world. This program is funded under Engineering Manufacturing and Development for correction of deficiencies and includes Block B upgrades which encompassed engineering and manufacturing development of new end-items prior to the production incorporation decision as well as Block C suitability and effectiveness development upgrades. Currently converting all Block B to Block C configuration. Capability Development Document interoperability requirements were addressed through a spiral upgrade acquisition strategy. It was the first spiral upgrade providing Key Enabling Department of Defense mandated open systems architecture upgrades for the mission computer hardware and software while simultaneously addressing required interoperability common avionics upgrades and current avionics obsolescence issues. Future development efforts will include pre-planned-product-improvements in the capability development document and re-design efforts to correct critical Reliability, Maintainability and Availability issues in support of readiness Operational Safety Improvement Program as prioritized by the United States Marine Corps (USMC) or an Urgent Universal Needs Statement.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604270A_DX5$$, $$0604270A$$, $$DX5$$, $$Electronic Warfare And Management$$, NULL, $$The Electronic Warfare Planning and Management Tool-X (EWPMT-X) is a software modernization effort on EWPMT Version 1 to an updated software architecture. Leveraging community contributions provides enhanced capability and features based on a government supported framework (TAKX) to enable quicker reaction to subsequent EW requirements. At end state, EWPMT-X will deliver spectrum dominance across Multi-Domain Operations (MDO) through spectrum visualization and modeling, Electromagnetic Warfare planning, sensor orchestration, fusion of intelligence, command and control (C2) that supports kinetic and non-kinetic targeting for the Commander's scheme of maneuver. Administrative realignment of FY26 RDT&E funds for Electronic Warfare Planning and Management Tool (EWPMT) transferred to Budget Activity-9 (BA-9) Program Element (PE) 0609277A: Project Code A90 - Electronic Warfare Planning and Management Tool (EWPMT) to the Agile Funding Pilot.$$, NULL, NULL, NULL, NULL, NULL, 4826000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604270A_DX6$$, $$0604270A$$, $$DX6$$, $$Multi-Function Electronic Warfare$$, NULL, $$MFEW-AL is the Army's only program providing tactical Commanders with deep look, organic, airborne, offensive electronic warfare (EW), empowering Commanders to shape the Electromagnetic Spectrum (EMS) to their advantage. The MFEW Air Large system will provide: 1) Offensive Electronic Attack (OEA) - Non-Kinetic Fires capability with the intent of denying, degrading, or disrupting enemy communications capability and non-communications emitters; 2) Electronic Warfare Support (ES) - Capability to search, intercept, identify, and locate or localize sources of intentional and unintentional radiated electromagnetic (EM) energy for the purpose of immediate threat recognition, targeting, planning, and execution of future operations; 3) Dissemination of Military Information Support Operations (MISO) products; and 4) Support of Offensive Cyber Operations (OCO) and Multi-Domain Operations. Enables integration, interoperability and force modernization with emerging capabilities in support of USAREUR-AF and USARPAC Operational Needs Statements, Transformation in Contact (TiC) initiatives, and Presidential Directives. DX6 / Multi-Function Electronic Warfare (FEW) is a part of the Department of Defense Capability Based (Agile) Funding pilot, which provides enhanced capabilities by fostering innovation and accelerated deployment of promising technology. Administrative realignment of FY26 RDT&E funds for MFEW-AL transferred to Budget Activity-9 (BA-9) Program Element (PE) 0609345A: Unmanned Aerial Systems Launched Effects Agile Systems Development; Project Code: A48: Multi-Function Electronic Warfare (MFEW) Systems to the Agile Funding Pilot.$$, NULL, NULL, NULL, NULL, NULL, 5392000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604270A_VS6$$, $$0604270A$$, $$VS6$$, $$Integrated Electronic Warfare$$, NULL, $$Multi-Mission Electronic Warfare (EW) Force Protection (FP) provides protection of ground forces operating in vehicle convoys, single vehicles and fixed locations in operational theaters which enables freedom of movement across the depth and breadth of the operational environment. Current EW FP systems are programmable with techniques to mitigate emerging threats. In order to keep pace with the threat evolution, development efforts will Multi-Mission Electronic Warfare EW FP capabilities with advance techniques to mitigate modern and sophisticated range of threats as they emerge. These development efforts may include development of new techniques, integration of existing techniques, as well as hardware and software development and integration in order to pace the threat. Justification: Fiscal Year (FY) 2026 Base funding in the amount of $1.573 million funds are provided to pace the threat focusing on Force Protection EW software enhancements to respond to changing signals of interest employed by emerging threats as required. These efforts include development of new techniques, integration of existing techniques, as well as hardware and software enhancement and integration in order to pace the threat.$$, NULL, NULL, NULL, NULL, NULL, 2092000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604270F_653891$$, $$0604270F$$, $$653891$$, $$Adv Infrared Counter$$, 17013000, $$"The Advanced Infrared Countermeasure (AIRCM) project improves aircraft self-protection against the increasing threat of sophisticated surface-to-air and air-to-air missiles. Countermeasure improvements are the result of multiple related activities. First, enhanced understanding of advanced threats derived from intelligence and Threat Acquisition and Exploitation. Countermeasure Modeling and Simulation creates updated threat models, countermeasure models, and aircraft models. Modeling and Simulation is then used to digitally evalaute new techniques and products for improved effectiveness against current and emerging threat systems. Countermeasure Development yields new devices and capabilities aimed to defeat advanced threats. Countermeasure Testing collects data for updated digital models as well as tests devices and techniques to determine effectiveness. The project also provides for modernization and enhancement of tools and capabilities needed to perform Threat Acquisition and Exploitation, Countermeasure Modeling and Simulation, Countermeasure Development, and Countermeasure Testing. The project also evaluates novel countermeasure devices and techniques for potential significant capability gains against threats."$$, 17013000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604270N_0556$$, $$0604270N$$, $$0556$$, $$EW Counter Response$$, 44032000, $$The Jammer Techniques Optimization (JATO) organization produces the jamming techniques and Electronic Attack (EA) optimization algorithms that are critical for current and future Airborne Electronic Attack (AEA) systems of the United States Navy (USN) and United States Marine Corps (USMC) to execute the evolving AEA mission. Through Modeling & Simulation (M&S), laboratory testing, and field testing, JATO optimizes parameters for AEA systems (such as AN/ALQ-99 Tactical Jamming System (TJS), AN/ALQ-249 Next Generation Jammer Mid-Band (NGJ-MB), Next Generation Jammer Low Band (NGJ-LB), and the AN/ALQ-231(V) Intrepid Tiger II Family of Systems) to best counter existing threats, and applies that knowledge to define the requirements for follow-on AEA systems. As commercial and military Radio Frequency (RF) threats evolve and proliferate, the JATO organization provides updated tactics, techniques, and procedures to maximize the potency of USN and USMC AEA in meeting the Combatant Command (COCOM) Commanders' Non Kinetic Effects (NKE) priorities, to include highly contested environments, Force Protection, Information Operations, and enhanced communications jamming. (Classified discussion available upon request). JATO's Advanced Techniques Group (ATG) focuses specifically on electronic countermeasures to advanced threat weapon systems and Command, Control, and Communications (C3) networks that are challenging existing EA approaches, and how to best apply advances in geolocation and unknown threat characterization to EA responses. Additional efforts include risk reduction activities to evaluate and minimize EA interference with US weapons systems, and research/technology studies in support of upgrades to existing AEA systems such as the AN/ALQ-99 TJS and AN/ALQ-249 NGJ-MB. The AEA Advanced Development project focuses on increasing the Department of the Navy's understanding and utilization of rapidly-evolving technologies that operate in the Electromagnetic spectrum. As commercial and military Radio Frequency (RF) threats evolve and proliferate, this project tracks the relevant technology, intelligence, and tactics to maximize the potency of USN and USMC AEA through the rapid insertion of emergent technologies (hardware and software) into existing AEA weapon systems and aircraft platforms. The Tactical Jamming Systems (TJS) follow-on development effort will develop and incorporate incremental capability upgrades to ensure TJS weapon systems, such as but not limited to AN/ALQ-99 TJS, AN/ALQ-249 (NGJ-MB) and AN/ALQ-266 (NGJ-LB) continues to address Airborne Electronic Attack (AEA) capability gaps against increasingly advanced and rapidly evolving enemy threats throughout the electromagnetic spectrum. TJS follow-on efforts include, but are not limited to, hardware and software development, integration and testing of the TJS capability on the EA-18G, as well as any potential future aircraft.$$, 44032000, NULL, NULL, NULL, NULL, 644119000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604270N_1742$$, $$0604270N$$, $$1742$$, $$EW Technical Development and T&E$$, 0, $$Provide for quick reaction prototyping of tactical information and electronic warfare systems to counter adversary platforms and Command and Control, Communications, Computers, Cyber, Intelligence, Surveillance, Reconnaissance, and Targeting (C5ISRT). Systems address various requirements across multiple platforms (air, surface, and subsurface), airborne and surface cryptologic operational requirements, and joint missions to research, assess, and develop information warfare and electronic warfare systems and capabilities. (Details held at a higher classification).$$, 0, NULL, NULL, NULL, NULL, 13600000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604270N_2175$$, $$0604270N$$, $$2175$$, $$Tactical Air Electronic Warfare$$, 50417000, $$The President's Budget 2026 control table locked including an error in the mapping FY25 Congressional reductions specific to Dual Band Decoy (DBD) to the associated project unit. Marks citing DBD ahead of need (-$2.950M) and DBD government support carryover (-$0.650M) were deducted from PE 0604270N PU 3308 but should have been deducted from PU 2175. The funds have been moved to the appropriate project unit for execution as intended. Integrated Defensive Electronic Countermeasures (IDECM) Block 4 (IB-4) is an Engineering Change Proposal (ECP) to the ALQ-214 to render it suitable for operation on F/A-18C/D aircraft (replacing the ALQ-126B and significantly improving F/A-18C/D survivability) while retaining all IDECM suite functionality when installed on F/ A-18E/F aircraft. The IB-4 acquisition, and contract strategy includes development of the Common On-Board Jammer for the F/A-18 C/D/E/F aircraft through sole source contract awards for modifications to the ALQ-214. IB-4, ALQ-214 ECP efforts include HW and SW design, development, integration and testing on the host aircraft. The F/A-18 EW suite includes the ALR-67 Radar Warning Receiver, the ALE-47 Countermeasures Dispensing Set, the mission computer and other avionics. F/A-18 E/F ALQ-214 ARC will provide the ALQ-214A(V)4 with improved RF threat detection algorithms and jamming against modern threat radars. Modifications to F/ A-18E/F Block II and Block III aircraft avionics may be required in order to develop and integrate this capability. These other avionics may include, but are not limited to, the ALR-67(V)3, ALE-47, ALE-50 Advanced AED, ALE-55 Fiber Optic Towed Decoy (FOTD), mission computer and fire control radar. ARC capabilities may be integrated into other DoD platforms with radar warning receivers or countermeasures systems. The DBD will provide expanded RF capability against current and emerging modern RF threat radars, significantly improving the survivability of the F/A-18 E/F and may be further developed and integrated into other Naval platforms. DBD will leverage Science and Technology (S&T) advancements through the Dual Band Intelligent RF Expendable (DIRE) program to accelerate DBD capability development. DBD replaces the ALE-55 FOTD beginning in FY2027. Modifications to other F/A-18E/F Block II and Block III aircraft avionics may be required in order to develop and integrate this capability. These other avionics may include, but are not limited to, the ALR-67(V)2, ALR-67(V)3, ALE-47, mission computer and fire control radar. This Project also includes/enables iASE which improves situational awareness for own-ship, wingman, and distributed command and control.$$, 50417000, NULL, NULL, NULL, NULL, 723838000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604270N_3308$$, $$0604270N$$, $$3308$$, $$Technology Development$$, 12382000, $$The President's Budget 2026 control table locked including an error in the mapping FY25 Congressional reductions specific to Dual Band Decoy (DBD) to the associated project unit. Marks citing DBD ahead of need (-$2.950M) and DBD government support carryover (-$0.650M) were deducted from PE 0604270N PU 3308 but should have been deducted from PU 2175. The funds have been moved to the appropriate project unit for execution as intended. Project Unit 3308/Technology Development funds efforts that focus on the quick reaction prototyping and fielding of Tactical EW/countermeasures solutions for increased resilience and survivability, by improving the active electronic self-defense of tactical aircraft. This self-protection provides friendly forces the ability to deploy, survive, operate, maneuver, and regenerate in all domains while under attack as well as strike diverse targets inside adversary air and missile defense networks to destroy mobile power-projection platforms. This Project also includes/enables iASE which improves situational awareness for own-ship, wingman, and distributed command and control. Significant investments have been made in the modular HW and reprogrammable software resident in ASE capability which is fielded today. Technology Development makes specific investments towards: countermeasure/jammer/receiver algorithm development, Advanced EW Suite capability studies/ investigation/analysis, threat data file and model updates as modern threats continue to evolve. These updated data files and algorithms are required to be deployed within hours of release by squadron maintenance personnel to aircraft while still on the ramp or flight deck. This program directly addresses the operational requirement of Strike Tactical Air platforms for optimization of EW/countermeasure solutions across the DoN.$$, 12382000, NULL, NULL, NULL, NULL, 42819000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604270N_3309$$, $$0604270N$$, $$3309$$, $$Assault Survivability Optimization$$, 65164000, $$FY2026 funding supports CC additional scope and schedule added to OTA for new system security and F/A-18E/F and EA-18G vibration requirements required to field CC and iASE to address modified cybersecurity requirements to reduce cybersecurity risk, the additional complexity of integration of the iASE Programmer with the CASS to maintain the I-Level maintenance capability, and additional requirements for F/A-18E/F and EA-18G integration of iASE Programmer including the MOB Hub. Funding also required to continue CC development, qualification and testing. The CC transition for F/A-18E/F, EA-18G, MH-60R/S, P-8, CMV-22, CH-53K, and MV-22 platforms will reduce expendable countermeasures logistics footprints, reduce future development and procurement costs, and improves industrial base performance through DOD wide common expendable square form factor. Project continues CC funding for aforementioned aircraft. Project continues funding required to implement MOB Hub and iASE capability for F/A-18E/F and EA-18G aircraft. MOB Hub iASE funding is for HW/SW design and qualification of the ALE-47 iASE Programmer. MOB Hub iASE replaces obsolete ALE-47 operational flight program and programmer HW, providing data to the gateway necessary for survivability in the current and future threat scenarios facing USN operational missions. This MOB Hub iASE upgraded programmer enables advanced expendable countermeasures to enhance countermeasure response, and provide additional battlespace awareness for own-ship, wingman and other mission participants. Project continues funding for Advanced RF Countermeasure development, testing and modeling and simulation capability to reduce future flight test cost. AED replaces existing GEN-X AED which is obsolete against modern RF threats. Passive RF Expendable Decoys (RR-203) leveraged advanced chaff technology used on the F-35 to provide improved Radar-Cross-Section performance capability to DoN platforms. Advanced Active and Passive RF expendable solutions offer standalone devices necessary for global naval operations for all DoN aircraft deployments for use against networked Integrated Air Defense Systems with coherent radars and provide aircrew with tailored response options of integrated on-board and off-board RF expendable solutions in a dense threat environment. Resources will be applied to the following areas: 1) Studies and evaluations to optimize employment of current countermeasures and iASE capabilities. 2) Development and demonstration of advanced expendable countermeasures and countermeasure techniques. 3) Testing and evaluation of IRCM and RF advanced countermeasures. 4) Development of system software enhancements and integration for the testing and deployment of advanced countermeasure techniques. 5) Development of and upgrades to modeling tools and specialized equipment required to conduct evaluation of advanced countermeasures against proliferating threats.$$, 65164000, NULL, NULL, NULL, NULL, 73471000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604270N_3327$$, $$0604270N$$, $$3327$$, $$MAGTF EW Aviation Development$$, 13611000, $$This project unit supports the United States Marine Corps (USMC) development of Marine Air Ground Task Force (MAGTF) Electronic Warfare (EW) and the various elements of its distributed System of Systems (SoS). The SoS addresses MAGTF EW sufficiency gaps in the areas of Electronic Attack (EA) and Electronic Warfare Support (ES) with a multitude of payloads designed for carriage on a variety of organic MAGTF air assets. Payload development plans follow an adaptable, modular and open architecture philosophy to combat the increasing capability gap and enable future growth at a reduced operational and sustainment cost. A key element to this capability is the AN/ALQ-231(V) Intrepid Tiger II program. The AN/ALQ-231(V)1 pod is the variant of the Intrepid Tiger II pod flown on the AV-8B, F/A-18A-D, and KC-130J platforms. The AN/ALQ-231(V)3 is the variant of the Intrepid Tiger II pod flown on the UH-1Y platform, with plans for integration on AH-1Z platforms. Plans include future integration of AN/ALQ-231(V) Block X advanced capability and counter-radar upgrades on USMC tilt rotor, fixed wing, rotary wing and unmanned aircraft. The AN/ALQ-231(V)4 is the first implementation of Block X upgrades on MV-22B aircraft and future (V)5 BLK X integration is planned to include payloads for KC-130J, MQ-9, CH-53K, and AH-1Z platforms. All payload variants are capable of conducting, supporting, and coordinating Electro-Magnetic Spectrum (EMS) operations in the form of EA and ES against Irregular Warfare threats. Additionally, all payloads are scalable and adaptable for emerging threats and are interoperable with the USMC's Electronic Warfare Services Architecture (EWSA). The Intrepid Tiger II capability is designed to be integrated for MAGTF tactical coordination of cyberspace and EW operations via the Cyber Electronic Warfare Coordination Cell (CEWCC).$$, 13611000, NULL, NULL, NULL, NULL, 96495000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605502N_3202$$, $$0605502N$$, $$3202$$, $$SBIR CRP - SPAWAR$$, 0, $$Originally established in Section 252 of the 2006 NDAA Public Law No. 109-163, the Commercialization Readiness Program (CRP) may not use more than up to 1% of the SBIR to be used for payment of expenses incurred to administer CRP. 15 USC 638(y) authorizes the DoD to administer a Commercialization Readiness Program to accelerate the transition of SBIR/STTR-developed technologies, products, and services to Phase III, including the acquisition process.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604272N_3348$$, $$0604272N$$, $$3348$$, $$DAIRCM Development$$, 14387000, $$The projects in this element advances the processor, laser, and sensor development of the AN/AAQ-45 DAIRCM system in order to outpace current/future threats in addition to adding growth for future capabilities. These modifications significantly increase aircraft survivability of Department of Navy (DoN) assault aircraft in complex terrain for worldwide deployment. The DAIRCM system consists of three major components: missile warning sensors, processor, and inexhaustible laser countermeasures. DAIRCM interfaces with the platform aircraft and provides signals to onboard Aircraft Survival Equipment. Within the DoN, UH-1Y is the lead platform for the DAIRCM Program. The DAIRCM program advances lessons learned from the Joint Urgent Operational Needs Statement (JUONs) to incorporate the system under glass in the H-1; improves laser power; increases processing to allow for additional sensors to meet platform/mission needs; improves sensor countermeasure features; improves effectiveness for flare deployment; and further develops cyber security. The DAIRCM design is scalable to expedite expansion to other platforms and improve crew threat situational awareness. The program also advances modeling and simulation for new countermeasures and develops necessary test equipment for program success. FY2026 RDT&E funding is required to continue development and test of the DAIRCM system. The program will continue development of Government tracking software, testing of under glass solutions and conduct operational testing on the lead platform (UH-1Y). The program will also record, prioritize and correct deficiencies found during test. DAIRCM will continue studies and evaluations of current and future aircraft threats, modeling and simulation for improved countermeasure capabilities, development, testing, and test equipment to address new and emerging threats.$$, 14387000, NULL, NULL, NULL, NULL, 244373000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604273M_3390$$, $$0604273M$$, $$3390$$, $$VH-92A Improvements$$, 74980000, $$VH-92A Product Improvements addresses improvement requirements written into the Capabilities Development Document approved by Joint Requirements Oversight Committee in Jan 2013 and updated for Milestone C. The VH-92A Improvement efforts are to provide near and enduring/relevant/evolving long term improvements to the fleet, focusing on documented deficiencies and enhancements related to critical mission systems, maintainability and reliability and obsolescence issues. The VH-92A improvements also address deficiencies identified at the completion of Initial Operational Test and Evaluation (IOT&E); development associated with Mission Communications System (MCS) upgrades (both software and hardware), distributed network communications, vehicle performance enhancements, and high hot performance (Power Margin) efforts.$$, 74980000, NULL, NULL, NULL, NULL, 130374000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604274N_0557$$, $$0604274N$$, $$0557$$, $$Next Generation Jammer$$, 64167000, $$This Program Element (PE 0604274N) supports the AN/ALQ-249 NGJ-MB program. NGJ-MB will address AEA capability and sufficiency gaps against enemy threats operating in the middle frequency bands of the electromagnetic spectrum. In addition, this PE supports NGJ-MB Extended (MBX), which is an Engineering Change Proposal (ECP) to the current NGJ-MB system that will extend the upper frequency coverage limit to counter modern and adaptive threats. This modification will increase frequency range of the NGJ-MB system and enhance the survivability of the platform and protected entities against emerging threats. In total, NGJ-MB will provide the ability to effectively engage enemy threats from increased stand-off distances, employ increased capacity (number of jamming assignments) against enemy targets, and support agile employment by operators. The NGJ-MB system will be integrated on the EA-18G tactical aircraft and will augment and then replace the legacy AN/ALQ-99 Tactical Jamming System in the middle frequency bands. NGJ-MB (to include MBX) is a Cooperative development and production program with the Royal Australian Air Force (RAAF).$$, 64167000, NULL, NULL, NULL, NULL, 3956441000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604280N_0725$$, $$0604280N$$, $$0725$$, $$Communication Automation$$, 11680000, $$The details of Program Element 0604280N Project 0725 are classified SECRET//NOFORN and are submitted annually to Congress in the classified budget justification books.$$, 11680000, NULL, NULL, NULL, NULL, 40817000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604280N_0728$$, $$0604280N$$, $$0728$$, $$Navy Multiband Terminal (NMT)$$, 42627000, $$The details of Program Element 0604280N, Project 0728 for NMT are classified SECRET//NOFORN and are submitted to Congress in the classified budget justification books. Navy Global Broadcast System (GBS) is a member of the larger Joint Command, Control, Communications, Computers, and Intelligence (C4I) program, providing high speed (up to 45 Mbps per transponder)/large volume information/data delivery to forces afloat, ashore, and Naval Special Warfare Command. Leveraging the NMT antenna, GBS provides a one-way broadcast to Naval maritime forces across the spectrum of mission areas, to include land, air and naval warfare, special operations, strategic nuclear operations, strategic defense, theater missile defense, and space operations and intelligence in support of RC3. GBS Transmission Security (TRANSEC) is an operational requirement from the Joint GBS ORD and provides robust datalink protection of both uplink and downlink for the GBS broadcast. GBS is evaluating Protected Tactical Waveform (PTW) solutions to meet the TRANSEC mandate. The Air Force & Army Anti-Jam Modem (A3M) and the WAMS are PTW solutions that are under consideration. Navy GBS will require extensive development activities for the new PTW modem solution and must conduct a Follow-On Test & Evaluation (FOT&E) with Joint Services. Overall program efforts include technology insertion studies required to support satellite communications. Technology Insertion, studies and implementation is necessary for military satellite communications systems development to support emerging technologies for Satellite Communications (SATCOM) programs. Increase of $14.310M from FY 2025 to FY 2026 will support Wideband Anti-Jam Modem System (WAMS) development, integration, and certification efforts. This provides Resilient Command, Control, and Communications (RC3) and Distributed Maritime Operations (DMO) capability. FY 2026 funding also supports technology insertion focusing on the development and testing of below decks Non-Geostationary Orbit (NGSO) SATCOM compatibility with the NGSO submarine mast antenna.$$, 42627000, NULL, NULL, NULL, NULL, 54538000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604280N_0729$$, $$0604280N$$, $$0729$$, $$Mobile Advanced Extremely High$$, 68866000, $$The details of Program Element 0604280N, Project 0729 are classified SECRET//NOFORN and are submitted to Congress in the classified budget justification books.$$, 68866000, NULL, NULL, NULL, NULL, 121357000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604280N_0742$$, $$0604280N$$, $$0742$$, $$Sub Integrated Ant System$$, 25715000, $$The details of Program Element 0604280N, Project 0742 are classified SECRET//NOFORN and are submitted to Congress in the classified budget justification books.$$, 25715000, NULL, NULL, NULL, NULL, 74108000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604280N_0921$$, $$0604280N$$, $$0921$$, $$NAVSTAR GPS Equipment$$, 49016000, $$The FY 2026 funding decrease of $13.689M from FY 2025 to FY 2026 is due to completion of LN-251M development as well as completion of the feasibility study for using a Janus Software Design Receiver (SDR) as a GPS Receiver Card and continue to study opportunities to incorporate improvements into GPS receivers. Navigation Satellite Timing & Ranging (NAVSTAR) GPS project (0921) encompasses the Navy's efforts to pace the growing threat to GPS Navigation through the fielding of new GPS receivers, Anti-Jam (AJ) Antennas, and Assured Positioning Navigation and Timing (A-PNT) technologies across all Navy platform types. NAVSTAR GPS is a group of A-PNT systems that provides authorized users with secure, worldwide, all weather, three dimensional position, velocity, and precise time data. NAVSTAR GPS provides A-PNT capability to Command, Control, Communications, Computer, Intelligence, Surveillance and Reconnaissance (C4ISR) and combat systems in standalone and networked architectures throughout air and maritime domains. This project is comprised of four distinct efforts: Sea Navigation Warfare (NAVWAR), GPNTS, Air NAVWAR and GPS Modernization. Sea NAVWAR provides AJ antennas and Global Positioning System (GPS) - Based Positioning, Navigation and Timing (PNT) Service (GPNTS) provides GPS Receivers and A-PNT technology to surface platforms, and Air NAVWAR provides AJ antennas and GPS Modernization provides GPS receivers to air platforms. Research, Development, Testing and Evaluation (RDT&E) funding is used to perform all the non-recurring GPS related development, integration, and testing efforts for surface ships and aircraft in support of NAVSTAR GPS. The Air and Sea NAVWAR programs provide continued access to GPS information in a denied or impeded electronic environment. Development efforts for both programs provide improvements to various platform type antennas and ensure compatibility with the new GPS M-Code signal. The Air NAVWAR program continues integration efforts using GPS Antenna System (GAS-1), Advanced Digital Antenna Production (ADAP), and other AJ antennas on air platforms while investigating smaller AJ antennas for space constrained platforms and aircraft with unique requirements. The Sea NAVWAR program integrates AJ antennas onto surface and subsurface platforms. The Sea NAVWAR program will continue to research the viability and development of enhanced AJ techniques and technologies. The GPNTS system is the primary and modernized A-PNT system for the surface Navy to ensure reliable PNT capability and interoperability insertion into GPS receivers and associated C4ISR and Combat Systems in a denied environment. GPNTS pairs with AJ antennas and provides precise A-PNT data required for combat, weapons, command, control, communications, navigation, and other systems, as well as providing the time synchronization critical for network environments. GPNTS will back fit current GPS/PNT systems as well as serve as a forward fit for new platforms. GPNTS is an Open Architecture (OA) development, enabling rapid software and hardware based capability improvements to be inserted without a requirement for single-source contracting. GPNTS will host the United States Space Force (USSF) GPS Directorate-developed Military GPS User Equipment (MGUE) card, allowing access to the new GPS M-Code signal. GPNTS will provide more robust and secure GPS/PNT capabilities than is currently in the Fleet. The system will provide the capability to migrate non-real time GPS data toward a Common Computing Environment (CCE) and provide a path for the integration of advanced navigation systems and sensors. GPNTS provides A-PNT capability to C4ISR and Combat Systems in standalone and networked architectures throughout maritime domains.$$, 49016000, NULL, NULL, NULL, NULL, 154373000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604280N_1411$$, $$0604280N$$, $$1411$$, $$Sub Tact Comm System$$, 15646000, $$The details of Program Element 0604280N, Project 1411 are classified SECRET//NOFORN and are submitted to Congress in the classified budget justification books.$$, 15646000, NULL, NULL, NULL, NULL, 62747000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604280N_2126$$, $$0604280N$$, $$2126$$, $$ATDLS Integration$$, 14566000, $$Advanced Tactical Data Link Systems (ATDLS) is the United States (US) Navy's only ship-to-ship/ship-to-aircraft tactical information solution equipping warfighters and Combatant Commanders with real-time battlespace data and extending the range of lethality. ATDLS is the backbone of Carrier Strike Group and AEGIS-Based Defense operations and is the key component in the fire control loop, providing critical track information for enabling maritime offense/defense, Joint Area Domain Command and Control (JADC2), Integrated Air and Missile Defense (IAMD), Ballistic Missile Defense (BMD), Anti-Air Warfare (AAW), Anti-Surface Warfare (ASuW), Electronic Warfare (EW), Advanced Offboard Electronic Warfare (AOEW), and Long Range Fires (LRF) missions. ATDLS Integration Program develops new and improved Tactical Data Links (TDL) networking capabilities, delivering operational and targeting support to the warfighter. ATDLS rapidly and securely connects carrier/shipboard digital combat systems to military aircraft, ground troops, coalition partners, and space assets with vital Situational Awareness, targeting, and sensor information. ATDLS also provides Joint Range Extension capability via Link 16 Network (Link 16) Terminals, Command and Control Processor (C2P), and Link Monitoring and Management Tool (LMMT). Link 16 Network (Link 16) Increment II: Link 16, enhanced by Tactical Targeting Networking Technology (TTNT), is the Military's only joint network providing secure TDL interoperability and data sharing in contested battlespace environments. The Link 16 development initiatives are in support of Joint Chiefs of Staff Joint Requirements Oversight Council Memorandum (JROCM) 075-17 for installation and integration of Multifunctional Information Distribution System (MIDS) Joint Tactical Radio System (JTRS) (MIDS J) terminals into the Navy shipboard environment. These include: (1) the modification the MIDS on Ship (MOS) cabinet as a MOS MIDS JTRS Engineering Charge Proposal (MMJE), and via the MOS Modernization (MOS Mod) cabinet systems for ships with the legacy JTIDS systems; (2) JROCM 097-20 and the JROC-validated MIDS JTRS Capability Production Document (CPD) 10 February 2011 which provided direction for Crypto Modernization (CM), Frequency Remapping (FR), Enhanced Throughput (ET), CMN, CCR, and TTNT. These systems are interfaced to shore sites and ships via C2P Technology Refresh (Tech Refresh) version 3.13 software, and to the combat systems with C2P via Integrated Shipboard Network Systems (ISNS) for TTNT; (3) Developmental Testing (DT) / Operational Testing (OT) of Navy platform JTRS modifications and the integration of TTNT; (4) provide product improvement for continued production capability MOS and MOS Mod, with extensibility of new Tactical Data Link capabilities of shipboard Link 16 terminals; and (5) the development and qualification to replace shipboard Link 16 4400 antenna with the 4557 antenna. FY2026 Justification (Link 16): No funding programmed in FY2026. Program testing and development requirements concluded in FY2025 to include A(v)6 initiatives, TTNT Terminal Controller SW development, and integration testing efforts of MIDS JTRS Block Upgrades 3 (BU3), TTNT, and the associated Terminal Controller. Command and Control Processor (C2P): C2P is the only shipboard solution that enables bi-directional exchange of tactical information across multiple TDLs within the joint operations areas. C2P processes and exchanges Link 11, Link 16, Satellite TDL J, and Joint Range Extension Applications Protocol (JREAP) tactical data among the US, North Atlantic Treaty Organization (NATO), and allied nation military platforms enabling the vital joint TDL interface. Additionally, C2P provides data translation services, acts as a single interface between host combat system and TDL networks, and forwards tactical data between platforms operating at extended$$, 14566000, NULL, NULL, NULL, NULL, 90422000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604280N_3020$$, $$0604280N$$, $$3020$$, $$MIDS/JTRS$$, 47977000, $$The Multifunctional Information Distribution System (MIDS) is the most widely fielded family of Tactical Data Link radio terminals in the world. The MIDS program office is the Performing Activity for the Navy (Lead Service for Department of Defense (DOD)), Link 16 capability and consists of two (2) product lines, MIDS Low Volume Terminal (LVT) (legacy hardware defined radio) and MIDS Joint Tactical Radio System (JTRS) (software defined radio). MIDS-LVT effort is a cooperative development program between France, Germany, Italy, Spain, and the United States with United States joint service participation (Navy, Army, Air Force), and has provided over 12,000 terminals to more than 50 Nations providing interoperability with North Atlantic Treaty Organization (NATO) and coalition partners. The Department of Defense (DoD) established the program to design, develop, and deliver low volume, lightweight tactical information system terminals for U.S. and allied fighter aircraft, bombers, helicopters, ships, and ground sites. MIDS-LVT significantly increases force effectiveness and minimizes hostile actions and friend-on-friend engagements. MIDS-LVT Block Upgrade 2 was executed as an Engineering Change Proposal (ECP) and provides the critical upgrades to the MIDS-LVT Terminal to enable U.S., Coalition and International partners' ability to meet the National Security Agency (NSA) mandated timelines for Cryptographic Modernization (CM) and the National Telecommunications and Information Agency (NTIA) and Federal Aviation Agency (FAA) mandated timelines for Frequency Remapping (FR). MIDS JTRS, designed as a Pre-Planned Product Improvement (P3I) and executed as an ECP to the production MIDS-LVT configuration, and is fully compatible with MIDS-LVT. The MIDS JTRS Core Terminal achieved Full Production & Fielding (FP&F) in March 2012. It facilitated the JTRS incremental approach for fielding advanced JTRS transformational networking capability and transformed the MIDS-LVT into a 4-channel, SW Communications Architecture (SCA) compliant, Joint Tactical Radio. A form-fit-function replacement to MIDS-LVT, MIDS JTRS also adds three programmable 2 Megahertz (MHz) to 2 Gigahertz (GHz) channels capable of hosting the JTRS legacy and networking waveforms. In addition to Link 16, Tactical Air Navigation (TACAN), and voice functionality found in MIDS-LVT, MIDS JTRS has four channels and adds capabilities such as Link 16 Enhanced Throughput (ET), Link 16 FR, SW programmability, CM, and Four Net Concurrent Multi-Netting with Concurrent Contention Receive (CMN-4). MIDS JTRS Tactical Targeting Network Technology (TTNT), is a block upgrade to the MIDS JTRS CMN-4 Terminal providing an Internet Protocol-based networking capability on tactical aircraft. TTNT is a low latency, high throughput waveform that has the capability to support data exchange between fast-moving tactical aircraft, weapons, and unmanned aircraft, in addition to air, land, and sea-based command and control nodes, in a variety of air-to-air and air-to-ground missions including time sensitive targeting, air warfare, close air support, non-traditional ISR, and anti-surface warfare. TTNT and MIDS JTRS CMN-4 directly supports Naval Integrated Fire Control (NIFC) capability requirements. These capabilities provide Joint Airborne Network-Tactical Edge functionality to run advanced mission applications in a cross- platform/cross-domain tactical network enterprise. Currently when updated software or any bug fixes are available, the warfighter must return the terminal to the vendor and pay for the labor to install the latest software push. With the new Field Loadable capability, the vendors will update the terminal's software to allow the warfighter to use the front panel of the terminal to load the$$, 47977000, NULL, NULL, NULL, NULL, 262439000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604280N_3078$$, $$0604280N$$, $$3078$$, $$Digital Modular Radio$$, 6396000, $$Digital Modular Radio (DMR) with Integrated Waveform (IW) and Mobile User Objective System (MUOS) capable hardware is the Navy's technical solution for the IW/ MUOS requirement. The compact, multi-channel DMR provides 3G, Wideband Code Division Multiple Access (WCDMA) technology, for high speed/capacity voice and data satellite communications. DMR radios currently operate aboard U.S. Navy surface and subsurface vessels, fixed-sites and other Department of Defense (DoD) communication platforms using frequencies ranging from 2 MHz to 2 GHz. Certified to pass secure voice and data at Multiple Independent Levels of Security (MILS) over High Frequency (HF), Very High Frequency (VHF), Ultra High Frequency (UHF), and Satellite Communications (SATCOM) channels, the DMR system was developed to the U.S. Navy's specifications and meets all the stringent environmental, Electromagnetic Interference (EMI) and performance requirements for use in the U.S. Fleet. This system is formally specified by both Fleet Commanders as a threshold capability, for global maritime command control and communications in a Distributed Maritime Environment, to execute current warfighting plans and is required for National Command and Control capability. This program is for continued development/integration of the IW and MUOS waveforms into the DMR in accordance with Military Standards 188-181,2,3. Additionally, the enhancements of High Frequency Distribution Amplifier Group (HFDAG) and, HF Automated Link Establishment (ALE) and Second-Generation Anti-Jam Tactical UHF Radio for NATO (SATURN) will also be developed/integrated into the DMR. HFDAG is a follow-on HF solution to fulfill transmit and receive HF communication capability with various modes of operation, such as ALE, for Navy platforms. HFDAG will utilize the existing DMR as the exciter/receiver. Generation 3 (GEN 3) HF ALE/HF wideband provides Navy users with improved HF communications, increased transmission rates from radio to radio, and serves as a supplement to SATCOM when SATCOM networks are overloaded or unavailable. SATURN is the follow-on HAVEQUICK II anti-jamming solution in accordance with NATO Standardization Agreement 4372. SATURN capability will counter adversaries' jamming efforts and ensure Navy's Assured Command and Control UHF communications operational end-to-end capability as well as enhance interoperability within/between DMR users and with Allied/Coalition partners. IW uses a Time Division Multiple Access (TDMA) communication system in an attempt to improve satellite bandwidth utilization over legacy SATCOM waveforms. This enables demand assigned services on UHF SATCOM networks to support new applications that require better performance and higher channel throughput. The MUOS waveform will enable MUOS satellites to provide worldwide communication satellite coverage for DoD requirements. MUOS will provide functionality comparable to commercial mobile phone systems. In FY 2026, the program will complete MUOS 3.2 and SATURN development integration and test efforts with the DMR. DMR will begin the design, testing, and integration of a follow-on tactical communication solution that will deliver critical cryptographic compliant waveforms to the fleet.$$, 6396000, NULL, NULL, NULL, NULL, 58122000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0605502N_3203$$, $$0605502N$$, $$3203$$, $$SBIR CRP - NAVSEA$$, 0, $$Originally established in Section 252 of the 2006 NDAA Public Law No. 109-163, the Commercialization Readiness Program (CRP) may not use more than up to 1% of the SBIR to be used for payment of expenses incurred to administer CRP. 15 USC 638(y) authorizes the DoD to administer a Commercialization Readiness Program to accelerate the transition of SBIR/STTR-developed technologies, products, and services to Phase III, including the acquisition process.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604280N_3341$$, $$0604280N$$, $$3341$$, $$Network Tactical Common Data Link$$, 3962000, $$Network Tactical Common Data Link (NTCDL) provides the ability to transmit/receive real-time Intelligence, Surveillance, and Reconnaissance (ISR) data simultaneously from multiple sources (surface, airborne, sub-surface, man-portable), and exchange command and control information (voice, data, imagery, and Full Motion Video) across dissimilar joint, service, coalition, and civil networks. NTCDL provides warfighters with the capability to support multiple, simultaneous, networked operations with currently fielded Common Data Link (CDL)-equipped air platforms (e.g. MH-60R), in addition to next generation manned and unmanned platforms (e.g., P-8, Triton, MQ-25 (Stingray), small tactical unmanned aircraft systems (STUAS) and Fire Scout). NTCDL is an incremental capability (surface, airborne, sub-surface, and man-portable) providing modular, scalable, multiple-link networked communications. NTCDL benefits the fleet by providing a horizon extension for line-of-sight sensor systems for use in time-critical strike missions and supports tasking, collection, processing, exploitation, and dissemination (TCPED) via its ISR networking capability. NTCDL supports Resilient Command and Control (RC2) through its relay capability, and supports TCPED through its ISR networking capability. FY 2026 request is for NTCDL to continue Capability Enhancement Development including Bandwidth Efficient Common Datalink (BE-CDL) waveform implementation.$$, 3962000, NULL, NULL, NULL, NULL, 98441000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604280N_4011$$, $$0604280N$$, $$4011$$, $$Naval Coastal Warfare Surv and C4I$$, 2894000, $$The Navy Expeditionary C4I project supports the Navy Expeditionary Combat Command (NECC) mission to detect, deter or interdict potential threats to DoN assets using agile, modular and scalable technology. NECC units have a number of current and future Command, Control, Communications, Computers & Intelligence (C4I) technological requirements for Tactical/Command Operations Center, tactical vehicles, combatant craft, and dismounted personnel. NECC operations require units to maintain effective command and control, develop and display a common tactical picture, and share intelligence and current operational information with higher headquarters, subordinate units, joint forces and coalition allies. Small, Medium, and Large Scale Communication Systems (LSCS) are the C4I hub for the Navy Expeditionary Combat Force (NECF); Expeditionary Deployable Node (EDN) is the latest converged LSCS baseline. Future C4I research and development includes implementation of The Expeditionary Deployable Node (EDN) and Navy Expeditionary Tactical Entry Points (NExTEP) at the Fleet Network Operations Centers (NOC), which supports the NECC Type Commander's (TYCOM) vision of a smaller footprint C2 system with reduced Fleet administration and patching requirements and a single domain and single user identity across all deployed systems. Future C4I research and development will enhance information transport, network cyber security posture, assured communications in denied environments along with agility and mobility. Funding is required for testing and evaluation of cyber security issues associated with obsolescence of network items and if not addressed will impact the ability of the Program Office to maintain system accreditation under Risk Management Framework (RMF) revoking multiple LSCS assets authority to connectivity on the Department of Defense Information Network (DoDIN). Efforts are in alignment with NECC's strategic Expeditionary Warfare Improvement Program (EXWIP) Integrated Priority Capability List (IPCL) priorities and maintain alignment with greater DoD initiatives, such as Joint Information Environment (JIE), Mission Partner Environment (MPE) in order to maintain interoperability and drive down DoN enterprise costs.$$, 2894000, NULL, NULL, NULL, NULL, 10756000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604280N_9999$$, $$0604280N$$, $$9999$$, $$Congressional Adds$$, 0, $$C370: This project develops and improves the Navy's Tactical Data Link (TDL) systems, and it includes the Advanced Tactical Data Link Systems (ATDLS) Integration Programs, specifically Link 16 Network, Command and Control Processor (C2P) and Link Monitoring and Management Tool (LMMT). ATDLS Integration Program develops new and improved capabilities for Navy TDL users. The ATDLS Integration Programs perform technical analyses and engineering efforts associated with implementation of new technology to enable rapid introduction of new products and technology, prevent obsolescence, and end of support issues. The programs insert new technology enhancements via incremental software & hardware upgrades and deliver in annual build release. The Navy Link 16 Network Increment II requires Enhanced Throughput (ET), Concurrent Multi-Netting (CMN), Current Contention Receive (CCR), and Tactical Targeting Networking Technology (TTNT), and tech refresh with Block Upgrade 3 (BU3). C2P is a critical component of the shipboard combat system enabling tactical data link integration with the combat systems. C2P is a critical component of the Aegis Ballistic Missile Defense (BMD) architecture. C2P Technology Refresh (TR) will modernize obsolete C2P system hardware components and improve C2P system cyber security posture. C2P Modernization (MOD) is a service life extension effort required to sustain C2P system viability and significantly improve its cyber resiliency. C2P MOD modernizes the legacy C2P system software to enable improved cyber resiliency, improved system operational availability and the ability to run in multiple hardware environments. Link 22 development and integration into the C2P allows for improved maritime tactical data link operations with coalition forces. LMMT will upgrade commercial off-the-shelf hardware and modernize software operating systems. LMMT will perform monitoring and management of all TDL and provide information in support of the Integrated Air & Missile Defense (IAMD) and Ballistic Missile Defense (BMD) missions. Command and Control Processor (C2P): The two Research Development Test & Evaluation (RDT&E) initiatives are 1) C2P Technology Refresh (TR) cyber security update and 2) C2P Modernization which now includes Link 22 integration. C2P TR cyber security update is a new initiative driven by recently discovered cyber security risk to the C2P system in support of the BMD mission. The C2P TR Cyber security update is planned to support acceleration on all AEGIS BMD ships. C2P Modernization funds the transition of the C2Ps legacy Compiler Monitor System (CMS-2Y) software code (old Navy unique computer programming language from the 1980s) to a modern software language. Transition to a modern software language is required to sustain the system software, to adequately address growing cybersecurity and operational availability challenges, and to enable more affordable transition to new hardware processing components as a result of commercial of the shelf processor obsolescence. Link 22, which was previously planned for fielding in the C2P TR architecture, has been delayed until the fielding of C2P Modernization. This was based on prioritizing existing resources to address the emergent cyber security risk that has resulted in the C2P TR cybersecurity update plan. Link 22 is a modernized replacement for Link 11, providing beyond line of site (BLOS) tactical data communications using high frequency (HF) radios. Link 16 Network Increment II: These Link 16 efforts are in support of Joint Chiefs of Staff Joint Requirements Oversight Council Memorandum (JROCM) 075-17 for installation and integration of Multifunctional Information Distribution System (MIDS) Joint Tactical Radio System (JTRS) (MIDS J) terminals into the Navy shipboard environment. These include: (1) the modification the MIDS on Ship (MOS) cabinet as a MOS MIDS JTRS Engineering Charge Proposal (MMJE), and via the MOS$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604281F_655050$$, $$0604281F$$, $$655050$$, $$TDL System Integration$$, 77170000, $$The Tactical Data Networks Enterprise (TDNE) program element analyzes and evaluates requirements, designs, develops, enhances, and fields prospective or needed systems. The TDNE focuses on the research, analysis, design, development, test, evaluation and fielding or other capability development of Tactical Datalink (TDL), gateway, radio, multi-function processor, antenna, multi-function aperture, license, waveform and other associated equipment, technology or capabilities. TDNE develops, enhances and fields technologies, architectures, documentation, tactics, techniques, procedures and capabilities. These efforts enhance Air Force communications capacity, efficiency, affordability, integration and optimization. TDNE supports interoperability of Air Force to: Air Force, Joint, Coalition, and NATO (Allied), and other partner platforms and systems; supports releasability engineering, cyber engineering, digital engineering, encryption and safety compliance, et al. Tactical Data Links (TDL) System Integration provides for the study, analysis, enhancement, development, integration, demonstration, joint/coalition/NATO interoperability exercises, costing, test, trials, and evaluation of TDL as a subset of the broader aerial layer network. Products include interoperability standards and reports, waveform standards, and hardware/software technical solutions. The number of Air Force platforms hosting TDLs has expanded from C2 aircraft to the fighter, bomber, intelligence, surveillance, and reconnaissance (ISR), tanker, airlift and other tactical fleets as well as precision guided munitions. Utilization of TDLs in joint and international environments requires the integration of terminals into host platforms and interoperability of TDL networks across all deployed joint/ Coalition/NATO platforms. USAF mandates require additional studies and analysis to meet frequency reprogramming and cryptographic requirements. To deliver TDL capabilities to required platforms and users, Tactical Data Links (TDL) System Integration is broken into four main thrusts of Tactical Data Links and Gateways (TDL&G) Integration, Advanced Aerial Communication Technology (AACT), the Common Tactical Edge Network (CTEN) program (which evolved from and includes prior Agile Communications efforts), and Second-Generation Anti-Jam Tactical UHF Radio for NATO (SATURN) activities. Tactical Data Links and Gateways (TDL&G) Integration activities consist of TDL integration and waveform management to ensure host platforms and users have current TDL waveforms, network access, and interoperability. This includes enabling and supporting Joint Interoperability of Tactical Command and Control Systems (JINTACCS), joint/Coalition/NATO Interoperability, Link 16 enhancements, cybersecurity and performance testing, requirements analysis and fleet roadmapping efforts. In addition to integration efforts for new and existing TDLs, these activities require funding for test units and facilities, interoperability management systems, and assessment tools to implement waveform standards to meet system information exchange requirements. Advanced Aerial Communication Technology (AACT) activities consist of developing and demonstrating new technologies to enable host platforms and users. This includes but is not limited to the development of capabilities to reduce the effects of advanced jamming in Anti-Access/Area Denial environments and increase communications resiliency for platforms and users. Technical solutions developed under this effort include, but are not limited to, Protected Tactical Waveform (PTW), Small Form Factor (SFF)/Digitally Assisted Close Air Support (DACAS), Software Programmable Open Mission System (OMS) Compliant (SPOC) radio and Link 16 Enhancements.$$, 77170000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604282N_3380$$, $$0604282N$$, $$3380$$, $$Next Generation Jammer Inc II$$, 228256000, $$This Program Element (PE 0604282N) supports the AN/ALQ-266 Next Generation Jammer - Low Band (NGJ-LB) program. NGJ-LB will address Airborne Electronic Attack (AEA) capability and sufficiency gaps against enemy threats operating in the lower frequency bands of the electromagnetic spectrum. NGJ-LB will provide the ability to effectively engage enemy threats from increased stand-off distances, employ increased capacity (number of jamming assignments) against enemy targets, and support agile employment by operators and increases survivability and lethality of 4th and 5th generation platforms and strike weapons. The NGJ-LB system will be integrated on the EA-18G tactical aircraft and will augment and then replace the aging AN/ALQ-99 Tactical Jamming System in the low band frequencies. Total cost should reflect $3,257.870M.$$, 228256000, NULL, NULL, NULL, NULL, 466967000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604283F_673587$$, $$0604283F$$, $$673587$$, $$ARSR-4 Replacement -$$, 17353000, $$This budget line item funds the replacement of the current Hawaii Air Route Surveillance Radar Version 4 (ARSR-4) to include prototype development, test, site preparation, and installation. The replacement radar will address DoD capability gaps driven by new threats and provide dual use for Hawaii Air Traffic Control (ATC). The new system is designated the ARSR-4 Replacement Hawaii (ARSR4R-HI) Long Range Radar (LRR). It is a key component of the integrated Homeland Defense capability for the defense of Hawaii and a high priority mission for Pacific Air Forces and the United States Indo-Pacific Command. The ARSR4R-HI program addresses the following surveillance shortfalls: 1. Lack of surveillance capabilities to meet today's mission needs such as inability to characterize and classify targets or cover all required airspace. 2. Inability to scale and update capabilities to pace evolving threats. 3. Obsolescence associated with 1980s era ARSR-4 equipment and infrastructure leading to excessive sustainment, operations, and maintenance costs. To address these surveillance shortfalls, development of the ARSR4R-HI system will consist of improved detection performance for modern air threats, mitigate new interference sources, and utilize state of the art surveillance technologies and processing capabilities. The ARSR4R-HI solution is based on a non-rotating, multi-panel, phased array radar system which provides persistent surveillance with improved accuracy and detection performance supporting an advanced engagement sequence to counter modern threats with target cueing and fire control quality data. The ARSR4R-HI components include a ground based surveillance radar, radar dome, associated shelters, and other smaller Government Furnished Equipment (GFE) items. The DoD currently owns the site for the location of the installation and the FAA leases the site. The ARSR4R-HI program includes the award of two Rapid Prototype Development capability demonstration contracts (Phase I) followed by down-select (Phase II) to a single vendor for Non-Recurring Engineering (NRE), mature prototype delivery, installation, interface with Command and Control (C2) nodes, and test of the new radar at the Mt. Ka'ala site. The FY 2026 cost of the ARSR4R-HI Middle Tier of Acquisition effort is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0604283F / Battle Mgmt Com & Ctrl Sensor Development Operational Systems Development The FY 2026 request for ARSR4R-HI includes 17.4 million of discretionary and 150.0 million of mandatory (reconciliation) funds for a total of 167.4 million. The mandatory (150.0 million) funds, along with 45.7 million of FY 2025 funding, enable award of the Phase II prototype system contract. Further information for this reconciliation request is provided in Section 20003 of the Reconciliation Exhibit. The FY 2026 request was reduced by 0.136 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024, 0.599 million was expended for civilian pay expenses in this program element, and in FY 2025 1.955 million is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, 17353000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604286N_0311$$, $$0604286N$$, $$0311$$, $$NAVAIR Aviation Advanced$$, 2371000, $$Advanced/Additive Manufacturing (AM) - Transfer to BA 4, PE: 0604286N Navy Advanced/Advanced Manufacturing PROJ 0311 NAVAIR Aviation Advanced Manufacturing starting in FY 2026 from PE: 0605013N Information Technology Development Project 2903 NAVAIR IT. Provides for the development of the Advanced/Additive Manufacturing/3D printing process, material verification and qualification to support deployment of Advanced/ Additive Manufacturing (AM) capability to Fleet Depot and Level II Maintenance level facilities, as well as provides for the qualification, validation, testing and incorporation of private industry Additive Manufacturing initiatives across the Naval Aviation enterprise to include NAVSUP and Defense Logistics Agency (DLA). Additionally, Advanced/Additive Manufacturing funds Cooperative Research and Development Activities (CRADAs) support with industry partners and next generation AM. This effort will fund the development, test, and approval of additional polymer material data curves, polymer material certification for aviation applications, and system documentation/training updates of additional high strength polymers for use on deployed AM systems. This will support deployed systems in producing critical parts for aircraft, support equipment and aircraft launch and recovery equipment, while enhancing Naval Aviation readiness and lethality allowing point of need part manufacturing to mitigate supply chain gaps, dramatically decreasing Mean Logistics Delay Times (MLDT) and increasing aircraft availability.$$, 2371000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604286N_0312$$, $$0604286N$$, $$0312$$, $$NAVSEA Maritime Advanced$$, 5186000, $$The AM program focuses on development and use of AM equipment for Naval applications in land-based and afloat applications, including system performance requirements, shipboard integration requirements and considerations, material selection, design optimization, equipment and component certification, and digital engineering integration. Efforts also include consideration of AM across a wide variety of potential applications ensuring AM manufactured components can meet mission requirements and that system/component technical requirements are updated to leverage AM.$$, 5186000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604294D8Z_908$$, $$0604294D8Z$$, $$908$$, $$Access to Advanced Packaging and$$, 90784000, $$The DoD needs modern microelectronics capabilities. Advanced packaging provides necessary performance improvements, size weight power and cost (SWAP-C) benefits, and unique opportunities to disaggregate DoD requirements into smaller and lower cost chiplets while maximally leveraging state-of-the-art (SOTA) commercial technologies. However domestic advanced packaging capabilities are limited and the heterogeneous integrated (HI) chiplet ecosystem is nascent. This project collaborates with DoD, the Defense Industrial Base (DIB), and domestic commercial industry to leverage and enhance existing capabilities to develop self-sustaining advanced packaging and test solutions that meet DoD needs.$$, 90784000, NULL, NULL, NULL, NULL, 222002000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604286N_0313$$, $$0604286N$$, $$0313$$, $$NAVWAR Digital Integration$$, 2497000, $$The NAVWAR Digital Integration Advanced Manufacturing project provides Navy Advanced Manufacturing (AdvM) technology aligns to Chief of Naval operations (CNO) priorities to deliver revolutionary capabilities to improve fleet readiness. These enterprise solutions will provide the foundation to (a) enhance warfighter capability by implementing disruptive AdvM technologies such as Additive Manufacturing (AM), Subtractive Manufacturing, 3D CNC milling, Computer Numerical Control (CNC) Lathing, and Robotic welding; (b) increase readiness through low-volume production of hard-to-source items; and (c) improve warfighting capacity by enabling low volume custom production at or near the point of need. Specific efforts include the development of the Digital Advanced Manufacturing Ecosystem (DAME) to address the design and certification of AM capabilities for both afloat and ashore, development of Cyber Security Risk Management Profiles for devices and applications on operational networks, definition of a secure Technical Data Package to describe components that can be digitally manufactured, and the development of an overarching, enterprise-level Digital Manufacturing Thread (device management, digital rights management, licensing, configuration management, data storage rule/access and application programming interfaces).$$, 2497000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604286N_0314$$, $$0604286N$$, $$0314$$, $$NAVFAC Expeditionary Advanced$$, 531000, $$Advanced Manufacturing (AdvM) : In accordance with the National Defense Strategy (NDS), A Design for Maintaining Maritime Superiority 2.0, and Navy Facility Command (NAVFAC) Strategic Design 2.0, this program provides the Navy with new capabilities to enable resilient and agile logistics thru advanced manufacturing (AdvM). Investing in AdvM enhances the fleet's ability to conduct operational logistics in a contested environment and ensures logistics supportability across the austere distributed battlespace. AdvM technology results in increased operational availability, on demand production of critical systems, and supply chain cost savings. This effort will identify critical parts suitable for AdvM production in the field; identify AdvM systems appropriate to produce and certify critical parts in the field; analyze and identify AdvM system implications across doctrine, organization, training, materiel, leadership and education, personnel, facilities and policy (DOTMLPF-P); conduct end-user training, field experimentation, and fleet exercise technology insertion to validate AdvM system capability and systems integration issues.$$, 531000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604287F_655120$$, $$0604287F$$, $$655120$$, $$Physical Security$$, 10589000, $$The Physical Security Equipment (PSE) program provides for Air Force (AF) Integrated Base Defense Security Systems (IBDSS) improvements and enhancements, to include the demonstration and testing of PSE systems related to Force Protection. This program supports the protection of tactical, fixed, and nuclear weapons systems, AF personnel and AF facilities in the homeland and overseas. The PSE program includes spectrum planning for radio frequency (RF), communication security (cyber), information assurance requirements, integration and interoperability Command Control & Communication (C3) platform & components and Tactical Sensor System to support the Force Protection implementation of expeditionary/AFFORGEN concept. This Program Element also includes funding for Force Protection Commercial Off the Shelf (COTS) equipment, market research, integration, evaluation and testing. Force Protection programs are inherently subject to rapid changes in the operational environment and will retain sufficient program flexibility to meet changes in location, scope and capability in order to protect AF people, facilities and warfighting assets. The Defender Multi-Domain Command, Control and Communications (DMDC3) is an initiative developing the foundational structure of IBDSS to provide a platform that integrates the computing power, the means of communication, and the tools for situational awareness. PSE efforts support Modular Open Source Architecture (MOSA) standards to enable faster installations and greater interoperability to address the Chief of Staff of the AF 'Fight the Base' goals. IBDSS FY2026 developmental efforts will continue to evaluate and test state-of-the-art technology to support integrated based defense systems installations worldwide, continue to improve and integrate COTS efforts into IBDSS physical security equipment, and further develop, integrate and test Defender Multi-Domain Command, Control and Communications (DMDC3) software applications. IBDSS-4 expands upon and scales IBDSS modernization efforts first developed under IBDSS-2. Capability improvements include zero-trust architecture, Machine Language (ML)/Artificial Intelligence (AI) integration, expanded sensor capabilities, Unmanned Aerial System(UAS)/Unmanned Ground Vehicle (UGV) integration, and improved mobile C3. The FY 2026 request was reduced by 0.490 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024 1.118M forecasted for civilian pay expenses in this program element, and in FY2025 1.430M is forecasted for civilian pay expenses in this program element. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0604287F / Physical Security Equipment Development & Demonstration (SDD) This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, 10589000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604288F_3600$$, $$0604288F$$, $$3600$$, $$Research, Development, Test & Evaluation, Air Force / BA 5: System$$, NULL, $$The Survivable Airborne Operations Center (SAOC), E-4C, replaces the aging E-4B fleet, which faces capability gaps, diminishing manufacturing sources, increased maintenance costs, and parts obsolescence as it approaches the end of its serviceable life. SAOC provides the President of the United States (POTUS), the Secretary of Defense (SECDEF), and the Joint Chiefs of Staff (JCS) a worldwide, survivable, and enduring node of the National Military Command System (NMCS) to fulfill national security requirements throughout all stages of conflict. As a command, control and communications center directing US forces, executing emergency war orders and coordinating the activities of civil authorities including national contingency plans, this capability ensures continuity of operations and continuity of government as required in a national emergency or after negation/destruction of ground command and control centers. SAOC fulfills the requirements of the AF Nuclear Mission by providing Nuclear Command, Control and Communications (NC3) capabilities to enable the exercise of authority and direction by the President to command-and control US military nuclear weapons operations. Program funding supports all activities required to execute development of the SAOC Weapon System to include system development, integration of NC3 and other DoD/AF programs into the SAOC weapon system, test activities, pre-operational product support, and Interim Contractor Support (ICS). Funds also support program office operations, management services (Federally Funded Research and Development Centers [FFRDC], Advisory and Assistance Services [A&AS], etc.), Program Management Administration (PMA), security, facilities, prototyping, equipment, implementation of digital program initiatives, and other required program office capabilities. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024, $1.540M expended for civilian pay expenses in this program element. In FY 2024, $4.000M is forecasted for civilian pay expenses in this program element. The FY 2026 request for SAOC includes $1,826,328 thousand of discretionary and $6,800 thousand of mandatory (reconciliation) for a total of $1,833,128 thousand. The mandatory funds address EMD in FY 2026. Further information for this reconciliation request is provided in Chapter 8 (Nuclear) of the Reconciliation Exhibit. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0604288F / Survivable Airborne Operations Center (SAOC) Development & Demonstration (SDD) This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, NULL, NULL, NULL, NULL, NULL, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604288F_656507$$, $$0604288F$$, $$656507$$, $$Survivable Airborne$$, 1826328000, $$The Survivable Airborne Operations Center (SAOC), E-4C, replaces the aging E-4B fleet, which faces capability gaps, diminishing manufacturing sources, increased maintenance costs, and parts obsolescence as it approaches the end of its serviceable life. SAOC provides the President of the United States (POTUS), the Secretary of Defense (SECDEF), and the Joint Chiefs of Staff (JCS) a worldwide, survivable, and enduring node of the National Military Command System (NMCS) to fulfill national security requirements throughout all stages of conflict. As a command, control and communications center directing US forces, executing emergency war orders and coordinating the activities of civil authorities including national contingency plans, this capability ensures continuity of operations and continuity of government as required in a national emergency or after negation/destruction of ground command and control centers. SAOC fulfills the requirements of the AF Nuclear Mission by providing Nuclear Command, Control and Communications (NC3) capabilities to enable the exercise of authority and direction by the President to command-and control US military nuclear weapons operations. Program funding supports all activities required to execute development of the SAOC Weapon System to include system development, integration of NC3 and other DoD/AF programs into the SAOC weapon system, test activities, pre-operational product support, and Interim Contractor Support (ICS). Funds also support program office operations, management services (Federally Funded Research and Development Centers [FFRDC], Advisory and Assistance Services [A&AS], etc.), Program Management Administration (PMA), security, facilities, prototyping, equipment, implementation of digital program initiatives, and other required program office capabilities. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024, $1.540M expended for civilian pay expenses in this program element. In FY 2024, $4.000M is forecasted for civilian pay expenses in this program element. The FY 2026 request for SAOC includes $1,826,328 thousand of discretionary and $6,800 thousand of mandatory (reconciliation) for a total of $1,833,128 thousand. The mandatory funds address EMD in FY 2026. Further information for this reconciliation request is provided in Chapter 8 (Nuclear) of the Reconciliation Exhibit. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0604288F / Survivable Airborne Operations Center (SAOC) Development & Demonstration (SDD) This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, 1826328000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604289M_2741$$, $$0604289M$$, $$2741$$, $$Additive Manufacturing$$, 2722000, $$This project supports costs associated with the research, development, testing and evaluation of Marine Corps Systems Command acquisition process modifications, prototyping, and future logistics innovations to support the USMC Additive Manufacturing (AM) Initiative under the direction of Marine Corps Systems Command. This project invests in the 3D printing of large-scale constructs such as metal and polymer landing craft and concrete structures to include buildings and bridges. The USMC Additive Manufacturing Initiative is intended to give Marine units access to additive manufacturing techniques allowing them the opportunity to exercise innovation in the resolution of issues affecting unit combat readiness and sustainment. This involves the development of Marine Corps Policy, the digital data repository required to share equipment technical data and part designs, a part approval process, engineering analysis and testing, establishment of facilities to produce prototype additive manufactured parts, and development of training to support the Marine Corps' use of additive manufacturing. This initiative incorporates development of strategic partnerships with other Department of Navy (DoN) Systems Commands and field activities to develop DoN Standards, Processes, and other associated acquisition activities to support future use of additive manufacturing in DoN acquisition, readiness, and sustainment.$$, 2722000, NULL, NULL, NULL, NULL, 11465000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604292N_2940$$, $$0604292N$$, $$2940$$, $$Future Vertical Lift (Maritime Strike)$$, 7125000, $$The Future Vertical Lift (Maritime Strike) (FVL (MS)) project directs developmental activities in support of the replacement of the current inventory of Navy helicopters in the 2040+ timeframe. Specific development activities required for FVL (MS) may include: capability requirements definition, documentation, and validation; completion of affordability studies; establishment of the appropriate security environment (e.g. computers, facilities, and administration); production of an Acquisition Strategy (AS), Life Cycle Cost Estimate (LCCE), Life Cycle Sustainment Plan (LCSP), Systems Engineering Plan (SEP), and Draft Capability Development Document (CDD); Request for Proposal (RFP) development: acquisition documentation; risk reduction initiatives; design trade studies; and support to joint vertical lift initiatives, including open hardware and software reference and objective architectures definition, mission system interoperability, and shipboard compatibility. Follow-on activities support preparation and execution of efforts to develop Modular Open Systems Approach (MOSA) common systems reference and objective open architectures, and eventual prototype aircraft flight demonstrations in support of the vertical lift Technology Maturation and Risk Reduction (TMRR) acquisition phase. Activities and technologies developed also have the potential to be leveraged for sustainment of legacy Navy helicopters. These efforts will enable timely development of a system that provides best value and capability to the Joint Warfighter while maintaining effective and efficient war fighting capability in support of the Navy's 15-year Aviation Plan and 30-year Shipbuilding Plan. FY 2026 budget funds FVL (MS) pre-Milestone A activities to include analyses, studies and development of acquisition documentation. Tasks to be performed may include acquisition program management functions, engineering modeling and analysis, conceptual design trade studies, and other related follow on activities.$$, 7125000, NULL, NULL, NULL, NULL, 18355000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604292N_9999$$, $$0604292N$$, $$9999$$, $$Congressional Adds$$, 0, $$Congressional Add: C360: Advanced vertical lift rotor technology$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604294D8Z_907$$, $$0604294D8Z$$, $$907$$, $$Access to State-of-the-Art (SOTA)$$, 116539000, $$Microelectronics are critical technologies that drive the modern economy and enable the defense systems that allow warfighters to accomplish their missions. Other nations recognize the need to control the microelectronics supply chain and indigenous state-of-the-art (SOTA) manufacturing. Aggressive investments and licit and illicit actions by peer nations threaten U.S. leadership. China alone purports investment of $150 billion and a national strategy to achieve dominance in all major areas of microelectronics by 2030. Russia and China have publicly stated that advanced microelectronics, AI, and machine learning (ML) are the keys to economic and military dominance. This project funds the operation of microelectronics software assurance (SwA) support to DoD programs and organizations of the Joint Federated Assurance Center (JFAC), codified in the National Defense Authorization Act (NDAA) for Fiscal Year 2025, Sec 922, to support the assurance needs of the Department of Defense by ensuring, pursuant to policies related to hardware and software assurance and supply chain risk management, that the software and hardware developed, acquired, maintained, and used by the Department are free from intentional and unintentional vulnerability during the life-cycle of development and deployment of assured, trustworthy defense systems. The collaboration between the JFAC and program offices will help mitigate existing and emerging critical threats and vulnerabilities in microelectronics to all DoD programs. The project supports the implementation of Executive Order 14028 Improving the Nation’s Cybersecurity for software assurance for critical software such as software bill of materials, and information communications technology supply chain risk management, and the PD, Cyber Roadmap for mitigation of software vulnerabilities that are cyber related. This project includes establishment of new strategic partnerships with existing commercial SOTA domestic foundries to develop a data-driven, risk- based approach to supply chain protection and develop the assured access, secure design, and manufacture of advanced microelectronics technology and electronic components. Successful implementation will transition these technologies to use in DoD programs, obtain access to multiple commercial microelectronics facilities, establish secure design capabilities, and solidify a data-driven approach to supply chain protection. It also includes keeping pace with the rapid advancements in microelectronics technology and the globalization of this industry sector. It will provide the basics for updating and strengthening DoD assurance policy and includes collaborating with industry to develop data driven evidence-based practices.$$, 116539000, NULL, NULL, NULL, NULL, 2147488000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604294D8Z_911$$, $$0604294D8Z$$, $$911$$, $$DOD Unique Needs RADHARD$$, 174701000, $$This project addresses Government needs for microelectronics that represent only a small market share while spanning a wide range of devices, from legacy components to state-of-the-art (SOTA) technologies. The Government must sustain specialty suppliers and maintain access to a diverse microelectronics ecosystem to develop and acquire the application specific integrated circuits (ASICs) and specialized or modified commercial off the shelf (COTS) components required to satisfy military needs for radiation hardened, radio frequency (RF) and optoelectronic (OE) microelectronics. By partnering in the maturation of state-of-the-art material sources, foundries, and packaging facilities, the DoD is able to develop the ability to align commercial practices with DoD needs for unique functionality and encourage open access design to stimulate innovation and drive affordability. Subject matter expertise, technology, and manufacturing capability and capacity, including fabrication, packaging and test, are all needed. Moreover, domestic supply chains must be made more stable for both RF Gallium Nitride (GaN) and integrated photonics availability, integrity and security for the Department and the Defense Industrial Base.$$, 174701000, NULL, NULL, NULL, NULL, 416480000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604294D8Z_912$$, $$0604294D8Z$$, $$912$$, $$ME U.S. ME Dominance-Dev$$, 130127000, $$This project will promote microelectronics innovation and create an evidence-based assured microelectronics pipeline including maintaining Joint Federated Assurance Center (JFAC) strategic partnerships, assuring field programmable gate array (FPGA) devices, supply chain awareness and security, and workforce development. It will slow and, in the long-term, reverse offshoring trends by fostering commercial and Government alliances to preserve the U.S. ecosystem, lower barriers to innovation and adoption, strengthen workforce expertise, and ensure DoD has access to the next generation of advanced technology by utilizing an evidence-based assurance approach. This approach enables management of microelectronics security that is commensurate with program risk throughout the product pipeline and maintain the United States as the global source for high- end, secure, and reliable microelectronics components. In addition, this project will develop a new data driven risk-based assurance paradigm for supply chain protection. This paradigm will strengthen security while improving access, without exposing sensitive intellectual property (IP) to the foundry and requiring post-manufacture validation of foundry products. The enhancement will develop evidence-based assured design concepts in manufactured systems, enabling a formal risk-based approach to protection techniques. Manufactured microelectronics will be tested to ensure that IP protections meet or exceed current National Security Agency standards for IP protection, and to develop DoD’s ability to detect certain malicious supply chain attacks on DoD microelectronics.$$, 130127000, NULL, NULL, NULL, NULL, 204945000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604294D8Z_913$$, $$0604294D8Z$$, $$913$$, $$Defense Microelectronics CFT$$, 0, $$Microelectronics components are the foundation of modern military systems. The Department of Defense (DoD) is exposed to various vulnerabilities that threaten the ability to source microelectronics needed to sustain programs of record. To prepare the Department for Great Power Competition, the DoD must take action to ensure access to the microelectronic components needed to sustain our defense programs and systems effectively and affordably. The Department also needs a better strategy to transition leading edge technology developed by both government and industry to DoD programs of record, to ensure the Department maintains a competitive edge.$$, 0, NULL, NULL, NULL, NULL, 3924000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604295M_3751$$, $$0604295M$$, $$3751$$, $$Vertical Takeoff and Landing$$, 33896000, $$USMC VTOL Development portfolio addresses vertical lift capability requirements that are feasible and affordable. This element supports Marine Corps Force Design and Marine Corps Aviation's Project Eagle initiative. This portfolio facilitates developmental and operational prototyping and demonstration of capabilities supporting Logistics/Aviation Sustainment, Future Attack/Strike, Assault Support, and Autonomy. Project activities are closely aligned with the OSD-sponsored vertical lift initiatives and will look to leverage any aspects of Joint Service programs (e.g., Future Long Range Assault Aircraft, unmanned, air launched effects) that may benefit the Marine Corps through accelerated development and/or reduced life cycle costs. The VTOL Development portfolio serves as a force multiplier, supporting development, maturation, experimentation and evaluation of enhanced performance qualities (e.g., agility, endurance, reliability, lift capacity, survivability), technically relevant modular kinetic/non-kinetic payloads, and superior warfighter-machine interface (e.g., autonomy), enhancing warfighter lethality. This project increases the MAGTF's lethality through its long-range fires, Logistics/Aviation Sustainment, Future Attack/Strike, and Assault Support efforts. Specific projects include the Contested Logistics focused Aerial Logistics Connector (ALC). Project activities directly support Force Design and Project Eagle, enable the Stand-in Force (SiF), and facilitate Expeditionary Advanced Basing Operations (EABO), and Littoral Operations in a Contested Environment (LOCE) through the development of manned and unmanned capabilities that enhance warfighter survivability and lethality.$$, 33896000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604295M_3752$$, $$0604295M$$, $$3752$$, $$Future Capabilities Transition$$, 4977000, $$The Future Capability Transition (FCT) portfolio implements a capabilities-based acquisition approach focused on lethality, enhancing Marine Corps Aviation's interoperability and effectivity in joint kill webs. FCT accelerates the transition of Science and Technology (S&T) efforts into lethal Warfighter capabilities, which includes OSD R&E Defense Innovation Acceleration (DIA) and OSD R&E Rapid Defense Experiment Reserve (RDER) projects. FCT supports the execution of Force Design by ensuring both legacy and future platforms influence S&T early enough to inform design and acquisition decisions that avoid duplicative design and engineering, reduce life-cycle costs and expedite delivery of enhanced lethality capabilities to Marine Aviation. This PE includes enduring VMX-1 RDT&E support along with support of Fleet evaluations and demonstration.$$, 4977000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604307N_1111$$, $$0604307N$$, $$1111$$, $$Integrated Combat System (ICS),$$, 101971000, $$MK 6 MOD X Computing Infrastructure (CI) delivers the developmental efforts and prototypes to enable future delivery of Infrastructure as a Service (IaaS) in support of all surface combatants (e.g. DDG, FFG, DDG(X), CVN, LPD, LHD, and LHA). IaaS provides hatch able hardware abstracted from software, enabling upgrade outside modernization periods (agility) to more ships (capacity). The MK 6 MOD X CI is a foundational element of the surface Navy's Integrated Combat System (ICS) System supporting all future ship classes. Top Level Requirements (TLR) were validated in the Initial Capabilities Document for the Future Surface Combatant Force. Software Factory (SW Factory) provides a Continuous Integration/Continuous Delivery (CI/CD) pipeline for software where combat system applications are developed, tested, certified, and fielded to the Fleet at speed. The AEGIS and Ship Self Defense System (SSDS) computer programs will be re-factored into a single ICS computer program. Provides rapid combat system development, test, certification, and authorization; more frequent delivery, and faster turnaround of Fleet feedback into working software and fielding to the IaaS-enabled fleet.$$, 101971000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604307N_1447$$, $$0604307N$$, $$1447$$, $$Surf Combatant Combat System Imp$$, 322012000, $$AEGIS Development Support is the foundation that maintains the Research and Development Land Based Test Facilities, Technical Design Agent (TDA), Commercial Off The Shelf (COTS) hardware engineering, and Program Management services required to support the development and integration efforts required to effectively design, test and certify, Combat System computer programs. Starting in FY26, this line will support the Combat System Test Bed (CSTB) efforts, which support model development designed to reduce testing requirements. AEGIS BL 9.2.2 delivered in FY21 to TI-12 hardware ships, integrated previous CSL capabilities plus Surface Electronic Warfare Improvement Program (SEWIP) BLK 2 integration (auto association); MH-60R integration; Advanced Training Doman; Boundary Defense Capability; Integrated Air and Missile Defense (IAMD) mission planner; Above Water Sensor Coordinator; Agile Moondog, Sirocco, Sundog part 1, Silent Squall part 1, and Vortex; Advanced Calibration Experiment; Cyber enhancements (cyber resource services, boundary proxy service, Security Information and Event Management (SIEM), network device integrity, update manager); and BMD 5.1.3.1 (MDA-developed). BL 9.2.2 delivered the previously listed capabilities plus warfighting improvements derived from operations in the Red Sea to remaining TI-12H ships in FY24. BL 9.2.2 will deliver previously listed capabilities with further threat-based modernization improvements derived from Red Sea operations to TI-12H ships in FY25. (Effort Completes in FY25) AEGIS Capability Package (CP) 2022, delivered in FY23, builds upon previous CSL capabilities, integrating Multi Mission Signal Processor (MMSP)-Restoration (AMOD DDG only); AEGIS Linear Processing System (ALPS); High-Energy Laser with Integrated Optical-Dazzler and Surveillance (HELIOS); SM-2 Blk IIIC initial capability; Agile Firestorm; Mk 38 Mod 4 Engineering Operational Sequencing System (EOSS) integration; and BMD 5.1.4 (MDA-developed) capabilities. CP 2022-2 delivered to DDG 91 to support its modernization test program in FY24. Dependent on SEWIP BLK 3 Integration effort. CP 2022-2 was delivered to DDG 91 to support its modernization test program in FY24. Dependent on SEWIP BLK 3 Integration effort. (Effort Completed in FY24) Previously listed capabilities with Infrastructure as$$, 322012000, NULL, NULL, NULL, NULL, 5759759000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604307N_3357$$, $$0604307N$$, $$3357$$, $$Aegis Training Improvement Program$$, 8998000, $$The AEGIS Training Improvement project provides enhancements and upgrades to the Total Ship Training Capability (TSTC) training components within the combat system to address needs for increased training capability and functionality in conjunction with AEGIS Capability Packages. These enhancements will address current and future training requirements by implementing new functionality to enable the individual warfighter through distributed battle group events to engage in more complex training requirements to support fleet required training certification events. Capability Development and integration are related to Integrated Air and Missile Defense, Underwater, Surface, and other warfare areas. Capability enhancements and upgrades include development of re-useable common components that can be leveraged by SSDS MK2 combat systems, and/or integration of re-usable common components developed by the TSTC Battle Force Tactical Trainer (BFTT) Program and Ship Self Defense System (SSDS) MK2 TSTC Training Improvement programs to meet AEGIS combat system training requirements. TSTC provides realistic joint warfare training across the spectrum of armed conflict, realistic unit level team training in all warfare areas (e.g. Naval Integrated Fire Control-Counter Air (NIFC-CA) and BMD missions to support IAMD). TSTC provides ships' Commanding Officers and Battle Group/Battle Force Commanders with the ability to conduct coordinated realistic, high stress, combat system level team training as an integral part of the Afloat Training Organization, the Tactical Training Groups and C2F/C3F Fleet Synthetic Trainers (FSTs). TSTC continues to integrate and update, as new tactical capabilities are being introduced, to enable crew operator proficiency training for basic and sustainment level training events, through distributed strike group certification fleet synthetic training (FST) events and including Composite Training Unit Exercise (COMPTUEX) Fleet Synthetic Training (FST) at Sea integration into Live, Virtual and Constructive (LVC) environment. Continued Development is required to integrate new capabilities and interfaces to provide training for AEGIS and SSDS combat system capability upgrades, and to address the Fleet's Live, Virtual and Constructive (LVC) Fleet Training Wholeness initiative. Additionally, modernization is needed to support the DoD Training Transformation Plan, the Chief of Naval Operations Fleet Response Plan and Commander United States Fleet Forces Command Fleet Readiness Training Plan. The Advanced Training Domain (ATD) is being developed to combine BFTT and the AEGIS Combat Training System (ACTS) into a common system that integrates with AEGIS BL 9.2.2AF, and SSDS BL 11.xAF. ATD is being hosted along with the AEGIS and SSDS combat system on TI-16AF common processing and display hardware. ATD is being designed to be the core of the Total Ship Training Capability, and is projected to be more reliable, simpler to use, and architecturally extensible to meet interoperability and capability enhancement challenges in the future. The BFTT is being updated to maintain integration and capability enhancements developed for the Cooperative Engagement Capability (CEC), Surface Electronic Warfare Improvement Program (SEWIP), and the Carrier Tactical Support Center (CV-TSC), and SSDS Fire Control Loop Improvement Program. TSTC integrates ATD or BFTT with combat systems elements such as such as AWS, SQQ-89, Vehicle Control Domain via MH-60R Sim, Surface and Air Search Radars, Electronic Warfare Systems (BEWT/SEWTT), Identification Friend or Foe (IFF), CEC & Data Link Systems, and Missile/Weapon Systems to provide a multi- warfare integrated training capability used for training and certification of crews and strike groups.$$, 8998000, NULL, NULL, NULL, NULL, 83433000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604317F_646003$$, $$0604317F$$, $$646003$$, $$Partnership Intermediary$$, 3558000, $$Since 2012 the Air Force Tech Transfer & Transition Program Office has managed two OSD-level Partnership Intermediaries (PIAs), TechLink & Miltech (Montana State University), as supported the Office of the Deputy Assistant Secretary of the Air Force for Science, Technology, and Engineering (SAF/AQR) in the management and oversight of the 16 Air Force PIAs (as of FY23). The 646003 project resources the management of DoD/AF PIAs, the development of data to support the Defense Technology Transfer Information System (DTTIS), invention disclosure & patent processing, program management activities, training, and support to the Technology Executive Officer (TEO). This program impacts virtually all technology fields, including our Critical Technology Areas, and non-funded mechanisms to help achieve the operational imperatives via Tech Transfer as captured in the Annual DoD Technology Transfer Report. Technology Transfer is a critical strategy for the National Defense Strategy and DoD that makes the best possible use of national scientific, technical resources and information to enhance the effectiveness of DoD forces and warfighting capability systems. Enabled by the TechLink PIA, TechLink brokered 80% of DoD license agreements over the past 5 years, with 90% of them being with small businesses. TechLink has also facilitated over 2,000 DoD T2 agreements since 1999 and has enabled the conversion of lab inventions into realized products and services that bolster the US Defense Innovation Ecosystem. Throughout FY24, TechLink facilitated 77 metric-related agreements between the DoD and industry. An incredible amount of activity driven by TechLink's business units and cross functional teams enable the achievement of technology transfer success for the Air Force and DoD. Since 2004, Montana State University's MilTech has performed over 600 technology acceleration and transition projects for all DoD Services, OSD, Joint and Special Programs. Additionally, MilTech has partnered will all DoD Services for over twenty years to support efforts such as electronic warfare, medical technologies and body armor projects and has been selected as the permanent bi-annual host of the Interservice Body Armor Working Group (IBAWG) event. Montana State University's MilTech has been rated as a Top Ten Veteran Friendly university and has supported MilTech's 20 years of successful technology transitions that protect Soldiers, Sailors, Airmen, Marines, and Guardians. Fundamentally, the Air Force Technology Transfer and Transition Program Office oversees all AF inventions/patents and technology transfer agreements. This project includes the management of DoD/AF PIAs, invention disclosure & patent processing, program management activities, training, support to the Technology Executive Officer (TEO), and support of the Defense Technology Transfer Information System (DTTIS). This DTTIS platform collects and manages technology transfer activities. Phase I of the DTTIS initiative focuses on deploying the system for use by the DAF Tech Transfer office. DTTIS is projected to provide an approximately 6.33 million in annual cost avoidance across the DAF. As of June 2025, DTTIS has received its Authorization to Operate (ATO) and went live in October 2024.$$, 3558000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604317F_646030$$, $$0604317F$$, $$646030$$, $$AFwerX$$, 0, $$The AFWERX mission is to accelerate agile and affordable capability transitions by teaming innovative technology developers with Airmen and Guardian talent. AFWERX leverages Spark (the Airmen and Guardian talent base), AFVentures (the dual-use expanded technology base), and Prime (technology transitions) to scale and accelerate the capability. Funding in this project supports AFWERX research and development, innovation hubs, and information technology, public affairs, and marketing. The AFWERX Program reduces risk in emerging technology markets by partnering with industries through Prime investments and providing access to Government analysis, testing and certification capabilities. Prime investments focus on Government-industry partnerships to influence and militarize emerging commercial capabilities to ensure US competitive advantage in key technology areas. The Spark mission is to inspire and enable Airmen and Guardians to unleash their collective talent and ingenuity. Spark connects innovators using virtual collaboration, immersive training, and networking opportunities to inspire ideas and cultivate more lethal force. By connecting operators closer to acquisition processes, Spark provides both a voice and a conduit to accelerate powerful ideas into game-changing operational realities. This focus helps guide technologies through transition across the valley from idea to scaled and sustained capability. Beginning in FY 2024, PE 0604317F, Technology Transfer, Project 646030, AFWERX efforts were transferred to PE 0604009F, AFWERX Prime, Project 640856 AFWERX Operations and Support.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604320M_0386$$, $$0604320M$$, $$0386$$, $$Rapid Prototype Development,$$, 16316000, $$The Marine Corps Rapid Capabilities Office (MCRCO) is established under the direction of the Commandant of the Marine Corps (CMC) to identify, develop, and transition emergent and disruptive capabilities that significantly enhance survivability, lethality, and effectiveness for the Fleet Marine Forces (FMF). MCRCO focuses on rapid prototype development, testing, and integration of cutting-edge technologies at Technology Readiness Level 7 or higher, ensuring seamless and efficient transition to the FMF. Leveraging both government and commercial off-the-shelf solutions, as well as developmental items, MCRCO plays a critical role in maintaining the Marine Corps' strategic readiness and technological edge. Additional details about the MCRCO, including project specifics, can be found at a higher classification level.$$, 16316000, NULL, NULL, NULL, NULL, 93494000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604320M_9999$$, $$0604320M$$, $$9999$$, $$Congressional Adds$$, 0, $$Wing-in-Ground-effect (WIG) platforms are an emerging alternative maritime transportation capability that will disrupt the adversaries kill chain and result in a cost imposition on enemy targeting. WIG platforms have potential to fill capability gaps in the Marine Corps' family of Littoral-Maritime Transportation & Mobility Systems. WIGs are water borne, inexpensive, maneuverable, platforms offering an alternative mode of high-speed surface transportation in a contested maritime, anti-access/area denial (A2AD) environment. Operating in ground effect provides maximum operational efficiency and allows the vessels to be certified as a maritime platform vice an aircraft, reducing certification and training requirements.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604327F_645341$$, $$0604327F$$, $$645341$$, $$Direct Strike Penetrator$$, 144143000, $$The Direct Strike Penetrator Systems program develops and modifies a family of advanced precision-guided penetrator munitions to include evaluation of integrated technologies for the development/integration of advanced position, navigation, and timing (PNT) capabilities (i.e., Global Positioning System (GPS), non-GPS, optical, passive, active, etc.) and smart fuze systems, and all penetrator components, that will provide the Air Force with improved ability to attack Hard and Deeply Buried Targets (HDBT), such as bunker and tunnel facilities, using air-to-surface conventional munitions. Systems developed include, but are not limited to Massive Ordnance Penetrator (MOP), GBU-72 Advanced 5,000-lb Penetrator Weapon System (A5K), and Section 804 Rapid Prototype/Rapid Fielding activities. Systems developed will be integrated onto current and future platforms to reduce the number of weapons required to hold HDBTs at risk and will result in more targets engaged per mission flown. Direct Strike Penetrators will provide critical global strike capability not met by inventory conventional weapons and will hold at risk the best protected high value assets essential to an enemy's war fighting ability. The project also provides an opportunity to quickly insert emerging technologies into existing and developing aircraft munitions and fuzes. A Hard Target Munitions (HTM) Analysis-of-Alternatives (AoA) was conducted in 2014 to determine the best weapons and/or development efforts for addressing the HDBT mission area. The HTM AoA determined that it was necessary to develop a family of HTMs in order to apply effects to the entire range of HDBT sets. The Air Force is using the AoA to develop, produce and modify HDBT weapons identified as the most effective and affordable. Modeling and simulation is used to assess and characterize current inventory and to drive design and explore the utility of new classes of penetrator munitions. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 0.0M was expended for civilian pay expenses in this program element. In FY 2025 and FY 2026, $1.5M each is forecasted for civilian pay expenses in this program element. This program leverages digital acquisition tenets of open, agile, and digital. Common component development, in collaboration with other weapon systems, to reduce redundant costs between systems with similar subsystems requirements. Invests in analytical, information management, data management, digital environments, networks, facilities, and security infrastructure upgrades directly supporting development and sustainment of this program's capabilities, while leveraging DoD and DAF enterprise IT solutions. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                         R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604327F / Hard and Deeply Buried Target Defeat System (HDBTDS) Program Component Development & Prototypes (ACD&P) This effort includes design, development, test, integration, and implementation of appropriate modular open systems approach, related components, and efforts, such as, but not limited to electrical, logical, and physical interfaces defined in relevant Open System Architecture (OSA) standards. This approach allows modular and severable subsystems, to include those that are software-defined, at the appropriate level to be incrementally added, removed, or replaced throughout the life cycle. The FY 2026 request was reduced by $0.131 million for civilian personnel to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative.” This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, 144143000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604414F_642834$$, $$0604414F$$, $$642834$$, $$Mitigations$$, 5982000, $$The Mitigations activity encompasses continuous efforts to support the Department of the Air Force (DAF) and Department of Defense acquisition community. It enables the Cyber Resiliency Office for Weapon Systems (CROWS) to be the DAF's focal point for enterprise cyber mitigations to critical cyber vulnerabilities for fielded weapon systems, subsystems, and support systems.$$, 5982000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604329N_3072$$, $$0604329N$$, $$3072$$, $$Small Diameter Bomb (SDB)$$, 23836000, $$Small Diameter Bomb Increment II (SDB II) is an ACAT 1C joint Department of the Air Force (USAF) and Department of the Navy (DON) program, with the USAF as the lead service. The SDB II increases joint lethality in contested environments. The SDB II can strike a diverse set of targets inside an adversary's air and missile defense networks to destroy mobile platforms through the weather. With increased loadout, range, and munitions effect the network enabled SDB II enhances close combat lethality in complex terrain and provides a net-centric operations capability. BRU-61C/A is a modification of the USAF BRU-61B/A upgraded for DON and F-35 environmental requirements. The BRU-61C/A is Universal Armament Interface (UAI) capable, pneumatic rack capable of carrying four SDB II's at once. The threshold aircraft for the USAF is the F-15E and F-35B and F-35C for the DON. This Project Unit includes all funding associated with integration on the DoN threshold platforms, F-35B and F-35C. This includes the integration of the SDB II weapon with BRU-61C/A rack on the F-35B&C, modification to the USAF BRU-61 four-place bomb rack for F-35 and DoN shipboard environments, the integration of the Universal Armament Interface (UAI) software into the F-35 Operational Flight Program (OFP), test asset procurement, flight testing, logistics and associated software updates for the SDB II weapon system. Internal carriage is being integrated and tested to support F-35 Initial Operational Capability (IOC). BRU-61C/A integration on the F/A-18E/F will begin after F-35 integration is complete.$$, 23836000, NULL, NULL, NULL, NULL, 462338000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604331D8Z_638$$, $$0604331D8Z$$, $$638$$, $$Rapid Prototyping Program$$, 235292000, $$The Rapid Prototyping Program (RPP) develops prototypes to deliver capabilities, inform requirements, and bridge the gap between RDT&E activities and fieldable solutions. RPP facilitates and accelerates joint, cross-cutting prototyping efforts within the Services and Defense Agencies. This program has the agility to select, fund, and implement projects in the year of execution as new opportunities or threats emerge. In consultation with the Service Science and Technology (S&T) executives, selected projects generally receive a single year of funding to accelerate capability transition to Services’ and Agencies’ programs of record. Projects deemed critical by the Under Secretary of Defense for Research and Engineering (USD(R&E)), the Joint Staff, and the Combatant Commands receive higher amounts of funding across multiple years. Planned funding supports the Joint Warfighting Concept (JWC), the Office of the Under Secretary of Defense for Research and Engineering's (OUSD(R&E)) critical technology areas, and Service and Agency needs to enable rapid response to emergent and time-sensitive threats.$$, 235292000, NULL, NULL, NULL, NULL, 608013000, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604336F_643360$$, $$0604336F$$, $$643360$$, $$Prototyping$$, 56926000, $$The Air-delivered Nuclear Delivery System project addresses a United States Strategic Command capability gap resulting from a congressionally directed study which led to endorsement of the Department of Defense's Deputy's Management Action Group and initiation of this project. The Department of Air Force is working with the Department of Energy's National Nuclear Security Administration and its National Laboratories to quickly develop and demonstrate a prototype Air-Delivered system based on fielded technologies to close this gap in the near term. The project requires close Department of Air Force and Department of Energy interagency coordination to produce a prototype that will enable rapid transition to a fielded system. Early development will include Modeling and Simulation analysis of several Nuclear Explosive Package options to refine the proposed Nuclear Explosive Package. The Air-Delivered Nuclear Delivery System must meet nuclear weapon's environmental standards from storage to weapon detonation, while meeting reliability and target defeat requirements. The Air Force will provide test resources to include ground test facilities, F-15E test aircraft, and B-2 test aircraft, and will work with the aircraft Program Offices to identify aircraft integration requirements including any potential Operational Flight Program software and hardware changes. The Air Force will procure and provide the National Nuclear Security Administration with the components necessary to produce Prototype Weapon Assemblies for capturing environments and demonstrating functionality in high-fidelity ground and air tests. Ground tests may include static ejection, vibration and thermal, cable pull-down, sled tests, and other environments testing. Flight tests will be performed by Air Force F-15E developmental flight test aircraft, with final prototype demonstrations planned to fly on B-2 aircraft. Considerations in the development of the prototype include nuclear surety, maintenance and logistics, refinement of requirements (Military Characteristics), and producibility. After successful flight test demonstration of the prototype, the program will mature developmental hardware to nuclear system "diamond stamp” quality, ensure nuclear surety standards are met, and mature aircraft interfaces including Aircraft Monitor and Control functions. The Air Force Research Laboratory is focused on high-impact, multi-domain science, technology, and prototyping solutions that drive innovation now while laying the groundwork for the Air and Space Force to win the future fight. The Air Force Research Laboratory effectively synchronizes the Department of Air Force science and Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604336F / Nuclear Delivery Systems Prototyping Component Development & Prototypes (ACD&P) technology enterprise and workforce to align towards the most consequential DAF priorities and accelerate the delivery of game-changing science, technology, and prototypes. In order to manage, execute, and deliver capabilities, this program element may include necessary civilian pay expenses; expenses to support the operation and maintenance of facilities; as well as expenses related to travel, supplies, IT hardware, software and support, and administrative contractor services. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, 56926000, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_projects (id, pe_id, project_number, title, request_amount, narrative, fy26_amount, fy27_amount, fy28_amount, fy29_amount, fy30_amount, prior_year_amount, fiscal_year) VALUES ($$0604341D8Z_490$$, $$0604341D8Z$$, $$490$$, $$Accountability Bookkeeping$$, 0, $$The Defense Innovation Unit (DIU) mission is to strengthen U.S. national security by accelerating the adoption of commercial technology throughout the military and growing the national security innovation base. DIU partners with organizations across the DoD and the interagency to rapidly prototype, field, and scale commercial solutions that can save lives, lead to new operational concepts, increase efficiencies, and save taxpayer dollars. With offices in Silicon Valley, Boston, Austin, Chicago, and in the Pentagon, DIU is able to attract the best and brightest talent and cutting-edge solutions. The National Defense Strategy for FY 2026 asserts that we have returned to an era of inter-state strategic competition with Russia and China, heightening the sense of urgency with which the nation, and Department of Defense (DoD), must reform our acquisition policies and approach to sustaining military-technical superiority. Notably, 11 of the 14 critical technology focus areas are dual use and rapidly developed by the commercial sector. While adversaries are challenging the U.S. across several dimensions, most importantly, our near peer competitors are at par or ahead of the United States in critical technology areas. Consistent with the Administration's research and development budget priorities, this new era of competition requires technological superiority to ensure the United States’ ability to project power, maintain international norms and rule of law, provide credible deterrence, and prevail in conflict. DIU increases the Department's access to commercial technologies and talent, with the ultimate goal of fielding technology at a pace that effectively deters our adversaries and helps ensure victory if we are forced to fight. Working across the country, and in collaboration with our allies and partners, DIU is developing new ways of doing business, growing our national security innovation base to include more "non-traditional" companies that had previously not collaborated with the military, working with traditional vendors in novel ways to increase efficiency, and challenging innovators to share their knowledge and expertise in support of our nation's defense. Through a competitive prototype process, DIU identifies and provides access to technology companies and products on behalf of DoD organizations. Additionally, DIU executes projects to leverage commercial sector technology analogous to military applications thereby increasing dual-use technology agility for the DoD. DIU Prototyping funds facilitate the award of projects that can augment commercial technologies, existing government-owned capabilities, or concepts for defense application. DIU focuses on six technology areas where commercial industry is the lead: • Artificial Intelligence (AI)/ Machine Learning (ML) – Applying AI/ML learning to accelerate critical decision making and operational impact. • Autonomy – Adopting and countering autonomous systems with a focus on human-machine interaction and scalable teaming. • Cyber – Making enterprise combat information open, accessible, and secure for defense personnel across the globe.$$, 0, NULL, NULL, NULL, NULL, 0, 2026) ON CONFLICT DO NOTHING;
